insert into public.lesson_records (lesson_record_id, student_id, course_id, staff_id, lesson_date, start_time, end_time, title, content, homework, memo) values
  ('e781578c-f90b-5699-b0ef-27eed617d7b5', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-11', '17:30:00', null, '通常 / 基本操作コース10キャッチゲームか、prgか小技で好きなもの', '前回の後半から少し迷走中で、今日も新しいものはやりたくなく、既存のアレンジがしたいとのことでした。prgから探してもらおうとしましたが、なんとなくゲームを開いていじっては他にいく、という感じでした。実際にアレンジするのは難しくて無理、とのことだったので、にじいろピンポンを最初から作ることを勧めましたが、それもイマイチだったので、そのままアレンジをさせておきました。 最後の方にはクローンを使ったアレンジを見せてくれて、ゲームとしてはよくわからないものではありますが、音の響きと出来上がる画像がおもしろいものができていて、そこを褒めると嬉しそうにはしてくれました。', null, '盛り上がり: 最後の作品を見せてくれたときと、帰り際はすっきりした顔をしていました。'),
  ('cf862042-e8b0-547f-b87d-75ec637424a4', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-07-11', '16:30:00', null, '通常 / コンテスト作品作り', '前回やったキャッチゲームの参考にお菓子を振ってくるギミックを追加しました。同じこーそを3種類のスプライトに移す方法として、バックパックのやり方を教えてました。得点の条件式の作り方として、演算式を作るのところまで、自力で「もし」の形は作れていたと思います。クリアの条件式から表示までを一緒に作って、同じ形のゲームオーバーのコードは頼らずに作れていました。最後の方見れてなかったが、ゲームがすぐとまってしまうバグが見れたのでそこを直してもらいたいです', null, '盛り上がり: ゲームをいろんなものを探索してました。'),
  ('5c1018bd-0b3b-5fa3-8832-7dff6d416543', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-11', '17:30:00', null, '通常 / コンテスト作品の作成続き 対戦相手の動きの完成を目指す', '今日は来るまでに体力を使ったのか、いつもよりエンジンがかかるのが遅く、しばらくはScratchでいろいろな作品を見ていましたが、やる気になってからは熱心に頑張っていました。 今日の目標を「ここだけ完成させよう」と伝えたところ、目標が明確になったせいかスムーズに作成を始め、完成まで持っていくことができていました。 やりたかったことはほぼ自力でできたようで、嬉しそうに完成作品を何度も見せてくれました。', '作品提出', '盛り上がり: 作り始めたら本人にとっても想定以上にスムーズにできたようで、とても満足げにしていました。ゲームとして、一定の完成度に達したものができたのが嬉しそうでした。'),
  ('b245e4b7-e9f3-503c-b916-e537ea25b18e', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-11', '17:30:00', null, '通常 / コンテスト作品の作成続き ゴミ拾いゲームの結果をどうエンディングにつなげるか検討', '修正するべき点、作成しなければいけない点なども自分で完全に把握して来室したようで、着々と進めていました。 非表示にしたはずのスプライトのあたりをクリックすると動いてしまうことに困っていたので、「背景が○○ではないとき」の使い方と、スプライトの他のスクリプトを止めるの使い方を復習して、解決してもらいました。 メッセージを受け取った時に音楽が鳴り続けるバグは、自分でコードを見直して、メッセージを送るコードが「ずっと」の中に入っていたことに気付いて直すことができていました。 エンディングが「町がきれいになりました」だけだったので、このゲームを作った理由を詳しく書くように勧めたところ、本人も納得して記載していました。', '本日渡した用紙を元に、作品提出', '盛り上がり: とりあえず完成までいけたということで、ほっとしていました。 自分でも満足のいく出来なようです。'),
  ('d521febb-4618-5a2c-8e13-ce05e55364d5', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-07-11', '16:30:00', null, '通常 / コンテスト作品作り', '前回ほぼ完成していたので、今回は追加要素で雪結晶で見えなくなったり、ダメージ与える部分が、食らう部分に代わる面白いギミックがさらに増えました。発想が上手くいかされていると思います。操作方法がいっぱいあるので、後半はギミックの整理を紙で整理しました。これで、提出フォーム作成に大いに役立つと思います。', 'コンテスト作品提出', null),
  ('2c95f187-cbc7-5203-9312-a0421d8995db', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-11', '16:30:00', null, '通常 / コンテスト作品の作成続き ゲーム後のエンディング作成', 'エンディングに向かう構成は考えてきてくれたようで、得点によってキャラクターに渡すものが変わるように作成していました。 メッセージを受け取った時のコード内で、スクリプトを止めるタイミングに混乱することがありましたが、丁寧に上からコードを読んでいくことで気づくことができていました。 今日はiPadのフリーボードで描いた絵の取り込みに少し時間がかかってしまい、作業が止まってしまいましたが、遅刻した分の時間を自主的に残ってきりの良いところまで作成するなど、計画性や集中力に成長が見られました。', null, '盛り上がり: 自作の絵がうまく取り込めたのと、先週考えた条件分岐がうまくできたのが満足そうでした。'),
  ('b072d743-83a5-5db0-8853-d7bcfa3ff7f1', '7d01236e-620e-5177-a6f4-af325a582aae', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-07-11', '17:30:00', null, '通常 / コンテスト作品作り', 'ドラゴンとの戦いの設定を作っていきました。基本はゾンビを倒せのゲームを参考にしながら、作りました。上下に動かすのは何の迷いもなくつくれ、ビームはまねて作れました。だが途中、コードが干渉していると思ったが、なんかのはずみで隠すのコードがずれていただけでした。この確認中にかずとくんをお手上げ状態にさせてしまったのは、よくない状態でした。次回の方針として、ビームのところで端とドラゴンの判定をまたでつなげて作ってしまったので、ドラゴンのところで、ビームが触れたらHPが減少することを作ってほしいです。それ以外に、ドラゴンの動きとEDを作れば終わりだと思います。 メッセージを多用しているので、バグが起こりやすい環境と思いますので、きをつけてもらいたいです。', null, 'タイピング: 利益ではないものもそれなりに打てていました
盛り上がり: タイピングの能力はすごく上がった。'),
  ('70a8fa4d-467c-5319-9725-f65e8958e0c5', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-07-11', '16:30:00', null, '通常 / 基本操作コース04_追跡ゲームの完成', '音を付けるコード作成から始まり、完成させることができました。コードの作成については、教えたことは素直に実行していき吸収していました。キャラクターやスコアにオリジナル性を持たせていたので、より複雑なコードの書き方を覚えていけば個性に富んだ作品を作ることができると思います。', null, 'タイピング: あ行と、か行を練習していた。
盛り上がり: オリジナルのキャラクターを作成している時は、自分のやりたいことちゃんと表現できていたので嬉しそうでした。'),
  ('522340f4-c1f5-5948-a02f-641116a8a5fc', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, null, '2023-07-10', '17:30:00', null, '休み（未対象）', null, null, null),
  ('435f13e0-199e-5877-aedd-e4c70153a783', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-10', '17:30:00', null, '振替 / 自分の作品作成 Laptopがふれたらの判定の部分を見直ししました', 'Laptopがパソコンマットに触れたら大きさに変えていくというコードに書き換えたり、先生が質問した疑問に自分で理解した様子でした。 ゲーム的には７〜8割出来上がっているそうなので、あとはメッセージで送り合っている部分がもう少し精査できたらいいかなと思います。', null, 'タイピング: なし
盛り上がり: こうしてみたらいいんじゃないかな？の提案に自分自身で解決方法を見出していた感じがとても良かったです！'),
  ('02c39108-27b6-5052-8cce-c2acbaaedc8f', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-10', '16:30:00', null, '通常 / ・自分の作品作成＞かめがゴミを避けるというゲーム場面の作成 ・作品の説明とどんな部分を頑張ったか？を考えて書く', 'ゲームは、キャッチゲームの延長線上でゴミをよけるというゲームにしたい様子でした。 リクエストとしてゴミをクローンで作成し、キャッチゲームを作って欲しいなと思うのですが、1から作成しようとすると手が止まってしまう感じではありました。 ゆきさんも伝えましたが、見本のところから盗んで作成してみたら？と伝えましたが、どれを持って来ればいいのか？みたいな迷いみたいなのがありました。', null, 'タイピング: なし
盛り上がり: アピール部分を考えて〜と伝えた時に、自分でここを頑張ったという部分をきちんと伝わってきたので、自分で理解している部分もあるんだなと思いました！'),
  ('48effbfe-1560-5f68-9220-13acf4bb2097', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-07-10', '17:30:00', null, '通常 / 大会準備 プログラム整理 剣必要なの？⇒不要ならば消去。剣についての不要なプログラムがある 旗が押されたとき⇒ひとつのプログラムにまとめる えにしくんに遊んでもらったときに、作品をちゃんと紹介できるのか？', '必要のないスプライトを削除、使っているメッセージを整理しました。ショップはナシになりましたが、掲示板はクエスト受注の過程をふみたかったようで残すことになりました。 最後のボスのイチゴの挙動をプログラムしました。制御と座標を組み合わせてプログラムしますが、あまり得意ではないようで少し考えこんでいました。一度話の大枠が分かると取り組みやすいようで、最後に綺麗に完成させることができました。 細かいところはまだ詰める必要はありますが、ほぼ完成に近い状態です。時間があれば裏ボスを作りたいといっていました。', null, '盛り上がり: 1時間ずっと集中していて素晴らしかったです。'),
  ('00e9be61-bb45-5da6-9a69-c0f08e5909c2', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-07', '18:40:00', null, '通常 / 自分の作品作成 スラボーが地面に触れないようにするゲーム、キャッチしたらクリアhttps://app.arspark.jp/projects/36101/editor', '自分の作品作成 ゲームオーバーとクリアは出来上がっているので、本番用にどういう部分を工夫したのかなど聞いて、提出用に準備しました！ 音を加えたいとのことだったのでクリアになった部分で音を加えてもらいました', null, 'タイピング: タイピングの速さが0.1秒早くなっていました！
盛り上がり: 自分で背景をやっぱりこれにする！などこだわりがあるようで、自分の中でのストーリーがあるようでした！'),
  ('bb3ba66e-8a44-5114-a3de-c8a318bc3f4c', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-08', null, null, '通常 / 大会準備', 'きょうは終始「もう完成してしまったので遊びたい！」と言っていましたが、本当にそれで提出していいのかと聞くと、なんだかんだ直すところがたくさん出てきました。敵にもモーションを入れる、剣の見た目を豪華にするなどの工夫をしていました。 最初の敵が弱すぎて一撃で倒せてしまうので、強さを調整したほうがいいと思います。 ただ、次回くらいで作品が提出できるレベルに達するかもしれません。', null, '時間帯: その他
盛り上がり: あおしくんと同じゲームを遊びたい気持ちが強かったです'),
  ('c31515ac-0184-565d-9b36-9048f4a2db19', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2023-07-07', '17:30:00', null, '通常 / 教室に慣れる、プログラミングの楽しさを味わう', 'タイピングをしてから、Scratchを開いて遊びたいゲームの検索をする練習をしました。ローマ字表を見ながら、「マインクラフト」「ピクミン」などと打ち込んでは、検索結果が出てくることに喜んでいました。 55分ごろまで検索練習を兼ねてScratchのゲームで遊ぶことに慣れた後、「そろそろプログラミングをしてみる？」と声掛けをしたらすぐにノッテきました。 体験で扱ったネコを歩かせようや洞窟ダイヤゲームをよく覚えていて、デジタル水族館の魚を「どこかの場所へいく」や「はしについたら跳ね返る」動きなども、すぐに自分でブロックを思い出して作成できていました。 デジタル水族館の魚に、基本操作コース02の動きを取り入れて学習しました。表の4つのマスを埋めることができて嬉しそうにしていました。 クリックしたら音が出る学習をしているうちに、宝探しゲームを思いついて、魚の色を保護色のようにして大きさを小さくして、見つかったらクリア―音、間違えたらブービー音を出すようなゲームに改造して、お母さんにプレイしてもらっていました。', null, 'タイピング: タイピングは初めてとのことだったので、3年生ではそのうち国語でタイピングの授業があることを説明し、最初のFとJのところをやってみました。この2つのキーに関しては、左右の手を使い分けて打つことができていました。
盛り上がり: 基本的に、何を取り扱っても楽しそうに良い反応を返してくれていました。 習った範囲で新しいゲームを思いついて、お母さんやけいとくんにプレイしてもらって、とても満足そうでした。'),
  ('b32c07ce-1b8a-5ad1-925b-f33bb287d50b', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-07', '16:30:00', null, '通常 / コンテスト作品の作成続き 土管（スプライト6）に触れたときの動きの調整など', '大量のコードが適当に重なり合っていて、ブロックを動かしたときに意図しない箇所まで動いたりしていたので、コードを整理するところから始めました。 ゲーム中のアイテムのコスチュームにこだわりすぎて時間をかけすぎてしまったと自分で反省していたので、デザインにこだわるのは最後にして、まずはゲームが最後まで動くように完成させることを目標にさせました。 ゲームの構成を話し合って、紙に書きだしました。解決しなければいけない問題点も一緒に書き出して整理しました。', null, '盛り上がり: 一つ一つのスプライトに思い入れがあるのか、デザインや音などを探すのについ熱中してしまうようでした。とても楽しそうではあるのですが、ほどほどにしてゲームの完成を第一に考えようという提案に素直にのってくれて、その後の作成は寄り道しすぎることもなくできていたようでした。 ゲームの構成をきちんと口に出すことで、今後しなければならないことがはっきりして、少し気持ちに余裕ができたようでした。
備考: 8月に引っ越し予定とのこと'),
  ('dbc651ff-aa76-5f6a-85ef-f1a0fdbccea5', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-08', null, null, '通常 / 宇宙バトルの応用', '前回の宇宙バトルを応用してできる内容ということでゾンビをたおせ1に取り組みました。動画を見せれば基本的にやってくれるのですが、スプライトをガチャガチャ動かす、スプライト名を適当な文字列に変えまくるなどの遊びをすることも多かったです。ゾンビや主人公の基本的な動きは作れました。', 'ゾンビをたおせ1続き', '時間帯: その他
盛り上がり: ネコを弾丸代わりに使うというユニークなアイデアが面白かったです'),
  ('3b989c71-be33-55c0-8dfe-2561e469d35e', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-07', '16:30:00', null, '通常 / コンテスト作品の作成続き バグつぶしとその先を作成', '自分のコードを見直して、キャラクターが動かない箇所の解決をしていました。 体力回復要素やお金の要素、ビームが当たった時の体力の減り方など、何度もテストを繰り返してはバランスを考えて丁寧に数値を設定していました。', null, '盛り上がり: 何度もテストプレイを繰り返す手間を面倒がらずに、熱心にゲームバランスを調整する集中力と根気強さが素晴らしかったです！
備考: 家でも頻繁にログインして手を加えているようです。'),
  ('6799d304-91de-5afb-8444-797a64b716ac', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-08', null, null, '通常 / 宇宙バトルの応用', 'レッスンでゾンビをたおせをやりました。前回までの宇宙バトルに似ている面も多いため、比較的スムーズに理解できたと思います。上向きの移動のコードを書いた後、下向きでも同じように作ってみようと伝えると自力でできていたので、力はついてきていると思います。ただ、弾丸を打ち出すコードはやや複雑だったので詰まって、完成までいきませんでした。基本的にまじめにやっていましたが、隣で同じ内容をやっていたこうしろうくんと一緒に遊ぶ場面もありました。', 'ゾンビをたおせ1続き', '時間帯: その他
タイピング: 満足できる結果が出せて嬉しそうでした。
盛り上がり: ゾンビなので怖い背景を使うかと思いきや、「ショータイムみたいなイメージ」と言ってパーティーの背景を選んだのは面白かったです'),
  ('57bac9cc-a23a-5b15-b808-92fc2339c0ce', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-08', null, null, '通常 / コンテスト作品の作成続き 壁ジャンプの追加、全体の構成の確認', '前回から作成したがっていた壁ジャンプを作るには、現在できているジャンプを少し改良する必要があること、新たにいくつか変数を使用するので何度は上がることを説明し、壁ジャンプを使わずにクリアできるようにステージを易しく編集するか、頑張って進めてみるか選択してもらったところ、ほぼ迷いなく、「がんばる！」とのことでした。 参考になる教材をこちらが作成する傍ら、ゲームのオープニングとエンディングの作り込み、作品テーマの確認を進めてもらいました。 作品テーマは「対戦」でいきたいとのことで、主人公の対戦相手となるスラボーを追加して、動きを設定できていました。 オープニングに追加する日本語フォントが、Scratch内のものでは作品イメージに合わないと悩んでいたので、Canvaでフォントを作成させたところ、とても面白がってくれました。', '壁ジャンプの作成', '時間帯: その他
盛り上がり: ここ数回は、ゲームのコードにかかりきりだったせいもあるのか、久しぶりのフォントやデザインの編集をとても楽しそうにやっていました。これでデザイン面での創作意欲が刺激されたのか、楽しそうにおしゃべりしながらオープニングやエンディングの作り込みにも力を入れることができていました。
備考: お父さんにコンテスト応募フォームの用紙をお渡しし、説明しました'),
  ('8b2a5dc8-23af-58d6-b0ef-42f37e12d39c', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '3d62819a-addc-5584-afc3-251fdb7abc04', '2023-07-08', '16:30:00', null, '通常 / 大会作品提出 コードモンキー', 'Scratchの作品提出の話をすると、最終確認をすると言って確認していた。 確認終了後コードモンキーに取り組んだ。', '次回、コードモンキー２４から', 'タイピング: なし
盛り上がり: コードモンキーを楽しそうにやっていた。
備考: ロブロックスへの興味も強いので、コードモンキーに飽きたらロブロックスも有りかなと思います。'),
  ('0ea46b29-bd89-5026-8977-05cf79f8279c', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '3d62819a-addc-5584-afc3-251fdb7abc04', '2023-07-08', '16:30:00', null, '通常 / 大会作品作り', 'やりたいアイディアを教えてくれたのでサポート。 以下アイディア １，Aボタンをを押すと手に持つ物のリストが出てきて選択できるようにしたい。 ２，地面を掘ると 普通の地面➡岩➡鉄 と変わるようにしたい。', '手に持つリストのリストが出てきた後に、リストを押すと左下の画像が変わるようにする。 地面を掘ったら画像が変わるようにする。 次回伊藤受け持ちたい', 'タイピング: なし
盛り上がり: たのしそうに集中して進めていた。 手に持つリストのリストを表示するところまでできた。 地面のドット絵を作って提供した。 とりあえず絵には納得してくれた。
備考: ペースを合わせるて待つのが大事！！'),
  ('b80c6a15-f95a-57cf-bc42-929117ff33dc', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-24', null, null, '通常 / 小技を習得する', '先週同様に大会作品の作成には気乗りしなかったので、体力ゲージの小技に取り組みました。一通りゲージを作り終わったあと、体力の値を色々変えたりして試していました。理解を深めるためにゲージの色を変えるなどのアレンジを勧めましたが、やる気にはならなかったみたいです。', '体力ゲージを大会作品に応用？', '時間帯: その他'),
  ('8583f179-6a7a-5705-9bd5-c06e485bd5dc', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-24', '17:30:00', null, '通常 / レッスンを進める', '動画を見ながら宇宙バトル1を作りました。角度や条件分岐のところは少し詰まっていたので説明を加えながら進めました。動画の通りに作り終わったあと、どのようにアレンジしたいか聞くと、敵も主人公と同じように攻撃してくるようにしたいとのことでした。そのため弾丸を複製し、少しだけコードを変えるとうまくいきました。', null, 'タイピング: タイピングにもわりと慣れてきたと思います
盛り上がり: お迎えのお母さんに作品を見せて満足そうでした。'),
  ('78d85b0e-072b-57ab-bf28-1fbc74f52fb9', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-24', null, null, '通常 / 大会準備', '片付けゲームの製作を進めました。先週練習した条件分岐などをうまく使っていました。また起こったバグの一部を自力で直すこともできていました。ただ、まだバグは残っているので、プログラミングの基礎的な部分を確認しながら一緒に直していきたいところです。', null, '時間帯: その他
盛り上がり: 先週のように問題を解くのも楽しくやりますが、やはり作品作りが一番楽しそうです'),
  ('99be445d-51b7-57ee-b91c-d13d488afa5f', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-22', '17:30:00', null, '振替 / 大会準備', 'ゲームとして成立させるために、勇者が剣を振った時だけ剣が敵に当たるように調整していました。また、敵の攻撃を受けたときに勇者のHPを減らすしくみを作りました。ブロックを複製して効率よく作っていました。 そのあと、ゲームオーバーになったときに画面を変えるところで詰まっていたので、どういう条件でゲームオーバーにするのかなど問いかけをしました。すると、敵を倒したときの場面転換と同じことをすればいいと気付いて作ることができました。 ゲーム本体は完成に近づいているようなので、ストーリーをつけることを勧めたところストーリーを書き始めました。', null, '盛り上がり: 今日はここまで進めようという計画を立てていてすごいのですが、逆にその計画が達成できてしまうと、時間が余っていてもやめたくなるようです。'),
  ('017910d9-0b2f-5344-89fb-0324d72af165', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-07', '17:30:00', null, '通常 / 作品作成よりも検定問題をやりたいとのことで、検定３級の問題 魔法使いを行いました', 'アレンジ時間を作成できる時間を作れるほど、時間に余裕がある状態で終わっていました。 解答合わせをした際に、問題の意図をきちんと理解していたようですべての問題が正解していました。', '未定、自分の作品作成をしたいけど・・', 'タイピング: なし
盛り上がり: 解いているときは自信がなかったようではありましたが、それでも自分で最後まで解けたことに満足していた様子でした！'),
  ('098dd680-69f9-56e6-9eee-120babf6828f', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-07', '17:30:00', null, '通常 / 検定３級問題 応用２４番', '制限時間まではなんとか全問やり終えた感じでしたが、答え合わせをすると以前できていた部分が忘れている様子でした。やはり自分の作品作成だけになってしまうとどうしても楽なコードだけを使いがちになってしまう様子。 特に〜まで繰り返しというコードがあまり自分では使わないので試験問題として出てきた時に使いこなせていない感じに。 次回答え合わせが途中になっているので、途中から解答合わせを再度しますが、どれだけ気分を乗らせた状態でできるか？が問題かなと思います。', '解答合わせの途中から続き', 'タイピング: なし
盛り上がり: 少し難しいと感じてはいましたが、自分でどこが違うか？のような感覚はあった感じなので、問題の中身としては理解している様子でした。'),
  ('3412fd20-8496-5151-ad20-43cec69d5651', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-07', '16:30:00', null, '通常 / チエテラス 第一章のまとめ問題までできるか？', '一章の７の例題問題が終わってなかったので、６のフローチャートの部分からおさらいをして、やってみました。論理演算が多少難しかった様子で、英語の配列をどう並べたらいいのか？がまだわからず、全ての問題を解けてはいませんでした。 ただ、条件分岐に関してはとても理解ができている様子。章末問題をすべてやろうと思いましたが50分全問でかかるため、今日はおさらいのみになりました。', '章末問題', 'タイピング: スラスラと自分でやれる感じでタイピングはやはり得意な感じでした！
盛り上がり: 条件分岐に関してはとても自信を持って行っていたので、とてもよかったかな！と思います。'),
  ('c4e44f93-a2e0-5ea0-846f-8373cccfe74b', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, null, '2023-07-07', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('06248651-989e-572c-8d28-1d4997ae9f6c', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, null, '2023-07-07', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('d2f58ed4-c788-5e6f-bd00-220e08bae1ba', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-07-06', '17:30:00', null, '通常 / 虹色ピンポンの完成＆アレンジ', '虹色ピンポンの続きをやっていきました。スコア付けは変数の使い道に離れていたそうで、気の散り様がなかったです。最後の虹色の軌跡を作るものも、ペンのツールが目新しいものだったので、テンションを高いまま作り上げることができました。 アレンジでは、爆弾が上から降ってきて触れたらアウトな仕組みを作りたいそうです。内容がキャッチゲームのコードを見せながらできそうだったので、進度的に難しいところは演算などはただ映して作るだけで、ほかの触れるもし条件などは自ら手が動くように教えました。だが、「もし」と「ずっと」の結びつきが弱く、ずっとの忘れが多かったです。次回はこれの途中から始めればいい。', null, 'タイピング: ストーリーを進め、レベルアップできました。
盛り上がり: 一時間制でずっと遊んでいました。'),
  ('fe82212c-aa52-594b-9a44-bd3ce751e312', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-06', '17:30:00', null, '通常 / コンテスト作品の作成続き', '自分で構成も見えているようで、念のため会話をしながら確認しましたが、あとは何をするべきかもきちんとわかっているようでした。 オープニングの流れができたので、ゲーム部分の説明やゲーム導入画面などを淡々と作成していました。 背景の表示非表示が一部おかしくなっていると質問してきましたが、一緒にコードを見直しているうちに、自分でミスに気が付いて直すことができていました。コードを読む力もだいぶついてきているようでした。', '次回は日光のためお休みなので、前日までに欠席と振替の連絡をくれるよう伝えました。', '盛り上がり: オープニングからゲームへ進む流れなども思い通りにできているようで、前回に比べて余裕があると自分でもわかっていて、楽しんで作成を進めています。'),
  ('23fab412-aebf-5617-8567-6139e3bf09e2', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-06', '17:30:00', null, '通常 / コンテスト作品の作成続き', 'オープニング部分とその他の部分を別ファイルで作成していたとかで、パーツを書き出しては読み込んでいました。 試行錯誤の最中のようで、作成途中のものを上書きしないでとっておきたいとのことなので、作品名に日付や時間の数値を付け足してそれぞれ別名で保存しておくことを提案したら、なるほど、と感心してくれました。 オープニング画面が完成した、といって、とても嬉しそうに見せてくれました。音楽に合わせるところを苦労したそうです。', '次回は日光のためお休みで、夏休みに入ったら振替をして作成に励みたいとのことでした。', '盛り上がり: 作品については思い入れがあるようで、作成が進むと頻繁に声をかけてきて嬉しそうに見せてくれました。 オープニングが完成したのが満足そうでした。'),
  ('f4abf726-f1d5-59e0-a40c-bec7f7df09bc', 'b2246586-4496-52f9-a825-be2488a00a31', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-07-06', '17:30:00', null, '通常 / すしゲームの続き', 'すしゲームの中で一つの物語を完成させていました。キャラに様々な差分を用意して表現をわかりやすくしての作成でした。自身の想像力を大いに発揮しての制作でしたので、スケールも大きくなっており、応用を効かせていくことでより複雑なものも出来上がって行くのではないかと思います。', null, 'タイピング: なし
盛り上がり: 出来上がったものを説明しているときは、特にイキイキと話してくれました。'),
  ('0d3bfce9-66d3-522d-8ac8-a5c738c3967c', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-07-06', '16:30:00', null, '振替 / 宇宙バトル１の完成', '宇宙バトルの続きをやってきました。基本は動画を見ながら作っていき、一工程ごとに旗を押してどんなことができるようになったのか確認していきました。1動画ごとだと、球が連射できないようになっていたので、連射をしたい意欲でモチベーションは下がりませんでした。完成したときは、喜んで自分が作った作品を何回も遊んでいました。 後半は霧がよかったので、基本は遊んでいましたが、アレンジできそうなポイントを話しながらやっていきました。', null, 'タイピング: 乱打うちはためにならんぞ
盛り上がり: 完成したものもお母さんにも遊んでもらい、ともに楽しくできました。音選びはこだわりがすごい。'),
  ('4e2a71cf-12ee-5780-9396-bc19e8b3a05c', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-06', '16:30:00', null, '通常 / コンテスト作品の作成続き', '前回までのところで、スプライトの表示非表示が思い通りにできていないとのことだったので、どの背景のときに表示させるのか考えを整理して、背景が○○ではないときに隠すのコードを追加しました。一つのスプライトで試してみてうまくいったのが嬉しかったようで、残りのスプライトについても積極的にコードを追加して、スッキリしたようでした。 リストについては、別の作品を扱うと混乱しそうなのか、自分の作品内でやりたがったため、リストの削除と追加を教えながら、買い物メモを作成するスプライトを作りました。', '各夕飯メニューの買い物リストの内容を考えてきてもらう予定なので、その部分のリスト完成、値段設定など', '盛り上がり: 何度もプレイしては不具合を丁寧に見つけていくタイプで、解決するたびにとても満足そうにしていました。気になったところはしっかり解決してから先に進めたいようで、今日は前回からの懸念事項が解決できて、自分でも進行度に満足できたようでした。'),
  ('64340f9e-33c5-561d-ab6d-018b9fc339b6', '57f45872-1f3e-5540-b676-bf9023444e39', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-07-06', '16:30:00', null, '通常 / 宇宙バトル1の作成', 'お手本の載っている動画を見ながらの作成で、内容を理解しながら作成することができていました。繰り返し処理などの応用部分も動画で解説する前から自分で気づけていた箇所も多くありました。', null, 'タイピング: ゆっくりではあるが確実に打てている
盛り上がり: 弾丸を発射するコードを考えているときは、楽しそうに考えていました。'),
  ('b5efb01c-0f9f-53f0-a811-c819cf39f1dd', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, null, '2023-07-06', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('89c5e1a4-1852-51ad-9886-a1afb3104227', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-22', '17:30:00', null, '通常 / 大会準備', '今までは放射線状に飛んでくる攻撃をかわすゲームでしたが、それだとうまくよけられないことがわかったそうで、横方向の攻撃に変更していました。乱数をうまく使っていろいろな場所から攻撃が来るようにできました。もう少しゲーム全体にストーリーやバリエーションをつけたほうがいい気がするので、考えるのを促してもいいかもしれません。', null, null),
  ('427845f3-9285-5d31-8673-6c6feba167c9', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-22', '17:30:00', null, '通常 / 自由作成', '触れるとHPを削ってくる敵を時間いっぱいよけ続けるゲームを作っていました。キー移動はもちろんのこと、HPが0になったらゲームオーバーにする、50秒耐えたらクリアにするなど、面白いゲームを作るための基礎となる要素は一通り組み込まれていました。それにまさきくんらしい個性が加われば高度なゲームができると思いました。', null, '盛り上がり: 自分で作ったゲームを先生に遊んでもらって反応を見るのが楽しそうです'),
  ('dc0e5874-d8dd-57ac-b4b5-8d246971aa44', '57f45872-1f3e-5540-b676-bf9023444e39', null, 'bb96307d-f71d-5a14-a63c-4cc0b3646d36', '2023-06-22', '16:30:00', null, '追跡ゲームの完成', '追跡ゲームの続きをやりました。野球をテーマに作りたいとのことだったので、2人がキャッチボールをして、1往復したら1点入るような方向で進めました。ボールを取ったタイミングで音を鳴らすとき、「もし～に触れたなら」を扱いました。キャッチする音を選ぶときには、ちょうど良いものがなくて悩んでいました。それっぽい打楽器の音を勧めましたが、こだわりがあるのかしばらく考えてから決めてました。そのあと、スコアをつけるために変数の使い方を扱いました。1ずつ変えるのと初期化するのを順にやることができました。作成中、ブロックをどの場所に入れればよいかをときどき質問したのですが、だいたい答えられていたのでブロックの構造についてはだんだん理解してきていると思います。', null, 'タイピング: 楽しみながら進めています。
盛り上がり: 基本的に興味をもって集中を続けることができました。好きな野球でゲームを作れたのもモチベーションになったかもしれません。'),
  ('5f566c71-2589-5f41-993e-0e8a0a8cec22', '7d01236e-620e-5177-a6f4-af325a582aae', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-07-04', '17:30:00', null, '通常 / コンテスト作品作り', '2週あいたので、まず作ったものを振り返ってもらいました。今回もゆっくりながら、アルゴンを倒して、最後のドラゴンを登場まで作りました。セリフのテンポの取り方が「何秒まつ」を利用して、スムーズなもので見ごたえがあります。そして、ストーリーであまり動きがなかったので、最後は自分で操作できるものにしたいと提案したら、喜んで受け入れてもらいました。hpの変数を作り、表示するタイミングも自ら調節できていました。次回は戦いの操作を作り、EDとなると思います。ちょうど作り終わると思います。', null, '盛り上がり: 最近は、メッセージ名を長くするのがお気に入りです。'),
  ('cc73ec1f-a802-5cdb-a5ba-149cd4d2eef1', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-07-04', '16:30:00', null, '通常 / コンテスト作品作り', 'ハンバーガーのキャッチゲームを制限時間をつけてました。この際に、最終的には作れているが、「なんだっけ？」と言っていたので、少し不安です。キャッチゲームが終わったあとの構想を聞いてみたら、あやふやしていたので、スコアによって演出を変えたらと提案したら、そこから助かる人数が変わるという発想が出てきたので、よかったです。そのあとは、背景を新しく作って、にぎやかになるイラストを感じました。 ほかの子にも少し思ったのですが、音をあまり使ってない子には完成してからも付け桑られるので、アドバイスした方がいいと思う。', null, '盛り上がり: 既存の絵より自分の描いた絵の方が気に入ってそう'),
  ('cf1e087b-d3ee-593a-b260-b89f7affe41b', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-04', '17:30:00', null, '通常 / コンテスト作品の作成続き ほぼ完成しているとのことなので、文章を考えながら全体的な見直し', 'コンテスト作品については、音やコスチュームなどの細かいところを修正していました。動きや音の効果などはとてもよくできているので、セリフや文字などでストーリーをわかりやすくすることも提案してみましたが、文字で書くことはあまり気乗りしないようでした。 30分ほどで、「これはもういい」と言ってきたので、提出間際にもう一度見直すことにして、新しいゲームを提案しました。コンテスト作品でずっと考え込んでいて、一から作るのはちょっと…という雰囲気だったので、アレンジを勧めてみたところ興味を持ってくれました。 最初はサムネイルにひかれたのか、【Prg】48 おさると仲良くなるゲーム＿定義を使ってRGB系を開いていましたが、コードを見て「これは無理」とのことで、【Prg】56 シューティングゲームを作ろう！をプレイしてすぐにゲームオーバーになる体験をしてもらい、「簡単にアレンジをする」ことを目標にしました。 クローンについては使用しているうちになんとなく覚えたようだったので、「クローンを作成する」と「クローンされたとき」のコードを一緒に確認し、自分の弾のクローンと相手の弾のクローンの生成の速さを調節することで、ゲームの難易度を調整できました。 すぐにゲームオーバーになるのをやめようとして、一生懸命コードを読んでいました。ゲームオーバーの動きをそのまま削除することで無敵モードにすることができて、ちょっと嬉しそうにしていました。', null, '盛り上がり: アレンジについては、ゲームレベルの調整だけでなく、弾がきれいにクローンされて飛ぶように調整したり、音をよりリアルに聞こえるように調整したりと、そうすけくんらしいこだわりのアレンジを熱心にがんばっていました。'),
  ('3933e54e-506d-5341-b9bd-1f77f933bbc6', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-04', '17:30:00', null, '通常 / コンテスト作品の作成続き 完成形をイメージして', 'ステージ選択画面が、ゲーム開始後もうまく消えなくて少し時間を取られていました。前回はきちんと動いていたため、一度作品を開きなおしたところ、問題なく動いたのでただのバグだったようです。解決したことにはほっとしたようでしたが、この件で少し疲れてしまったようでした。 レベル選択のスプライトを新しく追加していました。 今日は水泳の授業もあって疲れていたのと、席が少し暑かったようで、後半は何度か椅子に沈み込んでいました。それでも声をかけると「ここだけやってみる」と切り替えができたことは、昨年からの大きな進歩だと思われます。 最後の10分は、気晴らしに他のゲームをいじっていましたが、帰る間際に「今日はあまり進まなかった」「これだけ頑張って、何も賞が取れなかったらどうしよう」と不安げにしていました。結果に対してナーバスになるタイプなので、うまくモチベーションを保てるような声掛けを考えておきたいところです。', null, '盛り上がり: ゲームの構成自体は完成のイメージが見えてきたようで、本人も満足気でした。キャラクターや難易度など、選択肢をたくさん入れているところが、みずきくんのアピールポイントのようです。'),
  ('1c28d62b-08c8-53b1-b7fe-f12c8ba0f07f', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-04', null, null, '通常 / チエテラスで情報の学習', '基本、楽しそうに取り組んでいました。 英語はあまりわからないと言っていましたが、ifがScratchの「もし」ブロックに相当するなどということは、見てわかっているようでした。 2進数の計算のみ、手順ではなくて完成形しかスライドに載っていなかったため、少し悩んでいたので、最初の計算だけ一緒にやりました。その後は理解できたようで、一人でスラスラと解いていました。 コンピュータの基礎知識を問う問題については、そもそも知らなければ解けないものにも関わらず、スキップするのが嫌なようで、一生懸命解説を読んでがんばっていました。', null, '時間帯: その他
タイピング: 授業の終わりあたりに、時間調整のように少しだけ取り組んでいました。
盛り上がり: 終了10分くらい前にはだいぶ疲れていたようでしたが、学習意欲は最後までしっかりあって、楽しそうにできていました。
備考: サッカー部の顧問の先生が技術の先生だそうで、情報にも親近感をもっているようでした。'),
  ('9f9db1e3-d96b-50df-9a76-b2db798e954d', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, 'dade2709-836d-5970-989d-51cea2859430', '2023-07-04', '16:30:00', null, '通常 / コンテスト作品の作成と基本操作コースの確認、追跡ゲームのyou wonを出すところから', '基本操作コース10の内容であるキャッチカードゲームについて作成していました。コース内容であることに加え、個人での応用を効かせた作品を作成していました。内容的にはスコアを付ける工程まで完成させていました。', '基本操作コース10の内容について完成させる。 コンテスト作品の作成', 'タイピング: なし
盛り上がり: ものが落ちてくる行為を反復できるプログラムができた際にはかなり喜んでいました。'),
  ('7d746b9f-f13b-5d4e-a7fa-8e636ae44350', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-04', '16:30:00', null, '通常 / 基本操作コース04追跡ゲーム、または レッスンのアイスを食べにあたり', '今日は新しいゲームを作ろう、と声掛けをすると、嬉しそうにノッてきました。 説明を耳で聞くよりも、視覚で見ながらやりたいタイプのようなので、カードを見ながら作成して、その後で対話をしながら理解をさせる流れで進めました。 「どこかの場所へいく」と「〇秒でどこかの場所へいく」ブロックの違いを、両方試してみて理解することができました。 音を鳴らすところまで作成したら、お絵描き欲求が我慢できなくなったようなので、新しいスプライトを自作で入れて大きさの設定などを自分で考えさせるアレンジをしました。', 'スコアから先を作ると予告してあります。', 'タイピング: 学校で始めたのでやってみたい、とのことで、体験版の30級を3回チャレンジしました。もう少しでクリアできるところまで記録を伸ばすことができました。
盛り上がり: こんなゲームが作れるなんて、僕ってすごい！という感じで嬉しそうに盛り上がっていました。'),
  ('7ed97163-029d-5275-ac7a-6fc64bfbece0', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-07-04', '16:30:00', null, '通常 / 大会準備', 'カミナリの速さが変わることについて説明を追加。 ソードの挙動について整理。 ぼこのプログラム、騎士のプログラムについて見直しを行いました。重複している部分を直したり、足りないプログラムを補ったりしました。自分で再現したい事象をきちんともっていて、論理的に考えることができました。 最後のパーティーの画面になったときに、「隠す」とプログラムしたスプライトが消えなくて困っています。「すべてを止める」がうまくいっていなかったり、メッセージを送るタイミングの問題だったりと思います。次回詳しく確認する予定です。', '「隠す」の検証', null),
  ('970e862a-1f1e-5163-941c-dee2faf6d7bb', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-07-04', '16:30:00', null, '通常 / 大会準備', '工場を再建するという目的に合わせて、屋根を付けることを提案。 途中、お金のクローンが止まってしまうバグが発生しましたが、根気強く取り組めました。 工場再建のためパーツを購入することになり、ストーリーも追加したようです。終わりが設定できていました。際限なく工場が壊れる設定になったようです。検証も積極的に取り組むことが出来ていました。 ほぼ完成したようです。', null, null),
  ('e329de97-4d15-5d0b-9d07-77f752349eac', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-03', '17:30:00', null, '通常 / 前回の続きスラボーから逃げろ https://app.arspark.jp/contents/32128', '最初はやはり遊ぶモード満載。前回の続きから始めた時にあるくんが動かない！と叫んでいたのですが、こちら側がヒントをあげると、自分で動くコードを追加しないといけないというのが解読できていたようでした。 定義に関してはとても抵抗がある様子ではありますが、アルスパークでも実際に選ぶゲームはほぼ定義のゲームなので（マリオやブロック対戦など）すこしずつフェーズ的には難しい感じのゲームが良いのかと思いました。', null, 'タイピング: 日本語の単語を入力するのがまだ慣れていない様子ではあります。ただ、ゆっくりであればきちんとアルファベット入力はできるので、じっくり時間をかけて見守りたいと思います。
盛り上がり: 少しバグっぽい動きになっている際も、一緒に見本と見比べながら何がいけないのか？をじっくり見分けようとしていました。'),
  ('ccc18fa9-c879-5b1a-9376-b8995ff47e0b', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-03', '17:30:00', null, '通常 / 大会準備', 'まずはHPの変数の表示するタイミングなど細かい部分を調整しました。 スラボーに続く二番目の敵の攻撃はスラボーと違う方法にしたいとのことで、一緒に考えました。その結果、敵は横に動きながら、持っているイチゴを落として攻撃することにしました。どうやって落とせばいいのか困っていたので、似た動きが入っている基本操作コースのキャッチゲームを思い出してもらいました。テストプレイをするためには最初から遊ばないといけないので、作成者用のショートカットをつけてもいいかもしれません。', null, 'タイピング: 眠かったため本調子ではなかったみたいです
盛り上がり: 最初は眠かったようですが、徐々に目を覚まして集中しました。'),
  ('ed14bff1-5d8d-58c7-82be-c214cdf45be5', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-03', '16:30:00', null, '通常 / 作品作成', '以下の2点を先にどうするか？を決めることに今日は注視しました。 ①生まれた日の変数はどういった役目で、変数がどうなるとたぬきの動作はどうなるのおか？ ②空腹の変数がマイナスの時と結末はどうする？ ①の方は、生まれた日数は10日経ったらクリアという変数にしたいらしく、10日経つまで今のご飯を食べて、寝ての場面をルーティンするように作成したいとのこと ②空腹がマイナスの時は死んでしまったというコードを追加、メッセージをきちんと使いこなして、死んだというコスチュームにしていました。 メッセージの送り合いが多様しすぎて、指令系統が複雑になっている様子。一旦紙に書き出してどのコードは重複している、可読性を上げる、バグを潰すなども一緒にやってみました。 今日はりんごがどうしておある場面で出て欲しくないのに出てしまうというバグがあったのでそこをクリアしようとしていましたが、なかなか上手くいかず。 そこを次回までに一緒に考えてみることにしました（私の宿題でもある）', null, 'タイピング: なし
盛り上がり: 紙にプリントアウトした時に、「あ、このコードの指令はこっちの方がいいね」と自分で気がつけたことが大変すばらしい！また理論だって考える力もついてきているので、そうした場面をもっと増やしていきたいと思いました。'),
  ('418cbd25-6822-5a90-b71e-2ef9fca9941d', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-03', '16:30:00', null, '通常 / 作品作成', '場面５〜６の作成、一旦５の場面を作成し終えて、６でゲームっぽいものを作る予定にしていました。 ６に関してはあおちゃんがゴミを避けるというキャッチゲームの逆（ふってくるのを避ける）を作成し、ゴミが下に10回触れるまで繰り返す＞触れたら勝ちで、触れ続けてしまったらコスチュームが変わって死んでしまうというゲームにするそうです。', null, 'タイピング: なし
盛り上がり: 人と話すことで頭が整理される感じがとても良かったと思います。こういうのはどうかな？というアイディアが出てきました。'),
  ('790ae6ac-386b-5a25-8e54-2fb0123cb40d', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-24', null, null, '通常 / コンテスト作品の見直し OKであれば、【単元】リスト＿都道府県と県庁所在地クイズ', '来室時に、先週約束していたWindows機を用意したと伝えると、「やったー！」と言いながら入ってきて、すぐにRobloxを開いていました。遊び用で、自分のアカウントを持っているそうです。 Scratchには気乗りがしないようで、授業開始後もRobloxのゲームで遊んでいたので、作成の環境を整えてほしいと話を振ったところ、少し動く気になったようで、マニュアルを見ながらRoblox Studioをインストールしてくれました。 教室のテキストを見ながら、オブジェクトの配置や編集などは一通り取り組んでくれましたが、コードを書くことは「難しそう」と敬遠してしまって、テキストを読むだけで終了してしまいました。', null, '時間帯: その他
盛り上がり: 今は何かを作ったりする気はなくて、遊びたいだけ！と言い張っていましたが、こちらもRobloxは初めてなので、興味があるから一緒にやってみたいと誘うと、先輩心？が刺激されたのか、自分で一通りのメニューを触ってテキストの内容と照らし合わせて報告してくれました。'),
  ('0de82375-8fc4-5924-81d0-1493312d9a6e', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-24', null, null, '通常 / コンテスト作品の作成続き 素材からものつくりをする過程の作成', '素材から家を作ったあとのアニメーションを楽しそうに作っていました。 家に入ったように見せる効果を作成するため、「～に触れたまで待つ」の使い方や、複数のメッセージの使い分けを学習しました。', null, '時間帯: その他
タイピング: 丁寧に取り組んでいます
盛り上がり: アニメーションを思い通りに作成できたようで、満足そうにしていました。 コードを動かすタイミングが色々あることが把握できてきたようです。'),
  ('bd9c65c6-1ea7-5be2-b9b5-cec578e12594', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-26', '17:30:00', null, '通常 / ヤマト先生作品 スラボーから逃げろ https://app.arspark.jp/contents/32128 ふうせんわりゲーム https://www.youtube.com/watch?v=8vDfJTtlKTw どちらかを作成する', '風船割ゲームは少し風船の出てくる速度が速かったためか、あまり好きではない様子でヤマトちゃんのスラボーから逃げろをやることにしました。 えにしくんにとっては定義の使い方をまだわかっていないので、定義のブロックを書くことに抵抗がある様子でした。', null, 'タイピング: 遅刻してきたためなし
盛り上がり: 嫌だと言いながらもジャンプができるようになるととても嬉しそうにしていました。自分がわかるコードも含まれていたせいか、ここは簡単だからわかるなど話していたのが印象的でした'),
  ('35373814-4e3a-5720-b685-5265494a9a57', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, null, '2023-06-26', '16:30:00', null, '休み（未対象）', null, null, null),
  ('787578d2-dae1-5ebe-b3b9-a3871725e56e', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-26', '16:30:00', null, '通常 / 大会の作品作成', '今日はシーン５の部分を作成することに。５の場面では会話をなりたたせるために変数を使って会話をしているように切り替えたかったのですが、何かのイベントがないと変数は自動的には作動しないため結局メッセージのやり取りで会話を成り立たせることにしました。', null, 'タイピング: なし
盛り上がり: 変数を使ったら会話を簡単に作れるのではないか？と考えたところまでは素晴らしい！'),
  ('d4634307-4522-5e3c-a291-9a6d92591431', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, null, '2023-06-26', '18:40:00', null, '休み（未対象）', null, null, null),
  ('000180b8-bff1-5a0a-9523-b88b2897f0b0', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-06-26', '17:30:00', null, '通常 / 大会準備（クローン生産のタイミングを整理）', 'インベーダーが量産されすぎていたので、「ではない」を使ってプログラムを付け加え、クローンを量産するタイミングを調整しました。本人なりにたくさん方法を考えていろいろ実践していましたが、「ではない」を使うという発想にはなかなかたどり着けませんでした。 スラボーの挙動を一緒に確認しました。終わりの設定がまだだったので議論したところ、ステージの切り替えではなく、ボスの切り替え（ウェーブみたいなもの）を行う方針になりました。次のボスの出てくるタイミング、背景の切り替えなど自分でよく考えてプログラムすることができています。 内容の方向性が整理されました！細かいところはまだ足りないところがあるようです。', null, '盛り上がり: 1時間ずっと取り組めていました！'),
  ('dc5fc236-b773-567a-8c09-cfe48c244cb4', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-24', null, null, '通常 / コンテスト作品の作成続き 壁ジャンプとクリア画面の作成', '前回の最後に作成したクリア画面になったときに、ボールが下に落ち続けてしまう理由を考えて、修正しました。 地面の色によってボールが突き抜けてしまうのを防ぐために、判定に使う色の数を「かつ」を使って増やす学習をしました。 横から左右キーでボールを進めた時に壁を突き抜けてしまう理由を一緒にコードを見ながら考えさせ、横方向のときの動きに「はねかえる」動きの設定をしていなかったため、チーズを探せの学習を思い出しながら跳ね返るコードを追加しました。', '壁ジャンプの仕上げ', '時間帯: その他
タイピング: 1回だけ取り組んでいました
盛り上がり: クリア画面の作成は、これまでの学習内容から自力で解決に向かうことができ、達成感もあったようでした。 壁を突き抜けてしまう現象についても、どうしてそうなるかはすぐにわかったようで、納得しながら修正ができていました。'),
  ('adc68c3d-9186-5747-a8a5-a05f42964071', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-24', null, null, '通常 / 2級検定問題に取り組む', '今日の問題は前回よりも解きやすかったようで、35分で見直しまで完了していました。 完成例を見せて自分で答え合わせもさせましたが、ほぼできていたとのこと、自信もついてきたようでした。 もうすぐ期末試験だそうですが、検定までにあと2回授業があるので、そこで対策をすれば今のところ持ち帰り課題は必要なさそうということで合意しました。 授業の残り時間は、自分で好きなものを作ってみたいということで、昨年作成していた自作ゲームの続きを作成していました。', '検定問題', '時間帯: その他
盛り上がり: 今日の問題は気持ちよく解けたようで、終わった後も楽しそうに感想を言ったり、雑談に応じてくれたりしていました。 試験自体は楽しみにしているようです。'),
  ('8bab3603-efd2-5cfe-b265-59f5b996ddf6', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-06-23', null, null, '通常 / 大会作品', 'ステージの追加をしました。地面を設定するのにやや時間がかかりましたが、丁寧に作業できていました。ジャンプについて茶色の部分を通り抜けるのが気になっていたようなので、「もどる」という考え方をもとにプログラムしました。プログラムの仕方はなんとなく分かっていたようでしたが、プログラムをかく場所に自信がないようでした。 ステージの切り替えにも苦心していました。「端にふれたら」という考え方は悪くないのですが、複数ステージに対応できず、悩んでいました。座標で端を認知させた後に次のステージにいくようなプログラムを作りましたが、プログラムが高速で繰り返し、うまく動かなかったので「1秒待つ」の使い方を説明しました。', null, '時間帯: その他
盛り上がり: 楽しく集中して取り組めていました！'),
  ('db5575ae-52cc-5029-a31f-43de4adca0ec', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-23', '18:40:00', null, '通常 / 自分の作品作成（キャッチゲームに似たものを作成）', '最初はスラボーが爆弾を受け止めたらスコアが一点アップ、地面についてしまったら一点減るというのを作っていましたが、最終的にはスラボーがスラボーをキャッチするというゲームに変更。 スコア、地面に触れたらという変数がそれぞれ一定の点数になったらゲームオーバーとクリアを表示するというコード、音のコードを追加していました！', '次回はクリアとゲームオーバーが同時に出てしまわないようにバグを潰す、', 'タイピング: 以前よりも、タイピングの正答率は上がっているように感じました。ただ、なにか自分の言葉をタイピングしようと思うとまだローマ字の分解がわからないようなので、タイピングチャートを見ながら行っています。
盛り上がり: 演算をつかってスコアが＝〜点になったら〜をいう条件分岐をスラスラと書けるようになっていました！やっぱりチュートリアルを見ながらコードを書くというのがとうきくんには合っていたようです。'),
  ('9c96c8bb-13d9-590a-938c-68a8c0994e09', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-06-23', '17:30:00', null, '通常 / ドリル45、46で「止める」の復習、オリジナル作品', 'ドリル45、46⇒一人ではあまり取り組めない様子でした。催促するというよりも、隣で一緒に座っていると取り組んでくれる様子でした。プログラムについては部分的には分かるようでしたが、プレイヤーの向きによって場合分けすることができずに少し混乱していました。一緒に整理して確認しました。 オリジナル作品⇒クローンされてたスプライトの体力がうまく減らずに混乱していました。みるとクローンされたスクリプトに記入できていないだけでしたが、プログラム画面がごちゃごちゃしていたので気づけなかったようです。プログラム画面の整理をした後に一緒に確認しました。', null, '盛り上がり: あまり前向きにプログラミングに取り組めていない様子でした。ファイルの画面を勝手に見てしまっていたので、「ダウンロード」の画面以外は開かないようにお願いしました。'),
  ('913cf127-e6cd-5799-9826-faa8eaf34972', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-23', '17:30:00', null, '通常 / コンテスト作品の作成続き 提出する作品を決定する', 'コンテスト用の作品はリズムゲームで決めることができました。 上から落ちてくる三角が、2回目以降は重なってしまうことに悩んでいたので、横方向が重なるということは何がおかしいのかを考えさせ、3つのスプライトの上に戻った時のx座標が同じことに気付くことができました。 落ちてくるパターンが一緒なため、乱数を使ってずらしたり、ゲームクリアやクリア後のレベル表示などのアイディアも雑談しながら話してみましたが、「ちょっとめんどくさい」とのことで、今日はカウントダウンの変数のみ作成しました。', ',ゲームが動かなくなったバグの解消（完スプライトのCLOCK>1まで待つの数字が全角なのが原因）', '盛り上がり: スムーズに三角が落ちてくるようになったときは嬉しそうにしていましたが、そこで燃え尽きたのか、その先を作るのは面倒とのことでした。 それでも、「これが入賞しちゃったら、みんなの前で話すんだよね」などとニコニコしながら語っていたので、やる気がないわけではなさそうでした。'),
  ('cdf944bb-705c-5031-93f8-80173370b2ae', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-23', '16:30:00', null, '通常 / 自分の作品作成', '今日は自分の作品の続きをやるというので、どうしたいのか？を聞きながらやることにしました。 当たったら、点数が減るというのも1秒まつなどのコードを使って一点ずつ減るようにしていました。 また、説明をスキップするにはどうしたらいいのだ？というのも工夫として考えたようで、Jのボタンを押し、説明のコードをスキップするというメッセージを送ってゲームに直接行けるようにしていました。', null, 'タイピング: うでだめしでしっかりとタイピングの特訓をしていました。
盛り上がり: ソードの向きを下向きにしたり、説明をスキップするコードを付け加えたりして、自分なりにゲームを楽しませようとする工夫をしていました！'),
  ('861c077d-21a6-5574-8abc-ab8bde049363', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-23', '16:30:00', null, '通常 / コンテスト作品の作成続き ゲーム部分を作り込む', '作成はほぼ思い通りに進んでいるようで、終盤まではたまに説明をしてくれながらも淡々と作成していました。 ゲームのジャンプコマンドをキーボードで打ち込み、打ち込む文字を間違えるとミスになってしまうという独自の仕様が面白いですが、スプライトに触れた時の着地をどうするかで悩んでいました。', 'ジャンプの着地の修正 ↑スプライトに触れたらジャンプの落下を止めるようにスクリプトを止めるを使用していたが、ジャンプコマンドを入れるためにこのスクリプトは動き続けてほしいという要望。 なるべく今のコードを活かすなら、答え=jumpがtrueの時の中身をすべて定義にして、定義の方でスクリプトを止めるようにすると解決はする？ その際、同スプライトに触れるとx座標を-方向に動かすコードを入れていて、着地した後に土管の左端まで動いてしまうので、スプライトではなく色に触れた判定などに変える必要有り。', '盛り上がり: 自分のイメージを上手に表現していて、終始楽しそうに作成していました。
備考: 本人が言うには、マカフィーを装ったウイルスに感染しているそうで、5分おきくらいにメッセージが出てきて鬱陶しいと言っていました。'),
  ('ed91b9a5-ade2-5803-b6f3-b39a030f77c4', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2023-06-23', '18:40:00', null, '休み（未対象）', '今日は体調が朝から優れなかったようです。', null, null),
  ('c49adfc4-c320-561b-8284-0780ccd910cb', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-23', '16:30:00', null, '通常 / コンテスト作品の作成続き ゲーム部分の作成を進める', '先週教えたIDで自宅でログインできたらしく、ゲーム部分の作成が進んだと嬉しそうに話してくれました。 ゲーム中、敵の攻撃を受けた時にメッセージの送信ができておらず、変数が変化しないと悩んでいました。メッセージの送信をするまでに、5秒待つを含めたコードが多すぎて、5秒待つ間に次の動作にうつってしまっている可能性があったため、カテゴリの異なるコードは並列で書くことを勧めたところ、無事に解決できたようでした。 刷毛で色を塗る動きを作りたいとのことで、にじいろピンポンのペンツールの箇所を見せたら、スムーズに作成できていました。 時間ぎりぎりまで集中して、ゲームオーバーの画面や新しいステージを作るなど、作成を着々と進めていました。', null, '盛り上がり: 疑問点が解決したり、新しいツールを覚えたりして、自分が考えたゲームに近づいていくのがとても嬉しそうでした。'),
  ('f73731d3-a22e-5601-8576-3853c6a77b73', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-23', '16:30:00', null, '通常 / 自分の作品作成', '今日は自分の作品作成をすると言いだしたので、チエテラスではなく作品作成に取り掛かりました バグってしまう部分がどうやらあるかんじではありますがどうしたらいいのか自分でもよくわかっていない様子で、一旦大会のテーマと今の自分の作品がそうのか？を考えていました。', null, 'タイピング: なし
盛り上がり: 親がクローンを作成した時に親自体が表示されないようにしたなど、工夫をしていたようでした。'),
  ('ebee1a37-21b2-5235-9d06-62587497653b', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-23', '17:30:00', null, '通常 / ドリル レベル１の問題３〜６を全部できたら、遊ぶ', '向きに関しては問題なさそう、ただ何度に回す〜というコードに慣れてないのか、向き〜だけになってしまうとどうしても〜度に向けるを使いたがっていた感じでした。 ただ、四角に動くまでできた時に追跡ゲームの中にそのコードを書こう！と話したら、ちゃんと自分の作品のお魚にそのコードを追加できていたので、今日の授業はとても彼にとって良かったのかなと思います。 またコードを連続して書くということも学んだ様子でした。', null, 'タイピング: FGHJの部分でまだどのキーを押したらいいのか？がわからない様子。ただ本人的にはとても上手くいったと満足していたので、良かったと思います。
盛り上がり: コードのバリエーションが増えたことで、ゲームを作る面白さを感じた様子でした。'),
  ('8476069e-9586-5421-989a-e8f5974d0021', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-23', '16:30:00', null, '通常 / チエテラスの条件分岐、変数の理解（英語の部分）', '条件分岐の考え方、英語の意味をもう一度おさらいしました（チャプター１の２と３の部分） なお、変数の考え方（Increment ）がアルスパークで行ってなかったようなので、一旦箱としての考え方を勉強しました。 変数の箱の考え方は何回か行っていますが、やはり覚えていなかった様子。ここの部分がわからないとチエテラスでの変数の考え方が難しいかなと思っているので来週もIncrementで1~100までの足し算のコードを行って、やり続けていきたいと思います。', null, 'タイピング: なし
盛り上がり: チエテラスは難しいが、本人はこれをやるようになってからお母さんに楽しいと話しているようです。英語が絡むからなのか、文章として理解するのがはっきりわかるからなのか？は分かりませんが、まこちゃんにはとても合っているようです'),
  ('17e87cff-c094-5b97-a7fc-a5e339430c92', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-16', '17:30:00', null, '通常 / ビギナーズ部門のにじいろピンポンアレンジ続き ゲームオーバーを作成する ピンポンに飽きているようなら、アルスパークレッスン2-2のアイテムキャッチあたりを作成', '最近は授業開始前のゲームに引きずられてしまうことが多かったのですが、今日は約束の時間になったら久しぶりにアルスパークに向かい合うことができました。 もう一度水族館を作りたい、好きな色の魚を作りたい、というので、コスチュームの編集の仕方を復習しつつ、横に動かしたりランダムに動かしたりするブロックを思い出して自分で魚ごとに動きを作ってもらいました。', null, 'タイピング: 多少打鍵が乱暴になることがありますが、概ね楽しんでやれているようです。
盛り上がり: 一応完成した作品ができたので、久しぶりに「今日はがんばった」とお母さんに作品を見せて得意そうにしていました。'),
  ('417c96cb-db39-57b7-8d70-89b031cd2c7e', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-16', '17:30:00', null, '通常 / コンテスト作品の作成続き、またはチエテラス', '眞子ちゃん、とらくんと一緒にチエテラスの説明を受けてから取りかかりました。 さすがに中学生で、進みはとても速かったです。 英語が苦手と言っていたので、文章が長くなってくるときちんと読めていないような雰囲気はありました。', null, '盛り上がり: 久しぶりに授業に来れたせいか、楽しそうによくしゃべっていました。 チエテラスについてもあまり抵抗はなく、おしゃべりしながらもサクサクと進めていました。'),
  ('d8b86450-23e4-5f88-8a1c-a43fe4b58dd5', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-16', '16:30:00', null, '通常 / コンテスト作品の作成続き 新しいスプライトの動きを作成 ストーリーの確認', '自分でやることは決まっていたのか、黙々と作成していました。 特に悩むこともなく、こちらがのぞきにいくと「今これを作っている」と説明してくれたりはしましたが、構成に関する助言などを聞き入れるのは面倒だったのか、「これで完成！」だそうです。', 'もう少し完成度をあげてほしいところですが、少し飽きているので、一度他の作品をはさんでもよいかもしれません。', '盛り上がり: たっちゃんなりには完成形になって満足したようで、やり切った感は出していました。'),
  ('ff5fccc6-5d5b-513f-b6dc-7d11aad574a4', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-16', '16:30:00', null, '通常 / コンテスト作品の作成続き クリア後の構成を考える', '少し飽きがきているようで、数回テストプレイして「もういいかなあ」と言い始めました。コインが出てくる見た目は面白いので、前後のストーリーなどを作成するのも勧めましたが、とりあえず一旦置いておきたい様子でした。 眞子ちゃんがやっていたチエテラスに興味を示したので、眞子ちゃん、部長と3人でゆき先生からチエテラスの説明を聞き、少しチャレンジしていました。', null, '盛り上がり: チエテラスをやるということ自体にプライドがくすぐられたのか、とらくんにしては説明のときも静かに聞いていました。'),
  ('55091683-644a-5b08-8f47-1aef416a18e3', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-19', '17:30:00', null, '通常 / 自分の作品作成', 'スプライトの向きによって動く方向が変わるということを意識しながらコードを書いていきました。またクローンを作った際に放射線状に動くたまを一回一回リセットしないと、一番初めの動きにならないよ〜ということを今日は理解した様子だったので、来週はリセットの変数を作って、そこから始めると思います。', null, 'タイピング: なし
盛り上がり: クローンの動きをおさらいしました。どうしてこの動きが親と子が別で動かないといけないのか？を理解したようでした。'),
  ('c0719bc8-af0f-5595-ae4d-cb304dcf5094', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-19', '16:30:00', null, '通常 / 自分の作品を作成 アルスパーク', 'りんご、水を食べたり飲んだりしないとたぬきがどんどん空腹になっていくという育成ゲームを作成中。今回は水を飲んだら空腹が紛れるというコードを書いていきました。 ここまでりんごと水に触れたら&変数を駆使しています。 だんだんと言葉の理解や、これってどうやったらいいのだろう？という疑問が高度になってきて、私としても一緒に考える時間が増えてきました。 また逆説的なコードの書き方（主語を反対にしてみたらどうなるか？）などの理解も深くなってきているようです。大会に関してはおそらくあと２回ほどで完成する予定。', null, 'タイピング: スムーズにタイピングできていました！
盛り上がり: 条件分岐の使い方と変数の使い方がとても上手くなってきたと思います。またそれを自分で理解している様子で、これはこうすると、おそらくこうなるという「想像のなかでのコードをと実際やっていてのコードの違い」がわかっているようでとても満足して授業をしていました。'),
  ('4b01b9c7-89dd-5672-ac1c-e9565b907786', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-22', '17:30:00', null, '通常 / 虹色ピンポンを作ろう', '前回公判に作り始めた虹色ピンポンを作りました。説明書を見て、コードをまねて作り、できたことを確認することをしたかったです。ほんとに気が散漫なので、説明書と画面を交互に見て作ることが少してまがかかると感じました。1つ1つ動作を説明しても、ほかの場所をいじってしまうことがあったので、徐々に画面とコードを覚えていけばいいと思います。それでも、ゆっくり進んでいき、銃弾を跳ね返して、赤線に触れたら止まるところまで作れました。次回で、完成とアレンジができると思います。', null, 'タイピング: やっとスムーズに進められました。
盛り上がり: 始まる前に一人で軽く作品をいじるほど単身でいました。'),
  ('db3397e7-eb49-5699-8b6b-c495a116b8e7', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-22', '16:30:00', null, '通常 / コンテスト作品作り', '背景を切り替えた際に、前の背景で表示していたものが残ってしまう、または表示されないくなるバグが発生していたので、背景の名前を条件式使った、もしではないで分類するコードを教えてあげました。元の表示隠すのコードで使ったスプライトがたくさんあったので、少しごっちゃになると思ったが、元のコードを残さず、きれいにすべて新しいコードに切り替えられていました。手際がいい、また、イラスト描いてっと頼んできたので、わからない仕組みのコードを補助することはいいが、、そこまで頼るのは行き過ぎなきがしたので、注意しました。後半、リストを使った買い物の仕組みを作り始めていたので、そこは少し付き添いながら仕組みを作っていけたらいいと思う。まだ、リストを学んでいないので、', null, '盛り上がり: ジョジョ好きなことを知れて、得意げに話してくれた。'),
  ('36b22e4b-c8be-5237-8f00-c8d15663d7f4', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-22', '16:30:00', null, '通常 / コンテスト作品作り', '最初、コンテスト作品作りの期間が今日含めて4回しかないことを伝えると、そうちゃんも無理じゃんと気づいていたので、何体か用意していたスプライトを減らしました。今回はopとステージ移動を主に作りました。opで敵の攻撃が当たらないようにしたいと考えた時、メッセージのやりとりで順番をつけられることをヒントを出しながら思い出したので良かったです。ライフがゼロになった時に最初に戻るアイデアも優しさがあってよかったです。 ステージ移動は敵の退場セリフがずっといいパなしになるバグが起きていたので、1回きりで動いてほしいことをビームを発射のコードから考えてもらい、子のスプライトを止めることに思い出せていした。やっと、ステージ１は完成できたので、なるべく多く作らせたいと思い、ステージ２，３の構想を考えてくるように頼みました。', null, '盛り上がり: ステージ1ができたときは喜びのため息が出ました。'),
  ('c680ce7c-d117-552c-9af6-c9688a31d251', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-22', '17:30:00', null, '通常 / コンテスト作品作り', '今回はコロナ後のストーリーを着に進められていました。見た感じの進捗は間に合わなそうなことはないと思います。', null, '盛り上がり: 歌を口弾みながら作っていたので、悩みなく作れていると思います。'),
  ('4a256450-1e1d-54c6-98d7-43156a79633e', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-22', '17:30:00', null, '通常 / コンテスト作品作り', '最初に進捗の方を聞いてみたところ、あんまり進んでいないそうでしたが、追い詰められないと勧められないタイプと言っていたので、7月は頑張ってもらいたいです。文章をRPGのテキストのように1文字ずつ出すやり方を見つけたそうで、今回は思い通りいってそれなりに進んでいました。画像取り込みでzipファイルの開き方に困っていたので今後のために教えました。', null, null),
  ('fd51de7e-3554-5611-847f-784bd0ea0588', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-20', '17:30:00', null, '通常 / コンテスト作品の作成続き スクロール部分の解決等', '前回から悩んでいる横スクロールがうまくいかないところでは、自分から「【小技】簡単な横スクロール② 完成版 クローンを使う」を開いて参考にして頑張っていました。 x座標の値を変えたりと何か所か試した後、少しイラついてきたようだったので、一緒に考えようとPCを持って隣に座ったら落ち着いたようで、検証に戻ってくれました。 背景スクロールを始めるためのメッセージが送り続けられていたので、動いているスクリプトと動いていないスクリプトを確認させてそれぞれのメッセージの発信元をたどっていくことで、解決することができました。また、クローンされたときの座標に着目させることで、横スクロールが解決できました。 後半は、競争相手のキャラクターを作成し、どのように表示させるか楽しそうに考えながら作成していました。', null, '盛り上がり: 授業開始から5分くらいはゲームで遊んでいましたが、その後作成に入ってからは、時間いっぱい集中していました。 前回からの課題だった背景スクロールが完成したことでモチベーションもとても上がったようで、すべての背景やキャラクターで丁寧に動作確認をしてから満足そうに次の工程に入っていました。'),
  ('a0a27ea5-1077-58bc-ba4a-b35287feea78', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-20', '17:30:00', null, '通常 / コンテスト作品作り', '前回でそれなりに進めていましたので、今回も宇宙船外の背景を作っていました。1時間前から教室に来ていたので、若干集中力は途切れながらも、黙々と進められていました。そして、本人的には完成できたととのことだったので、次回はまだ付け加えたいなら加えてもいいので、プロット文アピールポイント考えるようにします。', null, null),
  ('5a67b0c8-c586-59c4-ba85-4bd32e23d111', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-20', '17:30:00', null, '通常 / コンテスト作品作り', '前回ごみの拾う確率の仕組みはできていたので、まずはお菓子やペットボトルのイラストを作ってもらいました。そして、ごみを持っていないときの判定を一緒に相談しながら、作りました。話を聞いていくと判定をする変数が別のもので考えていたので、そこは一緒に目をつけられてよかったです。このような仕組みが動かないときの動きも細かいところも手を付けられているので、クオリティは高くなっています。BGMや効果音も隙間なくつけられていたので、。このゲームはただクリックしてごみを集めるだけのゲームになってしまいそうだったので、ゲームの結末を作るよう提案したら、素直に乗ってくれました。だが、それを作ろうとしたら最後にあちこちで動かなくなりそうになっていたので、とりあえず案は考えてくるように頼みました。', null, null),
  ('d9deef5c-0956-58f4-b262-3efcb8e5a26b', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-20', null, null, '通常 / チエテラス 続き 【Prg】48 おさると仲良くなるゲーム＿定義を使ってRGB系 動画15:30以降から', '来室時に何をやりたいか尋ねたら、すぐに「チエテラスがやりたい」と笑顔で言ってきました。先に進んでも構わないが、難しかったところを戻って何度かやってみるのもよいと勧めたら、素直に間違いの多かったWhileとfor文のところに戻っていました。 初回よりは慣れてきたようで、章末問題の成績もCからBに上がっていました。 後半は、前回の続きのScratchがやりたいと自分から申し出てきて、動画を見ながら作成していました。おさるのスプライトに奇妙な画像効果をつけてアレンジしながら楽しんでいたようでした。', null, '時間帯: その他
盛り上がり: チエテラスを楽しみに来室しているようで、チエテラスをやりたいというのも即答していました！
備考: プログラム文に出てくる英単語はまったくわからないと言っていたので、何か資料があればもう少しスムーズに進められるのではないかと思われます。'),
  ('94b394cf-5838-582e-bead-ef9b0111ec73', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-20', '16:30:00', null, '通常 / コンテスト作品の作成続き 構成の確認', 'スコアが10になったらりんご、20になったらハンバーガーを表示というのを作成したがっていましたが、何から手をつけてよいのかわからなかった様子。ピンポンゲームのカードの最後を見せたら、「まで待つ」というのは覚えてる！と言って作成することができました。 スコアの累積によって、新しいスプライトが表示されたり、落ちてくるスプライトの数が増えたりするところが作成できて満足そうでした。 iPadのフリーボードで絵を描いていましたが、スムーズにエクスポートができず、一度スクショする必要がありました。', null, '盛り上がり: ゲーム画面のイメージなどにはこだわりがあるようで、それを思い通りにできたときは嬉しそうでした。だいぶ先が見えてきたので、少し余裕を持って取り組めたようでした。'),
  ('e550057a-e5c7-590f-b2e1-fb1f79474ac2', '7d01236e-620e-5177-a6f4-af325a582aae', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-20', '16:30:00', null, '通常 / コンテスト作品作り', 'ストーリーがゾンビを倒すまでできていたので、今回はビームの位置など細部を直していきました。一つ一つ理解しながら直せていたので、同じようなことに留まることはないでしょう。ゾンビを倒した後に、アルくん（ドラゴン）がやってくるところまでは話は進すめられたが、悩み止まってしまった。自分が案を出しても納得を行くような気がしなかったから、1週あくので、これからの話をメモってきてもらってもいいから考えてもらうよう頼みました。', null, '盛り上がり: できたところまでお母さんに見せましたが、照れていながらも自分で操作するところは操作しに来てくれました。'),
  ('4063ae45-5a05-536d-ada0-18dd69a02ab1', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-20', '16:30:00', null, '通常 / コンテスト作品作り', '隔週だと前回やったことに忘れてしまったので、ゆっくり思い出してもらいました。敵のhPで、勝ち負けによって背景が変わる演出が作りました。ダメージの判定で色判定を使いがちだったのですが、細い線だと判定がしずらいことを伝えたところ、敵の体部分を別のスプライトを作ってスプライト判定で自力で作れました。ダメージ音もいいものを付け加えられたし、一通りの流れは完成しました。まだ、細部を作りたい感じだったので、次回までに考えてもらうようお願いしました。', null, '盛り上がり: スクラッチのマイクラでネザーが作れることを喜んでいました。'),
  ('ac8f6164-0540-52e9-9725-d59280659f89', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, null, '2023-06-20', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('38df67a9-73de-50aa-8a6d-5ecf2165eb05', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, null, '2023-06-20', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('4754da2d-85da-501f-a772-e67fc2282c8c', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-06-19', null, null, '通常 / 大会作品', '前回に引き続き、ゲーム部分を作成していました。スラボーが剣を取る部分のプログラムがとても滑らかにできていました。敵が襲ってきたのを倒すようなゲームにするそうです。ダメージなどはまだ考え中のようでした。 コスチュームの操作に迷っていたので、ステージで動き始めるかなり前からコスチュームを設定するように伝えました。ジャンプのプログラムも回数をコントロールして速さに変化を加えていました。次回からは敵のプログラムに入りそうです！', null, '時間帯: その他
盛り上がり: ゲームよりも学びの部分のプログラムの方が作りにくいと思うので、日ごろから少しずつ考えてほしいです。とても集中して取り組めていました！'),
  ('68d6e983-d957-574a-a6bf-a642536fd337', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-06-19', '17:30:00', null, '通常 / にゃんこ大戦争に挑戦', 'かなり遅れてきました。敵やあるくんが出現せずに困っていましたが、座標のミスだったり、クローンを作っていなかったりしたことに原因がありました。座標についてはなかなか自分で気が付けませんでした。アレンジとして、背景を付けたり、変数を調整して無敵にしたりしていました。プログラム全体を把握できていて良かったと思います。タイピングの速度もかなり早くなっていて驚きました。楽しく取り組めていてよかったです。作品は完成しました！！', null, null),
  ('cf20e50f-72db-5f5b-a4f9-07f367184eea', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '25840600-1a86-5fb0-b223-dec47cec8c48', '2023-06-17', '16:30:00', null, '通常 / オリジナルゲームの作製', '授業時間になってもゲームをなかなかやめなかったので、少し強引にゲームをやめてもらった。それが原因かはわからないが気持ちが乗らず、脱線することが多く、前回まで意欲的に作っていたオリジナルゲームの作成の際も「あきてきた」「違うゲームを作る」などの発言があった。 最終的には、敵を一つ追加していた。', 'その日によって作品への意欲が変わるので、次回は様子を見て、オリジナルゲーム作りか、気持ちが乗っていなければ、別の課題を用意するなどリカバリーを考えておいた方がよさそう。', 'タイピング: 集中できなかった。
盛り上がり: 全体的に集中できていなかった。
備考: 授業開始時にゲームをやめてもらうときに、甘えさせてゲームを続けさせても授業に影響が出ますし、強引にやめてもらっても影響が出るので、事前に声掛けをしてスムーズに授業に入れるようにする必要がありそうです。'),
  ('954593fc-c3ed-5a27-8a99-28d3fea687c3', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '25840600-1a86-5fb0-b223-dec47cec8c48', '2023-06-17', '17:30:00', null, '通常 / オリジナルゲームの作製', 'オリジナルゲームで上手くいっていないところがあったので、スプライト(ボール)を一つ選んでスクリプトを一つずつ確認。 干渉しあって動かないところを見つけるところができた。 解決できたことには満足していた様子です。 メッセージの使い方や制御ブロックの理解がいまいちなので F-4 敵を作って玉を当てよう の問題にチャレンジしてもらいましたが、 コウモリが上下に跳ね返る動きに苦戦していました。 普段感覚でやっていて、基本的なScratchのブロックへの理解が足りないので、本人の自信を損なわないように基本の基本からやった方がよさそうです。', '本人のやりたいこと次第ですが、 F-4 敵を作って玉を当てよう の続きか、もっと簡単な課題に変えて問題を解く 又は オリジナルゲームの問題の解決', 'タイピング: なし
盛り上がり: オリジナルゲームのデバックができたのは嬉しそうだった。'),
  ('e1662bc6-675a-5210-a411-fc55654143ee', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2023-06-19', '16:30:00', null, '通常 / 自分の作品続き〜アルスパークに移植後、背景が黒くなってしまうバグの修正と缶が出てくるようにする', 'まずは背景画面が２回に１回黒くなってしまバグを修正、缶が出てこないところを根気よく修正していました。時間がかかっていたので途中からゆきさんと一緒に全てのスプライトのコードを印刷して余分なコード（重なっている部分が主）を消したり、きれいにし全てのコードが指示通りに動いていることを確認。 一旦この後は流れを全て作成してみて、最後まで終わらせることに意識を向けるようにガイドしました。', null, 'タイピング: なし
盛り上がり: ゆき先生といっしょにコードを全て見返してみて自分で余分なものを書いていたことがわかったはるちゃん。今後は作品の流れを全て作成することを意識することと言われた時に、このバグから解放されるんだ！という感じにとても見えました。'),
  ('a21b57f0-5b59-5409-a83d-1a3159d04294', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-17', null, null, '通常 / アルスパークのレッスンを進める', '宇宙バトルorゾンビを倒せで前者を選び、動画を見ながらレッスンを進めました。最初はやる気がありましたが、敵のコスチュームを描くのに夢中になってしまい、思ったよりは進みませんでした。スプライトと背景を準備し、敵を往復させるところまではできました。', null, '時間帯: その他
タイピング: 楽しくやっていました
盛り上がり: 今日はやや脱線した感がありましたが、作るのが嫌というわけではなさそうです。'),
  ('b2401a9b-9578-5687-a169-2a90d27b45a3', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-17', null, null, '通常 / コンテスト作品の作成続き', '初めに、今日作りたいことを対話しながら整理しました。 素材から家を作るアクションをどのような感じにしたいかイメージを固めてもらい、ボタンを押したら作成するかどうかのきいてくる感じにしたい、とのことで、「○○を聞いて待つ」のブロックを教えました。 上記質問に「はい」と答えた際に、素材が足りているかどうかで動きが変わるようにするため、条件分岐のネストを教えました。 素材が足りているときにできる家の登場などを、これまで習ったブロックでうまく表現できて、とても嬉しそうにしていました。', '他の素材について、同様に作成を進める。', '時間帯: その他
タイピング: パーフェクトにできていました
盛り上がり: 素材から家を作る、という一つの目的が形になって満足そうでした。'),
  ('5e716b51-8dd4-5ea8-b301-c9d975fada04', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-17', null, null, '通常 / 大会準備', 'ステージの移行や敵の表示がきちんとされないというバグがあったので、一緒に原因を探しました。そうたくんが「終わりのメッセージが間違ったタイミングで送られているんじゃないか？」という仮説を立てたので、そのメッセージを送っているコードを確認するように促しました。すると実際にそうだということがわかり、敵の体力が入っている変数を初期化するタイミングがおかしかったので直してもらいました。敵が変わるごとに背景も変えたりして、ゲームを一応初めから終わりまで通すことができました。 途中、今日の作業が終わったら敵の攻撃や勇者のシールドを作りたいと言っていたので、全体の方向性は忘れていないようです。', null, '時間帯: その他
タイピング: 電車の乗り過ごしで少し遅れたためさくっと終わらせました
盛り上がり: 自分で考えようとする姿勢が素晴らしいです'),
  ('ffd65381-8226-58ca-94e6-c9fb3908cd28', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-17', null, null, '通常 / 大原', '授業開始後はタイピングを飛ばしてすぐに作り始めたい、と意欲的な様子でした。 次のステージに進んだ時に、ボールの位置を左端に戻したいということで、どのタイミングで何をすれば希望する動きになるかを順序だてて考えてもらった結果、自分で解決することができました。 ボールが草や地面の絵の上で止まるようにする動きを言葉で考えてもらい、【単元】ジャンプの応③ アル君の冒険（チュートリアル）を参考にコードを考えました。無事に草や地面の上でとまるようになったときは、声をあげて喜んでいました。 縦方向のジャンプのコードしか作成していないため、高さのある壁をのぼるときの動きにまだ不備があり、その動きが面白かったのか、珍しく大ウケしていました。 最後のステージの後はどうなるのかを考え、表彰台の背景を作成していました。', '垂直の壁をのぼるジャンプと、クリア後の作成を予告済み。 表彰台を背景に描いていたが、色にこだわってグラデーションを使用していたため、色での判別が難しければ、表彰台の部分をスプライトにする提案もありかと。', '時間帯: その他
盛り上がり: ゲームの全体像が見えてきたのが嬉しかったのか、今日はとても饒舌で楽しそうに話しながら作成していました。'),
  ('0f26f84f-cc1a-51fb-b64f-b243dad5f0c7', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-16', '16:30:00', null, '通常 / チエテラスでの学習', 'お休みが続いていたため久しぶりのレッスンでしたが、席についてチエテラスの画面を見た瞬間、「これやりたかった！」と喜んでいました。 英語は全然わからないと言いつつも、楽しそうにやっていました。 ただ、あまり考え込むことはせず、わからないとすぐに適当な選択肢を選ぶ傾向はありました。一文の中に選択肢が続くようなものは、考えるのが面倒なのか、ちょっと苦手と言っていました。', null, 'タイピング: レッスン前、レッスン中などに、気晴らしのようにやっていました
盛り上がり: 久しぶりだったわりには、わりと上機嫌で来てくれて、よくおしゃべりもしながら頑張っていました。 部長と少し雑談をしていました。'),
  ('d710c26e-b7df-5ed2-b00d-fd2152d28cbe', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-17', null, null, '通常 / チーズを探せの続き', 'タイピングが終わったら自主的に前回のコードの画面を開いていました。壁で跳ね返るところは説明しても理解が難しそうだったので、写経で終わらせました。しかしそのあと、チーズの場所移動やスコア(変数)のつけかたについては納得しながら作れたと思います。「このキャラが何の動きをすればいい？」「そのためのブロックはどれ？」「どのタイミングで動かせばいい？」などを一つずつ質問すると答えられて、自分の手を動かして作れました。', 'チーズを探せの虫の動きだけできていないので、もし本人にやる気があれば', '時間帯: その他
タイピング: 使うキーがだんだん増えてきましたが、順調に練習しています
盛り上がり: 作成中は終始集中していました。終わった時は疲れて、休憩しました。'),
  ('fd98b057-fd6b-5716-8892-ea4f34c57a0a', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-06-16', '18:40:00', null, '通常 / 大会作品', '来てすぐに集中して始めました。ゲームと学びの2つのジャンルをひとつのプログラムに取り入れる予定です。丁寧に説明の画面、操作の画面が作られていました。ゲームについては変数を用いてプログラムがされ始めていました。具体的な構想（敵の出現方法など）については現在考え中のようです。学びのコンテンツとしてSDGsを取り入れるようです。できれば、学びとゲームの間のつながりを作るように伝えました。', null, null),
  ('1ede417e-be90-502b-9ca8-3cda5f18c47c', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-06-16', '16:30:00', null, '通常 / 大会作品', '変数の使い方に苦心していました。プレイヤーの入力内容を変数に代入し、その後条件分岐をして、プレイヤーの入力内容によってプログラムが変わるようにしました。「もし～～なら～でなければ～」の具体的な使い方に触れられました。 メッセージと「ずっと」を併用しようとしていたので、使うときの注意点を伝えました。あまりしっくりきていないようでしたが、失敗しつつ理解してくれると嬉しいです。', null, null),
  ('10cf9844-e0f4-573c-80c3-11ff632fbe40', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-06-16', '17:30:00', null, '通常 / 大会作品', '前回は駐車ゲームに注力していましたが、今日はリズムゲームのほうにシフトしていました。ステージに工夫を加えて格子状にしていました。色もプログラムでうまくコントロールさせることができていました。図形が下に降りてきたとき、うまく消去できたときに上に戻すやり方に少し悩んでいたので、キャッチゲームを一緒に復習しました。 x座標の設定に不備があったので完全にはできませんでしたが、楽しく本人の納得のいく完成度になったようです。', null, null),
  ('db1fc279-c078-530f-b1c3-e9062e51b9e8', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-06-16', '17:30:00', null, '通常 / オリジナル作品作成', '新しく作ったスプライトがうまく動かず困っていました。プログラムに大きなミスも見当たらなかったので本人にもストレスだったようです。複製を使って問題を解決することができあｍした。 また、最後に、スプライトがぶつかったときの減点について、スプライトがギリギリ接触しない不具合があり、減点されない不具合が起きました。時間がなかったので確認できなかったのですが、次々回は不具合を修正していきたいと思います。', null, '盛り上がり: にゃんこ大戦争でクローンを使っていますが、クローンについての理解がイマイチな様子なので、レッスン「宇宙バトル3（エキスパート1-2）」に挑戦するのが良いかなと思いました。オリジナル作品に関しては1週開けてもよいかなと感じます。'),
  ('a5ce5a4a-58f7-5b7f-90b4-96544be4eee1', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-15', '17:30:00', null, '通常 / コンテスト作品の作成続き', '基本的にはストーリーものなので、一人でサクサクと進めていました。 最後の15分くらいは、自作の絵が必要とのことでiPadで絵を描いたので、背景を透明にしてエクスポートを教えました。', null, '盛り上がり: 来るたびにストーリーが進むのには満足そうでした。 お話を作ることが性に合っているのか、毎回満足そうに作成しています。'),
  ('ec81419c-b18a-5f15-9337-9077fd41393e', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-15', '17:30:00', null, '通常 / コンテスト作品の作成続き', 'クローンに変数をつけて個別に認識することはできていましたが、クリックしたときの動きがうまくいかず、いったんそこから離れて別の箇所の作成を進めていました。 クローンをやめてそれぞれ別のスプライトにすることを勧めましたが、重くなることをとても心配していました。学校のChromeBookだと本当に重い！と言っていたので、審査員はさすがにそれよりも良いスペックのPCを使うはずだから大丈夫、と伝えましたが…', null, '盛り上がり: 作成自体は楽しそうに進めています。ストーリーや全体像は頭の中でできあがっているようで、ここが行き詰まったからこちらの部分を先に作る等、細分化もできているようです。'),
  ('e26c7f89-a7bd-55cf-a3e3-4cff5582a0cc', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-15', '17:30:00', null, '通常 / コンテスト作品作り', 'ボールキャッチでボールの初期位置が右側に偏ってたので、画面上で見える範囲の座標を確認しながら、調節していきました。ボールの動きはほぼ全壊で作ったので、アレンジとしてオウムをどうするかつくっていきました。最初は、自由に動き回っていたが、キャッチする人を邪魔したかったので、追いかけまわすことに落ち着きました。そして、なぜかボールが3つしかないのに4つ目があったり、コードを途中でも完成の動きをするし、探してもわからなかったので、次の作品に移りました。 後半から虹色ピンポンの作成に移ったので、画面外への気移りが多くて、最初の初期位置を決めることまでしか進みませんでした。', null, 'タイピング: 今回はスムーズに進めていました。
盛り上がり: いったんできた時は喜びました。'),
  ('5fc8a4f3-65d1-53d4-b620-f5a59cf6f67e', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-15', '16:30:00', null, '通常 / 基本的なブロックの使い方に慣れる', 'だいぶ先生達にも慣れたようで、今日はしもさん、こうくんのレッスンも抵抗なく受けてくれました。 体験の際に、Scratcやプログラミングへの興味、やる気に少し不安が見えたので、基本操作コースをやる意味を説明し、少しブロックを覚えてきたらゲーム作成で実践させてみるなど慎重に進めてきましたが、そのためか、体験、初回、今回と来るたびにやる気も出てきて、素直に取り組んでくれています。 体験のときは「全部つまらない」と言っていた音やスプライトにも少しずつ関心を示し出して、一生懸命選んでくれるようになりました。', '追跡ゲームの続きから', 'タイピング: 前回のおさらいから始めて、新しい文字（DK）までやりました。習ったところはスコアSが出せるので、楽しそうに進めています。
盛り上がり: 追跡ゲームのキャラクターや背景を、好きな野球関係に設定して、嬉しそうに解説してくれました。ゲームを作る事にも遊ぶことにも、体験の時から比べるとかなり前向きになり、楽しそうに来室して楽しそうに帰っていきました。'),
  ('9dfa9f00-b7a8-59a3-b842-67542c15e746', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-15', '16:30:00', null, '通常 / コンテスト作品作り', '買い物で商品を正しい順番で買い物できるようにしたいから、軽く「リスト」を使った表現しようと思いました。その時にコスチューム名を打ち込むことにだいぶ疲れを感じていました。そして、リストがあると画面上でいっぱいになってしまうから、リストのオンオフブロックを作りました。その条件式を作ることに手こずって先生側で作ってあげただけになったので、1発で分からなくてもいいけど、その仕組みを説明した上げた方がいいと思います。', null, 'タイピング: タイミングゲーのタイピングはまったそうです'),
  ('2fb90a55-cda6-5dca-8fb4-d815e3dd3c12', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-15', '17:30:00', null, '通常 / 自由作品', '何回かかけて作っている寿司屋ゲームをもっと作りこんでみない？と提案すると、そのゲーム自体は完結したけど続編を作ると言い、作成を始めました。隠されたボタンをタップするとネコが大量に分身したり、寿司屋の建物がだんだんくずれていったりと、やはりカオスなアイデアをいろいろと思いついています。また違う続編を作るそうです。', null, '盛り上がり: 何回も続いているあたり、寿司屋ゲームが相当楽しくて気に入っているのが伝わります。'),
  ('64a99506-72c5-5912-a76f-5bf6ebb1aa2a', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-15', '16:30:00', null, '通常 / コンテスト作品作り', '今回はてきのHPのダメージ判定を作っていきました。模試の条件に何を使うかは忘れていたが、演算式のブロックを使うことを教えたら、作り方は覚えていてスムーズに進めました。ダメージ判定が付いたことで、敵の攻撃行動が難しかったことに気づき、優しい難易度に直せました。そこから倒し終わった後や登場のセリフをつけて、とりあえず、始まりからステージ１の終わりまでは作ることができました。だが、このペースでいくと間に合わないので、ステージ2の作りスピード次第で敵の量を考えた方がいいと思います。 模試の条件が作れたとしても、作ったままで旗ら押されたなどに綱時忘れることが多かったので注意してあげてください。', null, 'タイピング: ずいぶん進めていたので次からは新しいものをやります
盛り上がり: ここあのタイピングの皆の成長具合に喜んでいました。'),
  ('6694acd4-b184-51d7-8580-e6a7c4aa2dea', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-13', '16:30:00', null, '通常 / オリジナル作品、ジャンプ→場面展開の方法を学ぶ「基本操作コース 追跡より」', '今日は最初に、ジャンプと落下のやり方を再度おさらいから。まず跳ね返る判定がそもそも、ボールや色だけにしてしまうと全部がその物体だから、落下ができないという現象になっていることを説明。 自分で、赤い色をトップに持ってくれば跳ね返るということを導き出してくれました！ その後、変数で場面展開をさせるために、基本操作コースの追跡でyou wonの部分まで勉強しました。', '追跡ゲームのyou wonを次回は出す', 'タイピング: なし
盛り上がり: 跳ね返り判定を自分で導き出せたのはとても素晴らしい！'),
  ('a1aa78e3-9058-5b43-9ad4-830e94afc92f', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-06-13', '17:30:00', null, '通常 / 大会作品', 'ほとんどの時間を自分で試行錯誤して進めていました。とても集中して取り組めていました。音にこだわっているようです。カーソルをクリックした場所に弾が自動で動くようなプログラムを作成しました。考え方と「マウスのX(Y)座標」のブロックを紹介しました。 動きや体力についても丁寧にプログラムできています。スプライトの動かし方や世界観の背景についての説明がほぼないので、これから増えていくと嬉しいです。', null, null),
  ('3ebc1472-2803-595c-bbb2-2740d4da522e', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-13', '17:30:00', null, '通常 / チエテラス２変数の復習、７配列、PRGのおさる「https://app.arspark.jp/projects/15528/editor」', '３０分ほどチエテラスを行い、復習と新しい部分を学習していました、割と早く終わったようだったので、その後におさるのPRGの作成から始めていきました。 おさるの方は、定義が繰り返し出てくる点などが今まで使っていたのと違うやり方なので、そこをじっくりゲームで体感してもらった後ビデオを見ながら作成。 今日は半分ほどおこない、ビデオの15:30までやりました', 'おさるは、ビデオ15:30~以降から', 'タイピング: なし
盛り上がり: 15分延長するほど熱心に行っていました！'),
  ('dc62cecb-5c3e-5631-b647-ad1c5ae6ce8d', '7d01236e-620e-5177-a6f4-af325a582aae', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-06-13', '17:30:00', null, '通常 / 大会作品', 'まずビームの調整を行いました。ビームを動かすことは自分でできていましたが、見た目の調整に苦心していたようです。話しながらどのようなタイミングでビームの見た目をどう変えたいのかを整理していきました。しっかり「1秒待つ」のブロックもいれることができていました。ビームに当たったゾンビの見た目にも変更を加えていました。その後、アイデアが尽きてしまったようで困っていました。カードを使って一緒に考えました。ストーリーの終わりをどのようにしたいのかを早めに考えるように伝えました。', null, null),
  ('912d5f38-e580-5371-8ebd-13d9e7a6b143', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-06-13', '16:30:00', null, '振替 / 大会作品', 'カミナリの動きをキャッチゲームのカードを見ながら確認していました。速さが少し早いかなと思いましたが、本人的には納得のいく出来のようです。前後にストーリーがある方が良いかなと思いましたが、あまり気が進んでいませんでした。スプライトを新しく手書きで作っていました。とても丁寧に作れていて良かったです。次回からスプライトの動きの調整に入ります。 ストーリーの強化が課題かなと思います。', null, null),
  ('cb8650e0-0a29-54b9-b317-69667480b25f', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-06-13', '16:30:00', null, '振替 / 大会作品', '最初にコインのクローンを確認し、バグ探しをしていました。その後確認するときちんと動いていました。コインの速度の変数について、表示用の変数と実行用の変数で分けていると聞いて驚きました。オリジナルの怪盗スプライトを描いていました。ゲーム前にストーリーがあるようですが、話を聞いたところコインがずっと出続けるようなので、ゲームクリアやゲーム後のストーリーがなさそうです。放置ゲーム故の特性かもしれませんが、ぜひ作ってほしいです。', null, '盛り上がり: 集中して取り組めていました！'),
  ('d47fb951-191d-5052-85f9-21305a878606', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-13', '17:30:00', null, '通常 / 自分の作品を作成、バグを潰す&背景を選択した後の動作を作成する', 'バグを潰す際に、誰かがスタートになってあげないといけないんだよ〜ということを説明したところ、だから動かなかったのか！と理解していました。 その後の遷移で、特に考えがなかった様子でしたが、背景がスクロールするという状態へ持っていきたいとのこと。 スクロールをクローンで表現するという部分で、子分がどうしても繰り返さず、１回きりのスクロールになってしまっているので、次回はそこを作成していきたいとのことでした。', null, 'タイピング: なし
盛り上がり: 自分のコードの修正をすること自体は楽しい様子です。少しずつでも思い通りに動いていくのを考えることが好きみたいでした'),
  ('86627f94-3e83-5888-a2fd-32534033b1bd', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-13', '16:30:00', null, '通常 / ハンバーガーを食べた後の動きを作る＞スコアが10点、20点になったら違うスプライトが出てきて、そのスプライトを食べるというところまで', '今日はハンバーガーを食べた後の動きを考えていきましたが、主語が誰なのか？を意識させてあげないと、他のコードと干渉してしまうのがあり、なかなかうまく作動しないという事象が起きていました。 本来であれば10秒以内にスコアが10点になったら、りんご、20点になったら自分で作成した絵のスプライトが出てくる、そしてそれを食べるという状態にしたい様子です。 演算のかつ、や条件分岐をすでに何回もやっているのにも関わらず、「どれだっけ？」と聞いてくる感じでした。', null, 'タイピング: なし
盛り上がり: 自分で絵を書いて、それを登場させるというアイディアを出していくのはとても良いことだと思います！残りの回数を気にしていたので、本人的にも長くなっているなというのがある様子。ある程度簡単な場面展開に直してやらないといけないかも。'),
  ('cf3387a6-f71c-5e52-9f85-1c299131a645', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-12', '17:30:00', null, '通常 / 大会用の作品作りの続き', '文字にねこちゃんが被ってしまって通り抜けてしまうようなコードの修正（チーズを探せと同じように跳ね返り判定はどうしたらいい？など） コードの可読性を高めるために、コードをみやすくしようなどに取り組みました。 また、ビームがねこちゃんから出てくるようにしたい！と言っていたので、シューティングゲームのコードを思い出してもらい作成していきました！ ただちょっと気になるのが、このコードは、あのスプライトと同じ行動をしているからコピペでいっか！という状態が若干気になり・・それが元でバグに繋がっているので、すこしずつそうした部分を修正できていければと思います。', null, 'タイピング: なし
盛り上がり: アイディアがたくさん増えていくのはとてもよいことだと思います！ビームが最後ちゃんと打てたことに満足していた様子でした！'),
  ('a6fde1be-7332-5d9e-8832-e0a14849c74f', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, null, '2023-06-12', '18:40:00', null, '休み（未対象）', null, null, null),
  ('6d6c63c9-d3ec-5947-b664-619a5e82e57c', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, null, '2023-06-12', '17:30:00', null, '休み（未対象）', null, null, null),
  ('ff3e415a-5501-574e-85f1-7872e723d5eb', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2023-06-12', '16:30:00', null, '通常 / コンテスト作品作り', '進めるにあたってすぐには解決できないバグがあったのでコスチュームの色塗りをしてもらいました。そのバグは、2回目に旗が押されたとき、背景が暗転するコードが勝手に4動き出してしまうバグです。対処法として、暗転する起点となる条件の「変数(まぶしくする)＝1になるまで待つ」の前に(まぶしくする)を０にするを挿入したら治りました。旗が押されたで変数の初期化を別のところに作っていると、旗が押されたの後ですぐに条件があるものでラグで初期化する前の変数の値で反応してしまうことがあります。だから、変数を1つのまとめて初期化するのもいいが、旗が押されたの後にすぐ条件があるものはそのコードの塊の最初に初期化する方がいいです。 また、缶が表示されないバグはまだわからないです。ただ、はるちゃんに幽霊の効果はプラスの方向が消えていくことを伝えてください。マイナスで作っていたので、', null, null),
  ('d27ad36a-e624-5e74-9f7c-787350f0843a', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-12', '16:30:00', null, '通常 / 大会作品の続き りんごを食べる部分から〜', 'りんごを食べる〜、りんごが出現する〜という部分でメッセージのやりとりが難しかった様子でした ただ、どういう展開にしようなど創作意欲はとてもあったので、来週も引き続き頑張ってほしいなと思います！', null, 'タイピング: 8割方、タイプミスなくできていました！
盛り上がり: 一個一個丁寧にみるひろとくんは、育てるゲーム系がとても向いています。 すこしずつではありますが、やりたいことをきちんと書くことができるのはとても素晴らしいと思います！'),
  ('486b1a2a-170c-5ee1-a840-e38b064dedb7', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-05', '16:30:00', null, '通常 / 大会準備', '最初はコスチュームの作成などの作業をやり、そのあと場面転換のときにスプライトがうまく動作しないというバグの解決に取り組みました。細かいバグに関しては、怪しいブロックを一つずつ取り外してテストしてみるという方法を伝えました。根本的な問題としては「背景が～になったとき」を避けたほうがよいという話をしましたが、完全には納得できていないかもしれません。', null, '盛り上がり: 困っている状況を話してくれました。思った通りに動かないのはやはり大変そうです。'),
  ('5690e490-137a-5b56-9a99-d5e0008351ad', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '25840600-1a86-5fb0-b223-dec47cec8c48', '2023-06-10', '16:30:00', null, '通常 / 条件分岐の理解', '〇回繰り返すブロックが使い慣れていなかったので苦戦していた。問題を解くのは嫌いではなさそう。 理解はしていたと思うが、スクリプトを読むことに慣れていないので感覚的にブロックを組んでいるところがあるので、やはり基礎からやってあげたい。', '以上を参考にお任せ致します。 ただし、自分だけで作品作りをするのはあまりお勧めできません。', 'タイピング: なし
盛り上がり: 問題を解くのは嫌いではなさそうです。 解らないところがあってもくじけず挑戦しますし、 解説も聞くことができます。'),
  ('3959d484-fda9-5275-8ada-797cf31ddd3b', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '25840600-1a86-5fb0-b223-dec47cec8c48', '2023-06-10', '16:30:00', null, '通常 / 大会作品の制作', '脱線しそうになった時に注意することで、ほぼゲーム作りに集中できた。脱線すると長引くので初期対応が大事。', '並列処理の復習（並列処理という言葉はわからないと思います。） 不等号の演算ブロックに挑戦。 最初にやりたいことを思い出しながらやった方がいいと思います。', 'タイピング: ミスなしになるまで最初からやり直していました。
盛り上がり: 敵（コウモリ）が動くのとコウモリがダメージを受けるプログラムを同じスクリプトに入れていたせいで、コウモリが思ったようにダメージを受けなかったので、並列処理をして思い通りに動かすことができた。ブロックを一緒にしたほうがいい時と別々にした方がいい時がある事を説明。次回もおさらいしてあげてほしいです。 敵のHPが０になったときに敵を消したかったが、「もしなら＋演算」が身についていなかったので、基本操作コース07_ピンポンゲームをおさらいしました。 思い出したようで〈変数＝０〉を使ってプログラムしていました。 ただし、不等号を使わないと正しく動かないので、不等号の演算ブロックを教えてあげてください。 もともとは説明を聞くのが好きではないタイプですが、自分の作品を作るためなら多少説明も聞きます。'),
  ('34744eca-45ac-559a-964c-6b1ccdaf6bdd', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-10', null, null, '通常 / 矢印キーによる操作を作成する', '基本操作コースをやる予定でしたが、チーズをさがせをやりたい！と言ったので取り組みました。急にレベルが上がるので、上下左右のキー操作の完成を目標にしました。前回のピンポンゲームでも左右のみのキー操作は扱ったので、その復習をしてから始めました。x座標とy座標が両方出てくるので、2つがどう違うのかについて質問したところ答えることができ、使い分けられていました。また、座標の変化だけだと向きが変わらなくて変な動きになることを確かめさせたあと、「～度に向ける」を習得してもらいました。レッスン時間内に角度を変えるところまで完成しました。', 'できれば、「チーズをさがせ」のチーズやクモの動作', '時間帯: その他
タイピング: 今日は基本にかえってFとJのキーをやっていました。
盛り上がり: 内容が難しいのでたまに混乱することもありましたが、答えを見つけたときはうれしい様子でした。'),
  ('14009d33-ab4e-594f-ac2a-b369b1e1fc05', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2023-06-10', null, null, '通常 / 大会用のオリジナル作品を作成する', '大会用のオリジナル作品を作成する ゲームの内容としてはSDGsの質問ゲームを作成して、ゲームに回答（正解不正解どちらでも）→対戦ゲームにすすむようなものにしようとしているそうです。 作品の大枠はできているものの、ゲームの部分がどういうゲームにしようかと悩んでいるようで、途中途中ちょっかいを出してくれたら「どうおもう？」と質問してくれました。 いくつかのアイディアを出した後、それじゃないんだよな〜と唸っていたので、ある意味自分の考えがまとまってない状態なのかもな〜とはおもいました。 お父さんと一緒に話して決めているそうなので、大枠自体があまり好きな感じではないのかも・・・', null, '時間帯: その他
タイピング: なし
盛り上がり: ゲームを追加したいという気持ちになってくれたのはとても良かったと思います！'),
  ('18985f3d-f1b9-538b-a62d-a2169d27bb29', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-10', null, null, '通常 / チュートリアル (フリエのボールキャッチ https://app.arspark.jp/contents/3106)', '自分で左右に動かす動きは、今までの授業からか覚えていた様子。あとはボールを落とす部分のみチュートリアルを見ながら作成。きちんと向きの概念をわかっていて、下向きにするから下に動くという動きを書いていました。', null, '時間帯: その他
タイピング: なし
盛り上がり: ボールのコードを書いている際に、色々と自分で工夫しながらコードを書いていました！将来は、アプリでゲームを売るということを目標にしているそうです！'),
  ('202b2ab7-4f62-5f6a-9791-f371185bfa91', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-10', null, null, '通常 / 大会用にオリジナル作品 マイクラのように作品を作りたいと話していたので、いっぱいをやろうとすると終わらなくなってしまう可能性もあるので、特定の動きだけに絞って行うことにしました。 土を掘る、木を削って家を作るという部分のみを作成してみること', 'まずは土を掘る〜の部分、ちょっと難しい部分ではあるので、どうしたら消えるという判定をさせるか？の部分でマウスでクリック&触れたら〜という判定で土を掘っている感じに見せてみました。 また木は変数を使って回数分押していくと木が削れていくようにコスチュームを変化させるように→演算キーを自分で出してきて、もし〜と一緒に合わせてコードを繋げればコスチュームを変化させることができるということをわかっていました！', null, '時間帯: その他
タイピング: なし
盛り上がり: 動きの動作自体を全部自分で作成することは、考え込む時間が長くなってしまうものの、ヒントがきちんとあれば自分で進められるので、ある程度ヒントを渡してあげるといいのかなと思います'),
  ('f213594d-39b3-5c1e-88ce-524ab20c8241', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-10', null, null, '通常 / 大会用 オリジナルゲームの作成（ジャンプゲームではしについたら、次のステージに行く）', 'ジャンプの繰り返すの原理を再度おさらい、はしという概念をどのステージでも入れてしまうと背景が変わらないというバグに対して、どうしたらいいか？を一緒に相談しながら決めてました。 次のステージというコードでもいいけど、ちゃんとコンピューターにステージの理解をしてもらうには特定させた方がいいよねということも含めながら、ステージごとにどこでもドア的なものをそれぞれ設置して次のステージに向かうということにしました。', '今日の続き、ステージごとの窓から背景が変わるコードを追加する', '時間帯: その他
タイピング: 自身を持ってタイピングできていたようでした！
盛り上がり: 色々なステージの転換方法を試してみて自分がやってみたいということを明確にできることがとても素晴らしい！ また、ちゃんとバグの概念も自分で理解した上で、やっぱりこっちがいいなと思えるのも素晴らしいと思いました。'),
  ('a5f9d962-c3b7-5634-9aaa-441501f74f3a', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-09', '18:40:00', null, '通常 / ビギナーズ部門のにじいろピンポンアレンジ続き', '最初にゲームの操作を教えてもらって一緒にプレイしてから、これは説明があるといいね、と促したらすぐに、「スラボーに説明させる画面を作る」と乗り気になってくれました。 背景も自分で整理して、せつめい用の背景とゲーム中の背景をきちんと名付けていました。 説明画面を出すときは緑の旗、ゲームが始まるときはメッセージを受け取った時などのイベントの使い分けも、よくわかっていて自分でできていました。（メッセージ名の入力補助は必要でした） ペンツールの「ぜんぶ消す」だけ緑の旗が押されたときに移動した後、同じタイミングで実行するはずのスラボーのセリフが出てこない現象でしばらく悩みました。結果として、ボールがレッドラインに触れていたため、開始直後にゲームオーバーになっているのが原因なことがわかったので、ボールの初期位置を設定することで回避できました。 背景で光らせることのできる爆弾や、応援する棒人間を加えて満足そうにしていました。', null, '盛り上がり: 終了5分前まで、みっちり集中してできていました。 途中、バグが見つからなかった時も席を立ったりせずに先生たちの検証する様子を一緒にじっくり見て、話に参加しようとがんばることができていました。'),
  ('806b8d39-4a93-5631-b0f7-06221732bdb3', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-09', '17:30:00', null, '通常 / ビギナーズ部門のにじいろピンポンアレンジ続き ゲームオーバーを作成する', 'タイピングで少しすねた上に、けいとくんが授業前にやっていたCar Drivingのゲームが気になって仕方なくて、授業に向かうことができませんでした。 この面をクリアしたら、〇分になったら、と何度か区切りを設けましたが、今日はどうしても授業に向かうことができず、遊んでいたゲームのコードをけいとくんと一緒に少し見てみるのが精一杯でした。 切り替えの約束をした終了15分前に、椅子からずり落ちてしまってしばらく泣いていました。痛がるのを否定せずに、本人が訴える「傷口」を丁寧に見て、大丈夫と保証したら落ち着きました。 残り10分でようやく作成画面を開きましたが、コスチュームの編集で終わりました。', null, 'タイピング: 最初のおさらいがクリアできなくて少しご機嫌斜めになっていました
盛り上がり: 今日はどうしても作成の気分になれなかったようなので、ゲームのクリア方法やコードを見ることにとどまってしまいましたが、本人はクリア方法を考えたり、面談に来ていた梅澤さんに話しかけたりと楽しそうでした。'),
  ('1965d804-2325-59c8-9d12-2d0e7cd12d53', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-09', '16:30:00', null, '通常 / プログラミング大会オリジナル作品続き', '基本的には黙々と作成をしていて、わからないところは的確に「○○を教えてほしい」と質問してきていました。自分でできるところと助言を求めるところがそれなりにわかっているようでした。 矢印キーでの移動に加えて、スペースキーを押しながらダッシュができるようにしたいとのことで、移動のキーによる条件分岐の中に条件分岐をネストする例を見せたら、あとは自分で作成して満足そうにしていました。 フェイドアウトの方法を聞いてきたので、幽霊効果を教えたところ、「幽霊効果は知ってたけど、こうやって使うんだ」と感心していました。', null, '盛り上がり: 自己解決ができなかった部分が授業でクリアになることが嬉しそうでした。 ストーリーのイメージもだいぶできているようで、終始楽しそうでした。'),
  ('4e866348-0095-5fe2-8880-fe8c87862765', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-09', '16:30:00', null, '通常 / プログラミング大会オリジナル作品続き', '家でもゲームの一部分を作成してイメージを考えているそうで、タイピングを省略してすぐに作成に入っていました。 オープニング部分のスプライトの動きを何度も実行しては、動きの速さやコスチュームの切り替えの流れを確認して一生懸命調整していました。 オープニングから次の場面への移行までを完成させていました。', null, '盛り上がり: 納得いくまで何度も調整を繰り返す根気強さが見られました。 オリジナル作品を形にしていくのが楽しいようで、通常の授業よりも饒舌にストーリーの説明をしたりしながら作成していました。'),
  ('c0b9187b-d73e-5ee1-b964-2021466749d8', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-09', '16:30:00', null, '通常 / プログラミング大会オリジナル作品続き', '自分からオープニング画面を作りたいと申し出てきて作成に入りました。 何から始めればよいのかわからないと言っていたので、背景をオープニングとゲーム中で変えてみたら？と提案したら、あとは自分でいろいろ思いついたようでスムーズに作成をしていました。 イベントの使い分けもよくわかっていて、自分で修正もできていました。', null, 'タイピング: 5分間がんばっていました。
盛り上がり: スプライトのセリフの色が変えられないところだけは残念そうでしたが、オープニングができたことでだいぶゲームっぽくなってきたせいか、満足そうにしていました。'),
  ('f5d04587-106b-5beb-8760-1d42c5d2834b', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-06-09', '17:30:00', null, '通常 / にゃんこ大戦争風ゲームの作成', '自分が過去に作ったスプライトをScratchから引っ張ってきてオリジナルに加工し、味方と敵に分けていました。使うスプライトについて楽しそうに説明してくれました。画面に配置する場所、背景の色にとてもこだわって取り組めていました。参考のコードのコメントを作成しながら、とくに変数について丁寧にプログラムできていました！ 一時間よくしっかり集中していました！！まだ最後まで終わっていないです。次回も取り組む予定です。', '自由作品と教材しっかりする日を作って、スキルアップの日を作る。', '盛り上がり: 楽しく取り組めていました！！'),
  ('3e2dae29-53f3-5d7f-8b7e-604f6f7f6d77', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-09', '16:30:00', null, '通常 / プログラミング大会オリジナル作品続き', 'オープニングからゲーム序盤を熱心に作成していました。スコアなどの変数を別のスプライトで隠そうとして悩んでいたので、変数グループに変数の表示非表示のコードがあることを教えたらとても驚いていました。 以前よくやっていたように、むやみにブロック定義を使わなくなり、ゲーム開始時の変数のクリアや表示設定が長くなったところだけ定義でまとめてみるなど、使いどころを考えて作成できるようになっていました。', null, '盛り上がり: 前回自分のコードをしっかり見て納得できたのが自信につながったのか、今日は得意げにコードを見せてくれたり、「ここなら定義を使うのもあり？」と聞いてきたりと、人に見てもらうコードを意識しながら楽しそうに作成できていました。'),
  ('524d3534-21ff-5acd-b7fb-0168ad574549', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-06-09', '18:40:00', null, '通常 / 大会作品準備', '前回、ジャンプがうまくできずに終わってしまったので、あるくんの冒険2でジャンプの確認をしました。色と「もし～ならでなければ～～」が特にポイントであることを伝えました。なんとなく分かったようです。 後半は自分の作品に取り組み、玉の動きを調整したり、ステージを変更したりしました。画面外で折り返したときに、主人公が地面にめり込んでしまう現象がありました。y座標注目し、地面より下にいったときに強制的に地面の上に立たせる提案をしました。ほぼ自力でプログラムできていたので良かったです。', null, '盛り上がり: 次は、茶色の地面を下から突き抜けてしまうのが気になるようです。次回余裕があれば確認したいです。'),
  ('a05d4025-66bd-5967-b00b-4d21eb455c74', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-06-09', '17:30:00', null, '通常 / 大会作品準備', '最初は、周りのバスをどかして車を救出するゲームでした。思ったより作成が難しいことと、バスの動かし方の経路を考えることが難しいことから、自分が車を動かして駐車をするゲームに変更になりました。 車の動かし方として、レールのような細い線を引きその上を車が動くようなプログラムを作成することになりました。「～ではない」を使うことを進めましたが、自分なりの方法でプログラムしていました。ポイントは進む方向と矢印キーの向きが逆になることです。 ゲームの中核はみえてきたので、次回からはストーリーを徐々に固めていきたいです。', null, null),
  ('dd41a864-62fb-5505-a93a-96ad16bd39f5', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, null, '2023-06-09', '16:30:00', null, '休み（未対象）', null, null, null),
  ('ec4a98c5-68da-585c-aff6-0657c5c1a1bb', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-08', '17:30:00', null, '通常 / コンテスト作品の作成', 'ストーリー部分を熱心に作成していました。ゆきちゃんとしては、ストーリーの3分の1から半分くらいができたところだそうです。 当初はストーリーだけの作品にすると言っていましたが、最後にゲーム部分を付け足して、解決してエンド！というのも良いかもしれないと考え始めていました。 残りの回数を話し、今後の大まかな作成スケジュールを決めました。 あと2回ほどでストーリーの完成、その後2回でゲーム、残りで全体の作り込みの予定です。', null, '盛り上がり: じょうたろうくんと話したりしながらも、手は良く動いていました。 頭の中にストーリーはあるようで、熱心に作っています。'),
  ('660042ca-953f-5d10-b546-f104bc48582c', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-08', '17:30:00', null, '通常 / ボールキャッチを完成させよう', '今回はボールを落下する仕組みを作っていきました。動画で作っていく手順でいったん止めてその項目はコードでいうとどのようなものになるか一緒に考えながら、進めていきました。最初にボールを上側に設置することについて、何度も「ずつ増える」の方を持ってきてしまい、「にする」の違いを説明してきましたが、かずまくん自身にはその違いはまだあいまいな感じがします。ボールをキャッチするコードは前回作ったゾンビを倒せでビームが触れた時と同じ条件だと過去の作品から自分自身で関連つけれたのは良かったです。作ったコードをほかのボールに複製していったが、そのままだと重なってしまうので、ドンくらい離したらいいと聞かれたが、自分で試して探してみてと自分で努力させる方向もやってみ明日が、スムーズには進みませんでした。', '虹色ピンポン', 'タイピング: 触れたキー増えてきました'),
  ('d374bae1-66c1-5e79-9df6-dcf4a19cb04e', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, null, '2023-06-08', '17:30:00', null, '休み（未対象）', null, null, null),
  ('88322ccc-eb6e-5982-92e2-8bc9ed5e398b', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-08', '17:30:00', null, '通常 / コンテスト作品の作成', 'Scratchで使用禁止のサイトを自分で調べていて、使用したいサイトが禁止なのではないかと心配していました。ゆき先生に説明をしてもらって、コンテスト応募作品に使用することは可能ということで納得していました。 前半はストーリーを作成していましたが、後半は気分を変えてゲーム部分の作成をしていました。 クローンがすべて同じ動きをするのではなく、個別に設定をしたいとのことで、変数使用を考え始めたところで時間切れになりました。', 'クローンの個別制御を解決する予定です。', 'タイピング: 今日はWindowsパソコンだったせいか、キーを押す感触がはっきりしていて楽しい！と盛り上がっていました。
盛り上がり: ゲーム作成が久しぶりだったためか、楽しそうに作成していました。 Scratchのアカウントも積極的に教えてくれ、こちらが声をかけにいくと、嬉しそうに作品の説明をしたりしてくれました。'),
  ('a2e90c4d-7bbc-584c-a02e-d70ea336ceac', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-08', '16:30:00', null, '通常 / 教室に慣れる、アルスパークの使い方に慣れる', '体験のときに、そこまで乗り気な様子がなかったのに授業開始の1時間半前に入室したので、飽きてしまわないか心配しましたが、アルスパークのゲームを一緒にやりながらおしゃべりしていたら、30分くらいでだいぶ慣れてきたのか、よくしゃべってくれるようになりました。「難しい」「マリオはあまり得意じゃない」と言いながらも、アルスパークの「Super Mario on Scratch 2 remix only clas」や「いちごの反乱」に何度もチャレンジして遊んでいました。 基本操作コース02では、表を見せて何を学ぶか目的をはっきりさせてから、一つずつ進めました。色の効果を変えるところで、他の画像効果を変えるのを楽しんでくれました。回すブロックの箇所も、分度器を見せながら半回転や1回転を考えさせたところ、素直に聞いて一生懸命計算していました。 体験のときの様子で乗り気でなさそうな場面もあったのは、プログラミングは難しそうで、習うつもりはなかったからだったそうです。ただ、実際にやってみたら意外と面白いところもあるかもしれないと思ったので、習いにきた、と話してくれました。 上記の発言と、授業前半の様子から、楽しさを感じてもらった方が素直にこちらの指示が入り、自分でも考えようとしてくれると思われたため、本人に選ばせて、ゾンビをたおせ1に入りました。スプライトの向きの指定やキーが押されたときのブロックなど、直前に学習したことも多かったため、説明を飛ばしながら自分で考えて熱心に作成していました。 一つ一つのコードの意味を納得してから作成に進むことを繰り返したため、できあがったときに大変スッキリした顔で、「よくわかった！」と言っていました。', '「ゾンビをたおせ1」はゲームとしては物足りないので、次回はこの先を作ってみたいそうです。', 'タイピング: タイピングは初めてということでしたが、今やっておけば学校でやるときにとても楽、3年生は後半の国語でタイピングがあるから、と説明したら、とても乗り気になってくれました。 タイピング道場のはじめから、FGHJのキーまでやりました。
盛り上がり: 体験のときよりも熱心に、こちらの話もよく聞いて楽しそうに取り組めていました。 他の先生や生徒さんたちには、人見知りする様子を見せていましたが、そのうち慣れていくのではないかと思われます。 興味がないと言っていた割には、自分の意見もよく出してがんばっていました。 習うと決めたからには前向きになったようでした。
備考: お母さんから、外でおやつを食べてはいけないと言われているそうで、飴を最後まで食べませんでした。お母さんに伝えてみてもよいかもしれません。'),
  ('b794bf11-985e-56e2-a03d-16e896655400', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-08', '16:30:00', null, '通常 / 大会準備', '以前アイデアを書いた紙を見ながら、ゲームスタートしてから最初の買い物を始めるまでの流れを作りました。閉店間際に急いで買い物するという設定なので、もともと昼のイラストだった背景を夜に変えるなど、細かい所にもこだわりが見られました。スプライト数が多いので時間はかかりましたが、メッセージを使って場面転換することができました。「予算内で買い物する」「セール品を買わないと予算オーバーする」など面白いゲームシステムを思いついているのですが、しっかり考えないと作れなさそうなので早めに取り掛かってもらいたいです。', null, 'タイピング: 結構複雑な文でしたが頑張って打っていました。'),
  ('1be74872-f92c-5718-b582-9e5a7ccf5272', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-08', '16:30:00', null, '通常 / コンテスト作品作り', 'コンテスト作品作りをしました。ヘーゲルの戦いについて、HPの変数の使い方はスムーズに作れていました。ただ、もし条件を作る際にずっとの入れ忘れることが多かったです。また、ビームの飛ばし方に対しても、打ったビームが手元に戻ってくるやり方は1度振れたことはあったがゆっくり考えながら作りました。まだ、低学年なのでしたい動きとコードの結びつきは甘いかもしれないが、もう1度覚える感じで進めるようにしていけばいい。 このペースで進むと、作り割らない感じするので、ペースアップするか、構成変更するかを考えた方がいい。', null, 'タイピング: 接戦になりながらもAランクになれました
盛り上がり: ビームを打てた土岐はすごく喜んでいた。'),
  ('d032af9e-2043-5bd3-b1b7-a73586e3a456', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-06', '17:30:00', null, '通常 / 変数をうまく使って載せるキャラのところまではできているので、どう移動しているようにみせるか？だね。', '車の移動に関しては、車自体が移動しているようにコードを書きたいそうなので背景移動の件はとりあえず紹介までに。 レッスン最中は、場面を変えるというコードを加えるために矢印キーを画面に表示させて、押すと変わるというコードを書いていました。 今日はそこまでで大体の作業が終了、次回までにバグに繋がっている部分を解消しながら進めていきたいと思います。', null, 'タイピング: なし
盛り上がり: 背景が押されたら変わるの部分で、スクラッチの特性をよく理解し、４の背景の次に１の背景に移行する〜という部分がすぐ変わってしまうというバグを、白い背景を一個噛ませて、コードを組んでいました、本人はそれはチートだとは言っていましたが、ある意味それも一つのテクニックではあるから大丈夫だと思うよ、と伝えておきました。'),
  ('e8e2c0b2-6ec9-5e0a-ac26-75af920d2ef8', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-06', '16:30:00', null, '通常 / 基本操作コース０２の確認、角度、座標、キーで色を変える→基本操作コース03 キーで左右の動き', '基本的にはまだ何もコードを覚えていない状態なので、基本操作コース０２の部分のおさらいと03でのキーで左右に動く動きなどをまとめて行いました。 先にその部分を学んでから先週作成した虹色ピンポンでもう一度作ってみようか？と話したところ、今日作ったコードを使うのがわからないという感じ。 しばらくは根気よく０２〜０３を繰り返しながら、すこしずつペースに合わせて進める方が良いかと思います。', null, 'タイピング: 最初のまとめの部分までBランク まだ打つことになれてない様子
盛り上がり: 自分でできない部分もあるものの、コードをきちんと書けた時の嬉しい顔は、やはりゲームが好きなんだという感じがしました。'),
  ('424d2894-5dde-52a2-bb2e-0622514801db', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-06', '17:30:00', null, '通常 / コンテスト作品作り', 'ごみ拾いのクリッカーゲームを作っていきました。前回はただクリックして変数が増える仕組みしか作っていなかったので、何を拾ったかわかるようにイラストを追加しました。集めたごみの金額に対して、拾えるごみの種類を増やしていくアイデア面白いです！この時、フラグ変数を使って、コードの切り替えをする仕組みを図を描きながら教えていきました。間に質問を投げながら作っていったので、次に自分で種類を増やすときは、1人で作り直すことができました。確率に乱数を使えたのもよかったです。コードの重さや1度きりの条件分などに対してに「もし」と「まで待つ」の使い分けができたらいいねということを伝えてました。今後のステップアップポイントです。そして、確かめる際に最初からスタートしていたので、ポイントなる変数だけを先にいじる方法を教えました。', null, null),
  ('9db34a26-3bec-54ee-bffb-abe1438df81a', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-06-06', null, null, '通常 / チエテラス半分。後半はScratchで演算多い系【Prg】47 シュンカンきおく順番当て', 'チエテラスで前回の復習から入り、次々進めてもらったところ、「レッスン6 フローチャートからプログラミングを作る」まで３０分で終えた！ 素晴らしい。 後半は「【Prg】47 シュンカンきおく順番当て演算」ゲームを動画を視聴しながら制作。終わりの時間で残り少しだったので「全部完成させてから帰る」とのことで、３０分延長して完成までいきました。', 'チエテラス２週、Scratch１週、というバランスで行きたいと。本人の希望です。 Scratchは、PRgの後半のゲームが難易度も高いので、それを順番にやっていくと良いかな～と思います。', '時間帯: その他
タイピング: ─
盛り上がり: すごい集中力で。かなり疲れたかと思います。'),
  ('86457de7-6222-5a8c-9b5c-1cdfb4200457', '7d01236e-620e-5177-a6f4-af325a582aae', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-06', '17:30:00', null, '通常 / コンテスト作品作り', '前回の続き。敵に夜に変えられたところから作っていきました。前回よりも話のネタが進まなくなったので、アイデアカードを使っていろいろ考えました。コード作成になった時は、わからない所があったら以前よりもしっかり質問してくれるようになってきています。オリジナル作品を作り始めて、自分が作りたいものがみえてきたのかな？？ 次回きちんと見直したいポイントは、メッセージ名のやり取りの確認です。', null, '盛り上がり: 次の展開に向けて考えてきてもらいます'),
  ('eb100923-ba33-5fbd-957a-cc1c798a040c', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-06', '16:30:00', null, '通常 / コンテスト作品作成', '前回に続いてコンテスト作品を作りました。剣の動かしかた難なく動かせ、敵の行動パターンの作りに苦戦していました。色判定でいろいろしようとしていたので、わずかな範囲の色判定だと反応しにくいことを伝えたらコスチュームを変えて反応できるようになりました。また、動いているときに判定してもらいたいことに悩んでいたので、判定と動きのコードを1列ではなく、並列で対応できることを教えてあげました。敵側もこちらで操作できるみたいなので、最終的にどうなったいいか確かめてもらいです。', null, 'タイピング: 進めてます'),
  ('3e45ea4d-4336-56ea-81a8-35c7a4e97e97', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-06-06', '17:30:00', null, '通常 / 大会準備', '最初はあまり取り組めていませんでしたが、何回かこちらから声をかけると手が進み始めました。対戦ゲームのようなものができるらしいです。プログラムに加えて、スプライトの絵も丁寧に書いていました。 一度、全体像を見せてほしかったのですが、本人がどうしても嫌そうだったので、来週一緒に確認することを約束しました。授業時間30分たったときに、一度確認させてもらう予定です。', '授業開始30分をめどに、プログラムを一緒に確認する予定です。', 'タイピング: 粘り強く取り組めていました。
盛り上がり: 1時間しっかり頑張っていました！'),
  ('d7013120-5d66-57d3-8df1-61b79ba9bc15', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-05-30', null, null, '通常 / チエテラスの続き、変数までやってみよう！', 'チャプター1 アルゴリズムとフローチャート レッスン4「変数とは」まで進む。「代入演算子」の個所にきたら声かけてと伝えており、該当箇所で少しレクチャーするも、１回で理解できたようで、そのまま自力で変数を終えることができました！ すごい！ 楽しいようなので、チエテラスをメインに組もうと、本人と話をしています。', null, '時間帯: その他
タイピング: ─'),
  ('2f780832-1d12-5f00-b403-4679b2a0f7cb', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-06-06', '16:30:00', null, '通常 / ジャンプゲーム（ジャンプの仕方を整理）', 'まず完成形を遊んでもらい、カードを示しました。自分なりにプログラムを進めたかったほうです。最初に障害物のプログラムを作りました。プログラムの実行順序に対する意識が薄く、「最初の位置に戻る」という考え方に苦戦していました。座標については今日はかなりしつこくやりました。 ジャンプの考え方はおおよそ理解できている様子でした。「～回繰り返す」のブロックにあまり慣れきれないようでした。ぶつかるとプログラムを止めるところまで進めました。 来週以降は自分の作成しているオリジナル作品に取り組みたいようです。すでにある程度作ってありますが、ごちゃごちゃしてしまっているので整理する必要があるようです。', 'オリジナル作品の見直しから入る予定です。', 'タイピング: 集中して取り組めていました。
盛り上がり: スプライトの色を変えてかわいくアレンジしていました！'),
  ('e9b6d5ff-1a26-5240-81fd-2b5c4602640b', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-06-03', null, null, '通常 / 検定準備', '検定問題になれるために、まずは３級（No21 応用５）を実施。最初の３０分で楽々できまいた！ 余力がたくさんありそうだったのと、検定まであまり時間がなかったので。そのまま連続で２級問題へ。最初のサンプル問題にチャレンジしてもらいました。 「〇〇まで聞いて待つ」というブロックを使ったことがなかったためと、最後の修正問題にやや苦戦しており、２級を全部終えるのに50分ぐらいかかりました。', 'スクラッチ歴がそこまで長くないため、２級で今まで使ったことがないブロックが出てくるかもしれないので、類問をたくさんやろうという点に、合意してくれています。 次回も検定準備でOKです。類問を順番に、次は２級のじゃんけん問題でお願いします。', '時間帯: その他
タイピング: ─
盛り上がり: 連続でずっとだったので、ややお疲れモードでしたが。手ごたえはあった様子です。'),
  ('af52c3d3-61b3-5fac-81f8-4fb67efe6318', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-06', '16:30:00', null, '通常 / オリジナル作品の続き〜SDGsで飢餓のゲームを作る', '最初の背景の部分がクリオネが全ての開始になっていたため、可読性がなくなっていた またそのためバグに繋がっていたので、イベントでわけて動作が重なっている部分を分けて考えてもらうようにしました。 ハンバーガーのキャッチゲームを飢餓のゲームとしてやりたかったようなので、昔やっていたことの続きを思い出しながら、なんとかハンバーガーを食べたらスコアが上がるまでを作成することができました。', null, 'タイピング: なし
盛り上がり: 今日は、猫アレルギーのためか顔が痒くなってしまっていて、大変だった感じでしたが思い出せる範囲内で作成できたのが良かったと思います！'),
  ('be7e1913-cd3b-593b-9d41-4f70bb4366f1', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-05', '18:40:00', null, '通常 / 大会準備', '今作っている作品は「ゲーム」モードと「学び」モードの二つに分かれていて、今回はゲームモードに取り組みました。アレンジ大賞の中上級の作品をもとにしたようなゲームを作りました。横移動とジャンプはできました。途中でアイデアが出ず詰まった場合はブレストカードを使う予定でしたが、止まらずに製作を続けられたので必要になりませんでした。', null, 'タイピング: 作品作成続きだったので、いつもやらない寿司打でリフレッシュしました'),
  ('13288e8f-1b87-515d-ab0f-4613b64325ab', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-05', '17:30:00', null, '通常 / 大会準備', 'スプライトの具体的な動きに関してよくわからなくなっていたので、紙に書いてあげながらアイデアを整理していきました。以前やった小技を活用した弾の発射はできましたが、主人公のHPを作るところまではいきませんでした。ゲームの本題からそれて戻ってこられなくなる時もあるので、時々アイデアを書いた紙を定期的に見直してもらうよう、声かけます！', null, '盛り上がり: 細部までこだわりたいという気持ちを感じます'),
  ('602ef468-77df-5656-93a4-9c8d3b1e9a90', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-05', '17:30:00', null, '振替 / 親子大会', '前回まででゲームの概要と背景はできたので、フリー素材を保存してスプライトの用意をしました。素材の量は多かったですが、何の素材を使うかは決めていたようです。 そのあと作成の流れに関して少し話し合い、ゲーム本体を作ってからチュートリアルを作ることに決めました。まずは「スタート」というスプライトを押したら背景を変えるところから始めたのですが、スプライトに文字を入力するなどの作業に慣れていないようでした。そこで方法を教えながらやってもらったのですが、けっこう時間がかかってしまいましたが、最後までしっかり取り組めていました！ 来週は本格的なコード作成に入れそうです。', null, '盛り上がり: 作品全体のイメージはつかめている様子でした。'),
  ('1070dbfb-bfb9-5e6c-b3f1-d5ab206f296f', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-05', '17:30:00', null, '通常 / にゃんこ大戦争を最初から作ってみる（https://app.arspark.jp/contents/36070）', '最初は、にゃんこ、太鼓、スラボーからにげろの３っつのゲームを行って、どれが一番自分でやりたいか？を決めるようにしました。 選んでいる最中ずっと、こうなったらいいのに！と１人で叫びながら30分。ゲームのおもしろさを決めるのは自分で少し変更しないといけないんだということをやんわり説明 にゃんこ〜でひとまずアレンジをし、HPの数を増やして遊んでもらいましたが、残り30分で最初から作ってみようということで写経へ。 コード自体は読みこなせているので、集中力との戦いかなと思います。', null, 'タイピング: 以前よりはだいぶタイピングへの取り組み方が変わってきたように思います、
盛り上がり: アレンジをしてゲームを難しくするという考え自体はとても素晴らしいと思いました！'),
  ('96fbd97e-7d4c-5a72-bbfb-06f9178b4cf6', '13bd73d0-f535-5291-8362-6712e5cd7384', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-05', '16:30:00', null, '振替 / 親子大会用の作品作り', '２週間ほど休んだためかやはり何をやっていたか忘れていた様子。紙に書いていたこともなんとなくしか覚えてない感じだったので、1から作ることに。今の段階では、スタートを押したら人が出てきて、迷子になるというゲームにするそうです。', null, 'タイピング: なし
盛り上がり: ブレインストーミングカードを使用してひろとくんと話しながら、色々なアイディアをみんなから聞いたためか、自分の考えもまとまっていた気がします。'),
  ('880eac45-fccd-5eef-8021-381fb13c0c41', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-05', '16:30:00', null, '通常 / 親子大会用の作品作成', 'だんだんとストーリーが固まってきた様子で、たぬきが旅をして、たまにりんごの木が出てきたら食べる→食べるとHPが復活、食べられないと体力消耗するというゲームを作ることになったそうです。 今日はかんたくんとも一緒にブレインストーミングカードを引いたせいか、アイディアがどんどん追加され、面白いゲームになりそうな感じがしてきました！', null, 'タイピング: なし
盛り上がり: 誰かと対話することでひろとくんの場合はアイディアの質が深まる感じがします。かんたくんととても楽しそうにやっていました！'),
  ('54d0bdbf-f9d8-58c9-b4df-50d88466f662', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-03', null, null, '通常 / 親子大会', '最初の30分くらいスクラッチの脱出ゲームで遊んでしまいました。(一応脱出ゲームのコードは見ていました) レッスン後半は作品作りをやりましたが、やはり内容を見せてくれませんでした。教室のスクラッチアカウントでやっているようなので、こっそり確認することは可能です。', null, '時間帯: その他
盛り上がり: 先生が作品を見るのは嫌がりますが、会話はしてくれます。'),
  ('b1fcd37e-c84a-51eb-8aa2-839625f1d8a7', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-03', null, null, '通常 / にじいろピンポンの作成を人に教える、にじいろピンポンのアレンジ', '月曜日にレッスンを受けていたせいか、テンションは高めでした。 のあくんに教えることは、とても嬉しそうにやってくれましたが、自分の作成は全くやりたがらず、スプライト、音楽、背景など、どんなアレンジ提案をしても「やらない！」と言い切っていましたが、機嫌が悪いわけではなく、完成したにじいろピンポンに余計な手を加えたくないという感じでした。 ペンの太さを「〇にする」ではなく「〇ずつ変える」にしていたため、ゲームをするたびににじいろが大きくなることに、前半はひたすら面白がって盛り上がっていました。その後、どうしてそうなっているのかを考えさせ、「〇ずつ変える」と「〇にする」の違いについては理解して、自分で修正することもできていましたが、本日の建設的なコード編集はここだけでした。 「ゲームマスターになるには、このゲームをたくさんやってうまくならないといけないから」と主張して、ほぼ1時間集中して、ひたすらピンポンしていました。 終了間際にトイレに立ち、床に寝そべる場面もありました。 今のピンポンが気に入っているなら、次回は他のゲームを作ろうね、との誘いにも、「ゲームは作るんじゃなくてやるほうがいい」と言っていましたが、基本、反抗しているというよりも反射的に否定の言葉を言っているだけで、機嫌は終始良かったです。', null, '時間帯: その他
タイピング: のあくんに画面を見せたりしながらやっていました。
盛り上がり: ほぼ授業にはなりませんでしたが、のあくんに教えるのは得意げにやってくれ、適当なゲームで遊ぶのではなく、ひたすら自分の作品をいじり倒した集中力は、ある意味すごかったです。'),
  ('79f15507-51f3-555c-9547-5792633b38e6', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-03', null, null, '通常 / 虹色ピンポン', '最初は先週同じものを作ったこうしろうくんに教えてもらって作る予定でしたが、こうしろうくんはゲームのアレンジとプレイに夢中になってしまったため、動画を見ながら作りました。写経に近い感じではありましたが、少し作るたびにコードの意味を説明しテストプレイしてもらうことで、コードと動きの関係をつかんでもらうようにしました。ちょうどレッスン時間の終わりくらいで完成しました。ブロックを探すときに「このブロックは「せいぎょ」のところにあるよ」などと言っていて、何回か使ったものは覚えてきていると思います。ただ、「～にする」と「～ずつ変える」を間違えることがあるので、近いうちに違いを理解させてあげたいです。', null, '時間帯: その他
タイピング: こうしろうくんと仲良く並んでやっていました
盛り上がり: 動画を見せると興味を持って作成に取り組んでくれました。表情は少し硬いのですが、楽しんでいても表情の変化はあまりない子とのことなので大丈夫そうです。'),
  ('c0a9b188-5365-55a7-86d3-e9e09849c2e5', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-03', null, null, '通常 / コンテスト作品の作成', 'オリジナルの片づけゲームを作成しています。 ゲームが始まったら、部屋に散らかっているものをクリックして所定の位置に戻すと褒められる、という仕様なのですが、ボールのスプライトをクリックしてもマウスについてこないと悩んでいました。 どこが問題なのか、どこから手をつけていいのか、完全にわからなくなっていたので、少しずつコードを確認していく手順を一緒にやりながら教えました。 ①ボールスプライトをクリックしたらマウスポインタについていく、というコード自体の正誤を確かめるため、そのスクリプトだけをクリックして動かせることを確認しました。 ②スクリプトが合っているということは、他に問題があるということで、緑の旗を押した後の該当箇所で、複数のスクリプトが実行中の状態になっていることを確認しました。実行中のスクリプトの中で、ボールスプライトの位置に干渉しているブロックがないかを探させ、ゲーム開始時に表示させる座標のブロックが実行中のままになっていることに気付かせました。 ③スクリプトを実行させるタイミングが本当にあっているのか、繰り返したいブロックと繰り返してはいけないブロックはどれか、迷ったらそのブロックを丸ごと削除するのではなく、少しずつ外して動作を検証していくことをやってもらいました。 以上の手順で、とりあえず今日の問題は解決できたようでした。 上記が解決した残りの時間は、音楽などの素材を探していました。', null, '時間帯: その他
盛り上がり: 問題が解決できたことは、とても嬉しそうでした。 コードの方ができてきたので、その後は素材探しをしていましたが、PCについての雑談などをだいきくんに持ち掛けたりと、楽しそうにしていました。'),
  ('fb44e13b-25df-51bc-bc9a-67ba54df81b2', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-03', null, null, '通常 / 親子大会', '「敵の体力を作りたい」「敵を一人倒したら違う場面に移したい」ということを積極的に伝えてくれました。変数を使う必要がありましたが慣れていないようなので、変数の値を変える方法、変数の値による条件分岐の方法を教えました。また場面転換に関しては、メッセージを使うとできるというヒントを出すとできていました。メッセージはこの作品内でもすでに一度使っており、マスターしているようです。', null, '時間帯: その他
盛り上がり: ときどきあおしくんに作品を見せていました'),
  ('16460156-625d-5d6e-b778-fbd683debf0f', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-03', null, null, '通常 / コンテスト作品の作成', '素材を集めることがメインの回が続いたので、今日は素材はほどほどにして少し作成を進めつつ、追加したい素材を考えていこうと促しました。 改めて、どんなゲームにしたいのかを話し合い、素材を集めて家などを作るゲームにしたいということを確認しました。 プレイヤーキャラクターは、既存のスプライトではなく少し凝りたいようだったので、とりあえず説明役のキャラクターを決め、オープニング画面を作成しました。 ゲームの仕様を考えるため、作りたいアイテムと必要素材を書いてもらおうとしましたが、紙に向かうと考えがとまってしまうようだったので、実際に作成しながら考えるスタイルに切り替えました。その方がイメージがわきやすいそうです。 素材がいくつ集まったかどうかわかるようにするためにはどうするか、の発問で、変数を使うことに気付き、素材獲得数用の変数を作成していました。', 'マイクラのイメージが強く、そこをこだわり始めると作成が終わらなくなりそうなので、完成までのスケジュールをたててあげるとよいかと思われます。', '時間帯: その他
タイピング: 地道に毎回きちんと取り組んでいます
盛り上がり: マイクラのようなゲームを作りたい、ということは一貫していて、こんなゲームにしたいと語るときはいつも嬉しそうにしています。 画面上の桜の木などが素材になる過程や、アイテムを獲得するための手持ちの道具など、こだわりたいところが色々あるようでした。'),
  ('0187c2e0-9264-5138-998c-c8659d013e95', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-03', null, null, '通常 / 親子大会', '先週でゲームの流れはイメージできているらしく、ストーリーを作っていきました。平和な世界→敵が現れる→戦闘画面に移行 という順番で進んでいて、戦闘になると背景やBGMも変えたりしていて、世界観がよくできていると思います。ただ、「〇回繰り返す」の中に「ずっと」が入っているためバグになると思うので、来週はそこを対処したいです。', null, '時間帯: その他
盛り上がり: 長いコードも出てきていますが、集中して作れています。'),
  ('ca435b62-45aa-5420-a9ce-6bd7415bf0d3', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-03', null, null, '通常 / コンテスト作品の作成', '前回作成したクローンを使ったジャンプが嬉しかったようで、タイピングを飛ばして楽しそうに動かしていました。 プレイヤーを矢印キーで動かしつつ、背景も一定の速度ではなくプレイヤーの動きに合わせて動かしたかったそうですが、さすがに今のゆうかちゃんのキャリアではとても時間がかかり、肝心のアレンジまで手が回らない可能性が高いことを伝えると、背景を順次切り替えていく方向に切り替えてくれました。 今日は背景まわりの作成をすることを目標に、オープニング画面と複数のステージを作成しました。メッセージ機能のよい復習になりました。', '背景を切り替えるメッセージまわりの完成と、ブロック上でのジャンプ部分の作成', '時間帯: その他
盛り上がり: 前回、前々回は、やりたいことと現状のスキルが合っておらず、ゆうかちゃん自身もかなり混乱しているようでしたが、今日で少し見通しがたってきたのか、久しぶりに楽しそうに作成をしていました。'),
  ('6cd7d560-a9bc-5fba-a08d-1d3145a985fa', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-02', '18:40:00', null, '通常 / 虹色ピンポンのアレンジ', '最終的には２Pで遊ぶゲームになりました。 ちゃんとゲームのクリアまで考えられ、隠すや表示、もし〜、ずっとなどはかなり定着した様子が伺えました。 演算を２つ組み合わせて使うやり方を今日は教えたのですが、どう重ねるか？というところで何個も重ねてコードが書けるということにとても驚いていました！', null, 'タイピング: なし
盛り上がり: ボールの色の変更、音へのこだわりがあることがすばらしい！'),
  ('a48f6792-2bbd-5bc3-95e9-b15d836f52fa', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-02', '17:30:00', null, '通常 / 今日はピンポンゲームのアレンジ', '戦闘機が邪魔するというアレンジにしたかった様子でした、戦闘機が当たったらゲームオーバー。 今日はちょっとお疲れモードだったので集中力に欠けていましたが、なんとか最後まで自分がやりたいことができたようでした。', '来週はゲームオーバーまで作成するといいのかなと思います', 'タイピング: なし
盛り上がり: 自分がやりたいことをちゃんと言えることはとても素晴らしい'),
  ('d6194733-aa23-57f6-b1d7-d608b4405e14', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-02', '16:30:00', null, '通常 / オリジナル作品を作成し始める', '最初はアイディア出しから始めないといけなかったのでブラインストーミングカードを引いてもらい、開始しました。おじいさんおカードから杖をイメージ、村人が助けて〜といって杖を持ったあるくんが助けに行くというストーリーになるそうです。', null, 'タイピング: なし
盛り上がり: カードをひいた後に頭の中で色々な想像をしたようです。 創意工夫をする部分に関しては、とてもいいなと思いました！'),
  ('88f6e600-3bda-51e5-800b-2914c46456f9', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-06-02', '17:30:00', null, '通常 / 大会作品続き', 'ゲームの内容に少し困っているようでした。晴くんの太鼓の達人の作品をみて、リズム系のゲームにすることを決めたようです。落ちてくる矢印に合わせて矢印キーを押し、音がなるようなプログラムを作成しました。 最初、位置座標でプログラムすることを考えましたが、あたり判定がシビアでうまくプログラムを動かすことができませんでした。アイデアとして、「半径●以内であれば」ということ提案しました。うまく動かすことができたので良かったです。', null, '盛り上がり: いつもより少し疲れていて他のことに気が取られてしまう印象でしたが、晴くんと話したり最後に作品で遊んだりして、楽しく取り組めていました。'),
  ('3ed7da6f-ed70-5e70-9760-f6254f3a5943', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-06-02', '17:30:00', null, '通常 / 楽しく取り組む（ビーム、太鼓の達人など）', 'ビームは一度やったことがあるようだったので、太鼓の達人に取り組むことになりました。「今日はこれをしないといけない（何かしなければいけない）」といって、進んで取り組めていました。コードを移すことになってしまいましたが、音楽を自分で持ってきて少しずつ確認しながら楽しくできている様子でした。太鼓が出てくる回数を増やしてボーナスタイムを作り、作品に工夫ができていました。 授業最後には自分が作った作品を遊んでもらえて嬉しそうな様子でした。', null, '盛り上がり: しっかり集中して頑張れていました！すごい！！'),
  ('f6622d33-3ab0-5322-9d88-9f52a87f679e', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, null, '2023-06-02', '18:40:00', null, '休み（未対象）', null, null, null),
  ('393a3286-4578-5100-afa5-4597039d2e4b', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, null, '2023-06-02', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('4cd6fb2d-bc06-58c6-a1e4-27e6380ca8f6', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, null, '2023-06-02', '17:30:00', null, '休み（未対象）', null, null, null),
  ('f61aa1f2-65c9-5c1b-a431-3a545fd6ee67', 'b2246586-4496-52f9-a825-be2488a00a31', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-01', '17:30:00', null, '通常', '前回うまく作れている思った寿司屋のゲームをカオス化していきました。カオスになる前の品名の表現や色のグラデーションはほかにみないまさき君のいいところなので、そこもう少し伸ばせば、いいコンテスト作品になりそう。 この後にも、トイレのゲームや背景だけを高速で変えて、ストップモーションみたいな感じなものも抱け上がっていたので、表せる表現は凝ったものに上がっています。', null, '盛り上がり: 最初の寿司屋の自慢は元気良すぎました。'),
  ('c89af1ce-8afe-5969-b1b5-8d3bc02e760f', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-01', '17:30:00', null, '通常 / 大会作品作り', '今回はコスチュームの選びがメインとなっていました。ただ、いらすとやから持ってくるだけではなく、自分好みに変化させて、いいこだわりを持ています。テキストの表現もあった手若干の切なさが伝わってくるがまた良かったです。画面切り替えで幽霊の効果を使っていたが、変わっても効果が切れてないので、効果を消すかマイナスに幽霊に効果を使うか下上げた方がいい', null, 'タイピング: 指さばきがすごいです'),
  ('c3b3dc76-74ea-5e6e-a9d7-50cdfe429eb6', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-01', '17:30:00', null, '通常 / コンテスト作品の作成', '自分への自信や作成意欲に多少波がありますが、途中まで公開したストーリーがScratch上で反響があったこと、作画？を頼んだ相手から、テキストの内容と表示の仕方でとても完成度が高く、下手に手を加えなくても素晴らしいと評価されたことが嬉しかったのか、作品を完成させようという意欲は湧いたようでした。 ストーリーのテキストをすべてコスチュームで作成しているため、容量を心配していましたが、テキストの表示方法を凝るところはここぞというときにしてみたら、等の意見には納得していました。', 'お話自体は力作かつ自信作のようなので、テキスト以外の見せ方の部分の工夫をしていきたいところです。', '盛り上がり: 作品途中経過に対し、大量のコメントが来ていて、概ね好評だったことで、モチベーションは上がったようでした。
備考: 個人のScratchアカウントで作成しているようなので、次回IDを聞いてインポートできるように環境を整える'),
  ('6c27ede9-850b-5384-aaba-964a75fc09ac', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-01', '17:30:00', null, '通常 / ビーム、ゾンビを倒せの復習とキャッチゲームの作成', '最初に、ゾンビを倒せで作ったところの復習をしていきました。ゾンビはどこでどう動いていたか、ビームをどうしたら何発も打てるようになったのか確認していきました。ビームのところは最初作った時は一発のみだったことは覚えていたが、あやふやだったので動画を見返して、仕組みを再確認していきました。最後に、少しのアレンジとしてビームの形を特大のビームに変えて、どこでもあたってしまうようなビームに代わりました。その変形はかずま君自身が楽しんで、コスチュームの複製の仕方など新しく知れたこともあったのでいいアレンジだったと思います。（下迫田） ボールキャッチゲームは、スプライトをたくさん並べたところで燃え尽き感が見られましたが、残り時間があと15分だったため、キャラクターの左右の動きだけ作成して終了という約束をして取り組みました。 キーで左右に動かすには、「スペースキーが押されたとき」ブロックを使うということはすぐにできていて、その後、マイナスを使うんでしょ？との発言があったため、ゾンビを倒せで使ったx座標を〇ずつ変えるの動きは覚えたようでした。 使用しているスプライトがバスケット選手だったので、座標を-〇ずつ変えるだと、後ろ向きに動くのを確認させ、向きを変えるために「〇度に向ける」ブロックを使うこと、スプライトがさかさまにならないように、体験で使用した「左右のみ」のブロックを使うことを教え、実際に違いを確認させたところ、オーバーリアクションで感心していました。ここまでで10分前を切ったため、次回は続きを作ることを予告して終了しました。（大原）', null, 'タイピング: 新しいキーをちゃくじつにおぼえていきます'),
  ('eceae4bb-0b0f-58ed-b4b4-039d311c42da', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-01', '17:30:00', null, '通常 / ・前回のチーズを探せの動作確認、乱数を使ったランダムな回転をするか、本人次第（前回は、好きなように動かして満足していたので） ・コンテストの動画視聴、コンテストの説明と構想', '最初にコンテストの説明をして、昨年優秀作品の動画視聴をしました。動画自体はそれなりに興味を持って見ていましたが、「コンテスト」のイメージはあまりはっきりしないようでした。それでも、オリジナル作品を完成させてみようというテーマには喜んでいました。 どんな作品を作ってみたいか、という話を始めてすぐに、「やってみたいことがある」と言って、スラスラと作りたいゲームについて話してくれました。 ・所持金があって、買い物をしていくゲーム ・買い物リスト、または目的の料理があってその材料を買っていく ・買い忘れがあったり、違うものを買ったり、予算オーバーをしたらアウト ・同じ食材でも、適度にセール品を買わないと予算オーバーする仕組みにする 今日浮かんだゲームのイメージはこのような感じで、それを紙に書きだしました。作りたい料理候補はカレー、焼き肉、デザートを挙げ、それぞれに必要な食材を家で確認してくるとのこと。 いらすとやで店内の背景や食材の画像をダウンロードして、アップロードしました。', '素材集めが終わったら、ゲームの仕様をもう少し明確にして、コード作成に入る', '盛り上がり: 似たようなゲームがアルスパークになかったこともあり、とても生き生きと「こんなゲームにしたい」と語ってくれました。 はじめてのオリジナル作品で気分も盛り上がったようで、いつもよりも積極的に意見を言ってきてくれました。'),
  ('d8f120d8-aae8-53a6-a73b-eafcb32319f1', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-01', '16:30:00', null, '通常 / 大会作品作り', '今回は前回話題に上がった公園の写真を取り込んで、敵ごとの背景選びをしました。それぞれの敵たちにあった背景を選んで、それぞれ紙にメモしながらやっていました。そして、最初の対戦のへー減のバトルに作ろうとし始めた時、スプライトが画面上にたくさんあったのでの初めの段階で隠すように提案してみたら、メッセージのやり取りでうまくコードで作れていました。ほかのスプライトのへの作成もバックパックを利用して起用に作れていました。主人公のHPとヘーゲルの攻撃の絵をかけたので、次回はその動かし方を作って、3，4体の位の動きは作りたいです。', null, 'タイピング: 検定の順位がっ少し下がっていて悔しがっていました
盛り上がり: 背景の選定はいいリアクションしながら選んでいました。'),
  ('94fadc8d-3200-5cfc-b3f4-2a8641460d4d', '7d01236e-620e-5177-a6f4-af325a582aae', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-30', '17:30:00', null, '通常 / 大会作品を作ろう', '今日はオープニングつくりをしていきました。敵役の登場に斜めに登場したいとアイデアを出してくれたので、とりあえずこの通り作ってと言って三角関数を用いて表現してもたら、めっちゃ喜んでくれました。セリフのやり取りの際にメッセージ使ってみたらと提案したら、特に迷うことなく作れました。アイデアがどんどん出てきたので、今まで1番コミュニケーション取りやすい感じにできました。助言程度で作っていき、時間の間の取り方などを教えていけました。コードのセリフや出現のやりとり順番に少し不安を感じるので、そこは支えていきたいです。', '敵を去っていた後の対戦の作成', '盛り上がり: 敵役の登場の仕方を作ってから一番喋れたように感じました。'),
  ('e6c6169d-1cae-524f-885e-78b55ac86066', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-30', '16:30:00', null, '通常 / 大会作品を作ろう', '今回は主にオープニングつくりをメインに作っていきました。背景に文字の大きさに調整するのが若干時間がかかってしまいました。背景とスプライトの出方の順番に苦労していましたが、きれいに整えることができました。 次に、飢餓のゲームとして落下ゲームのとして食べ物を集めていくようにしていきたいそうです。カードを見ながら作成していったのでそこは問題なく進められそうです。', null, 'タイピング: 2秒後半の打鍵速度は良かったです'),
  ('a12fda76-dfde-5da1-bd2a-7c45c4a5a5a6', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-30', '17:30:00', null, '通常 / 大会準備', '前回の続きをしました。得点などのプログラムを作っていました。棒人間のコスチュームにアレンジを加え、敵っぽい要素を出していました。 対戦ゲームになる様子ですが、ストーリーが思い浮かばず、後半はかなり苦戦していました。ブレストカードを使ってみましたが、それでもアイデアが浮かばなかった様子です。ふとした時に思い浮かぶと思うので、来週までになんとなく考えてくるようにお願いしました。', '今回はタイピングを見送りましたが、かなり苦手意識がありそうなので、大会準備中とはいえたまに取り組む必要がありそうです。', null),
  ('6e1a2898-b830-58cb-a82a-c82a6c5fef7f', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-30', '17:30:00', null, '通常 / 大会準備', '前回まで作っていたものはお試しだったようで、今回から本格的にプログラミング大会にむけて準備を始めました。最初はマリオのスプライトを使ってプログラムを始めていましたが、使えないことを伝えると、他のスプライトを使ったり、ストーリーを変えたりして柔軟に対応できていました。 移動手段として車を使い、バトルするゲームになるそうです。スプライトを丁寧に作っていました。次回から本格的にプログラムに入りそうです。', null, '盛り上がり: とても集中して取り組めていました。'),
  ('d5dcf362-8032-5591-94fa-08d7078beacf', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-30', '16:30:00', null, '振替 / 大会準備', '前回の続きからプログラムを始めていました。全体的にバグをつぶしながら丁寧に取り組めている様子でした。背景の明るさを変数でコントロールしていて、新しい考え方でよいと思いました。プログラムの書く場所、メッセージを使う必要性についてすこしアドバイスをしました。背景がうまくコントロールできないときがありましたが、プログラムの事項順序を確認するように伝えました。うまく対応できたようです。 プログラムがうまく働かないときに、自分なりに仮説を立てて取り組めているので素晴らしいと思いました。一人でバグに立ち向かうのは寂しいし詰まるので、他の人を頼るように伝えました。', null, null),
  ('b572406a-0b09-5536-af5d-f17115041239', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-30', '16:30:00', null, '通常 / 簡単なジャンプのさせ方を学ぶ', '1の内容は前回とほぼ同じだったので、復習を兼ねて自分で作ってもらいました。「〇回繰り返す」こそ思い出せなかったものの、キーを押す、条件分岐などの考え方はしっかり理解してくれていたようです。 その後、あるくんの冒険2に挑戦しました。今回が初のレッスンでした。ビデオをよく見つつ取り組むように伝えましたが、自分では見切れない様子でした。答えがもう提示されてしまうと面倒になってしまう傾向があるようです。 色によってジャンプをコントロールすることを伝えました。なんとなく理解できたようで、最後は自分の作品にも取り入れていました。', '今日やった内容を大会にも生かせればなと思います。', 'タイピング: ミスタイプ2％、はやさ1.3 タイプ/秒 とても集中して取り組めていました。
盛り上がり: 集中して取り組めていました！'),
  ('07d3b3cf-6f1e-5607-9959-a8f94e7a834b', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-30', '16:30:00', null, '通常 / レインボーピンポンを完成させよう', '前回に続いて虹色ピンポンを作っていきました。説明書を見ながら、ここまで作ってみようねと教えながら、作ってみました。前回よりは先生のくっつりより少し弱くなったかもしれませんが、作業が終わると町の時間が発生していました。このコードを作ったら何ができたか質問して、大切さを重用しました。打った回数や虹色の軌跡を作ったら、目新しいものが感じられて、喜んでいました。これでひとまずは完成したので、その後のアレンジとして、ほかのスプライトを何体も用意して、当たったら消えるようにしたいそうです。', null, 'タイピング: とりあえずキーを押してしまう感じが多いです
盛り上がり: いったん出来上がった時はとても喜んでいました。'),
  ('33e41b84-6916-565f-9171-396c15ec31e0', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-05-29', '18:40:00', null, '通常 / オリジナル作品作成の続き〜', '最初の画面（チュートリアルの部分）でボタンを押したら次の画面に行く〜というところで戸惑っていましたが、はるちゃんの作品を参考にしながら「あ、そっかそんな簡単なやつでよかったんだ」と思い出してもらいました。 途中、壮大なゲームになりそうな予感がしたので。はるちゃんのように開発画面のボタンをどこかのタイミングで作った方がよさそうだね〜という話もしておきました。 終始自分の作品を作ることに楽しんでいたようで、わからない部分を私に聞きながらものすごい集中力で行っていました！', null, 'タイピング: なし
盛り上がり: 色々なアイディアが作成中に出てきているかんじ。やはり手を動かしながらの方がげんきくんにとってはあってそう'),
  ('1e743d91-bd71-58d3-97b5-3f3a945ea2c4', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-05-29', '16:30:00', null, '通常 / 虹色ピンポンを最初に見て、コードを読み込む→その後にオリジナル作品の続き', '虹色ピンポンでは、ペンツールの部分を再度おさらいしました。 残像もペンツールで一応スタンプという機能を使ってできるんだよ〜ということをおさらい（割と忘れていた部分ではあったみたい）色の変化などもどうしてそうなるのか？をもう一度考えてもらいました。 その後、もう一度オリジナル作品を文章ではなく、絵コンテで作成（文章だと読み込む時間がかかるという話しをしながら） 実際にはバトル系で、難しいモードと優しいモードを作り、優しいモードの時にはタイミングを見計らってヒントがでるという仕組みにしたいそうです。→ここリストか、変数をつかわないといけないかな。', null, 'タイピング: うでだめし →タイピングの速度がかなり上がってきました。うでだめしをしたのはとても大変だったようですが、力がついてきているので、本人も結果に満足していたようでした。
盛り上がり: 絵にすることで自分のやりたいことがもっと精査された様子。スプライトのキャラクターを自分なりに好きなものにしたいということ。なので、来週までに検索してもらい良いキャラクターのコスチュームがあったら、LINEで送ってもらうことにしました。'),
  ('eee47a03-1df1-5826-a39a-b7b65986c7b8', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-29', '17:30:00', null, '通常 / 大会準備', '授業前からショップや掲示板を作ってすでに始めてくれました。浮島も作成してくれていました。自分の王国を悪役から守るイメージ（ゼルダリスペクト）だそうです。「最背面にする」のブロックを紹介しました。 たたかいのプログラムを先に取り組むようにアドバイスしましたが、本人はショップに置くものや見た目の方が気になるようで、先にそちらに取り組むことにしたようです。 いくつかのステージがある長めのプログラムになるようです。「難しい」と言っていましたが、最初のステージだけとりあえず作り、その後考えるようにすすめました。本人もスプライトの多さにびっくりしていました。コスチュームを変更することで対応できることも紹介しました。', '詳細をまた考えてくるようにお願いしました。', '盛り上がり: 悩みつつもしっかり手を動かせていたので良かったです。'),
  ('07728353-e974-5c7f-b5ab-547f449e7dcc', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-05-29', '16:30:00', null, '振替 / プログラミングコンテスト、虹色ピンポン（ちょうど題材的に教科書の09 ピンポンと同じだったため）作成', 'レベルを２アップして今日はやるよ〜と伝えました。 約束事として ・のあくんに来週この単元を教える をテーマにしてやったので来週はその調子でくると思います。 完成まで終わり、自分で動画をみて完成させた達成感は感じていたようでした。 「覚えているんだけど、忘れてしまった」という場面がいくつかあったので、本人にも刺激になったようです。', '今回の作品をアレンジでもいいし、もしくはのあくんに教えるという感じでも。 お母さんにはコンテストの作品を作成したよという話を伝えて、大会に出すと意思があれば出しましょうと伝えています。', 'タイピング: なし
盛り上がり: 自分で作り上げた達成感がとてもあり、またレベルアップしているんだ！という自信がついたようです。'),
  ('1ac3dc27-3145-5a56-a231-61984fe98a3e', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, null, '2023-05-29', '17:30:00', null, '休み（未対象）', null, null, null),
  ('414ea1f4-d666-511b-bdc3-ab87386b08ca', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '25840600-1a86-5fb0-b223-dec47cec8c48', '2023-05-27', '17:30:00', null, '通常 / オリジナル作品の作製', '黙々と作っている。温暖化やSDGｓについて調べている様子。作品は見せてくれない。 最初珍しくScratchのゲームで遊んでいたので注意。', 'オリジナル作品の続き。', 'タイピング: なし
盛り上がり: 本人が言うには、作品は順調に進んでいるとのこと。
備考: 作品を見せてくれないので、本人にわからないようにどこかで内容の確認が必要。'),
  ('d69e074d-009e-5256-9870-01fd8e34ac2d', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '25840600-1a86-5fb0-b223-dec47cec8c48', '2023-05-27', '17:30:00', null, '通常 / オリジナル作品の続き', 'オリジナル作品の作製。自分でフリー素材を見つけて使ったり、音声作成ソフトを使ってオリジナル音声をつくっていた。著作権について自分で調べたり意欲的だった。 クリアのスプライトの作製、片付ける対象のスプライトのプログラミング（ここがうまくいっていない） うまくいかないプロぐラミを直さないまま、他のことに取り掛かってしまう傾向あり。 一度立ち止まって自分の作ったプログラムを見てみる時間があるとよいと思う。', 'オリジナル作品の続き', 'タイピング: なし
盛り上がり: 自分で作る調べるのは大好き。黙々とやっている。わからなければ質問してくれる。'),
  ('c9e09e2c-f9ba-5d73-bcea-89c29c1dc44e', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '25840600-1a86-5fb0-b223-dec47cec8c48', '2023-05-27', '16:30:00', null, '通常 / オリジナル作品の作製', '最初はスプライトの色を変更していました。集中力が切れることもありましたが、湊太君を見てやる気を取り戻し、 スラぼうが話す⇒魔法使いが近づく話す まで自力で作っていました。', 'オリジナル作品の続き。一回何をやりたいか聞いてから始めたほうがいいかもしれません。', 'タイピング: 新しい項目にチャレンジ 順調
盛り上がり: 湊太君が良い刺激になっていて、集中力が切れても湊太君がしっかりやってるのを見るとやる気を取り戻します。'),
  ('6b2347ab-d47d-585f-9c1e-4abad1bba3ea', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '4fb853b8-7d59-5565-9d96-060872e780d1', '2023-05-27', null, null, '通常 / プログラミング大会の作品作り', '前回は、作業が全く出来ていませんでした。 今回も、手が動いていなかったので、こちらがお題を渡して作業を行っていました。 中々うまいアドバイスが与えられなかったので、次回までに良い対応が出来るよう頑張りたいと思います。', '引き続きプログラミング大会の作品作り', '時間帯: その他
タイピング: 問題なく出来ていました
盛り上がり: 背景作りを頑張って作成していました。'),
  ('0864de36-a950-56e0-88c2-a35ac2a03033', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-05-27', null, null, '通常 / 親子大会のアイデア出し', '使いたい素材がたくさんあるとのことで、それらを紙に並べて書き、整理してもらいました。そのあと前回と同じように素材となる画像を集めていきました。自分で描いた画像やフリー画像のサイトからダウンロードした画像をスプライトとして取り入れました。しかし素材が多すぎるとプログラミングに手が回らないと思われるので、ある程度のところで切り上げてゲームの全体像を考え、コーディングに入ってもらおうと思います。また、3Dだと技術的に厳しそうなので2Dに誘導していきます。', '次回以降、画像を使うときはGoogleドライブの「生徒」フォルダに入れる', '時間帯: その他
タイピング: 集中していました
盛り上がり: 作業がゆっくりめのペースではありますが、モチベーションはあると思います。'),
  ('26a8294a-541c-5334-ae4f-0146c66924f3', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '25840600-1a86-5fb0-b223-dec47cec8c48', '2023-05-27', '16:30:00', null, '通常 / オリジナル作品の作製', 'オリジナル作品の続きを作成、以下項目を追加。 １，最初に敵キャラクターを隠す ２，ボタンを押すと敵キャラクターが出現する ３，盾を作って押すとシールドが出る ４，敵キャラクターが出現したときにHPを表示する 敵のHPを表示するために新しく変数を学びました。 変数は箱で数字や文字を入れることができることを説明、関連ブロックの意味を説明。 次回変数に関しては軽く復習してあげてください。', '変数の復習をし、その後オリジナル作品作りの続き。 おそらく今日の話だと次は敵と戦えるようにしたい感じです。', 'タイピング: 新しい項目にチャレンジ 順調
盛り上がり: アイディアをしっかり形にできて嬉しそうだった。葵史くんをいい意味で意識して作品作りに取り組んでいた。'),
  ('601e448f-af5d-50cb-8bae-0ecc4586d7f6', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-27', null, null, '通常 / 今後取り組む課題の決定、計画', '全国小中学生プログラミング大会の説明をしたところ、興味があると即答しました。第7回大会と第2回親子プログラミング決勝大会の動画を視聴してから、なんとなくアルスパークを触りつつアイディアを考えたいとのことでしばらく自由時間としました。 当初は謎解きのようなゲームを作りたいと言っていましたが、アイディアに詰まってしまい、ゆき先生とブレストカードを使って話したりしているうちに少し展望が見えてきたようでした。', '3級の検定問題を一度やって感覚を思い出し、余裕があれば2級に挑戦', '時間帯: その他
盛り上がり: コンテストを紹介したら嬉しそうにしていました。いきなりの提案だったせいか、かなり考え込んではいましたが、コンテストに出したいという意志は強く、最後までやる気は見せていました。検定についてもやる気十分で、コンテストと両方やる！と言い切っていました。
備考: 【ユーザー視点から考えること、作成することを重視！！】'),
  ('1e945b8e-90e9-5557-af22-3e01e58250e3', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-27', null, null, '振替 / プログラミングを楽しむ', 'ロボットの振替なので、楽しんでもらうことを前提にしました。事前に教材の目安はつけておきましたが、本人が体験のときの洞窟ダイヤアレンジが楽しかったのを覚えていて、同じようなことをやりたがったため、好きなゲームを選んではゲームバランスが自分に合うように変数やスピードの数値を変えたり、音を変えたりするアレンジを繰り返しました。 ＜使用ゲーム＞ 【Prg】初級 計算ドリルを作ってみよう！ 【素材だけシリーズ】カーレースゲームを作ろう！ にじいろピンポン メッセージ無しアイテム脱出ゲーム', null, '時間帯: その他
盛り上がり: 1時間飽きずに楽しそうに取り組んでいました'),
  ('9d699409-becb-55ac-9342-41860f9868ae', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-26', '16:30:00', null, '通常 / 大会準備', '30分ほどで作品の大枠は完成しました。その後、うった数の変数を設定し、クリア画面を作っていました。丁寧に作業できていました。 最後に、時間によってボールが動く速さが変わるアレンジを追加しました。大枠は自分で考えられていましたが、演算の使い方とブロックの置き方がイマイチだったので、一瞬しかプログラムが動いていませんでした。「もし～でなければ～」のブロックを使った方法を紹介しました。理解はできている様子でした。', null, '盛り上がり: 来週から本格的にオリジナル作品に取り組むことを伝えました。 自分の作った作品を楽しくプレイできていたので良かったです。'),
  ('dde8231b-f883-5ca3-a1ad-ee82ca444b20', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-26', '18:40:00', null, '通常 / 大会準備', '対戦がテーマとなりましたが、具体的な作品のアイデアがなかなか思いつかなかったので、カードを使って考えました。いくつか弾き、宝探しとなりました。スプライトに帽子をかぶせたり目をつけたりして、自分なりにアレンジできていました。 左右に動かすときに角度の話をしました。動く前に動きたい方向に向くようにアドバイスをしました。敵などのスプライトを登場させました。手裏剣が回るようにプログラムしたかったようですが、角度にあまり気が付けなかったので残念でした。', null, '盛り上がり: 空中にとどまらないように色を使ったプログラムを共有しました。ジャンプしたときに茶色にめり込んでしまうことが今後の課題です。'),
  ('a627721f-497f-54ab-b93f-687b9f4efa98', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-05-26', '18:40:00', null, '通常 / プログラミング大会中学生の部の方に提出することに一旦し、時間があるためすこし考えるペースを多めにしながら作っていきたい。', '最初は何を作ろうか？と中学生部門の最終選考のyoutubeを見たせいか悩んでいましたが、ブレインストーミングカードで考えて箱を選んで、ゲームと学びの感じのオリジナル作品にすることに。箱の設定など最初のコマを今日は作成した感じなので次回からは、層を深くするのをどこまで書くか？をどんどん決めていければいいかなと思います。', '作品作成', 'タイピング: なし
盛り上がり: 自分でどういう作品を作ろう！と決めた時間からはサクサクと指が動いていたので目標を一つ決めると早いなぁと思いました！'),
  ('899ba47e-09b1-5c27-840d-64707eab8762', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-26', '17:30:00', null, '通常 / オリジナルに挑戦', '懐中電灯の小技やきれいな残像の小技をやってみるように促しましたが、「いやだ」の一点張りであまりやってくれませんでした。大好きなホラーアニメがあるそうで、それに関連した作品をやってみたいようでしたが、「難しいしできない」としょっちゅう言っていました。最後は、描画機能で遊んでいました。', '来週以降は、アルスパークのレッスンのアドバンスかエキスパートに挑戦し、30分でもいいので取り組み、基礎を確認していく予定です。', null),
  ('97f6dc68-e6b1-56e4-8bfb-72d933d62ee7', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-26', '17:30:00', null, '通常 / オリジナル作品(前回楽器演奏)', '前回作った楽器を参考にして作品を作るようです。音が鳴ったのと同じようにしてキーをたたいて、音楽でバトルゲームを作りたいそうです。今日はゲームが始まる前の説明のプログラムを作成していました。説明の言葉がかなり長かったのですが、辛抱強くタイピングできていて良かったです。 たたいたキーの順番を判定するプログラムが必要になってきそうです', null, '盛り上がり: 集中して取り組めていました。'),
  ('cec3b066-bdf6-571f-beaf-8a9500e2785e', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-05-26', '18:40:00', null, '通常 / プログラミング大会 ビギナーズ部門のアレンジから作成してみて、オリジナル作品に移行してもOK', '最初はオリジナル作品を作ると話していましたが、やはり行き詰まり、ちょっと遊んでいる感じになってしまったので、一旦ビギナーズの方でピンポンを作って、そこからアレンジになりました。アレンジをどうするか？の部分ではボールを2個増やすまでやってみると話していました。', '一回アレンジまでやってみて、そこからオリジナルでできそうだったらやってみるという、ピンポンを一旦安牌の部分においてみました。', 'タイピング: なし
盛り上がり: 虹色までできた時にとても嬉しそうでした！'),
  ('d25b3ff8-01db-5258-afb5-c44247cce8ed', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-05-26', '16:30:00', null, '通常 / プログラミング大会のオリジナル作品を作成', 'コインが自動的に落ちてくる作品（以前なんでもつくっていいよーと話していた時の作品の続きからみたいな感じ） コインが落ちてくる＞爆発＞クローンが止まる＞泥棒が出てきたら対戦をする という内容で、クローンが止まるという部分までが完成しました。 途中変数とメッセージが干渉し合うようなプログラミングを作ろうとしていたので色々とアドバイスをし、バグを潰しながらクローンが止まるまで作成しました。', '次回は対戦の部分を作成', 'タイピング: なし
盛り上がり: 自分の作品がちゃんと作動すること、コードが長くなったらどんな弊害が出てくるのか？を今日はちゃんとつぶせてできたので、満足した感じでした'),
  ('a5d1f4cd-ecbc-5fb9-a68d-47c3bec678af', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-05-26', '17:30:00', null, '通常 / アレンジ大会 ビギナーズ部門（https://www.802p-oyakotaikai.com/%E9%83%A8%E9%96%80%E7%B4%B9%E4%BB%8B/%E3%83%93%E3%82%AE%E3%83%8A%E3%83%BC%E3%82%BA%E9%83%A8%E9%96%80/） の作成から', 'お手本Youtube動画を見ながら一緒に作成、10:38秒目まで一緒に行いました（ボールがボタンに触れたら跳ね返るまで） 結構な集中力で45分間一生懸命やっていました。 動画を見ながら作成することで集中したのでしょうか、解説を見ながらやることでちゃんとそういう動きになるのか！と感動していたようでした。', '10:38秒目から完成、アレンジまで', 'タイピング: ココアははじめのラウンド２まで、子供タイピングは4個ぐらい、少しずつだけどタイピングできる数が増えてきました
盛り上がり: 説明を聞き、動きが実際になることでとても満足していた様子でした。'),
  ('a25d4df0-eca6-5aad-aa90-7d704439d99e', '13bd73d0-f535-5291-8362-6712e5cd7384', null, null, '2023-05-26', '16:30:00', null, '休み（未対象）', null, null, null),
  ('e6f1bbed-3d2a-59e8-9894-7bec6a7f9e0e', '7d01236e-620e-5177-a6f4-af325a582aae', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-23', '17:30:00', null, '通常 / 作品にオリジナル性、ストーリー性を付け加える →昨年度の親子プログラミング大会優秀作品の動画を見て、工夫されているところはどこかを見つけて、自分にできることを考える', 'オープニングを一生懸命作っていました。 キャラクターの動きやタイミングをよく考えて、丁寧に作成しようとしていました。 ディラックが歩いているときと立ち止まったときに使用するコスチュームの違いや、繰り返す回数なども、何通りか試してしっくりいくように調整していました。 わからないところを端的に質問できるようになってきました。', null, 'タイピング: 授業前に熱心にやっていました
盛り上がり: オープニングの動きが思い通りにできたようで、満足そうでした。'),
  ('9aa83d3c-42c0-5537-b4ec-203fe2a41191', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-23', '17:30:00', null, '通常 / コンテスト作品の構想、作成', '作りたい素材があるようで（スプラトゥーンのようなイメージ）、熱心に表現方法を考えて何度も作りなおしていました。 コンテストに対する全体像を考える前に、自分で作ってみたいパーツがあるようなので、まずは本人の希望通りに作らせてから全体像を整えていく感じになりそうです。', null, '盛り上がり: どうしたら思い通りの表現ができるか、コスチュームやコードを一生懸命考えていました。授業終了直前にそれっぽい動きができたようで、ほっとしたように見せてくれました。'),
  ('677e24d6-e0f3-51b0-8ec1-58a448c8ecae', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-25', '17:30:00', null, '通常 / ゾンビを倒せを完成させよう', '前回に続いて、ゾンビを倒せを作っていきました。前回ビームのコードをゾンビに作ってしまったから、そこをややこしいことにならないようにゆったり進めました。ビームを作った時、流れではさいしょは1回きりのビームしか打てないようになっているので、そこでなんで1回しか打てないと疑問を持ってくれたのは良かったです。その解消として「端に触れたら止まる」ようにするコードを一緒に作っていきましたが、なぜそのようにするかは質問形式で作っていきましたが、かずま君は忘れやすいので次週ビームが何度も打てるようになった理由はもう1度確認が必要です。 いつもながら、意識があちこち行ってしまってなぜかコードや音が消えていることが多かったので、そこを少なくしてスムーズに進められるようにしたいです。 飴を食べた後に口の中を指でいじる癖があったので、「パソコンはみんなが使うものだから手を拭こうね」と注意したら、本人も悪いと思う自覚はあったので、良かったのですが、無意識でやっていることだと思うので、パソコンに触る前に注意しましょう', null, 'タイピング: タイピング中はアルファベット以外のところを触らないように
盛り上がり: 音にはこだわりを持って選んでいるな感じます'),
  ('855027de-b641-5e7a-95ac-87e642c08697', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-05-25', '17:30:00', null, '通常 / できれば親子大会の作品', 'レーンに流れる寿司をできるだけたくさんつかむゲームを作りました。若者が回転寿司屋で寿司を触る迷惑行為をしたというニュースを元ネタにしたそうです。四角形を組み合わせて寿司のコスチュームを描いたり、その寿司を次々と一定方向に流していったりとクオリティが高くて面白いゲームになりました。また、特定の場所を触ると警報音が鳴ってカオスな世界に変わるというまさきくんらしい要素も追加していました。最近は色々と作りこまれた良い作品ができることが多くなっていると思います。', null, '盛り上がり: 今日は早いうちから製作を始めていて集中していました。'),
  ('af0695f3-83e1-58dc-8419-7c2a1241bf1a', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-25', '17:30:00', null, '通常 / コンテスト作品の構想、作成', '今回はゲームではなくストーリーを見せる系でいきたいとのこと、テーマは「夢・保育士」だそうです。 承太郎君と一緒に素材を張り切って集めていました。保育士になる夢に、コロナ禍の生活での経験を入れていきたいとのことで、冒頭部分を作成していました。 画面の構成などは決まったようだったので、ストーリーの先を考えてくるよう伝えました。', '文字を順に出すだけで終わらないような工夫もあわせて考える', 'タイピング: いつも通りのスピードでした
盛り上がり: ストーリーを書き込んでいくことを楽しそうにやっていました。 イメージ自体はわいてきたようで、背景と登場人物を組み合わせるのを熱心にやっていました。'),
  ('59c3e545-17d9-5a0e-b40a-6de192a29a77', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-25', '16:30:00', null, '通常 / コンテストに向けてアイデアを練ろう', '最初に、前年度のコンテストの優秀作の動画を見て、面白いアイデアを読み取ってもらいました。メダカやハチのゲームがお気に入りだった面白いと感じていました。そうちゃんは去年も釣りのゲームを作成したので、作る意欲はとても高かったです。選んだアイデアとしてバトル物が作りたいそうです。背景には見晴らしのいい芝生や山、途中で池の中で戦いたかったりしたいそうです。背景の絵として、そうちゃんの家の近くの公園の写真を撮って使いたいそうなので、写真を撮ってくるようにしました。敵の10体くらいも選んでいて、各敵ごとに相性のいい武器や鷹飼方ができたらいいねと共有しました。今回はゲームの大まかな流れを考えることができたので、次回からコードを作っていけたらいいと思います。', '各敵ごとの動き、背景の決定、コードづくり', 'タイピング: 以前やったところを復習していました
盛り上がり: みなみ野の公園生態を厚く話してくれました。'),
  ('20e0e639-4b08-54a7-9983-6d63a59cd06a', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-05-25', '17:30:00', null, '通常 / 親子大会', '主人公が弾丸をよける弾幕ゲームを作ることにしました。そこで【小技】弾幕東方シューティング風 02 基礎編 のコードを参考にすることを勧めたところ、それを見ながら自分なりにアレンジして作ることができました。回転させながらクローンを作り続けるというポイントを理解したようです。また、主人公の棒人間も追加しました。 最初は「カオスなゲームが一番面白い」とのことでとにかくたくさんの弾丸を発射してみたのですが、さすがに多すぎてよけきれないことが分かり量を調整していました。', null, 'タイピング: 楽しんで取り組んでいました
盛り上がり: 作っている作品をまさきくんと見せ合うなどして仲が良いです'),
  ('de448cb8-f0e5-553e-8b50-7b2e9677e636', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-25', '17:30:00', null, '通常 / コンテスト作品の構想、作成', '文字PV以外の作成意欲が少し下がっているのと、ゲーム部分は昨年かなり頑張って作ったので、あれ以上どうしたらよいのかわからなくなっている感があり、少し心配していました。今日は文字PV作成も一段落したとかで、しばらく考え込んでいましたが、以前に書き溜めていたストーリーがあるそうで、それを活用しようという気になったようでした。 これまでScratchの作品を閲覧しながら気に入った素材のサイトを自分で集めていたようで、今日はストーリーに合った背景や音楽などを収集して基本となる画面を作成していました。', null, 'タイピング: ゆきちゃんと一緒に楽しそうにやっています
盛り上がり: 素材を集めていくうちに作成意欲がわいてきたようで、授業終了時には「こんな感じで作っていきたい」と画面を見せてくれました。ストーリーを読ませる形の作品になりそうですが、承太郎君が一生懸命考えたお話とのことで、形にできるのが嬉しそうでした。
備考: 作品を作ろうという意識は上向いてきていますが、選抜大会の方はまだちょっとしり込みしている部分もあり…作品が仕上がってくると自信も戻ってくるかもしれないので、あまり強制せず、作成を楽しんでもらいながら様子を見て勧めていきたいところです。'),
  ('40ea75d3-ce4a-5c5c-9fed-20f70445aa4d', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, null, '2023-05-25', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('65bb1827-c6e1-56ed-b0b2-3c5eee42a605', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-23', null, null, '通常 / 昨年の全国小中学生プログラミング大会の動画を視聴、構想を練る', '授業開始時は、コンテストに参加することを了承して動画視聴に入りましたが、見終わった後は、この大会はちょっと…という感じでした。他の大会もあるので、とりあえずオリジナル作品を作ってみないかと促してみましたが、昨年でやり切った感があったのか、今年は特にやりたいテーマが思いつかないとのこと、コンテストと資格試験のようなものだったらどちらに興味があるかと聞いたところ、資格試験と即答したので、ゆき先生に試験や教材の紹介をお願いしました。 最終的に、チエテラスの教材を熱心にやっていました。', null, '時間帯: その他
タイピング: よくできていました
盛り上がり: 資格試験という言葉にとても食いついてきて、チエテラスの教材も楽しそうに取り組んでいました。'),
  ('1c2db8bd-c2ca-5d3b-b915-1126a34a340a', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-23', '17:30:00', null, '通常 / コンテストに向けてアイデアを練ろう', '最初に前年度の親子大会の優秀作の動画を見てもらい、面白うなアイデアを見て感じ取ってもらいました。テーマを決める際に、最初は作りたいものはないといっていたが、なかなか一人では外表れにくかったが、そこから先生に引き出してもらい考えていることがわかっていました。棒人間同士の戦いを作りたいそうです。今回は、まずは導入である棒人間のコスチュームパターンを作っていきました。数あるコスチュームを見てそれだけでストーリーが伝わってくる出来具合で、特に顔の表情が描くのが上手かったです。 背景の地球の溶け込み具合が気づきにくいくって、絵と得の組み合わせるのがとてもたけている思います。', null, null),
  ('1fb4cf42-2cb8-5d31-b47b-d6bde52a7e4d', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-23', '16:30:00', null, '通常 / 教室の使い方を理解する、基本的なゲームを作ってみる', '前半の動画視聴は、興味を持って楽しそうに見ていました。 全体への説明が終わった後、ビギナーズ部門の説明をしたら「そっちをやりたい」とのこと、にじいろピンポンのPDF資料を見せながら作成しました。 作成しているところをそばで見ていてもらいたがる傾向が大きいながらも、説明書のどこを見てどこまでやればいいのか細かく指定すると、自分で文章を読んで真似して作成することはできました。 ボールがボタンスプライトの上をはずんで跳ね返った時は、とても興奮して喜んでいました。', null, 'タイピング: ココアタイピングに興味を示していました
盛り上がり: 作成自体にはとても興味を持って楽しそうに取り組んでいました。 自分で動かしたスプライトがボールを跳ね返すところでゲームを作成した実感が持てたのか、何度も試しては興奮して喜んでいました。'),
  ('151c061b-6185-50d4-976e-351147da84da', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-23', '17:30:00', null, '通常 / コンテストに向けてアイデアを練ろう', '最初に前年の親子大会の優秀作の動画を見てもらいました。面白いと感じるアイデアをみとってもらいました。テーマ基目に考えてもらうと、普段から遊んでいる功績を集めるクリックゲーをゴミ集めにアレンジしたいとすぐに思い浮かびました。実際に作り始めると、ごみ厚めに関する色合いや変数や使い道はそのゲームの幹のなるぶぶんは作りが速かったです。次回は、まずは簡素的にゲームを完成させ、それ以降の細部づくりに活かせていけたらいいと思います。', null, 'タイピング: 高速に終わらせていました。
盛り上がり: 背景選びや必要ヨウ素の考えの候補が速い'),
  ('5705f036-817a-5a18-a18c-326d999fd5e5', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-23', '16:30:00', null, '通常 / 全員コンテストに向けて準備開始 ◎作品にオリジナル性、ストーリー性を付け加える →昨年度の親子プログラミング大会優秀作品の動画を見て、工夫されているところはどこかを見つけて、自分にできることを考える', '動画は楽しんで見ていました。 昨年の自分の作品もよく覚えていて、それなりの自負もありそうでした。 オリジナル作品のテーマ一覧を見て、少し難しめのものに挑戦したいと「SDGs」の中から選んでいました。当初はさらちゃん自身がよく意味のわからないテーマを選んで、何から手をつけていいか混乱していたので、自分でイメージがわくテーマにするように勧め、「飢餓」を選んでいました。 オープニングで飢餓について説明をし、飢餓をなくすためのゲームを挟んでエンディングにするという構成と、オープニングの説明用キャラクターを決め、説明文の作成に入ったところで終了しました。', null, '盛り上がり: さらちゃんなりに、昨年よりも上を目指したいという意欲はあるようで、面白いだけではなくまじめなテーマを選んで、説明文のために熱心に飢餓について調べていました。 見る人が少しでもわかりやすいように、説明をセリフではなく背景に直接書くようにするなど、工夫しようする姿勢も見られました。'),
  ('4a58ae56-6931-5df7-98d5-7198a7647c5f', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-23', '16:30:00', null, '通常 / コンテストに向けてアイデアを練ろう', '最初に親子大会の前回の動画を見てもらい、どのようなアイデアが自分の活かせるか考えてもらいました。ショウタ君的にはメダカのゲームが面白かったそうです。 なかなか、テーマ関連のものに興味を抱かなくて悩んでいたが、対戦系のものにテーマを決めて、ヒーローと魔王が闘う形に決めました。魔王の形が円形を組み合わせて、様々な形態を作っていたので、作り始めると構想は一気に広がっているように見えます。コスチュームごとの動きを次回考えていけたらいいと思います。', null, null),
  ('cd2fd1df-491f-59fd-869b-fc3679a1cf18', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-23', '16:30:00', null, '通常 / コンテストに向けてアイデアづくりをしよう', '最初に八王子の親子大会の前回の作品アーカイブを見て、使えそうなアイデアを考えました。まだ、経験が浅いので、ビギナー部門かオリジナル部門が作る方を選択するようにしましたが、動画を見て自由に作ってみたいことだったので、オリジナル部門の方で作り始めました。テーマに絞られずに作り始めたところ、ボールの上を飛び回るアスレチック系を作っていました。ボールから飛び移る際にジャンプの作り方がわからなくて詰まっていました。このゲームには自然落下のジャンプが必要と考えられるので、まずはジャンプの基礎をジャンプを見せて、原理を考えてもらいました。手早にやったので、あまり理解をできているかあやふやになったと思います。自然落下のジャンプを作るのはレベルが足らないので軌道修正をさせた方がいい。', null, '盛り上がり: コンテストの意欲は感じました。'),
  ('00370ba2-0a89-53d0-840b-788f6e497a7c', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-20', null, null, '通常 / 追跡ゲームに使用するスキルの習得', 'こうしろうくんの誘いもあり、追跡ゲームに興味を示したので、席を横並びにして「一緒のゲームを作ってみよう」と声掛けをしたところ、大変乗り気になって、時間ギリギリまで「次のところもやる」と前向きに取り組んでいました。 座標についてはきちんと理解するところまでは至ったいませんが、アルファベットは良く読めていて本人もそれを自負しているようだったので、スプライトを手動で動かして、どの向きの動きのときに、どのアルファベットの数値が変わっているかを何度も見せたところ、xとyの使い分けの部分の作成はできました。 マイナスについては「知らない」とのことだったので、正解を作成してから動きの違いを確認させました。 スコアの変数の方が、イメージがわきやすいのか、理解が早かったです。', '追跡ゲームのレベルアップから', '時間帯: その他
タイピング: アルファベットはきちんと読めているので、キーの位置にさえ慣れればすぐに上達しそうです。
盛り上がり: こうしろうくんが一歩先のところを学習していたせいか、そちらを何度も見せてもらったり、こうしろうくんの説明を素直に聴いたりして、疲れたら二人分の飴を持ってきたりしながら楽しそうにやっていました。'),
  ('f8cb7bc1-f998-52e9-b2f5-e68d29692722', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-20', null, null, '通常 / 作品にオリジナル性、ストーリー性を付け加える →昨年度の親子プログラミング大会優秀作品の動画を見て、工夫されているところはどこかを見つけて、自分にできることを考える', '動画の視聴中、普段よりも感想を口にするなど積極的な反応が見られたので、作品の構想に入るところでゆうかちゃんと向い合わせ、講師を含めた3人でのおしゃべり形式にしてみました。普段のレッスンの細分化などでは、ゆうかちゃんが積極的に応答することもあり、黙りがちになってしまうのですが、今回は楽しそうにやりたいことをどんどん口にしてくれました。 マインクラフトのように、素材を集めて何かを作る形式にしたいとのことで、スプライトのドット絵にとても興味を示していました。iPadで描くことにもチャレンジしてみましたが、用意したいスプライトの数に到底追いつかなそうだったため、フリーのドット絵のサイトを教え、画像のダウンロードとアルスパークへのアップロードを習得させました。', '素材の準備をしつつ、全体的なイメージを少しずつ明確にしていきたいところです。', '時間帯: その他
タイピング: 少しずつ安定してきています
盛り上がり: まだイメージが曖昧な部分もありますが、自分で素材を用意してアイテム作成をする作品ができるかもしれない、ということがとても嬉しそうで、終始キラキラした感じでした。'),
  ('ad0cb3bd-04bf-5a51-a072-c549488e37fb', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-20', null, null, '通常 / 作品にオリジナル性、ストーリー性を付け加える →昨年度の親子プログラミング大会優秀作品の動画を見て、工夫されているところはどこかを見つけて、自分にできることを考える', '動画は楽しそうに見ていましたが、作品についての構想では珍しく悩みまくっていました。普段のレッスンでは、オリジナルにしてもアレンジにしても、どんどんやりたいことを口に出して手も動かすタイプなので、もしかしたら「コンテスト」ということで気負ってしまっているかもしれません。 なんとなく作成を始めてみたらイメージがわいてくるかも、ということで、プレイするのが好きというプラットフォーマー系のゲームを作成しようというところで時間切れでした。', '自分のゲームイメージを形にするスキルが足りていないとしょんぼりしていたので、次回はプラットフォーマーの教材を用意して軌道に乗せてから、ゆうかちゃんの得意なアレンジを加えてストーリーを考える余裕をもたせてやりたいです。', '時間帯: その他
タイピング: 問題なくできています
盛り上がり: ゆうかちゃんには珍しく、考え込む時間が多かった回となりましたが、背景やスプライトのイメージを考え始めると少しずつ乗り気になってきたようでした。'),
  ('103dad47-701a-5364-8bd6-1ae29bd6ec89', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-19', '17:30:00', null, '通常 / 作品にオリジナル性、ストーリー性を付け加える →昨年度の親子プログラミング大会優秀作品の動画を見て、工夫されているところはどこかを見つけて、自分にできることを考える', '動画は楽しそうに見ていて、ところどころツッコミや意見を入れては場をもりあげてくれました。 前回から作成している楽器演奏の作品を作成してみてから、コンテストに使うかどうか決めたかったようで、熱心に楽器演奏に使うキーを決めたりしながら、見た目も音も楽しい作品に仕上げていました。 コスチュームの細かい編集や使用するキーの位置などもよく検討して、触って楽しい作品にできていたと思います。', 'コンテスト参加作品の見通しをたてる', '盛り上がり: 設定に妥協しないけいとくんの辛抱強さがよく発揮されていて、作品を触る人がいろいろ工夫して演奏できるようにがんばっていました。けいとくんの作品を使って、けいとくんが弾いていなかった「かえるの歌」の輪唱バージョンを弾くと、とても喜んで、一人合奏ができるようにキーの位置を改善したりしてくれました。'),
  ('95aa82bc-7797-550e-9cb8-6e8c80b004e9', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-19', '16:30:00', null, '通常 / 作品にオリジナル性、ストーリー性を付け加える →昨年度の親子プログラミング大会優秀作品の動画を見て、工夫されているところはどこかを見つけて、自分にできることを考える', '動画は面白がって見ていましたが、前回作成中だった騎士vsドラゴンが気になっていたようで、動画視聴後しばらくそちらをいじっていました。 途中から、キャラクターを変えて対戦ゲームにする！と言い出し、自力で作成を始めていました。アレンジ大賞の中級対戦ゲームが面白かったようで、自分で作ってみたいようでした。ゲーム作成のモチベーションは上がっているので、とりあえず作成を進めてからストーリーを考えてもよいかもしれません。', null, '盛り上がり: 対戦ゲームへのこだわりがあるらしく、一生懸命考えたり質問をしたりしながら、自分の知識を総動員して頑張っていました。 今は盛り上がって作成している段階なので、水を差さずに作成させていきたいところです。'),
  ('c799c822-3c0e-588c-94e6-4c123470873d', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-19', '16:30:00', null, '通常 / 作品にオリジナル性、ストーリー性を付け加える →昨年度の親子プログラミング大会優秀作品の動画を見て、工夫されているところはどこかを見つけて、自分にできることを考える', '動画はツッコミを入れたりしながらも熱心に見ていました。 何が大事かはわかったようで、「はいはい」と返事をしつつもそれなりに考えている様子が見られました。 作りたいものはすぐに思いついたようで、スプライトを自作したりしながら、かなりのスピードで作成を進めていました。', null, '盛り上がり: 自分の言葉とコードで作成することの重要性がわかったのか、アレンジ大賞で自信がついたのか、他のゲームで遊んではコードを拝借していた昨年とは違い、それなりに楽しそうに自分で作成できていました。'),
  ('a707524a-91a4-58ae-b7ad-f0ed6d50562a', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-22', '16:30:00', null, '振替 / 作品にオリジナル性、ストーリー性を付け加える →昨年度の親子プログラミング大会優秀作品の動画を見て、工夫されているところはどこかを見つけて、自分にできることを考える', '動画をとても熱心に見ていて、かなり感銘も受けたように見えました。 ひろとくんと同じ学校の同学年なことがわかって一気に仲良くなっていました。ゲーム作成への熱意の面でも気が合ったのか、お互いに作りたい仕様などを話しては意見を出し合ったりと、口も手もとても熱心に動かしていました。 やりたいことがありすぎて暴走して全体像が見えなくなることがあるため、最初に計画を立てることを勧めたところ、高尾山で冒険をするたぬきのストーリーを作りたいと言って、高尾山の名物や生き物などをWebで調べながら、ストーリーの流れ、アイテム、登場キャラクターなどの計画を丁寧に紙に書きだしていました。', null, '盛り上がり: コンテストを楽しみにしていただけあって、動画を見ながらもアイディアがわくのを抑えきれないようにコメントを入れていました。 ひろとくんと最後まで盛り上がりながら、しっかりと設定を書き出して満足そうにしていました。
備考: 新しい自分のPCを持ってきていて、嬉しそうでした。'),
  ('1d5d54ec-74b0-52f1-b5dd-67d7531883bc', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-22', '16:30:00', null, '通常 / 作品にオリジナル性、ストーリー性を付け加える →昨年度の親子プログラミング大会優秀作品の動画を見て、工夫されているところはどこかを見つけて、自分にできることを考える', '動画をとても面白そうに見ていました。かんたくんと積極的に意見を出し合ったりしていました。 作品の全体像を考えるということもよく理解していて、どんなゲームにしたいのか、設定やキャラクターの仕様などを紙に熱心に書き込んでいました。頭の中で、かなりのイメージがわいているようでした。', null, '盛り上がり: かんたくんと同じ学校の同学年だったことがわかって、とても楽しそうに話しながら計画をたてていました。'),
  ('88cf28b8-3b51-5a68-af1e-56505336a514', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-22', '17:30:00', null, '通常 / 作品にオリジナル性、ストーリー性を付け加える →昨年度の親子プログラミング大会優秀作品の動画を見て、工夫されているところはどこかを見つけて、自分にできることを考える', 'コンテストの動画は興味深そうに見てコメントもしていましたが、参加を勧めてみると即座に「却下！」と言っていました。ゲームはやりたいけど作りたいわけではない、おもしろいゲームがあったら、自分で時間をかけて作るのではなくて、すぐに遊びたいんだ、と力説していました。 それでも柊くんと、にゃんこ大戦争についてしゃべりだしたら少し興味が出たのか、BGMの視聴サイトで1曲ずつ丁寧に聴いて、ゲームに使えそうな曲タイトルをきれいに書きだしていました。 選んだ曲を使って、狸大戦争にしたら面白そう、と言っていましたが、先生から作成のプレッシャーをかけられることは嫌そうでした。', null, 'タイピング: タイピング中に手首がトラックパッドに触れてしまうのか、何度もウィンドウが切り替わって少しイライラしていました。
盛り上がり: 曲を選んでどんな場面に使えるのかを考えているときは、とても楽しそうでした。 こちらから勧めすぎたりしなければ、自分から何かをしようとする姿勢を見せてくれました。'),
  ('e771240d-e533-5e3c-b4ed-27a77e6851b4', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, null, '2023-05-22', '18:40:00', null, '休み（未対象）', null, null, null),
  ('8f213c9b-d6ad-5a0f-8a2d-0fadc7dc2fa2', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-22', '17:30:00', null, '通常 / 大会準備', '去年のコンテストの受賞作品を見ました。作品のいろいろなところに注目ができていて素晴らしかったです。ストーリーに関してはあまりすぐに気が付けていませんでした。蚕や猫を例にとって説明すると「なるほど～」というようなリアクションでした。 アクションゲームにするそうです。何かから守るゲームを作成するそうですが、「何から」「何を」守るのかはまだ未定なようです。今日はホーム画面に使えるスクリプトを作成していました。アイデアはたくさん出てきそうなので、来週以降楽しみです！', null, 'タイピング: 準2級が出て喜んでいました！'),
  ('c085c851-82be-5083-8147-4e9f2ea788fd', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-22', '16:30:00', null, '通常 / 大会への準備！', '去年の受賞作品のムービーを見ました。 その後、自分の作っていた作品のバグを一緒に確認しました。「〇秒まつ」をいれるとうまくプログラムが動かない問題が発生して、かなり悩んでいました。同じ内容を別の文法（違うブロック）を使って試してみるようにアドバイスをしました。「背景が～になったら」の代わりに「～まで待つ」を使って解決しました。ウミガメのプログラムも同様にひとつずつ整理して考えました。完成後も、同じプログラムを書いているのにうまく動かなかったり動いたりが続き、かなり苦労しました。', null, '盛り上がり: プログラムの内容に大きな間違いはないので、「うまく動かない」ことが本人に大きなストレスになっているように思います。しっかりサポートしていきたいです。。'),
  ('8188ebcd-eea1-5271-836c-6b3afbab3dcc', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-20', null, null, '通常 / 変数を使ってスコアをつける、ゲームクリアの作成', '「今日は何をやる予定だったか」たずねたところ、きちんと覚えていて、作品を動かしながら説明してくれました。 のあくんと学校で顔見知りになったと言っていたので、先輩意識を利用させてもらいました。「今日はのあくんも追跡ゲームをやるから」と伝えたら、とても嬉しそうに自分のPCと並べて座り、上下左右に動かすスプライトの説明をして、座標を使って動かすんだよ、と丁寧に教えてくれました。 のあくんに教えたり、自分の課題を進めたりと忙しそうでしたが、最後までとても集中して、こちらの説明もよく聴き、自分でも考えながら作成できていました。 スコアの変数は意味がわかりやすかったようで、どのタイミングでスコアを増やしたいかという質問だけで、正しい位置にブロックを入れることができました。 初期値のブロックは、「最初に入れる」ことはわかったものの、最初は「ずっと」の中に入れていて、得点がおかしいと考えこんでいましたが、「どうしてスコアが毎回すぐに0にもどるのかな？」とのヒントで解決できました。 スコアが完成してからゲームをプレイして、「ゲームがいつまでも終わらないのはおかしい」と自分から「ゲームクリアを作った方がいいんじゃないか」と申し出てきました。 演算式と「まで待つ」のブロックは、「こんなのがあるのか」と面白がってくれました。', null, '時間帯: その他
タイピング: 大文字のLが表示されたときに毎回迷っていましたが、最後の方にはだいぶ慣れてきたようでした。
盛り上がり: のあくんに先輩として接することで、集中力、思考力が飛躍的に伸びていました！ こうしろうくん自身も、説明を口に出すことで頭の中が整理できたようで、納得するのも早く、何よりも最後まで楽しそうに取り組んでいました。'),
  ('2aa84cb6-48da-5bc3-81e3-6dce8d48b1c6', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-19', '16:30:00', null, '通常 / 作品にオリジナル性、ストーリー性を付け加える 作品に使えそうなスキルの確認', '前半は八王子親子プログラミング大会の昨年の決勝大会動画を視聴しました。 動画は熱心に見ていて、興味も持ったようですが、帰り際の本人の話によると、コンテストについてはイマイチ理解しきれなかった可能性もあり…そのあたりのイメージは、低学年には経験がないとつかみづらいかもしれませんが、たくやくん自身の作品を作りたいという意欲はきちんとあるので、そこを伸ばす方向でコンテスト提出にもっていきたいところです。 年齢の割にはしっかりしている子ですが、全体を意識することは難しい面もあり、作成をしていても、コスチュームの一部分や一つの動きにこだわりすぎて、何を作っていたのかわからなくなってしまうことがあります。文章を書くことはできる子なので、次回は設計図のようなものを書かせてみてもよいかもしれません。', '作りたいものを整理して設計図を書き、作成していく手順を先生と一緒に考える', '盛り上がり: コンテストの動画はとても面白かったようで、良い刺激にもなったようでした。'),
  ('6f1f3cac-bce6-5cd2-ad4c-0a7905ce7337', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-05-20', null, null, '通常 / 親子大会の作品作り', 'みんなと一緒に前回の受賞作を見たあと、アイデア出しから始めました。RPG系の対戦ゲームを作ることにしました。森や海などのステージごとに違うボスを用意するそうです。また、剣の種類を変えることでパワーアップをしたり、プレイヤーのレベルもつけたりする計画を立てています。', null, '時間帯: その他
盛り上がり: 積極的に取り組んでいて楽しんでいたと思います。'),
  ('470434c6-264a-5b22-a49a-03b900fb61a8', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '4fb853b8-7d59-5565-9d96-060872e780d1', '2023-05-20', null, null, '通常 / 八王子プログラミング親子大会', 'プログラミングのコンセプトを全部含んだ作品を作ると言って、気合をいれて作業に取り組んでいました。 どんな物を作るのと聞くとそれは言えないと、断固拒否されたので完成したら見せてくれるようにお願いしときました。 話を聞いている感じだと彼の中では、しっかりとした設計図が出来上がってるように思いました。なので、何もなく順調に進んでいけばクオリティーの高い作品が出来上がるように思います。 本日も作業をしっかりしていたので、特に問題ないかなと思います。', '制作の続き', '時間帯: その他
タイピング: なし
盛り上がり: 葉琉くんが分からないというコードの質問に、親身になって一緒に考える姿が見受けられました。遠くから見ていてとても仲良く一緒に作業を取り組んでいました。 今後も助け合いながら、作業に取り組んでくればどんどん成長していくことだと思います。'),
  ('51b1fd66-8232-5c3c-a93a-a2a41a03055f', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-05-20', null, null, '通常 / 親子大会の作品作り', 'みんなと一緒に前回の受賞作を見たあとアイデア出しから始めました。作るゲームは、そうたくんと同じRPG系の対戦ゲームに決めました。全体のイメージを紙に書いてみようと促すと、スラボーが主人公で、途中で仲間を集めながら魔法使いなどの敵を倒していく流れに決まりました。今日できた作業はスプライトを用意してコスチュームを自分で変えるくらいだったので、次回以降具体的な動きに入っていきたいです。', null, '時間帯: その他
盛り上がり: 最初はモチベーションがあまりなくゲームを遊んでしまったのですが、隣のそうたくんが製作を始めているのを見てあおしくんもだんだんやる気を出してきました。'),
  ('6a0715c9-8864-5608-808e-7df01163647d', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '4fb853b8-7d59-5565-9d96-060872e780d1', '2023-05-20', null, null, '通常 / 八王子プログラミン親子大会の制作', 'プログラミング大会のコンセプトを、しっかり決めて制作されていました。 制作内容は、「部屋を掃除するゲーム」を作るという事で頑張って素材集めをされていました。 そざい集めには、フォントを制作出来るサイトを使って制作されていました。 動きのプログラムで分からない事は、大貴くんに聞いて解決している姿が見受けられました。 とても、仲良く一緒に作業をされていたのでとても良い感じでした。', '制作の続き', '時間帯: その他
タイピング: なし
盛り上がり: 大貴くんと仲良く一緒に作業をされていました。 また、コードの失敗を何度も繰り返しながら間違えを見つけて、解決する姿がとてもワクワクしていました。'),
  ('c25a3593-c6b5-572c-9b91-72c645594744', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-05-15', '17:30:00', null, '振替 / 回転による反射、マウスのx座標', 'テキストに沿って進めるというよりは「次はどの部分を作ろうか？」と問いかけながら進めていきました。パドルの動きでマウスのx座標を使うのが難しかったようで、少し時間をかけて考えていました。シンプルに考えるため、x座標とy座標で別々に考えてみることを促しました。また、壁でボールを反射させるときは「端に触れたら跳ね返る」がすぐに思い浮かんでいましたが、パドルでボールを反射させるときはどうすればいいのか見当がついていない様子でした。そこで、反射する前後のボールの軌道を絵に描いて見せると、角度が変わっていることに気づけました。最後は若干時間がオーバーしてしまったのですが、続けたいと言って完成までたどり着きました。', null, 'タイピング: 真剣にやっていました
盛り上がり: 自分のペースで考えることを楽しんでいると思います。'),
  ('4ccd16b7-85a6-5ddf-a1fb-f318fd011986', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '4fb853b8-7d59-5565-9d96-060872e780d1', '2023-05-13', null, null, '通常 / 左右上下の動きをマスター', '追跡ゲームを最初にやってもらう。 鋼志郎君は、はじめはこのゲーム制作に乗り気ではなさそうで。クリオネのスプライトをずっといじっていたので。追跡ゲームのロボットをクリオネにして作ろうと提案。追っかけるものは「クリスタル」に決定。 講師は、最初にゲームの全体を子どもに考えさせるようにお願いします。 「これって、ロボットはどうやると動いた？」 「ロボットが星にあたると、どうなった？」 ↑↑要は、意図的に細分化思考で考えさせる。 最初の矢印キーで上下左右に動かす＝X座標とY座標の理解までできました。 ただ、次回は忘れてしまっている可能性も高いので。２年生だし。 帰りがけに、「今日はX座標とY座標をやったね。来週はゲームでよくでてくるスコアをつける方法をやろうね」と伝えています。なので、「先週、X座標よY座標やったの覚えてる？」「今週はスコア作ろうねって約束したよね～」と話をしてあげてください。 落ち着きがあまりない子なので、毎週一つを意識的に取り組んでもらい、翌週必ず復習して積み上がっている経験をして欲しいです。よろしくお願いします。', '今週は「スコア」というゲーム制作スキルを作れるようにしよう！とモチベアップさせてください。', '時間帯: その他
盛り上がり: ゲームのキャラクターにクリオネを使おうと提案した時は、嬉しそうでした。クリオネが追いかけるものを何にするのか、選ぶのが楽しそうでした。
備考: ★相当の負けず嫌いな子だということ。教室内で対戦ゲームして負けると、そのままふてくされがひどくなるので注意です。 ★お母様が、割と内容や進度を気にされているので、特に先に記載したように毎週一つのテーマを持って積みあがるようにしてください。'),
  ('e71685db-0686-5e07-86f5-33fde7e71a95', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-19', '18:40:00', null, '通常 / 親子プログラミング大会準備 -ストーリーなど', '去年の大会の決勝に残った作品のムービーを見ました。比較的真剣に見ていました。自分でアイデアが出てこなかったので、カードを使ってアイデア出しをしました。天秤、葉、時計などが選ばれました。対戦ゲームのようなものを作るそうです。剣の動きやアルゴンの動き、天秤などの素材の色などをこだわりました。今ままで学習したことをしっかり使えていて良かったです。来週から楽しみです！', null, 'タイピング: 腕試しのふつうに挑戦しました。とてもよく集中していました。
盛り上がり: 時間いっぱい集中できていました！'),
  ('d44257fd-659c-5dd8-a83e-04f17b4dc196', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-19', '17:30:00', null, '通常 / 親子プログラミング大会準備 --ストーリーなど', '本人はプログラミング大会に出品したくない様子でした。スプライトも自分のオリジナルではなく、既存のものを使うことになりました。 ホラーゲームを作りたいそうです。場所が変わったり、充電が必要なライトで照らしたりして点検するゲームだそうです。今日はどちらかというと、他の作品を見たり壁紙を探したりしていました。来週までにより詳しい内容を考えてくるようにお願いしました。', null, 'タイピング: 腕試しのふつうに挑戦しました。正解率も高かったです。'),
  ('4968e634-aefc-5b04-9245-c835732ca84a', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-19', '17:30:00', null, '通常 / カブトムシを動かす 条件分岐での上下左右の動き習得を目指して、キーで動かすイライラ迷路でもよいかも', '前回プログラムした「全てを止める」が、「ーキーを押したとき」のプログラムがあるためうまく動いておらずかなり不満げだったので、変更方法を伝えました。一度実演して見せると、左矢印キーを押したときのプログラムは何とか自分でできましたが、ジャンプのプログラムを変更するのは難しかったようです。自分でも「難しい」ということに気が付けていました。 一度習得した内容がなかなか覚えられていないようです。繰り返し取り組む必要があると感じました。', 'こどもタイピングをすっごくやりたいそうです！', 'タイピング: 腕だめしの簡単に挑戦してもらいました。正答率は66%ほどでした。本人は難しいに挑戦したかったみたいです。こどもタイピングにも興味があるようなので、次回から挑戦したい様子でした。
盛り上がり: 去年のプログラミング大会の決勝の作品のムービーを一緒に見ました。その後「プログラミングやる！！」とモチベーションが上がっていたのでとてもびっくりました！！！'),
  ('1ac7214e-4240-56ab-9f21-6a20fda0ea9f', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, null, '2023-05-19', '18:40:00', null, '休み（未対象）', null, null, '備考: 本人が自宅電話に出ました。夕食中とのことでお休みです。'),
  ('293288bd-981a-5ffb-bf78-2271362f8f56', '13bd73d0-f535-5291-8362-6712e5cd7384', null, null, '2023-05-19', '16:30:00', null, '休み（振替対象）', null, null, '備考: 5/22 16:30に振替'),
  ('4f96b489-22e9-5e26-85ac-c140645f112d', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, null, '2023-05-19', '16:30:00', null, '休み（未対象）', null, null, null),
  ('486ab480-7e63-52fe-8075-8b4a53419c66', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-18', '17:30:00', null, '通常 / アルスパークの使い方を復習しよう', '前回からほぼ1か月空いてしまったので、全体的なアルスパークの復習をしながら、ゾンビを倒せ１を作っていきました。基本的な向きやざほひょうの見方、スプライトの探し方はわかっていました。そして、過去何度かつくった「上下左右に動く」の作成は前回よりコードの選びが速くなっていて、xyの違いも１テンポおいて正しく選ぶことができました。成長しています。次に、ゾンビに動き方を動画を見ながら使い方の木なるポイントを聞きながらコードを学んでいきました。新たに間違えて別のスプライトに作ってしまったときに、バックパックに使って移動する来tも学びました。', 'ゾンビを倒せの続き', 'タイピング: なかなかUが見つけられていませんでした
盛り上がり: 久しぶりだったから着てすぐ自由に作り始めました。'),
  ('87575b8a-e6a7-542f-8614-dcefd389efe7', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-18', '17:30:00', null, '通常 / コンテストの計画、小技系から興味のあるものを習得', '承太郎君と一緒に、コンテストに向けての説明をしました。アレンジ大賞のコードが評価されたことで、昨年のように流用したコードで凝ったものを作成するより、自力でバグがないように、オリジナリティのある作品を作った方が良いということも、とても素直に納得していました。 昨年度の大会の動画を見ながら、色々と考えていたようでした。 後半は、自分で使えるコードを増やすという目的で、小技の中から「体力ゲージ」を選んで自主的に学習していました。', null, 'タイピング: 相変わらずのスピードで、3回ほどチャレンジしていました
盛り上がり: 昨年の動画を熱心に見たり、こちらの話をよく聞いて質問を返したりと、コンテストに向けてのやる気が見えました！'),
  ('74233f5a-f704-50a7-96bf-b740012682a3', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-18', '17:30:00', null, '通常 / ストーリー性を考える コンテストの動画を視聴して計画をたてる', '前半は、完成した自作を公開した、と言って2つの作品を見せてくれました。文字の動かし方については、クローンと座標の変化で上手にできていました。Scratchでは「秒待つ」よりも「タイマー」の方が時間が正確なので、あえてタイマーの数値を利用して動かしているところがポイントだと説明してくれました。 今後のコンテストについて、承太郎君に強化してほしいこと、留意してほしいことをゆき先生と一緒に伝えました。納得はしたようですが、まだ、作りたいものとの一致がしないようで、文字PVの修正などをしながら、作品に使えそうなコードやイメージなどを探していました。', null, 'タイピング: 久しぶりにタイピングをした、と言いながらも、それなりに良い結果が出ていました
盛り上がり: 文字PVに関してはかなり作成に慣れてきたようで、嬉しそうにいくつも解説をしながら見せてくれました。 Scratchでの共同作成を通して、クリエイターとしての意識が強くなっているように見えました。'),
  ('bc1a0f25-4fd0-50f0-be19-4933c15a7a8e', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-18', '16:30:00', null, '通常 / コードの並列作りを理解しよう', '先週は変数の計算でだいぶん頭を悩ませていたので、コードの作り方を意識させるをメインしたアルくんの冒険１を作っていきました。最初、遊んだ時に斜めジャンプを気づけていたので、それを作れるようになるよう目標立て進められました。左右の動きはなにも迷うことなく作れていました。ジャンプはy座標が増減するする動きということは理解していましたが、コードに表すと、動画で上がる動き見せて作ったが、下がる動きは少し迷うっていました。上がる下がるは逆の動きなので、上がる動きは上に向いてることからその逆と連想しやすいように誘導しました。そして、下がる動きを上がるの繰り返しの中に入れて試していたため、ジェスチャっちゃーで今の状態を示してあげたら、可笑しいことに気づき、上がりきってから下がることに作り替えることができました。 その後、ゴール演出も自分好みのものに作り替えて、完成することはできました。あと、斜めジャンプできるときとできないときのコードの違いが見せられていないので次回初めに見せられたらいいと負います。', null, 'タイピング: 皆レベルアップしてきてつよくなってきました
盛り上がり: ポケモンのはまり方がすごかった。'),
  ('4dc7bc5f-9fc6-559b-8d89-38c1f8ccaf9b', 'b2246586-4496-52f9-a825-be2488a00a31', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-18', '17:30:00', null, '通常 / 脱出系ゲームの作成、もし興味を示してくれたら、「変数で場面を変える」', '今日はスマホで北朝鮮のニュースを見ることにハマっていたようで、テポドン発射のショートアニメを作成していました。スプライトや背景の動き、コスチュームの表情の切り替え方、大きさを活かした遠近法など、内容が物騒なのはともかく、よく工夫された作品ができていたと思います。 残念ながら完成したら作品を削除してしまい、その後はひたすら「ずっと」ブロックを並べたりして遊びに入ってしまいました。 帰り際に、最初に作った作品を褒めたところ、「仕方ないからまた考えて作ってあげる」とのことでした。 ストーリーを表現するための工夫については着実に進歩しています。', null, '盛り上がり: 表現力がついてきていて、そこを褒めると謙遜しながらも嬉しそうにしてくれていました。'),
  ('0e2126e0-d032-5ed9-b4c7-ad1a8e661b77', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-18', '16:30:00', null, '通常 / 乱数の理解を深める→座標を乱数で指定する、乱数を使って虫の回転方向をランダムにする', '前回、チーズがネズミに触れたらどこかの場所へ行く、と作成していたところ、今日の初回のプレイでちょうどチーズが迷路の後ろに入り込んでしまい触れられなくなったので、「どこかの場所へいく」と座標を乱数で指定することの違いと後者のメリットを説明しました。りょうやくんもしっかり納得して、自分でスプライトを動かして座標の数値を調べながら作成できていました。 ランダムな動きをする敵については、敵の大きさにこだわりがあって迷路内を動かすことができずに「どこかの場所へいく」で動かしていましたが、スコアの変数については、スプライトに触れるときの主体のスプライトがどちらかまでしっかり意識をして作成できていました。 終盤では、敵のコスチュームの編集や、ウロウロさせる動きが面白くなってしまったようで、回転方向をランダムにするところまでは進めなかったため、お手本の虫の動きを見せて、次回はこの動きをする敵を作ろうと予告しました。', null, 'タイピング: ポケモンタイピングで良い結果が出て喜んでいました
盛り上がり: 自分がゲーム内で作りたいことと学習内容が一致すると、とても熱心に考えて説明もよく聞いてくれます。座標に乱数を使う意味も面白がってくれました。 自分が納得するゲームを作りたい、という意識が強いため、脱線することもありますが、りょうやくんなりに考えて作成を楽しんでいるようなので、一つ一つの単元を習得する意味を納得してもらいながら進めていきたいと思います。'),
  ('c40810e4-6686-5fdd-9793-72e40e869d70', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-16', '17:30:00', null, '通常 / ゲームで使えるスキルの習得', '昨年度の親子大会入賞者がお友達だとかで、どんな作品が入賞したのかとても気にして見ていました。 今日はYouTubeで見つけたジャンプを自分で作ってみたいとのことで、ジャンプの速さを変数にしたジャンプを一生懸命作成していました。 当初はジャンプしたままになってしまうバグがありましたが、自力でコードを見直して解決できていました。 複数のスプライトのコスチュームをうまく組み合わせて編集して新しいスプライトを作成したり、ジャンプの種類を増やしてみたりとみずきくんなりの工夫が見られました。', 'コンテストに向けてストーリーの大切さを説明し、モチベーションをあげていきたいところです。', 'タイピング: 軽く1度ながしていました
盛り上がり: 最終的に記憶通りのジャンプができたようで満足そうでした。 バグがなかなか直せなかった時も、途中で投げ出したりゲームに逃げたりせずに集中することができていました。'),
  ('d58358f0-5476-5d2b-b54f-a36641430621', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-16', '17:30:00', null, '通常 / ピンポンゲームから知識を得よう', '今日はピンポンゲームを通して様々な知識を学んでもらいました。このゲームは、「端に触れたら跳ね返る」や「マウスのx座標」など知らないとつかえないブロックなどが多くあるので、それをつかうために1つ前の質問を与えて挙げて、新しいブロックがどうゆうものなのかわかるように進めていきました。受けごたえもよく理解はできていると思います。随所に、音のアレンジを加えると、ボールを跳ね返す音や赤線に触れた時の音の選びがセンスが良くてやっていて気持ちいです。そして、スコアの付け方やゲームクリアの仕方などは迷わずに作れていたので、その辺の知識は蓄えられています。最後にスコア10になった時、歯車を回す演出があえて大きくすることで見ごたえのあるものなっていました。', null, 'タイピング: 頑張っています
盛り上がり: 時間が過ぎても完成までして達成感を得ていました。'),
  ('e2a52e71-eb62-5d3e-bf4f-59cc656d839f', '7d01236e-620e-5177-a6f4-af325a582aae', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-16', '17:30:00', null, '通常 / ジャンプゲームアレンジ', '前回作った作品のプログラムを一緒に確認しました。なんとなく思い出したようです。アレンジの内容があまり思いつかなかったようなので、ゲームの終わりの設定を提案しました。「スコアが10点になったら終わり」のプログラムを忘れてしまっている様子でした。条件分岐のブロックを使うこと、等号のブロックを活用することを説明しました。 またテニスボールの動かし方が気に入っていなかったようなので、乱数を使って工夫することを提案しました。 やったことをあまり覚えていないようなのでもっと復習が必要かもしれません。最後にキャッチゲームを遊び、内容を確認してもらいました。', null, 'タイピング: 集中して取り組めていました。みたことのないステージまで進んでいてびっくりしました！
盛り上がり: しっかりコミュニケーションがとれました！'),
  ('5ffa3bc9-40b3-5475-9045-fa8295c64121', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-16', '17:30:00', null, '通常 / ジャンプ-変数の使い方', '歩く速さがだんだん上がるプログラムを作ってもらいました。テキストをしっかり読み、スムーズに取り組めていました。変数の使い方もよくわかっている印象でした。 次に歩くのではなくジャンプにその変数の使い方を応用し、速度の変化するジャンプを作ってもらいました。ジャンプのおわりとして地面を把握するために色の判定をつけたり、本当のゲームっぽくカウントダウンを付け加えたりしてアレンジを加えました。うまくジャンプさせるために「地面に埋まる」という現象への対応を熟考しました。その現象を改善するために、ジャンプするタイミングのプログラムを検討しました。 自分なりに改善策を考え、対応できていたので素晴らしかったです。変数を使ったジャンプのプログラムはしっかり理解できていました。', null, 'タイピング: 正答率もとても高く、集中して取り組めていました。'),
  ('50ae7a37-882d-5494-b0f7-7674fb7cdd97', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-16', '16:30:00', null, '通常 / 初回。教室になれる', 'とても前向きに取り組めていました。動き、音、色を変えるなど、基本的な動きを確認できました。積極的にいろいろなブロックを動かして試せていました。座標の話も少しかみ砕いて説明しました。理解できているかは微妙です。自分の作品に対して世界観をとても大切にしている様子でした。次回は名前を動かすことを伝えました！', '名前を動かす', 'タイピング: うでだめしの簡単に挑戦しました。難易度はちょうどよさそうでした。
盛り上がり: とても楽しく取り組めていました！'),
  ('3bc9b382-33c5-5153-ad1c-f46089aee16b', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-16', '16:30:00', null, '振替 / 単元別演習F 条件分岐', '一番最初に敵から逃げるプログラムを自力で仕上げていました。文章をあまりきちんと読めていなかったようなので、自分で作っているうちに敵と逃げるスプライトを混同してしました。いっしょに話して整理して進めるとうまくプログラムを作ることができました。 敵と逃げるスプライトがぶつかったときに話す言葉を工夫していました！ 次に、自分で作品を作り始めました。騎士が剣を散らしてドラゴンを攻撃するようです。作りたいイメージとある程度のスキルもあるので、順序立てて考えられるようにするとスムーズに作品作成ができると感じました。', null, 'タイピング: とても集中して取り組めていました。正解率も高かったです。
盛り上がり: 積極的に取り組めていました！休憩もほぼなかったです！すごい！'),
  ('287da3f8-4341-52be-9df8-c8f1f07146a7', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-16', '16:30:00', null, '振替 / 定義の使い方を学ぼう', 'とらくんにはアルくんの冒険にて、定義を使ってみてコードの見やすさを重視して作ってもらいました。基本は見ないで作り、こだわってほしいところはこちらから指示をするような形で作っていきました。作り上げていき、1か所違うところでバグが発生したとき、どこが違うか探してほしいにもかかわらず、すぐに左に捨ててしまう癖を少し気になりました。発想はいいのに少し無駄になる可能性があるので、立ち止まることも大切にしてもらいたいです。早早と作りあがったので、ジャンプを放物ジャンプに変えてもらいました。それで、敵も動きが少ししかなかったので、アレンジをしてもらったら、大量のクローンをで雪崩のように流れ、見ごたえのあるものができました。', null, 'タイピング: 5分間集中して途切れずにできていました。
盛り上がり: 最終的にできたものは周りのみんなが楽しがってもらえていました。'),
  ('4b2ecf83-d631-5fd1-bba0-2846c1ef8168', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-16', '16:30:00', null, '通常 / 条件分岐と演算式の活用を考える', '先週に引き続き、結果発表の画面を作成しました。 太鼓の3種類の判定を得点にするイメージがわかなかったようなので、さらちゃんが盛り上がっているタイピングの得点はどう出ているのかなどもあわせて考えながら、演算式を組み立てていきました。 演算式が完成するまでは「一人だとわからない」という反応でしたが、得点が出せるようになると、その先の条件分岐による結果発表の切り替えは自力で作成でき、満足そうにしていました。', null, 'タイピング: 学校で出した最高記録を更新できたと喜んでいました
盛り上がり: イメージしていた結果発表ができたようで、達成感も味わえたようでした。'),
  ('3b2d05ce-0c80-539d-be47-7c496de1c3f7', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-05-15', '16:30:00', null, '通常 / コンテストに使える小技を身に着ける', 'コンテストの作品作りに役立つかもしれない小技に取り組みました。定義を使わない簡潔な書き方で作りました。 最初に、被弾したらHPの変数を減らすコードを書きました。その際に、変数が重複して減ってしまわないようにしてもらいました。レースゲームでも使った「～ではないまで待つ」を使えばよいので、レースゲームの内容を思い出してもらいました。 次にボールを繰り返し発射する動きを作りましたが、想定よりも詰まってしまいました。そのとき口頭で細分化をすると少しずつ流れが見えてきました。 最後に、本題であるHPゲージを作成しました。まずは、透明なスプライトを動かすことでペンで線を書き、それがゲージになるという原理を説明しました。そして、ゲージの右端と左端の場所はどこかなと問いかけると、座標を動かしてゲージを完成させることができました。', null, 'タイピング: タイピング練習は久々でしたがうまくできていました。'),
  ('97479275-e384-5eb8-b6d3-1975a04ec551', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2023-05-15', '17:30:00', null, '通常 / 小技、体力ゲージ wkhttps://app.arspark.jp/projects/32936/editor この体力ゲージの部分をペンツールを使ってどう表現するのか？を最初にやってみる 座標で動くのと同じなんだというのが分かれば、この部分はえにしくんのとっては楽しいものになるかな？と その後に自由に作成していけば', '最初は色々と右往左往して違うゲームをやったりしていましたが、最終的にはゲージのプログラミングをしてくれました。 ただしゲージを書くというよりかは、ボールがあったっている時間が長いためにバグになってしまっている部分があるよ〜と話をふり、昔やっていたことを思い出してもらいました。 1秒待つ〜というコードを増やせばできることや、〜ではないまで待つというコードが増えることでバグ解消に繋がること、誘導しながらでもきちんと思い出しならがらやってくれました。 最後はあるくんと猫のHPのゲージを作ってみました。', null, 'タイピング: 以前と比べてはるかに長文が打てるようになり、キーボードの使い方も様になってきたと思います。
盛り上がり: 今日はアレンジ大賞のコメントを伝えたら、すこしご満悦になっていました。お母さんが伝え忘れていたこともあり、余計嬉しかったみたいです。'),
  ('014b6baf-9dc4-5d49-ad34-100fc18736b0', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2023-05-15', '16:30:00', null, '通常 / ジャンプゲーム基本操作09がちょうどおわっったところなので、チュートリアルあるくんの冒険https://app.arspark.jp/contents/3050 を最初から作成してみる→台にのれるようにするにはどうしたらいいか？を細かく教えていきたい', 'ジャンプの基本が終わったので、再度おさらいから。 Y座標を何回繰り返すのコードを使うのはどうしてなのか？を理解した上で、地面にめり込むバグを説明 地面からジャンプするためには、色とスプライトからのやり方二つあるとの説明とともに、地面の部分に触れていない時は下がるということを理解しました。 チュートリアル２もちゃんと自分でみないでも自分で完成するところまで（しかもクリアまで）出来上がっていました。', null, '盛り上がり: ゲームをしていくことに対しての抵抗感がなく、またいろいろな細かいコードの知識が増えることに楽しみを感じている様子です！'),
  ('f4010817-6d2c-57d2-ac0a-541a55e9368f', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2023-05-15', '17:30:00', null, '通常 / あるくんチュートリアルジャンプ②を以前やっていたので、そのジャンプで土台にめり込まないようにするために（https://app.arspark.jp/projects/22024/editor） →あるくんジャンプ③の土台がいくつかあるVerを最初から作成してみるの部分までやってみる', '土台にめり込まないようにするためにの話を最初に説明。 やり方はスプライトに触れたら〜と色に触れたら〜のどちらかで大丈夫だという話と、デメリットもあることを説明しました。 その上でチュートリアルあるくんジャンプ③を自分で最初から組み立てられるか？を行なってみました。 今日は最初の30分ほどは良かったのですが、残り30分はずっと居眠りをしていて、何回かお水を飲みに行ってもらったり、すこし体を動かしたり休憩時間を入れながら行いました。 最後は自分でジャンプのコードまではかけていたので、次回は完成まで進めていきたいと思います。', null, 'タイピング: タイピングもだいぶ慣れてきて、タイピングだけでも時間をかけて練習できるようになりました。
盛り上がり: めり込まない→触れたところからジャンプするという意味にするんだよと伝えた時に、なるほど！という理解が感じられました。'),
  ('4d0ee94e-dc36-5be8-94f0-d33d41f9291a', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, null, '2023-05-15', '18:40:00', null, '休み（未対象）', null, null, null),
  ('5852fec5-2286-50e2-9c57-ee3af23e1ef6', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '3d62819a-addc-5584-afc3-251fdb7abc04', '2023-05-13', '17:30:00', null, '通常 / 【DKゲーム】02迷路チーズをさがせ！ 素材だけ ヒント付き', '素材だけの02迷路チーズをさがせ！ の作製に取り組みました。 自己流でScratchでゲームなどを作っていた経験があるということで「自分で考えて、問題を解決する能力は高い」のですが、基礎的なところが身についていなかったり自己流だったりするところが散見されるので要注意です。 次回からは「写経中心が良い」と思います。 自分で考える地力のある子なので「写経→スクリプトを読み解く」というプロセスを繰り返して実力をつければすごく伸びると思います。 ただ、教えてもらうのはそんなに好きではなさそうなので、「スクリプトを読み解く」のほうは無理にしなくてもいいかもしれません。 ただ「写経は必須」だと思いますので次回からお願いします。', '必ず「写経」をお願いします。 なるべく難易度の低いものから始めるほうが良いと思います。 地力があるので複数の課題を用意しておいたほうが良いです。 本人が嫌がらなければ本人に「スクリプトの意味を読み解いて理解する」プロセスがあるといいと思います。イヤそうならしなくていいと思いますが「写経」は必須です。', 'タイピング: 不明
盛り上がり: 自分で考えてブロックを組むのが好きなようです。 自分で考えてトライ＆エラーができます。
備考: 次回指導のターニングポイントだと思うのでよろしくお願いします。'),
  ('0605c7a9-36f8-51e1-abe2-e05c48207cff', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-05-13', null, null, '通常 / リストを使ったゲームの細分化、リストと多要素との連携の学習', 'リストを使いこなす練習としておばけのかくれんぼに取り組みましたが、予想よりも早く終わりました。座標をリストにするというヒントを出すと、「x座標をリストの[乱数]番目にする」というブロックをすぐに作れました。その後[乱数]をもう一度使う必要があることがわかり困っていたのですが、変数に[乱数]を格納することで解決しました。本題のリストよりも他の場所のほうが大変だったと思います。', '都道府県と県庁所在地クイズ(リストの応用)', '時間帯: その他'),
  ('5906d8a6-1e4c-527a-bb9b-98c33957b1dc', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-05-13', null, null, '通常 / ビルのゲームの完成', 'ビルのゲームが途中だったので続きをやりました。最初はビルをクローンとして出すコードを書きました。クローンは一度だけやったことがあるとのことでしたが、あまり慣れてはいない様子で、クローンの動作を作っているつもりで本体の動作を作っていたりしました。そのため、クローンの動作は「クローンされたとき」のブロックにつなげて作ろうという話をしました。その後、鳥がビルを通り抜けた数を変数としてカウントするのをやりました。変数を加算する条件として「x座標=○○なら」を使っていたので、考え方は合っているけどぴったりその座標を通過するとは限らないということで「x座標<○○なら」というやり方なら確実だと伝えました。 30分くらい余ったので好きな小技を選んでやってもらいました。前半と同じくクローンを使う内容だったのでアウトプットをしてもらおうと思い、できるところまでは自力でやってもらい、クローンの生成をすることができました。最後までは難しかったようなので写経で完成させました。', null, '時間帯: その他
タイピング: まじめにやっていました。
盛り上がり: ゲームが完成したときは達成感を感じたようでした。'),
  ('1c74ee94-81b0-5a68-91d9-c700339dde16', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-13', null, null, '通常 / 教室、授業に慣れる', '30分以上前に入室していて、授業開始直前に思うようなゲームで遊べなかったせいか、少し疲れた様子を見せていたので、授業を楽しんでもらうことを最優先に進めました。 「アイスを食べに」に興味を示したのですが、チュートリアルへの反応がイマイチだったので、サムネイルを見ながら「どんなゲームにしたらおもしろいか」を考えて一緒に形にしていきました。 ゲーム仕様についてはしっかりと「こういうふうにしたい」と話してくれたので、のあくんの要望に合わせてブロックを教えていきました。 「～へ向ける」「動かす」「表示する」「隠す」「メッセージの送信と受信」「スタート時の座標」「〇秒でどこかの場所へいく」「もしスプライトに触れたなら」「終わるまで音を鳴らす」の学習ができました。 今日学んだスキルのところにスタンプを押して、次回以降、表をうめていくという説明をして納得していました。', null, '時間帯: その他
タイピング: アルファベットは余裕で読めていてキーの位置もなんとなくわかっているようでしたが、今日はまだやりたくない、とのことでした
盛り上がり: 30分ほどで、のあくん流「アイスを食べに」が完成して、満足そうでした。お母さんに見せることをとても楽しみにしていて、お迎えの際に嬉しそうに説明していました。 2つのレースゲームで遊びながら、ゲームを簡単にするという名目で乱数や変数の数値の変更をやりましたが、それをとても楽しんでくれました。
備考: スパイダーマンが大好きだそうです。'),
  ('c2cfac1b-e56b-5af8-873b-65167fcc1a5f', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-13', null, null, '通常 / スプライトの向きと条件分岐の学習', '前回疲れと飽きが見られたようなので、今日は敢えてあおしくんと同じ課題に取り組んでもらいました。条件分岐を使用した基本的なゲームの作成には慣れてきたようです。 タッチするスプライトの中にボスキャラを作ったりと、コスチュームや音を工夫して楽しそうにアレンジしていました。 複数の動作を無理に一つのスクリプトにつなげていて思う通りに動かなかったため、伊藤さんが並列処理を教えてくれました。', 'アレンジの完成', '時間帯: その他
タイピング: サクサクと済ませていました
盛り上がり: 今日のゲームのアレンジは楽しかったようで、終盤「疲れた」とは言っていましたが、最後まで飽きずに取り組んでいました。 あおしくんとは、お互いとても良い刺激になっているようで、切磋琢磨しながら盛り上がっていました。'),
  ('d96cd5ff-c05e-5c84-bfa2-4be7d711b126', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, null, '2023-05-13', null, null, '休み（振替対象）', null, null, '時間帯: その他'),
  ('4e772489-b275-5301-84b6-43aaa3d9af6c', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, null, '2023-05-13', null, null, '休み（振替対象）', null, null, '時間帯: その他'),
  ('15f87b02-da40-5510-81ac-977a111c51f7', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-13', null, null, '通常 / 条件分岐の学習とゲームアレンジの楽しさの学習', '課題の範囲の作成は、ほぼノーヒントですぐにできていました。 こちらが敢えてヒントを出さなかった、ゲーム開始時のスプライト表示や条件分岐の際のずっとブロックなども、自主的に追加することができていました。 時間オーバーするまで、一生懸命にアレンジをしていました。アレンジ大賞以来、自主的にアイディアを出してそれを自分で形にしようとする力が伸びたように思えます。', 'アレンジの完成', '時間帯: その他
タイピング: ミスが0%になるようにこだわっていました
盛り上がり: 今日からそうたくんが同じ時間になったせいか、授業開始時やタイピングからプログラミングへの切り替えもとても素早くなりました。 途中でだれることもなく、アレンジを一生懸命考えて楽しそうに作成していました。'),
  ('fa76f948-4395-57c4-b358-37757c92f79f', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-12', '18:40:00', null, '通常 / りんごキャッチゲーム1（リンゴの落ちてくる動作など）', '見本で遊んでもらったあと、チュートリアルを見ながら取り組むように進めましたが、ほぼ自力で取り組んでいました。世界観を大事にしていて、落ちてくるカプセル、キャッチする人間の他にも白熊を置いたりウサギを動かしたりして、冬のキャッチゲームを演出していました。 カプセルの落ちてくるプログラムも自分で作れていました。少しカクカク動いていたので、チュートリアルを一緒に見ながら確認しました。動画通りにプログラムするとカプセルの向きがひっくりかえってしまったのですが、「回転しない」を自分でしっかりプログラムできていました。', '仕上げです！', 'タイピング: ミス率もすくなく、集中して取り組めていました。
盛り上がり: とても集中して取り組んでいました！'),
  ('2ef8b22e-77c7-546b-acc0-8cb8511f084c', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2023-05-12', '17:30:00', null, '通常 / 日が空いているので一番最初からもう一度確認、右左上下のキーで動かすのはもちろんのこと条件分岐で矢印の方向に動く', '本当はジャンプ＋敵が出てくるの部分＞条件分岐で矢印の方向に動くまでやりたかったのですが、ジャンプと敵がでてくる部分で終了。ちょっとお疲れモードのかんじで（遠足だったため）またGW明けというのもありコード自体を結構忘れている感じでした。', null, 'タイピング: 同じを見つけるのがまだ難しいみたい、学校でもやり始めたのもあるので頑張っていました
盛り上がり: やっていること自体はとても楽しそうで、他のことも楽しくやっていました。'),
  ('6f4ebb40-0bee-50f5-8f1e-f9917d4d8731', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-12', '17:30:00', null, '通常 / 弾幕シューティング（角度、クローン）', '久しぶりにこちらからリクエストしたことをやってくれました！！！回転させたり、クローンを自分から作ったりできていました。回転させるスプライトの見た目に注目し、自分なりに工夫していました。回転速度について質問しましたが、あまりこだわりがないようです。 クローンされた後の動きの作り方を少し忘れてしまっていたようです。親分と子分の考え方を強調して説明しました。クローンされた後の削除も伝えました。 今日は特に楽しく取り組めていました！この調子でいきたいです。', null, null),
  ('a3eb72ab-1908-5a6a-9458-426a3dea1f83', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-12', '17:30:00', null, '通常 / 変数の目印としての役目 ジャンプのプログラムで「飛ぶ」= 0 なのはなぜ？？', 'マリオのジャンプのプログラムに注目してもらい、「飛ぶ」の変数の役割に注目しました。すぐには気づけなかったようなので、マリオ全体のプログラムをみるように促しました。「地面にいるとき」とそうでないときとで区別されていることを一緒に確認しました。 その後、ジャンプにフォーカスし、地面の認識の話をしました。地面に落ちるまで下がり続けるということはすぐに納得がいったようです。ジャンプの上がるときは定数で一気に上げましたが、下がるときは重力も考えて「～まで繰り返す」を使ってうまくプログラムを作ることができました。背景やスプライトに自分なりに工夫をつけられていました！すごい！！', null, 'タイピング: 集中して取り組めていました。
盛り上がり: 優勝で嬉しそうでした！！良かったです！！'),
  ('448393bd-af93-5783-a523-78cd63093078', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2023-05-12', '18:40:00', null, '通常 / 前回基本操作コース09が途中、ジャンプは問題なさそうなのであとは敵が動くのを追加してスコアの部分を作成する', 'ちゃんとジャンプを作る問題自体は覚えていた様子、GW明けでもコードの内容自体は覚えていたので、途中の部分からでもスラスラと書いていました。 敵のコード自体も問題なく右から左に動くなどもできていたので、チュートリアルのアドバンスの方でフリエを助けろをやってもらいました 応用としてだったので、すでにコードが書いてあるのを手直しという感じだったのもあるので早々に終了。 多少やっつけな感じはありましたが、久しぶりの授業だったので、最後は早めに退出となりました', '今度は今日やったチュートリアルのバグっぽい部分の修正をしていきたいと思います', 'タイピング: なし
盛り上がり: ちゃんと自分が描いていたもの自体を覚えていたのがすごい！'),
  ('dcf668cf-6b10-5ccd-988e-e3c7ba2855c3', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-12', '18:40:00', null, '通常 / （前回の続き）ジャンプの謎の部分を解決 変数と乱数を組み合わせて空飛ぶブロックを追加など', '前回作った作品のジャンプの部分を一緒に見直しました。地面のスプライトを別に作って、地面にめり込まないジャンプのプログラムを一緒に目指しました。ポイントとして、「上昇」と「下降」を別々に考え、さらに空中にいってしまったときに重力を考えることを提案しました。 うまくいっていないときも自分なりにプログラムを解釈して、うまくいかない原因を探せていたのでとても良かったです。最終的にきちんとジャンプさせることはできませんでしたが（スライムのなかにめり込んでしまう形になりました）、いろいろなジャンプのさせ方を検討したので、技が増えたのではないかと思います。', null, 'タイピング: ややミスタイプが多かったです。'),
  ('f1bd5056-8598-5f34-8d89-44cfe4decde5', '13bd73d0-f535-5291-8362-6712e5cd7384', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2023-05-12', '16:30:00', null, '通常 / スタートを受け取った時～という命令以外に旗が押されたら～という条件分岐で全ての命令が、できるようにするほうに移行する方がいいのかな？メッセージの多用自体は悪くないがどこのメッセージなのか？がわかりにくくなってしまう？ →メッセージの名前をわかりやすいものに変えることを最初に伝えてあげる', 'メッセージの送り合いすぎでわかりにくくなってしまった感じがあったので、メッセージのきちんとした名前の付け方がどうして必要なのか？の話から、条件分岐でもちゃんと変数と組んでやればメッセージを送らなくてもできることを理解しました。 また変数でも、全体のスプライトに適用なのか、個々のスプライト用なのか？の違いまで含めて案内。 その上で今回は、アレンジ大賞で作っていたもので条件分岐に再度トライ。 点数で背景が変わるというコードを変数と演算、条件分岐で組んでもらいました（もちろん背景は全体変数しか選べないことも伝えすみで）', null, 'タイピング: なし
盛り上がり: 条件分岐が重ねるという部分がまだ難しくなる話をしていたら、そのコードも書いてみたい！となっていたので、次は変数の目印もし〜でなければ〜の重ねるをしていこうと思います。'),
  ('fc1a2eb0-c4ae-5c25-8de3-d7d5fef3524c', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2023-05-12', '16:30:00', null, '通常 / 前回正方形を書くという部分で止まっているので、再度復習し、繰り返すというコードを使って同じように描けないか？を話す（アレンジ大賞の件もあるので） 終わったら三角形→五角形にチャレンジ！', 'アレンジ大賞の件で最初にどの部分がバグになってしまっていたのか？を確認。繰り返しという部分がなんとなく〜の理解だったため、図形の問題で何回繰り返すのか？の何回の部分を自分で確認してもらいました（画数が増えるとその分何回繰り返すというのも理解してもらいました） 360度の問題で円を描き、ジャンプの問題も再度確認してもらいました→どうして何回繰り返すを使うのかまでを理解したように思います。', null, 'タイピング: なし
盛り上がり: 算数には抵抗がない様子で、円を5個書いてオリンピックふうに書いてみるというのがとても楽しそうに描いていました。')
on conflict (lesson_record_id) do update set lesson_date = excluded.lesson_date, start_time = excluded.start_time, end_time = excluded.end_time, title = excluded.title, content = excluded.content, homework = excluded.homework, memo = excluded.memo;

insert into public.lesson_records (lesson_record_id, student_id, course_id, staff_id, lesson_date, start_time, end_time, title, content, homework, memo) values
  ('19685b95-262c-5154-9082-5c6923218928', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-05-11', '17:30:00', null, '通常 / できれば聖くんと一緒に作る', '聖くんと同様にビデオモーションのゲームをやってもらいましたが、残念ながらつまらなかったとのことでいつものように自由作品で、脱出ゲーム風のものを作りました。背景やコスチュームを何度も変えたり、脱出条件を簡単にはわからないようにしたりと、いつもの作品より少し凝っていたように思います。', null, '盛り上がり: アルスパークは何か新しく面白い要素が追加されたら興味が出るのにな、ということを言っていました。'),
  ('ea0a6e46-d649-5c27-ba34-f81663181836', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-11', '17:30:00', null, '通常 / コンテストのアイデアづくり', '最初に中学生向けのコンテストがあること知らせて、ある程度期間はあるので、気持ちに余裕が持ちつつも、アイデアを考えてもらいました。そのまま、作ろうとするので、メモが肝のしながら、構成を書き起こせてもらいました。rpgにテーマに作ることをしてさっそく素材を集めました。タイルを2値化して座標を置くなど凝りを感じました。', null, 'タイピング: はじめてゴールドに行ったそうです
盛り上がり: 特別賞おめでとう'),
  ('3ae56944-48cf-5059-9079-8b178fb03181', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-05-11', '17:30:00', null, '通常 / ビデオモーションセンサーの使い方を学ぶ', 'ビデオモーションかPRGで選んでもらい、前者になりました。カードに沿って、スプライトに触ったら音を鳴らす・コスチュームを変えるのをやりました。そのあと少し応用的な内容として、触った方向によってスプライトの向きを変える方法を伝えました。それを使うと、ボールを手で触って動かすことができました。最後はボールをゴールまで動かせたらクリアというゲーム性のあるものを作りました。', null, 'タイピング: しっかりできていました。
盛り上がり: ビデオモーションが目新しくて面白く感じていたと思います。'),
  ('93f586b3-cc63-505f-95ed-80f76bc2e8a0', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-11', '17:30:00', null, '通常 / 花咲かせようとタイマー表示をしよう', '前回上に行ってしまうバグをあったで、それを引数の数字の値を調節してもらいながら、どこが上に行ってしまっている要因を探してもらいました。時間をかけて真ん中にも行くようになったので完成できました。 後半時間が余ったので、今後の作品にも役立つと思う小技のストップウォッチを作ってもらいました。時間を変数でなくスプライトで表示することはコンテストにも役立つと思います。実際のタイマーのコードは演算が複雑に作られていたので、若干のずれはあるが「何秒待つ」を利用して作りました。桁数が上がるときに挙動の考え方が、ゆきちゃんにもコードに落とし込むこと（条件分岐で使う）が少し難しかったらしく、メッセージ無しを利用して作るところまで行きました。形にもなったが、まだ不具合はあると思うので、次回も触れた方がよさそう。', null, 'タイピング: いつもながら高速でやっていました。
盛り上がり: アレンジ大賞のコード賞受賞おめでとう'),
  ('98903a9d-aad1-50cc-a0bb-36f82f42dcaf', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-05-11', '16:30:00', null, '通常 / 算数的な変数の使い方を身に着ける', '算数的に考える力を伸ばしたいということで変数の演習をやりました。本人曰く算数は大好きだそうです。今まではスプライトを一定の速さで走らせることが多かったですが、実際に走るときはだんだん速くなっていくということで、変数を使う意義を理解してもらいました。最初は「1歩進む」でコードを作り、そのあとに「[変数]歩動く」に直すという方法で完成させました。詰まりながらではありましたが、試行錯誤して理解にたどり着くことができました。最終的に1から100までの足し算に挑戦しましたが、これは特に難しかったようで一番悩んでいました。しかし「足す数」と「合計」という二種類の変数の使い分けを説明すると完成させることができました。', null, 'タイピング: 敵を倒すごとに喜んでいました。久しぶりでしたが調子は良く、ノーミスでクリアした回も何度かありました。
盛り上がり: 「変数をうまく使えばこういうことができちゃうんだよ」などと伝えたときに、「そうなの！？」と、驚きながらも楽しそうに感じていたと思います。'),
  ('b49a431b-93ff-5cd4-a303-25edc8e4d642', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-11', '16:30:00', null, '通常 / 乱数の仕組みとスプライトの動かしの応用', 'まず、乱数とは何かを実感してもらいました。さいころを例にコスチュームをランダムに変えようとしたとき、最初は1個1個別にコスチューム変化のブロックを作ってそのまま進め、これを乱数ブロックで1まとめにできること体感して乱数をの使い道を体感できました。 次に、乱数と前回の追跡ゲームを発展させたチーズを探せを作っていきました。まず、ミミの上下左右の動きを作る際に、イベントの黄色のブロックを使ってサクサク作っていたが、もし条件での動きを見せ、これをどうやったらいいか考えさせました。もし条件までは作れていたが、経験が浅いのでずっとを忘れいたのでそこは補助しました。次に、チーズのランダム性を作ろうとしたが、「どこへ行く」のブロックで作っていたので、次回は乱数を使って作り直すところからやりたいと思う。', 'チーズの乱数で座標つくり', 'タイピング: 指を1つ1つ確認しながら打っていました。
盛り上がり: 久しぶりだったから集中力は一段と高かった。'),
  ('aac41d5e-5c78-57ae-a4ac-6dfb228dcac9', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-04-26', '18:40:00', null, '通常 / 等速ジャンプ、変速ジャンプ', 'とりあえずアルくんジャンプを等速ジャンプで完成させてみようと言うと、前回の内容と同じ要素が多かったため比較的すぐにできました。そのあとジャンプのスローモーションを見せながら、実際のジャンプは一定の速さではないということを説明しました。速度がだんだん遅くなったり早くなったりしていることを理解してもらいました。そのうえで、等速ジャンプからどういう風に変えればよいか聞くと、変数で速さを変えるという発想をすることができました。変数の扱いは問題なくできました。そのあとは、現れたバグを直しながら作成を進めました。アルくんが地面にめりこんだときに地上まで上昇するなどのアイデアを思いついていてよかったです。', null, '盛り上がり: どういう風にコードを書こうとしているのかを伝えながらやってくれました。モチベーションを持って取り組めたと思います。'),
  ('d13395cb-e177-57c3-81d1-2465d8d0175a', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-25', '17:30:00', null, '通常 / 座標の変化による様々な動きの習得', 'ピンポンゲームも見せてみましたが、今日は周りがジャンプゲームだったためか、こちらをやってみたいということで順番を変更しました。 そうすけくんなりのジャンプのイメージがあるようで、テキスト通りのジャンプができたら、すぐに滞空時間を入れたりして細かいアレンジをしていました。 スプライトの既定位置の設定などは、癖になっているようで、何も指示をしなくてもしっかり座標指定をしていました。 座標による横方向の動きやスコアなどもすぐに作成できていて、独自のキャラクターを登場させるアレンジなどを熱心にしていました。', null, 'タイピング: 決まった範囲のローマ字ならよく打てています
盛り上がり: スコアによって背景や音楽を変えて、ストーリー仕立ての作品を作ろうと頑張っていました。世界観のあるものを作るのが好きそうだったので、コンテストをやってみようと声をかけると、少し嬉しそうにしていました。'),
  ('99bda300-b47f-5eea-8e8f-1ddbe3ba667d', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-25', '17:30:00', null, '通常 / メッセージではなく変数を使用した場面変更方法の習得', '課題を出した当初は「めんどくさくない？」などと言っていましたが、主旨を説明したら理解してくれて、素直に取り組んでいました。 さすがに質問と答えの使い方も良く慣れていて、あっという間に背景変更と開発者ボタンまで作成できていました。 課題終了後はしばらくprgのゲームをいくつか開いて遊んだりコードを見たりしていましたが、途中で創作意欲にかられたようで、「思いついたことがあるのでやってみたい」とオリジナル作品の作成に入っていました。', null, '盛り上がり: アレンジ大賞の結果がとても気になっているようで、「票は入ってた？」「やっぱり自信がないので聞きたくない」と繰り返し言っていました。詳しくはまだわからないけど、結果は楽しみに待っててね、と伝えました。 検定2級の合格が自信と向上心につながったようで、ゲームで遊んでいても「これをやっておくと良い」と納得すると、切り替えができていました。'),
  ('1484a551-4958-51d3-8bc0-66c4c7e870f9', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-25', '17:30:00', null, '振替 / ジャンプゲームの作成', '基本操作コース９のジャンプゲームを作りました。最初に遊んでもらい、作り始める際にどうゆうゲームだったのか言葉にして話すことができました。こちらから尋ねる質問もしたいことは伝わってきていました。したいことがコードに直すことは座標系など局所的にできるが、それ以外は補助しながら作り上げていきました。とちゅう、集中力が切れてしまうこともあったが、スコアをつけることもとうき君から発信してくれた場面もあったので、進みがよかったです。 次回にジャンプなどの効果音とかも付けられるといい', null, 'タイピング: しっかりとキーボード確認しながら打ててました。
盛り上がり: スラボーにあった背景bgmがよかったです'),
  ('bb0752ba-adf3-5a88-9c58-b37f76f9e6a0', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-25', '17:30:00', null, '通常 / アレンジ大賞の投票、メッセージではなく変数を使用した場面変更方法の習得、リストの使い方', 'アレンジ大賞の投票は、授業前にほぼ終わらせていました。 アレンジ大賞での大量のメッセージ使用は自分でも自覚があったようで、今回の授業内容の主旨を説明したらすぐに理解して、納得して取り組んでくれました。 作成自体はとてもスムーズで、完成後に少しアレンジをしてゲーム仕様にすることもできていました。 検定2級にチャレンジしたいので、新しいスキルを身に付けたいという意思が強かったので、リストの習得を目指しました。', null, 'タイピング: 淡々とクリアしていました
盛り上がり: きちんとスキルを身に付けるという目標意識が高く、今日の2つの課題にもまじめに取り組んでいました。 2級、1級の問題がとても気になるようで、「どこまで勉強したら受検できる？」と前向きになっていました。'),
  ('e2b596c6-2cd1-5d1e-a186-64626a5db572', '7d01236e-620e-5177-a6f4-af325a582aae', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-25', '17:30:00', null, '通常 / ジャンプを習おう', 'ジャンプの基礎である基本操作コースのゲームを作っていきました。ジャンプはy座標が上下に大きくなって小さくなることは理解していましたが、それをコードに「何回繰り返す」を使って落とし込むことに苦戦をしました。同じ繰り返す内にプラスとマイナスの項をいれてしまうことはジェスチャーを使って間違っていることを伝えられました。そのあとの、スコアやゲームオーバーの追加はスムーズに付け加えられており、「もし」単独だけの使用も少しずつ減っていきました。最近になって少しずつ応答もよくなってきたので、先生たちに慣れてきたと思います。', 'アレンジの付け加え', 'タイピング: トコトンは待っていました。
盛り上がり: 授業開始前30分もタイピングもやっててすごい'),
  ('23bd3c49-19cd-5227-8589-60760cd6af46', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-25', '16:30:00', null, '通常 / 演算式の使い方と条件分岐', '結果発表の画面を追加するということでアレンジを始めましたが、変数のカウントと結果発表に使用したい総スコアとの違いがなかなかイメージできなかったようで、混乱していました。実際のゲームの結果発表画面の画像を見ながら、それぞれの数値がこのゲームのどの変数に対応しているかなどを一つ一つ見ていって、ようやく納得できていました。 ゲーム全体のコードを確認して、ゲーム終了の箇所を探し、そこから結果発表画面に移動するように作成しました。 結果発表の背景やスプライトにはとてもこだわりを持って、熱心に作成していました。', '今回の続き', 'タイピング: さらちゃん自身は納得いかない結果のようでしたが、それなりのスコアは安定して出していました。
盛り上がり: やりたいことはわかっているけれど、どの数値をどのように使用するかということになかなか結び付かず、前半は苦労していました。画像があるとイメージしやすいようで、一度納得ができたらとても集中して作成できていました。'),
  ('b1e3fac9-b13f-57e7-af31-f48862f14ca7', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-25', '16:30:00', null, '通常 / アレンジ大賞の投票', '1つ1つの作品にじっくり遊んでもらって、個々に評価も付けてくれました。バトル系のものが好きだったので、どのゲームでも接戦になる勝負をして楽しんでもらいました。丸々1時間もかかったが、大変満足いくように遊べていました。', null, '盛り上がり: 極に合わせてうたっちゃうほどうきうきでした。'),
  ('77a3a5fb-21e3-5ab9-b600-24eef5b25c12', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-04-24', '17:30:00', null, '通常 / アレンジ大賞の作品評価', '1番から順に遊んでいき、気に入ったゲームは何回か遊んでそれに投票していました。途中、バグが残っている作品が気になり、中のコードを確かめました。マリオVSルイージで、必殺技が出るはずのところで出なかったとのことでした。マリオとルイージのコードを見比べ、作り忘れているであろう場所を見つけることができました。', null, '盛り上がり: えにしくんがいなかったからか少し寂しそうな気もしましたが、みんなの色々なアイデアを面白がっていました。'),
  ('82cc349d-ff59-5a93-a672-32660d4b8aa5', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-24', '16:30:00', null, '通常 / アレンジ大賞の評価とどのゲームが面白かったか？の考察まで', 'アレンジ大賞の評価を重点的に行いました。はるちゃんのおもしろいと言ったゲームの中では一番は、ダイキくんの作品だったのですが必殺の変数を組んでいる部分が面白いとのこと。 そこで一緒に必殺のコードの分解を評価し終わった後に見てみましたが、実際に見てみるとバグになっていることを発見。 変数自体がこのスプライトだけに使用するというコードにしないとダメだったねという話と、コードが被っている部分も発見。 一緒に見ることで、面白いと思ったゲームでもバグになってしまうことが理解できたようで、今後の自分の作品でも変数を使う際の注意点をおさらいできた様子でした。', null, 'タイピング: なし
盛り上がり: 自分の作品を作っている際に、どうしても動かない部分が出てきてしまいバグを最後まで潰せなかったのですが、色々と〜効果というコードを駆使して先品作りをしていました。'),
  ('65b4bfc1-9bdc-5265-be01-0a4c6ca2861e', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-04-24', '16:30:00', null, '通常 / アレンジ大賞の作品評価', 'アレンジ大賞の投票をしました。途中で「このゲーム面白い」などと言いながら遊び進めていき、投票まで終えました。 少し時間が余ったので、マリオVSルイージの写経を勧めました。とりあえずコードを見てざっと理解してみたいというのでそうしてもらいました。最後までは読み切れませんでしたが、動き系のコードは意味が分かったと言っていました。今まで作ってきたものよりも少しレベルの高いコードでも、ある程度理解できるという実感は持てたと思います。', null, '盛り上がり: ひろとくんの作品を気に入った子がいたことを伝えると喜んでいました。'),
  ('db6eb290-9f94-55c7-8af3-5430fa1a62e8', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-24', '16:30:00', null, '振替 / 基本操作コース08 さぁ踊ろう →自分のアレンジ作品をもう少し面白くしてみる', 'コスチュームを変化させる、明るさや魚眼レンズなどを使ってゲームをわかりやすくする、背景にBGMをつけてみる、スタンプの機能を使う ↓ 自分が作ったガチャガチャのゲームをもう少しわかりやすくしてみらた？と促して、カプセルを押した時に押したというのを明るさのコードを使うともっと、押した！というのがわかりやすくするコードを追加。 自分でもゲームっぽくなってきたと大満足していました！', '基本操作コース09 ピンポンゲームで今日やった色の効果、当たったら、色が変化し当たったというのを目でわかりやすくするというコードを追加しながらやってほしい。', 'タイピング: playgramの時よりも0.2秒ほどタイピングの速さが早くなっていました！
盛り上がり: 単純な色の効果でも、コードを重ね合わせる、繰り返すを使うともっと面白くなるのだ！といのが理解できたようで、楽しそうでした！'),
  ('e510412d-5848-573f-bc08-08feca51192f', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '4fb853b8-7d59-5565-9d96-060872e780d1', '2023-04-22', null, null, '通常 / アレンジ大賞の投票', '何事もなく集中して、みんなの作品を遊んでいました。 二人でやるゲームは、しっかり人を誘ってやっていたので素晴らしかったです。 今日まで比較的話さない子だと思っていたのですが、授業の回を重ねる度に声を掛けてきてくれているようにも感じました。', '未定', '時間帯: その他
タイピング: なし
盛り上がり: 一緒にバトルゲームをしていた時、凄い笑顔になり楽しんでいました。 ゲームは結構好きな感じがしました。(私の主観では)'),
  ('df78c512-d246-50ed-9844-3b6ac5411135', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '4fb853b8-7d59-5565-9d96-060872e780d1', '2023-04-22', null, null, '通常 / アレンジ大賞作品の投票', '最初は凄い楽しんで、アレンジ作品をPlayしていました。 中盤から、疲れてしまったのか教室の床で寝転んでしまっていました。 何度か声を掛けて授業をすように声を掛けましたが、集中してくれるような様子ではなかったので、最後の20分くらいは自由な時間にしました。 「気づいた事」 鋼志郎君は、左利きという事に気づきました。 右手だとマウスの操作が上手く行えていなかったです。 ゆき先生となほ先生が、親御さんに事情を説明してくださいました。 なのでGW明けに、もしかしたら左利き専用のMyマウスを購入して持ってくるかもしれません。', '未定', '時間帯: その他
タイピング: なし
盛り上がり: 最初の20分くらいは、楽しそうに遊んでいました。 中盤からは、集中力が途切れてしまいちゃんとした授業は行えませんでした。'),
  ('6e8049b2-d3f2-53a3-b101-400c33662d8f', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '4fb853b8-7d59-5565-9d96-060872e780d1', '2023-04-22', null, null, '通常 / アレンジ大賞投票提出', '楽しんでアレンジ大賞作品をplayしていました。 授業の途中から、そうた君と仲良くなり二人で大騒ぎしながら楽しんでいました。 アレンジ大賞投票後は、スーパーマリオのゲームをして二人で盛り上がっていて楽しそうでした。', '未定', '時間帯: その他
タイピング: なし
盛り上がり: 二人でゲームをして楽しんでいました。'),
  ('5f44a4cd-013b-5903-8c80-4ca595ded214', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-04-22', null, null, '通常 / アレンジ大賞投票', 'アレンジ大賞の投票をするため、みんなの作品を遊んでもらいました。最初のうちは特にマリオVSルイージ系のゲームを楽しんでいましたが、30分くらい経ったところで疲れてしまい、休憩を取りました。集中しすぎたのに加えて、左利きのためマウス操作が慣れず手が疲れたそうです。休憩したあとゲームを遊ぶのを再開できたのですが、やはり疲れてしまい、今度は横になりました。', null, '時間帯: その他
盛り上がり: シャチのぬいぐるみがお気に入りらしく、座席に持ってきました。休憩のときには先生と一緒にぬいぐるみでキャッチボールをしました。'),
  ('b9a1cecb-4b32-5b75-8e77-e370b2ccbf15', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-04-22', null, null, '通常 / アレンジ大賞の投票', 'マリオVSルイージ系のゲームにとても興味を持って、一番最初にそれらを遊びつくしました。仲の良いそうたくんが早めに来たため対戦系ゲームで一緒に遊びました。最終的にすべてのゲームを遊び、投票まで終えました。', null, '時間帯: その他
盛り上がり: やはりそうたくんと遊ぶのがとても楽しそうでした'),
  ('99c0140e-88ba-5379-8c0e-865b5930b78a', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-22', null, null, '通常 / アレンジ大賞の評価', 'アレンジ大賞の作品をみて、楽しく遊んで評価していました。採点をするとなると２Pのゲームの方が好きみたいで、一緒に私と遊ぶことが楽しかったみたいです。 最後10分ほど時間があったので、気になるゲームの中のコードを見てみよう！と話して、どんなコードを使っているのか？を一緒にみました。 自分でも今使っているコードがたくさんあるんだということを学んだようで、今日は今日で学びがあったようでした。', null, '時間帯: その他
タイピング: なし
盛り上がり: ゲーム自体はとても楽しく遊んでいました。'),
  ('2b49a8a6-260b-5199-9def-0310e7153808', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-22', null, null, '通常 / アレンジ大賞、ピンポンゲームの最後のyou win の部分を作成する', 'アレンジ大賞、ピンポンゲームの最後のyou win の部分を作成する', '次回はピンポンゲームの延長で、スコアもしくはHPの変数を使う系のゲームを応用としてやってもイイと思います。', '時間帯: その他
タイピング: なし
盛り上がり: アレンジ大賞はゲームをすること自体は楽しかった様子で、だいたい40分ほどで採点が終わっていました、残り時間があったのでピンポンゲームが最後終わっていない部分をやりました。 先週やったことのおさらい、どこまで覚えているか？を最初に確認。どこがポイントだったか？を思い出して、どのコードの部分が角度なのか？をちゃんとみながら、説明してもらいました。 You Winを出す際ですが、何回か「旗が押された時はどうなっててほしいんだっけ？」と質問したところ「隠れててほしい」と言っていたのにも関わらず、見た目のところからコードを探さず、条件分岐の方からコードを探そうとしていました。もしかすると、表示、隠すの部分ももう一度おさらいした方がいいかも？ また、変数の使い方自体にルールがあるんだよ〜と説明しましたた、今日の１回で理解しているかは不明。何回か変数を使う系で、慣れてもらった方が早いかもしれません。'),
  ('061bb59a-7584-51aa-a446-5bfae3dfe42f', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-21', '18:40:00', null, '通常 / アレンジ大賞の評価', '中学1年だから、作業の様子もとても早く開始30分で終わっておりました。その後やはり自分の作品が気になっていたようで、もう一度再度アレンジをかけていました。 ただ、人の作品を評価すると言うのも疲れたようで、途中までやってみて、コードを読み込むのが大変だったのか、最後は諦めてスクラッチの中にあるゲームを行なっていました。', null, 'タイピング: なし
盛り上がり: 自分と同じ作品を選んだひいろくんの作品が気になった様子で、最後までコードの中を観察していました'),
  ('7efce9ff-894e-5eae-ba5c-7c2a2be00fe4', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-22', '16:30:00', null, '通常 / アレンジ大賞の評価&図形のチュートリアルをみて、四角を描く', 'アレンジ大賞の評価は黙々と行なっていて、２Pが必要なゲームでも自分の手を使ってどのキーがその動きをしているのか？を検証している様子でした。 全部見て自分で好きな作品を選び、概ね今日の内容には満足している様子。 最後20分ほど時間があったので、四角を描くというのをやってみました。 ただ、ペンツールのやり方に慣れてない様子で、長方形を描くことになってしまい、次回はそこの何歩描くという部分をやり直しかなと思います。', '次回も図形から', 'タイピング: なし
盛り上がり: いろいろな人の作品を見ること自体は苦ではなく、楽しく取り組んでいました。'),
  ('f8adcb60-e771-5b34-8cb9-0b2a0cfa8f14', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-21', '16:30:00', null, '通常 / アレンジ大賞の評価', '最後まで時間をかけてやろうとしていましたが、若干プログラミング自体に何の意味があるのか？という気質があるため人のを見るのも嫌がりながら見ていました（途中で飽きたりしていたので）それよりもめんどくさい、と言う感じで、やっと1時間をかけてみ終わり、どのゲームが面白いという感想などはあまりなかった感じ。', null, 'タイピング: なし
盛り上がり: プログラミングのコードを見るというのをしている場面もありました。ただどのコードが、この動きになると言うところまでには考えるのがいやだったようでした。'),
  ('8eb4a014-ea95-5112-b6c8-b7b51d16b3bb', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-21', '16:30:00', null, '通常 / アレンジ大賞の評価', 'やはりゲームの楽しさを追求するという部分ではとても長けているので、そう言う意味では人の作品を見てみるとバグがあるなど、これってどういう意味なんだろう？という自分がいつも作っている作品ではないものへの理解をしようとしていたようでした。', null, 'タイピング: なし
盛り上がり: たっちゃんと一緒に楽しくゲームをしていました。また最後は今まで作っていた作品の続きをし、同じようにバグを潰すことに時間をかけていたようで、ある意味だれかの作品をみることで、みんなにわかってもらうためには？の視点が増えたように感じました。'),
  ('c7b2034f-c15d-503d-9ba1-5d9d40babca0', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-21', '16:30:00', null, '通常 / アレンジ大賞の評価', '２９人分の評価をするのは割と大変だった様子でしたが、自分で面白いものを見つけることやお兄ちゃんと一緒になってゲームを楽しむ様子があり、今日はいろいろな意味で勉強になったのかな？と思いました。', null, 'タイピング: なし
盛り上がり: 最後の15分ぐらいはどうしようか？と聞いたら、アレンジを再度アレンジをかけるというわけではなく、先週マリオを写経していたのでその続きをやりたい！とのこと。 割とじっくりコードを見るタイプなので嫌がらず、淡々と行なっていました。'),
  ('dedae3e8-868b-57d4-9391-7a8fa061c748', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-21', null, null, '通常 / アレンジ大賞投票', '自分でタイピング表をご所望し、作品を選ぶのも自分でしっかり選択することができました。すべての作品に目を通し、投票する作品も３つ選べていました。最後に、自分の作品をアレンジしました。リスを加えてプログラムが止まるようにして、回転させたり動したりしました。とても楽しそうな様子で良かったです！', null, '時間帯: その他'),
  ('67d10a65-aad4-5f0b-b5b9-53951597282c', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '4fb853b8-7d59-5565-9d96-060872e780d1', '2023-04-21', '18:40:00', null, '通常 / アレンジ大賞投票', 'アルスパーク', '未定', 'タイピング: なし
盛り上がり: みんなの作品を楽しんでプレイしていました。 アレンジ大賞の投票後は、ゲームをして楽しんでいました。'),
  ('c1d2f08a-3abb-5530-80d5-d938e3c3b0e8', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '4fb853b8-7d59-5565-9d96-060872e780d1', '2023-04-21', '17:30:00', null, '通常 / アレンジ大賞の投票', 'アレンジ大賞の作品を一生懸命閲覧していました。 この作品バグが有ると、間違えを凄い見つけていました。 最終的にしっかり投票してくれたので、良かったです。', '未定', 'タイピング: なし
盛り上がり: 他の人のゲームをして、凄い楽しんでいました。'),
  ('afac6c59-c10d-58f6-ab92-b71fcc0b3858', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '4fb853b8-7d59-5565-9d96-060872e780d1', '2023-04-21', '16:30:00', null, '通常 / アレンジ大賞の完成 むらっちたたき', '真面目にみんなの作品を閲覧していました。 アレンジ大賞投票後、作品作りをされていました。 帰宅時にアルスパークには、欲しい音楽が入っていないと質問されたので次回インターネットから取り込める方法を教えたいなと思います。', '作品作りの続きかな？ 他の先生と要相談で、最終判断します', 'タイピング: なし
盛り上がり: 作品作りに、凄い夢中になっていました。'),
  ('9d2c393e-4b6c-5609-8594-d5f400c36bdb', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-21', '17:30:00', null, '通常', '作品に投票してもらいたかったのですが、アレンジ大賞上級のお手本の作品に熱中してしまい、あまりやる気がない様子でした。マリオの対戦のゲームを誘って一緒に遊び、そこからいくつかの作品を楽しみました。投票はやりたくない様子だったのでやりませんでした。', null, null),
  ('ea245d6b-b914-5f04-b1c5-739c599ec926', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-21', '17:30:00', null, '通常 / アレンジ大賞投票', 'アルスパーク時間いっぱいかけて、2/3以上の作品を遊びました。2人用の作品を2人で遊んで楽しんだり、けいとくんから作品の紹介をしてもらったりして、時間いっぱい楽しんでいました。自分で3つの作品をしっかりチョイスすることができていました！', null, '盛り上がり: 椅子の座り方が少し気になりました。'),
  ('0d74e00e-5ee0-5d51-ade9-d369a4b9fc71', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-20', '17:30:00', null, '通常 / アレンジ大賞の投票、追跡ゲームの作成', '最初に、作成はしなかったがアレンジ大賞の投票をしました。目に留まった作品を遊んでもらい、マリオ系のゲームや優貴君の作品に気に入って遊んでいました。 次に、前回の続きの追跡ゲームを作成しました。前回作りかけたものを遊んでもらいロボットが星に触れると音が鳴ることをどこにどう作ったか聞いてみたところ、わからない感じがしたのでまずはそこのもし条件から復習しました。次に、新しくスコアを加えるため、どのタイミングで点が上がればいいかきいたところ、なかなか聞く耳が通らなくて聞き方を右往左往したが具田ぐ他になってしまいました。これは、雨をなめて歯に挟まったり、体がかゆくなったりして、作る集中が奪われてしまったから進まなかったと思われる。そのときに、変数の説明をしたが、もう1度繰り返した方がいい。 最後にレベルアップの条件では、一馬君には難しいコードだと思ったので、コードを見せて1ことに言い直しながら作り上げることができました。', null, 'タイピング: 来る前にお母さんのパソコンでやりこんだらしいので無し
盛り上がり: ゆうきくんの作品は良くツッコミを入れて楽しんでいました。'),
  ('a97e0dec-3731-5d67-88e0-3f48e504b5c1', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-20', '16:30:00', null, '通常 / アレンジ大賞の投票', 'アレンジ大賞の投票では中上級の武器を持って戦うものに気に入ったらしく、自分の作品と合わせて投票していました。 あとの時間は、今日で最後だったので自由に遊んでもらいました。授業前に学校の宿題をやっていましたが、それを途中でやりだしたり、また雨を食べに行ったり、ほんとあちこち集中するところが変わるなお思いました。', null, '盛り上がり: また夏休みとかに遊びに来てください'),
  ('add2922a-72c1-53b9-9528-985ebac89c07', 'b2246586-4496-52f9-a825-be2488a00a31', null, '4fb853b8-7d59-5565-9d96-060872e780d1', '2023-04-20', '17:30:00', null, '通常 / アレンジ大賞直し', '前回の様な、グロい作品じゃないものを制作されていました。 少しかまってちゃんな所があります。 私の勝手な推測ですが、かまってほしくてグロい作品を制作してるのかなと感じました。', '他の先生と要相談！', '盛り上がり: 作品への突っ込みを入れたところ、嬉しかったみたいでいつも以上にテンションが高かったです。'),
  ('ea67339a-9698-5087-acd2-858389516054', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-20', '16:30:00', null, '通常 / アレンジ大賞の審査', 'アレンジ大賞の審査を行いました。終わりが中途半端なものには難色を示していて、はっきりとしたものにはお気に召していたようでした。１つ１つ作品は評価をしていたようでした。武器を使って戦うものに投票していました。 次に、アレンジ大賞の前に使っていたキャッチゲームのアレンジをやっていました。キーパーでボールを反射させたくて悩んでいたが、自身で作ったピンポンゲームを振り返ってもらって反射の仕方を思い出すことができました。少しずつ昔やっていたことを触れていくのもいいと思います。', null, '盛り上がり: 投票は楽しく見ていました。'),
  ('e45ed857-f429-54eb-bbec-e7a0c7a17d4c', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-20', '17:30:00', null, '通常 / アレンジ大賞の投票、ブロック定義', '投票は、30分じっくり取り組んでくれていました。 レッスンの方は、最初に元のコードを確認してから、テキストを見て進めていました。 ブロック定義の作成には少し慣れたようですが、座標の指定のミスがあるようなので、次回見直していく予定です。', '【DKアート】08 画面に花を咲かせよう！の完成', '盛り上がり: アート系にもそこそこ興味は持てるようで、熱心に取り組めていました。 コードのバグの予想部分も、自分で見つけようとする姿勢が見られ、少し成長を感じました。'),
  ('b4859bc0-b144-59f8-b414-eeb77d1a0d9d', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, null, '2023-04-20', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('dfab5492-c29c-599d-85fc-d98c716525da', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-20', '16:30:00', null, '通常 / アレンジ大賞の投票、変数の活用', '投票にはまじめに取り組んでいました。「バグがないゲーム」への評価が高く、ぱっと見の面白さではなく、ゲームとして成り立っているかどうかを評価しているところが良かったです。 スプライトに触れた時に鳴らす音が20秒以上あったため、得点がなかなか上がらないと悩んでいました。「終わるまで音を鳴らす」を使った場合、その音が最後まで鳴らないと繰り返しの頭に戻れないことを説明し、短い音を入れて動きを確認して納得することができていました。 「まで待つ」や「すべてを止める」などはよく理解できていて、自分で作成できていました。 むらっちたたきで使ったせいか、最後にクローン作成のブロックを付け加えて楽しんでいました。', null, 'タイピング: スマブラタイピングを検索して取り組んでいました
盛り上がり: 一つのゲームが完成できて満足そうでした。 ゲームが終わったらきちんとすべてを止めようとするなど、ゲームとしておかしくないかをよく考えて、納得いくように作っていました。'),
  ('030ef2fa-4c5c-527f-83cb-0396071ec118', '7d01236e-620e-5177-a6f4-af325a582aae', null, null, '2023-04-18', '17:30:00', null, '休み（振替対象） / 4/17に振替済み', null, null, null),
  ('8d7697f3-554a-5e82-968b-25961cf22174', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-18', '17:30:00', null, '通常 / アレンジ大賞の投票、背景スクロール', 'アレンジ大賞のマリオバトルゲームが気に入ったようで、熱心にチャレンジしていました。 投票後、前回お母さんからLINEで伺っていた「カエルを家に帰せ」の背景スクロールをやりたがったので、完成版で遊んでから、矢印キーでのカエルの操作と背景スクロールの部分だけブロックを削除し、一緒に考えていきました。 カエルの左右の動きを変数で操作する意味、イベントの「矢印キーが押されたとき」と、条件分岐の「もし矢印キーが押されたなら」の使い分けの意味を、実際に両方のブロックを作成して納得してもらいました。 背景のスプライトの初期位置を、実際に紙を3枚ならべて考え、理解していました。 背景スクロールの理解ができたところで新しい背景を追加してスクロールさせてみました。1発でうまくいき、嬉しそうにしていました。 上記の復習として、新しく背景スクロールのゲームを作成することにし、背景が動くようになるところまで完成させることができました。', '自作の背景スクロールゲーム（ジャンプゲームの応用を兼ねて）の完成', '盛り上がり: 先週からやりたがっていた背景スクロールがうまくでき、本人なりに納得できたようで、嬉しそうにしていました。自分が知りたかったことをきちんと教えてもらえたという安心感がわいたのか、首を振る動作だけでなく、言葉で返事をしてくれるようになりました。'),
  ('c4c35b15-86b1-53cc-930c-c201acdece62', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-14', '18:40:00', null, '通常 / アレンジ大賞作品の完成、提出', '時間いっぱい集中して、ゲームを完成させていました。 「マウスをクリックしたら戦闘機が倒せるのはおかしい」とこだわり、クリックしたら雷が出るようにしたり、戦闘機からパイロットが落ちるようにしたりと、リアリティにこだわって、熱心に作り込みをしていました。 カミナリやパイロットの出現位置を戦闘機の座標にするとうまくいかないことに悩んでいて、これがクローンのせいだというところまで気づくことができたので、クローンの座標を変数に入れておく提案をしたところ、その後はほぼ理解できてうまく修正できていました。', null, '盛り上がり: ゲームのスプライトを戦闘機にしたことからどんどんアイディアを膨らませて、オリジナリティのある作品に仕上げられていました。説明を書くところまで、楽しそうに取り組めていました。'),
  ('acdf5c1f-b3df-5dfe-a823-0f522f49c0d1', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-18', '17:30:00', null, '通常 / アレンジ大賞の審査', 'ほかのみんなの作ったアレンジ大賞の作品を審査していきました。全体的に遊び流すことが多かったが、承太郎君の作品に目が留まり、凝っているopに関してはコードまで見て興味を示していました。みずき君も文字pvに関する素材を目を通してもいいかと思います。', null, '盛り上がり: 今日はずいぶん早く来てゲーム三昧できました。'),
  ('0724f8a3-4709-56b1-a414-64cf7c4a9eb8', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-14', '16:30:00', null, '通常 / アレンジ大賞作品の完成、提出', '丁寧にゲームを作っていました。直接得点には関わらない和みキャラクター？についても、画面を通り過ぎる動きを熱心に作成して、満足そうにしていました。 奇抜なアレンジ等はありませんが、学習したことをよく活かした、たくやくんらしい素直なゲームを完成させられたと思います。', null, '盛り上がり: ゲームの部分が完成して余裕があったためか、にわとりとひよこの可愛い動きを一生懸命作っていて、楽しそうにしていました。'),
  ('12e7fa5d-f890-54e0-afa1-cb8cabb0e96d', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-18', '16:30:00', null, '通常 / アレンジ大賞の審査', 'みんなが作ったアレンジ大賞の審査をしていきました。1つ1つをじっくり見ていき、終わりがないものや分かりにくいモノに難色を示していたが、選んだ候補に上級生が作ったもの中心に起承転結がしっかりしたものが集まっていました。意外と集中力が途切れずに審査を終えてよかったです。 残った時間に、太鼓の達人のゲームに興味を示していて、コードを見た時に意外と単純なことを知ると終わりのスコア表示を加えて、次回作っていけそうです。', null, '盛り上がり: 1つ1つの作品にリアクションを取っていてタイの思想でした。'),
  ('69f974b9-677f-5418-b534-b8e278e16ca0', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-14', '16:30:00', null, '通常 / アレンジ大賞作品の完成、提出', 'アレンジ大賞の提出は終わっていたので、前回に引き続き、中級作品の写しをしていました。コードもきちんと読みながら丁寧に写せていました。', null, 'タイピング: あと2点で4級という、年齢を考えると素晴らしい結果を出していました！5分間集中を切らさず打てたのもすばらしいです。
盛り上がり: 自分で少し難しい作品を作れるのが嬉しかったようで、時間いっぱい頑張っていました。 「来週も続きをやる！」と満足そうに帰っていきました。'),
  ('3b191f92-501a-582a-a1c7-9b596006c4c3', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-14', '16:30:00', null, '通常 / アレンジ大賞作品の完成、提出', '途中で、残り時間を考えずに新しいことをやろうとしたりすることもありましたが、最終的にはやりたいことの取捨選択をして、時間内に提出ができました。 バトルゲームというよりも、上から降ってくるモグラをよけるゲームになりましたが、過去の素材を活かして楽しそうに作成していました。 昨年のコンテストの時よりは、締め切りを意識して（最終的にではありましたが…）時間内に終わらせることができていました。', null, 'タイピング: 熱心に取り組んでいて、3級相当の結果を出していました。
盛り上がり: 自分の過去のアイディアと現在のアイディアを組み合わせて、終始楽しそうに取り組めていました。'),
  ('8f26e1f3-cd89-5c0f-b8bd-64b296677631', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-17', null, null, '通常 / 変数の使い方など。等速ジャンプ', '一度、変数の考え方について説明すると、①も②もスムーズに取り組むことができていました。時間に余裕があったので、「地面がある」ということをプログラムして認識させました。最初はスプライト名で区別をつけていましたが、より汎用しやすい「～色に触れたら」を使うことを説明しました。どれもとても良く理解できていました。 最後にネコを最前面に出すことで、地面に立っている感じを演出させることもできました。', null, '時間帯: その他
タイピング: 少しミス率高かったです。'),
  ('c4ac9abc-712e-5fe2-946a-eed30f912e4b', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-17', '17:30:00', null, '通常 / アレンジ大賞続き', '回復系のアイテムと敵がランダムに動くようにアレンジしました。スコア変化のプログラム、スプライトを動かすプログラムは自力で取り組むことができました。 敵の攻撃にあたってHPが0になったときにゲームが終わらないと言って苦戦していました。もう一度、スコアの考え方について説明して、最後にはうまく終わらせることができていました。', '作品名を聞きそびれてしまいました。確認します。', null),
  ('98c25275-fd9f-5510-8114-11265c946953', '7d01236e-620e-5177-a6f4-af325a582aae', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-17', '17:30:00', null, '振替 / ピンポンゲーム（座標・角度・条件分岐）', '玉の動きによく注目することができていました。座標についてはなんとなく理解できていた様子（X座標とY座標の向きはあやふやでしたが）。向きについての概念があまりないようで、玉が左右にしか動かずかなり悩んでいました。パドルで跳ね返す部分については、角度が変わっているということを気づけていたので良かったです。スコアの加算、赤いバーに触れたらプログラムを止めることはしっかりできていました。 最後の文字をメッセージを使って出すことになりました。「もし」の使い方やメッセージの扱い方はまだ慣れない部分があるようです。', null, 'タイピング: 授業前から集中して取り組めていました。
盛り上がり: コミュニケーション多めで取り組めました！！'),
  ('8e95e05a-af76-58bc-bb93-99de9c457e5e', '13bd73d0-f535-5291-8362-6712e5cd7384', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-17', '16:30:00', null, '通常 / アレンジ大賞の完成 むらっちたたき', '何個かスプライトを追加していたのですが、途中からリレーションがうまくいかなくなってしまった見たいで、結局何個かのスプライトは消去 最後にスコアがアップしていくごとに、背景が変わったり、コメントが出るようにしてうまくゲームをまとめていました！', null, 'タイピング: なし
盛り上がり: 簡単なリレーションに関しては自分が納得いくまで調整し、ゲームが面白く見えるように頑張っていました。'),
  ('4b321369-bf41-534a-81bc-48ba5324660e', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-17', '16:30:00', null, '通常 / アレンジ大賞を完成させる「むらっち叩きゲーム」', '最後に１つ難しくしようとし、金魚鉢を追加。 金魚鉢に触れてしまうと、傾くようにしゲームが止まってしまうように変更追加。 うまく難しさを増やそうとアレンジしたことはとてもすばらしい！', null, 'タイピング: なし
盛り上がり: 自分ができるところは確実に狙っていく、そういう逞しさがとてもあると思いました！'),
  ('66c4648c-0462-58f2-b840-03ca5a998f64', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-17', '16:30:00', null, '通常 / 自分の作品で、場面ごとに見れるように設定するために変数を使って、コードを組むhttps://app.arspark.jp/projects/30359/', '自分で少しアレンジを加えて、ボタンにマウスが触れたらおっきくなったり小さくなったりするコードの部分。 ちゃんとではないまで待つというコードを使って、ずっと触れていると、大小大きくなってしまうというコードのバグを潰しながら、貰った教材を作成。 今後は、自分の作品にその部分を応用できれば、いいなぁと思います。', null, 'タイピング: なし
盛り上がり: 自分で今まで使ったコードをふんだんに用い、また見本教材をキチンと確認しながら行なっていました。最初に説明した時は、初見ではコードのリレーションがどうなっているのか？と言うのがわかっていなかった様子でしたが、やりこんでいくうちに自分でどうコードを書けばイイのか？を理解していたようでした。'),
  ('9b92778b-41ee-5c3c-9a2a-be15f34db90d', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2023-04-17', '17:30:00', null, '休み（未対象）', null, null, null),
  ('98c8b76b-f594-5af0-b2cc-3a61a4bb2b3c', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '4fb853b8-7d59-5565-9d96-060872e780d1', '2023-04-15', null, null, '通常 / 教室に慣れる、基本のコードを確かめる', '分からない事はしっかり聞いてきてくれました。 また、後ろで見守っていましたが、気になる様な問題点はなかったです。 テキストを見ながら、しっかりした順序で進められていたので良かったです。 呑み込みが早いので、飽きないように対策が今後必要かもしれません。', '授業前に他の先生と生徒のレベルを確認し、どの課題をしてもらうか決める', '時間帯: その他
タイピング: playgram
盛り上がり: 追跡ゲームに、タイマーを設置したいと自ら言ってきてくれました。 なので、アレンジをしてもらいました。 設置方法の指導は、まみ先生がしてくださいました。 教わりながら、理想の形になるのが嬉しかったみたいで、帰宅時に親御さんにもうアピールをされていました。 見ていてとても、嬉しそうでした。'),
  ('2fef9f06-25de-5af8-9dad-8153141d9359', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-04-15', null, null, '通常 / 興味のある題材を使って、基本的なコードを学ぶ', '先週は何をしているのかよくわからなかったようなので、興味を持ってくれそうな水族館をやってもらいました。こうしろうくんは魚(特に深海の魚)が好きなようで、クリオネなどを楽しそうに泳がせていました。「ずっと」「～に行く」など今回扱った基本的なブロックは何回か使うことで覚えられたと思います。BGMを鳴らす際に、考えて「ずっと」ブロックを入れるなど応用も効いていました。また、クリオネの色をリアルにしたいということで、写真を検索して色を変えていました。ただ、先週よりは本題からの脱線が少なく、モチベーションを持って楽しく作品が作れたと思います。', null, '時間帯: その他
タイピング: 最初はキーの場所が分からなかったのですが、一度確認すると覚えることができました。
盛り上がり: こうしろうくんはお母さんにも「楽しかった！」と伝えたそうです。'),
  ('be191017-a96c-583d-9997-86f5a5ad7d41', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '25840600-1a86-5fb0-b223-dec47cec8c48', '2023-04-15', '17:30:00', null, '通常 / アレンジ大賞への作品提出', '課題作品が完成しているところからスタート 自分で必殺技を使えるようして完成して作品を提出した。 最初に「こうしたい」と思ったものを作ろうとしていても、 難しいと途中で妥協して、自分がスムーズにできる範囲で作品を完成させる傾向あり。 実力はあると思うので、考えてプログラミングするスキルを身に着けるのがステップアップのカギかと思います。', '目的を決めて、妥協せず、考えて完成させることのできる課題がいいと思います。', 'タイピング: なし
盛り上がり: 作品が完成して満足そうでした。 完成した作品を一緒にプレイしたときは、とても楽しそうでした。
備考: やりたいことを完成させるために、じっくり考えて取り組むことがスキルアップのカギ。 「一つのアイディアを完成させて見直してから、次のアイディアに取り組むというプロセスを身に着けることも必要だと思います。'),
  ('607ccc3a-f340-5289-b707-247cd42944f1', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-15', null, null, '通常 / 基本操作コース07_ピンポンゲーム', 'ゲームプレイ後に、すぐになんとなく作ろうとしていたので、今後複雑なゲームを作れるようにするために細分化の必要性を説明して取り組んでもらいました。こちらの提案は素直に聞いてくれて、細分化も大体はできていましたが、言語化の際の具体性にはまだ欠けている状態です。（「ゲームが終了すると出てくる」←終了する条件が書いていない、など） なぜか、すべてのスプライトをアルくんで作り始め、そこにパドルや棒のコスチュームを追加していたため、すべてのスプライトが「アルくん＋数字」の名前になっていて、本人も混乱していました。次回はスプライトを作成するときにそばにいて指摘したいところです。 画面上でスプライトが動くのを、すべて座標の指定でやろうとする傾向がありました。ピンポンゲームのボールはランダムに動いたら打てない、規則性をもって動かさないといけない、という説明はしましたが、イマイチぴんときていないようで、指摘されたから〇歩動かすブロックに変えてみた、という感じでした。 座標の話や角度の話も、説明すると「わかってます！」と嬉しそうに頷くのですが、表面上の言葉を知っているだけで、理解までしているかは怪しいです。 「繰り返し」や条件分岐のブロックの順序などもかなり曖昧で、条件分岐の中に「ずっと」を入れたりしていました。 自分がもともと知っていることについてはよくできていて、プレイヤーの名前を入れるアレンジなどもスラスラと作ることができていましたが、基本的なコード構成については見直しが必要です。', null, '時間帯: その他
タイピング: 淡々と終わらせていました
盛り上がり: ゲーム作成自体は楽しそうで、アレンジも得意そうにやってくれました。 楽しんでやろうとしているモチベーションを下げずに基本を学びなおしていくのが今後の課題と思われます。'),
  ('0dd61a4d-b192-5ed6-8a95-0675326240f4', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-04-15', null, null, '通常 / アレンジ大賞', 'ちひろくんのアレンジ大賞は今日が最初で最後ということで、すぐに終わりそうなむらっちたたきに取り組んでもらいました。穴を用意してそこにむらっちを出すという、他の子にはないアイデアが面白かったです。むらっちの座標の候補を決めて乱数で決めようとしていましたが、そこで詰まっていました。そこで、「むらっちが穴に行く」のように発想を変えることを促しました。最終的には、穴に対して「穴からむらっちが出てきている」コスチュームを追加するという方針を思いつき、それで作ることに決めました。終わりまで行かなかったため家で完成させるそうです。', null, '時間帯: その他
盛り上がり: 全体的に、できるだけ自分の力でやりたいという意志が強かったように思います。'),
  ('4657583d-e418-5abc-b8a7-61c2d10d932c', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-15', null, null, '通常 / アレンジ大賞の作成、提出', '前回の最後に紹介した、スコアの点数によって最後に登場するキャラがセリフを変える、というのを、「やりたいけど、やり方がわからない」と言ってきたので、紙に条件を書き出してから条件分岐の構造を考えていきました。 以上以下と、より大きいより小さいの違いはしっかりとわかっていて、条件の演算式も最初の一つを一緒に作った後は、自分で作成できていました。 最後に出てくるキャラを少し編集して、微妙にキモ可愛く？できたのが満足そうでした。', null, '時間帯: その他
タイピング: 安定してできています
盛り上がり: 思い通りの条件分岐とキャラのデザインができたようで、嬉しそうにしていました。 コード作成とデザインの両方を楽しめていたようでした。'),
  ('69a3331b-7634-553a-9a94-62069aa039d4', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-15', null, null, '通常 / アレンジ大賞の作成、提出', '授業開始時と、そうたくんが来室してゲームを始めた時に少しゲームに気が散っていましたが、いつもよりもすぐに「アレンジをする」と気持ちを切り替えて、楽しそうに集中できていました。 スプライトの表示非表示やイベントの使い分けもよくわかっていて、作りたい内容を話しながら危なげなくブロックを選ぶことができていました。', null, '時間帯: その他
タイピング: ひたすらマ行を繰り返していました
盛り上がり: これまで、ゲーム終了後にスコアを話すアレンジしかできていなかったのが噓のように、お邪魔キャラとボーナスキャラを一気に作成できていました。何よりも、途中で眠そうにしたり姿勢を崩したりすることもなく、一度も席を立たずに楽しそうにできていました。 そうたくんにゲームを見せたり、タイピングのやり方を教えたりと、教室の先輩らしい態度も見せてくれました。'),
  ('e0454b59-a409-5b01-8a97-d3b578a3248e', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-13', '17:30:00', null, '通常 / アレンジ大賞の作成、提出', '攻撃を受けた時のHPの減少がすぐに反映されずに、攻撃を連打を受けた時のHPがおかしくなっているのを修正しました。「攻撃を受けてもHPが減るときと減らないときがある」と困っていたため、コードの見直しを一緒にして、条件分岐の中のコードも含めてすべて、上から順に処理していくということを説明し、一連の殴る動作のためのコスチューム変更を終えてからスプライトに触れたかどうか判定をしてメッセージを送る、というのがどういうことかを考えてもらいました。その結果、触れたかどうかの判定とメッセージ送信を先にすることに気付き、自分で修正することができていました。 元のコードに頼らずに、自分がこれまで習ったコードを駆使してシンプルなプログラムに仕上げることができていました。', null, 'タイピング: 相変わらずしっかりと黒字になっています
盛り上がり: これまでは、参考にしたい作品をそのまま取り入れて、コードの修正どころがわからずに結果としてバグが直せない、という状態に陥りがちだったゆきちゃんですが、今回は自分でコードを作成しただけあって、とてもスッキリした仕上がりにできていました。自作の為、パンチのみでキックの方ができなかったという心残りはあるようですが、最低限の動きを丁寧に自作できていて、そこを褒めると嬉しそうにしてくれました。 自分でも、コードの見直しがしやすいということに気付けていたようでした。'),
  ('81b975f6-fecc-5fa1-98b8-bdf042996e67', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '25840600-1a86-5fb0-b223-dec47cec8c48', '2023-04-15', '16:30:00', null, '通常 / アレンジ大賞の応募と「02迷路 チーズをさがせ！②邪魔者ver」', '自作のアレンジ作品を見せてくれて、工夫した部分などを教えてくれた。 アレンジ大賞に応募するために文字を打ち込むのが大変おっくうな様子でした。 ０２迷路では チーズのプログラミングを写経して、その後ブロックを読んで意味を確認していきました。 乱数をサイコロに見立てて説明し、理解した様子でした。', '「02迷路 チーズをさがせ！②邪魔者ver」の乱数が入っているブロックの次のブロックからプログラミングの意味の確認をお願いします。', 'タイピング: 前回より正誤率が上がっったことを褒められて嬉しそうでした。
盛り上がり: アレンジ大賞の作品の工夫した部分を楽しそうに紹介してくれました。
備考: 声掛けして反応がない時も、しっかり考えているので、回答はゆっくり待ってあげるのが吉'),
  ('ef0f4094-0b9b-5b64-879a-065c4f6be2c2', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-13', '17:30:00', null, '通常 / アレンジ大賞作成、提出', 'ここまでで完成、という線引きが予め頭の中にあったようで、一人で黙々とバグを修正し、動きを確かめて、「これで完成！」という感じでした。 後半は、自作の文字PVの作成を進めていました。Scratchの個人アカウントで文字PV作成チームを募り、承太郎君がリーダーとなって作成を進めているそうです。手始めに承太郎君が導入部分を作成し、それを次のメンバーがリミックスして中身を足していくという方式とのことで、「今、新しいことを始めているんだ」と少し誇らしげに話してくれました。 文字のバックに黒い長方形を出して文字が反転して見えるような効果を作ってみた、と見せてくれました。ただ、四角の大きさが完全に手作業で、手間がかかるとのこと、何か計算でできる方法が見つかればよいね、という話をしました。', null, '盛り上がり: どちらの作品にも、とても熱心に取り組んでいました。時々ゆきちゃんに自分のマリオのコードを見せて、「この部分はパクってもいいよ」などアドバイスをしたりもしていました。'),
  ('60f06333-3c18-5e72-ad1a-759d82bae3ce', 'b2246586-4496-52f9-a825-be2488a00a31', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-13', '17:30:00', null, '通常 / アレンジ大賞作成、提出', '内容にはグロい見た目になってしまいましたが、それでも途中で投げ出さずに提出までやり切りました！見た目やデザイン的には本人の言う通り子供向けとは言えませんが、まさきくんなりに表情が変わるようにするなどの工夫も見られたこと、作品を最後まで完成させてきちんと提出するという経験ができたことは、彼なりの進歩と経験になったのではないかと思われます。', null, '盛り上がり: 他の皆と同じように提出まできちんとできたことが嬉しそうでした。同時間の上級生組の良い影響もあったようです。'),
  ('d33a0f08-8178-571e-b047-25adb4af6edf', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, null, '2023-04-13', '17:30:00', null, '休み（未対象）', null, null, null),
  ('d5166906-0ce1-534d-88c9-1df4278ae764', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-14', '16:30:00', null, '通常 / イライラ迷路の完成', '前回作成したイライラ迷路が気に入ったようで、珍しくかなり饒舌でした。けいとくんにツッコミを入れられて、笑って対応したりもしていました。 ゲーム自体は、新しいステージを作るのに盛り上がっていて、ステージが変わったら動かすスプライトを変えたりして楽しんでいました。', null, 'タイピング: 準2級を出して喜んでいました。さすが！
盛り上がり: 雑談の方がよくしゃべることも多い眞子ちゃんが、ゲーム内の仕様のことなどでひっきりなしにしゃべっていて、とても楽しんでいるように見えました。「来週もイライラ迷路をやりたい！」と言いながら帰っていきました。'),
  ('f4a8decd-97d0-5d07-b207-6078cccef247', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-14', '17:30:00', null, '振替 / アレンジ大賞続き', 'スマブラを少し意識していたようです。基本の動作はほぼ自分で考えてプログラムすることができていました。銃をうったときに音が出なかったので、提案して音を付け加えてもらいました。 本格的なゲームのアレンジをしていて、最初のカウントダウンが特に印象的でした。前回頑張った分、今日は少し余裕を持って取り組めていました。やりきった様子で良かったです。', null, '盛り上がり: 投票の結果が気になるようでした。'),
  ('972b061c-a6c9-5289-89bc-86fa8ec4de71', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-14', '17:30:00', null, '通常 / 楽しく取り組む', '自分の好きなホラーゲームのキャラクターの絵を描くのに夢中でした。出現させるプログラムを作ってみることを積極的に提案しましたが、乗り気ではなかったようです。 絵を描くことがつまらないわけではなかったようです。今日作ったものを、自分のアカウントで公開したいようなので、今日作ったものを自分のアカウントに共有しました。', null, null),
  ('85b4757b-54b3-5ce8-8600-a98def4b7a3c', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-14', '18:40:00', null, '通常 / アレンジ大賞上級続き', '前回取り組んだところのうまくいっていない箇所を指摘しました。条件分岐の順序だったり、数式の値だったり、送るメッセージ名、変数名などに間違いが多かったです。 うまく動いていない箇所を分析するまではしっかりできていましたが、該当箇所のプログラムを見つけるのがまだ少し慣れなそうです。考えて取り組めているので、徐々に慣れていきそうです。 最後まで作品は完成できませんでしたが、しっかりと動くプログラムになったので作品を公開しました。', null, null),
  ('368e105c-ad3f-559c-9918-dbad086039ba', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-14', null, null, '通常 / 迷路ゲーム（歩かす・基本の復習）', 'マウス操作は難しすぎるとのことだったので、矢印キーで操作することにしました。向きについて少し忘れていたので、再度説明しました。壁に触れたらゲームを終えるという動作も「すべてを止める」のブロックを使って自分で進めることができました。最後に、壁を動かしたりステージにアレンジを加えたりしました。ほぼ1時間、集中しつつも楽しく取り組むことができました。', null, '時間帯: その他
タイピング: 集中して取り組めました。自分から始められていたのでとても良かったです。
盛り上がり: 最後に自分で作品を動かしたときに満足そうでした！もうすぐ誕生日です！！'),
  ('5c871719-b46c-5271-b902-e308620c064e', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-13', '16:30:00', null, '通常 / アレンジ大賞提出、基本操作コース04_追跡ゲーム', 'アレンジ大賞は完成していたので、見直しと、説明文の入力などをしてもらいました。 残り時間で基本操作コースの内容を「物語を作ろう」と「追跡ゲーム」で選んでもらい、後者になりました。アルパーク上のゲームが未完成のものだったため、すぐに「ゲームとして物足りない」と指摘があり、そこのアレンジも含めて作成をしようとやる気になっていました。 スプライトを動かすときに向きにこだわりたいとのことで、動かす前に丁寧に設定をしていました。', null, 'タイピング: 課題の量が多いのを選んでいましたが、時間がかかりつつも最後まで辛抱強く取り組んでいました。
盛り上がり: ゲームの完成度にこだわりたいようで、丁寧に動きを考えていました。「ゲームを作りたい」という希望が通ったためか、集中して取り組んでいました。'),
  ('39b7f5fa-2a22-5b26-a012-891f1ee2b7b0', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-13', '17:30:00', null, '通常 / アレンジ大賞の作成', '今日がアレンジ大賞の作成が最初だったので、アレンジ段階が進めやすい初級で作り進めていました。ステージセレクトだったり、背景に合わせてコスチュームが変化したり、とても世界観にあった作りが見れれ増した。出来上がったものをまさき君と見せあってたりして、完成したものににぎやかになっていました。', null, null),
  ('756afa0d-249c-5ce6-b2d7-e262f7793d3b', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-13', '17:30:00', null, '通常 / 座標の復習と音の仕組みを学ぼう', '前回までに移動系のものがつついたので、固めるために追跡ゲームをしました。最初に、上下左右に動かすことを作ってもらうとすると、サメのときにやった気がするといいて、縦横の移動にxy座標を使うことは覚えていました。ただ、「にする」になっていたり、マイナスがなかたっりしていたので、動きを見せてどう違うのか優しく考えさせながら進めることができました。新しく「どこかへ行く」も旗をしてずっと動くようにしておねだりして自力と作ろことができました。そして、触れて音をなることも触れる条件はサメでやったように「調べる」から持ってく来れました。そのあとの、音を「終わるまで」との違いを体感して連続して音がなるがおかしいことを訂正してもらい終えることができました。 今日はあまり席を離れることなく、ずっとパソコンに集中していました。何回か重ねてある程度は吸収する力がついてきた気がします。', null, 'タイピング: 前半はSを続き、好調に続けられました。
盛り上がり: 前回までにやったことが少しでも残っていたことに成長を感じます。'),
  ('08ecd07c-2a6f-5490-b029-c7c9860cbc9d', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-13', '16:30:00', null, '通常 / アレンジ大賞完成、提出', '今日やりたいこと（レアむらっちと、マイナスむらっちを作る）をしっかりとイメージして来室してきました。何をするのか自分でわかっていたので、てきぱきと作成を進めていました。 コスチュームの表示順が逆になっていたせいで、むらっちが上からおりてくるようになっていたため、コスチュームのタブを確認させてどうしてそうなってしまうのか考えてもらい、表示の順が逆ということに気付くことができました。 レアむらっちなどの表示時間や、表示されるタイミングなども、「〇秒待つ」ブロックをうまく使って調整していました。', null, 'タイピング: ランキングで新記録が出せて喜んでいました
盛り上がり: イメージ通りのゲームができたようで、とても満足そうにしていました。 お母さんやみずきくんにも熱心に見せていました。 やりたいことをしゃべるだけでなく、自分からコードを読んで手を動かすという姿勢が身についてきています。'),
  ('83bd63fe-8cfd-595d-9e66-c5087f5ba29c', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-13', '16:30:00', null, '通常 / サッカーゲームを作成', 'ラスト2回だったので、ようくんがやりたいことをきき、習い事がサッカーやバスケをやっていたので、作りやすいサッカーゲームを動画を見ながら作成していきました。さいしょは、あちこち気が散って、あんまり進まななかったが、形ができてくると、集中力を続き、一気に作り上げました。まだ、スコアがなどの変数のところが完成していないが、念願のサッカーゲームが作れたので、楽しく作れていました。ボールのスピードとかも変えて独自物を作れていました。', null, '盛り上がり: サッカーゲームはとても楽しくやっていました。'),
  ('93478cdb-da06-54f0-b2b9-9e55a66b228c', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-11', '17:30:00', null, '通常 / アレンジ大賞作品の完成', '基本的に反応が薄いところがありますが、こちらから問いかけると少しずつ、自分がやりたいことを言葉にしてくれるようになりました。 スコアの演算式で悩んでいるようだったので、条件を丁寧に説明してもらったところ、自分で不等号の向きが違うことに気付いて直すことができました。 作りたい映像イメージがしっかりしているようで、背景の切り替わりや音の使い方をよく工夫していました。その一方で、それらの効果が切り替わる指定が曖昧なため、メッセージや変数の使用等、場面転換の手法を学習していってほしいです。', '備考欄に書いた教材の横スクロールをどうしても自分でやってみたいようだったので、完成形をアルスパークに入れておきました。 資料に載っている部分だけブロックを削除して自分で作ってみようか、との提案に大きくウンウンと頷いていたので、次回、その希望が変わってなければやってあげたいです。', 'タイピング: 黙々とやっていました
盛り上がり: 授業前に、お母さんからLINEで受け取っていた教材の資料と完成形を見せたところ、大きく反応していたので、喜んでもらえたようでした。 今日はそちらは後回しにしてアレンジ大賞をやろうというのにも納得してくれて、時間いっぱいまで熱心に作成していました。 マウスをぐるぐるしたりするのが悩んでいるときの仕草のようで、そのときに声をかけると質問ができ、一緒に考えることもできました。
備考: お母さんからLINEが来ていた件について、そうすけくんのメモを元に、作りたがっていた作品を見つけました。 https://www2.nhk.or.jp/school/watch/bangumi/?das_id=D0005180315_00000 NHK for Schoolで公開されている資料をプリントアウトしておいたところ、喜んでもらえたのか(反応だけではわかりにくいので…)そうすけくんは大事そうに持ち帰っていました。 一応お母さんには、こちらの教材はScratchのバージョンが2.0のため、ブロックの種類や色に若干の違いがあって混乱するかもしれないことをお伝えしてあります。'),
  ('161f8368-02d0-59b7-af4b-7a0b112abd17', '7d01236e-620e-5177-a6f4-af325a582aae', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-11', '17:30:00', null, '通常 / アレンジ大賞作品の完成', '今日の目標は、キジムンのステージがクリア出来たら「終わり」の背景を出して音楽を鳴らす、とのことでした。「キジムンのステージがクリア」するのはどの部分か、という発問で、自分の書いたコードを見直し、「メッセージを受け取った時」「背景が○○になったとき」の違いを復習しつつ、作成を進めました。メッセージに比べて背景は、変わった時がわかりやすいため、イメージがしやすいようでした。 背景の画像と音楽は、こだわりがあるのか、ずいぶん熱心に選んでいました。 音のブロックを他のスプライトにコピーして使おうとしていて、音が鳴らないと悩んでいたので、そのスプライトの音のタブを見せて、音は各スプライトが持っているため、ブロックはコピーできてもその中身まではコピーされていないことを確認しました。', '緑の旗が押されたときと、背景が変わった時の違いはなんとなくわかったようだったので、このままメッセージの理解につなげていきたいところです。', 'タイピング: タイピングは好きなようで、毎回熱心にやっています。授業終了後も率先して取り組んでいました。
盛り上がり: 目がかゆいのか、頻繁にこすっていてつらそうでしたが、やりたかったことはできたようで、提出ができたときはスッキリした感じでした。 作品のコメント欄は、自分で入力したいと言って一生懸命打っていました。'),
  ('03be7a39-c2c4-5c5d-aaad-68f792c0f934', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-11', '17:30:00', null, '通常 / アレンジ大賞続き', 'アレンジ大賞というよりは、ほぼオリジナル作品になりました。 メッセージを使ったときのスクリプトの扱いに苦戦していました。音が繰り返しながれてしまう、変数が変わり続けてしまうのを工夫して改善していました。プログラムの実行順序について気を配れていました。 いろいろな要素の詰まった作品に仕上がりました。', null, null),
  ('e9900a20-4952-5276-863f-7c456678fa5d', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-11', '17:30:00', null, '通常 / アレンジ大賞続き', '邪魔者の追加に取り組んでいました。また、マリオやルイージの攻撃のコード、変数の使われ方に注目していました。弾丸の方向に注意して、プログラムでうまくコントロールすることもできています。 少ない時間のアレンジ大賞になりましたが、集中して黙々と取り組んでいました。また金曜日に取り組み、完成させる予定です。', null, '盛り上がり: 時間中、1度も席を立たないで取り組んでいました。とても集中できていました！'),
  ('666d9a1b-b0e1-5956-bf2e-4c4b1046caf7', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-11', '16:30:00', null, '通常 / ジャンプゲームアレンジバージョンor雲に隠れた太陽 基本操作の確認、変数の使い方', 'ジャンプ、コスチューム変化などの基本的な動作に加えて変数を少し工夫して使ったゲームです。さらちゃんにも取り組んでもらいました。 条件分岐の考え方が苦手なようです。そこに変数も加わると特に混乱してしまうようでした。しかし以前と違ってプログラムを見たときに「これじゃダメじゃない？」とブロックをみて指摘できるようになってきました。ゲームの大枠は完成しました。最後にプレイしたときは本人も満足そうでした。', null, 'タイピング: 高得点でした！集中して取り組めていました！
盛り上がり: コスチュームの変化のタイミングにこだわっていました！'),
  ('2a633942-9340-5260-89ec-4a99f6b6478a', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-11', '16:30:00', null, '通常 / アレンジ大賞初級に挑戦', '終わりの画面を出す=終わりのコードを探すところから始めました。一応どのコードが何をしているかは読めているようで、「ここで背景を変える」というのも自分で探せました。 この作品にも少し飽きてきていたのか、終わりの背景が出せたら「もうできた！」と立ち上がっていましたが、お絵描きやコスチュームのアレンジが好きそうなので、「マイナスむらっちを作っては？」との提案をしたところ、かなりノリノリでマイナスむらっちスプライトを作っていました。マイナスむらっちのおかげで、スコアの変数も見直し確認することができました。 アレンジ大賞提出後、「ゲームなら勉強してもいい」とのことで、単元別演習F-1「おにごっこ」を作成しました。マウスポインタを追いかけるためには、どちらを向いて何をすればよいか、というヒントは必要でしたが、その後はカードの裏を見ずに作成することができました。 実際にドリルを完成させて遊んでみると、すぐにゲームオーバーになるため、しょうたくんなりに工夫して初期座標や大きさを変更するブロックを最初に入れ、長く遊べるように仕上げていました。', null, '盛り上がり: コスチュームのアレンジは本当に楽しそうで、そのおかげか、一気にやる気が出ていました。 作品を2つ仕上げられたのが嬉しかったようで、お父さんに熱心に紹介していました。'),
  ('a20ca216-abce-50a8-b075-1bb0dc547e51', '7d01236e-620e-5177-a6f4-af325a582aae', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-04-04', '17:30:00', null, '通常 / アレンジ大賞、むらっちたたきのアレンジ。', '★本日のポイント どうなったらキジムンが現れるか（＆同時に背景が変わるか） 現時点で動きません。 ゲームのアレンジのイメージは以下 １）むらっちたたきでスコアが「30」になったら ２）背景を変えて（＝Boardwalk）キジムンが登場 ↑但し、このゲームの流れを恐らく今日は忘れている可能性が大です。 ◆メッセージの使い方があいまい。 「スタート」のメッセージでむらっちが動く ⇒キジムンはその間隠れる ⇒全て「緑の旗が押されたら」スタートすると思っていたので、「スタート」メッセージで、誰がどう動いているのかきちんと確認できていない様子（ササ～～とみているだけなので）', '２点、今後整えたいスキルがあります。 ①メッセージの使い方（特にメインキャラクターが「緑の旗以外のメッセージで起動する」ことについて） ②スコアという変数の使い方。思い出したものの、「変数」として仕えていない。そのため、今回のアレンジ作品でスコアをつけているものの、「変数」として何かをコントロールしていない。たぶん。今回の仕上げには間に合いませんが、ここを追々。', '盛り上がり: 最初、キジムンのスプライトを選び、コスチュームをいじっていたところ、髪の毛とスカートが分解され、スッポンポン頭ツルツルになり、これを非常に気に入りました。今までで一番の笑顔を見せてくれました(#^.^#) アレンジのアイデア自体は浮かんでいなかったので、話しをしながら飛び出しながら髪の毛とスカートがなくなるように設定しようといことになりました。'),
  ('403f30c6-b8e8-5709-8f21-32440537fb36', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-04-08', null, null, '通常 / 教室に慣れる、基本のコードを確かめる', 'テキストの内容を順にやっていったのですが、指示が分かればあまりテキストを見なくても感覚的にできていました。座標をなめらかに変えていくのが好きだったみたいで何回かやっていました。最初はアルくんやむらっちを動かしましたが、自分の名前のアルファベットでもやりました。', null, '時間帯: その他
タイピング: わりとスムーズに打てていました。
盛り上がり: 作ったり動かしたりすることがとても楽しいという感じでした。'),
  ('671b9095-0147-5095-afde-f422ea937be8', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '4fb853b8-7d59-5565-9d96-060872e780d1', '2023-04-08', null, null, '通常 / 教室のルール説明', 'とにかく落ち着きがなかったです。 「こう先生」が頑張って教えているのにも関わらず、聞く耳を持たないというような様子でした。ほぼこちらが指示して、操作をしている状態だったのでおそらく理解はしていませんん。 次回「ゆき先生」が親御さんに相談するそうです。 相談後に授業の方針を決めていくと仰っていました。', '授業の目的を教える→やる範囲を決めた所まで行ってもらう→自由時間を与える。 上記のような方法で行う予定です。', '時間帯: その他
タイピング: 落ち着いて行っていました
盛り上がり: ゲーム感覚でPCの操作をする様子がとても楽しそうでした。'),
  ('7d7bb1ae-523a-5549-b0d8-9c83076d8d0a', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-08', null, null, '通常 / 教室に慣れる、基本操作コースからスキルの確認', '経験があるとのことだったので、お題を出して作成という繰り返しでスキルチェックをしました。 基本操作コース1枚目のスキルはほぼ確認できました。 上下左右の動きは、先に向きを指定してから〇歩うごく、の形式で作成していたので、座標で動かす方法も一緒に確認し、それぞれの利点のチェックをしました。 音や画像は、ネット上から検索して持ってくる癖がついています。公開する作品を作成する段階で、著作権の話などもしておきたいところです。 内容的には初歩でしたが、「これできる？」と問いかけると「できる！」と嬉しそうに反応して、できあがると声をかけて、「見て見て！」という感じで楽しんでくれているようでした。', 'ピンポンゲームでスキルや癖のチェック', '時間帯: その他
タイピング: タイピングはそれほど得意なわけではないと言ってはいましたが、それなりの正誤率を出せていました。
盛り上がり: 簡単な内容でも、ばかにしたようなそぶりはなく、基本的に「それもできるよ！」と嬉しそうに取り組んでくれました。 スキルの穴埋めをしながらいろいろ作れるようになっていこうね、という目的にも納得してくれているようで、時間いっぱい熱心にできていました。'),
  ('1f5e9026-183c-5a2b-b522-fd8a9761e07f', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-04-08', null, null, '通常 / アレンジ大賞', 'お手本を再現するのは前回できたので、今回はアレンジに入りました。疲れた様子だったので、休憩をはさんだりしながら進めました。アイデアがなかなか思いつかなかったので、自分が今までに作ってきたゲームを参考にすることを勧めました。最終的には「君のスコアは〇点だよ」と伝える恐竜を出すというアレンジを加えました。恐竜のセリフは文字列の連結を活用して作りました。', null, '時間帯: その他
タイピング: 最初はふざけていましたが、「その記録を書くことになっちゃうけど大丈夫～？」などと言うとまじめにやっていました。
盛り上がり: 友達のそうたくんに見せようという気持ちでなんとか頑張りました。'),
  ('0ef59cf6-37b6-555f-be88-d4f8a2e3761b', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '4fb853b8-7d59-5565-9d96-060872e780d1', '2023-04-08', null, null, '通常 / アレンジ大賞作品の作成', '作品のイメージで悩んでいた。 デザインで悩んでいたので、デザインの提案を与えたが微妙な反応を取られたので上手く距離を取りながら見守っていました。結果自分で、解決が出来ていたみたいなので結果として問題なかったです。', 'アルスパーク/【アレンジ大賞】初級＿むらっちたたき→コンセプトにズレが出てきているので、そのズレを一緒に直そうと帰りに「まみ先生」が言ってくれたそうです。', '時間帯: その他
タイピング: 通常通り行っていました
盛り上がり: デザインを一所懸命に考えていた様子がとても、ワクワクしているように見えました。'),
  ('1cbd9eb7-3293-51c7-9edd-ca4c290c19f2', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-08', null, null, '通常 / アレンジ大賞作品の作成', '返事を焦らせなければ、ずいぶんとしゃべってくれるようになりました。やりたいことについても、だいぶ文章で説明できるようになってきました。 スコアが基準に満たなかった時に「ゲームオーバー」にしたかったようですが、最初からゲームオーバーになってしまうバグがあったので、実行中のスクリプトが強調されていることを伝え、スタート直後に「ゲームオーバー」メッセージが送信されてしまっていることを確認してメッセージ送信スクリプトを見直す、という手順を一緒に学習しました。 元のスクリプトでは、ゲームスタート時に「クリアの条件ではない」ため「でなければゲームオーバー」の条件に当てはまってしまい、ゲーム開始時からゲームオーバーの状態になってしまっていることを、一つずつコードを確認しながら理解できました。 ゲームクリアとゲームオーバーの条件を紙に書きだして整理して、「タイムが1より小さくなるまで待つ」「スコアが30より大きいときと、でなければ」の形にまとめられることを確認してから作成したところ、なつめちゃんも納得しながら修正することができていました バグが解決できてすっきりしたのか、他にやりたいことをいろいろ話してくれて、ダミーのくまちゃんを作ったり、音楽を入れたりとそれなりのアレンジができました。', '今回の作品のテストプレイと見直しをして提出する予定', '時間帯: その他
タイピング: これまでと比べて良い結果が出て嬉しそうでした
盛り上がり: まだ少し自信がないのか、間違えたくないのか、新しいコードを作成するときに見ていて欲しがる傾向はありますが、やりたいことを口にしたり、講師が席を離れた時は自分なりに進めてみたりと積極性が見られるようになってきました。 ゲームのアレンジも、現時点でのなつめちゃんの持つスキルはかなり出すことができていて、本人も満足そうでした。'),
  ('f1c3617a-5d93-5f6f-9116-e8353323b28f', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-07', '16:30:00', null, '通常 / アレンジ大賞の作成', '前回作りかけのアルくんはボーナス得点でかなり難しめ設定で作っていました。スタート画面はアルくんの説明だったり、ややスプラッタなことも表現できていました。作業中はアイデア止まることなく黙々と作り上げていました。そして、スコアが上がるごとに背景も変わっていき、どこまで背景を楽しませることができるか感じられるアレンジになっていました。', null, 'タイピング: スコアが伸びてきました。
盛り上がり: アレンジでずっと集中して取り組めていました。'),
  ('e13c8562-2125-5384-8a74-88ca2d8ea6d0', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-07', '16:30:00', null, '通常 / アレンジ大賞作成', '週が空いたこともあり、アレンジ大賞の作品はどうゆうことをしたか思い出しずらく、背景をうさぎにあったものに変えて、早めに作品を切り上げました。 次に、イライラゲームの作品を作りました。動画を見ながらの作成でしたが、ところどころにアレンジも同時に作りながらやっていました。次週で完成できそうです。', null, 'タイピング: 気が付いたら何度もやっていました'),
  ('0c3e7917-7265-5f8c-a9c1-68062203ccc0', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-07', '18:40:00', null, '通常 / アレンジ大賞上級アレンジへ', 'HPの表示が重なる。剣の絵なのに銃が撃ててしまう、などのバグの修正に取り組んでいました。 ひとりごと多くてもごもごしてくれて考えてくれてるから、話しかけ時が難しい！！！！自分で原因を考えられていました。原因を探すポイントについて共有しました。見つけられないところもあったので、次回取り組みます！！', '完成させる！！', null),
  ('b6a07a3b-2700-5919-b6fe-7a55e627838f', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-07', '17:30:00', null, '通常 / アレンジ大賞 マリオのアレンジ', '自分が作りたいというアイディアが多く、そして自力でコードが書けている状態、 またスプライト同士のリレーション問題も干渉せずできていました。 一個だけボーナスタイムの時に速度が早くなる〜という問題部分がわからなかっただけで、大和先生にヒントをもらい、理解をしていたようでした。', null, 'タイピング: なし
盛り上がり: きちんと自分がやりたい動きをコードで「どのように書いたらいいか？」が理解できていて素晴らしい！そしてちゃんと動作確認など、コードを書いたらすぐ見直すという部分も本人にとってはとても楽しい時間になっていたようでした。'),
  ('4e16044a-9e8e-5295-8c1c-101137c4fa15', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-07', '17:30:00', null, '通常 / アレンジ大賞 マリオを全部写す→アレンジに向かう', '今日はコードを写し終わるというところがメインだったのですが、どうしてもコードがわからないという言葉を連続。 途中で嫌になってしまったようで、結局今日は途中で帰宅となりました。 どうやらどのコードのブロックを写しているのか、コードの読み取り自体が嫌になってしまったようです。次回までのやり方を少し考えないといけないフェーズに来ているのかもしれません。 今はネガティブになっているので、何を言っても響かない感じ', null, 'タイピング: なし'),
  ('5bc8d7fa-4828-5058-8695-8b53104d619c', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-07', '16:30:00', null, '通常 / アレンジ大賞 初級 バグの部分を潰す', 'ボーナスタイムの時に出るむらっちや、クローンの使い方というのが曖昧だった様子で、同じコードを単純に写していました。そのため、スプライト同士が干渉しあってバグにつながっていたりしました。 また、アイディア自体は良いもののスプライト同士のリレーションの整合性不明確になってしまっていたため、出てこないでほしい時にむらっちが出てき続けるというバグにもつながっていました。 以上の点を紙に書いて、もう一度コードの書き直しをしてもらい、なんとか途中までは出来上がっていた様子です。', null, 'タイピング: スコアがだいぶ伸びてきて本人も結果にとても満足していた様子でした。
盛り上がり: 来週完成できるかな？'),
  ('7bde6678-9af9-5855-818c-81a1f0ae9bec', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-07', '16:30:00', null, '振替 / アレンジ大賞 初級でアレンジをするという目標を立てて、来週までに完成させる', '最初に全てを移して、どのようなアレンジをするか？を考える日にしていました。途中まで移し終えたところで、保存を間違ってしまったそうで、やったところまでが全て水の泡となる事態に・・・ もう一度最初から移して、来週アレンジを完成させるということで話がつきました。 やってみたい内容は写し終えたら考えるということだったので今日はコード自体を写すことで終わってしまいました。', null, 'タイピング: なし'),
  ('360d6870-e578-5b25-9d60-165a9d484a5d', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-07', null, null, '通常 / アレンジ大賞初級', '背景を追加してかわいくしました。スペースキーで変わるそうです。最後にスプライトを出すことにしました。方法としてメッセージを使うことを提案しました。メッセージ名も自分でタイプすることができました。表示だけでなく、隠すプログラムも自分でいれることができました。 最後にタイトルを考え、作品を提出しました。集中して取り組むことができていました！', null, '時間帯: その他'),
  ('cf552f2b-75ed-588e-951d-ca64fd119dfd', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-07', '17:30:00', null, '通常 / アレンジ大賞に挑戦', 'どうしても中級に取り組みたかったそうなので、リミックスして取り組みました。「中心にスプライトを置いて上下に動かしたい」とのことでした。y座標の存在は覚えてくれていたのですが、「端についたら跳ね返る」を使う都合上、向きと「〇歩」を使ってもらいました。どれもあまり定着していない様子でした。 その後、あるくんやあるごんがぶつかったら動きがとまるようなプログラムを作りました。ルイージの動きを作るとマリオの動きは自分で作ることが出来ていました。', null, '盛り上がり: 目標が達成できると嬉しそうに遊んでいました！小学校の話もたくさんしてくれました。'),
  ('b12e1a9b-ac77-53b7-96ac-61f6272929cc', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-04-06', '17:30:00', null, '通常 / アレンジ大賞の作成', '授業前から作っていた作品では、時間がたつごとにバナーが短くなる演出をコスチュームを変えて作れていて、いいアイデアだなと思います他。 後半に、作ったアレンジ大賞のむらっちたたきは、相変わらず正樹君武士が発揮して少し黒いものになったが、背景や音、コスチュームのこだわりは細か宇出来上がっていました。帰るまで、いじっていたので、出来具合だけを見れば、来週はもっと良くなると思います。', null, null),
  ('1f159aaf-d765-59e7-8cec-f7bdc56b4f46', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-04-06', '17:30:00', null, '通常 / アレンジ大賞', '倒す敵である「329」と、触ったらゲームオーバーになる「アルスタッフ」をそれぞれ作りました。キャラクターの見た目もアレンジしました。 元のゲームから背景を変更したので、キャラクターが出てくる座標の範囲を広げたほうがいいということを伝えると、乱数をいじって範囲を広げることができました。 ゲームはこれで完成したそうなので、次回は説明文を考えてエントリーしてもらいます。', 'アレンジ大賞にエントリー', 'タイピング: 「ホームポジションの練習」や「〇行の練習」をいくつかやっていました。
盛り上がり: 教室に通い始めて間もない状態ですが、楽しみながら方向性の決まった作品を作れました。'),
  ('db9946aa-cff1-5d22-a7a1-901a661ad924', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-06', '17:30:00', null, '通常 / アレンジ大賞の作成', 'マリオの作品を元の作品をあまり見ずに作っていきました。それぞれ作ったコードごとにコメントでどうゆう動きをすものか示していて、非常に見やすい環境を作っていました。モーションや攻撃判定の条件も独自に悩み止まることなく作れていて、頭がさえていました。あとはエンディングを作れば、一つの作品になると思います。', null, 'タイピング: めちゃくちゃ早い
盛り上がり: 本人もびっくりしたくらいにかなり集中してました。'),
  ('c05d4484-5f2a-53a3-9e29-c341c126b93f', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-06', '17:30:00', null, '通常 / アレンジ大賞の作成', 'OPムービーは前回のzoom講義が活かされているような動きのあるものに上がっていました。操作方法の有無もスタート前に尋ねるアレンジも親切心があっていいなと思いました。ジャンプも元の作品のものがパッとしなかったので、何か別のジャンプの仕方をスクラッチで探しながら作っていました。ほかの動きも自力で作っていて素晴らしいです。あと1回で終わると思います。', null, 'タイピング: まずまずチャレンジしていました
盛り上がり: とてもこだわりを感じられました。'),
  ('c0344f85-1173-535a-b55a-52bfef351131', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-04-06', '16:30:00', null, '通常 / アレンジ大賞の基本のコードを作成する', '前回はコスチュームなどのアレンジに時間をかけすぎてしまったので、今回は基本のコードを進めてもらいました。ときどき写経しながら、クローンの生成やスコアの加算をして一通りゲームとして成り立たせることができました。しかしむらっちがすぐ消えてしまい難易度が高すぎると言っていたので、次回はそこの調整から始めたいです。', 'アレンジ大賞続き', 'タイピング: 今日も英単語のタイピングに取り組んでいました。やはり少し難しいらしいです
盛り上がり: 自分で考え、内容を理解しながら作ることができました。'),
  ('e3b02eaa-6be4-5691-9a66-2e1890c5de76', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-06', '16:30:00', null, '通常 / アレンジ大賞', 'アレンジ大賞の元の最頻はほぼできていたので、アレンジをしました。むらっちをとても増やして、アレンジをすぐ終わろうとしたので、スコアを積み重なって言ったらどうなるのと揺さぶりながらアイデアを渡してあげました。あれこれと悩んンで作っては消したりしてアルくんが追加に動き回り、リアクションを取るようなアレンジを加えてくれました。本人的にもアレンジ作業は満足していたので、完成にさせました。', null, '盛り上がり: 周りのことに気が飛びがちです'),
  ('e03cf476-c3ca-5885-8eca-2fbdd1fc69d9', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-06', '17:30:00', null, '通常 / アイスを食べに続き', '（アイスを食べに2）レッスンの画像を見ながら集中して取り組めていました。今日は角度について取り上げました。左、下に動かすときの角度について少し困っていたので、角度の考え方についてはっきり説明しました。さらに壁に当たると初期位置に戻るアレンジをしました。アイスに触れたときと同様「もし」と「～に触れたら」を使ってプログラムすることに気づきがあったようです。 （アイスを食べに1）2は終わったのですが、1が終わっていなかったので戻りました。あるくんが話す言葉にアレンジを加えていました。', '2はしっかりできたので、アイスを食べにはもう終わっても良いかなと感じました。', 'タイピング: 評価Sでした！すごい！！
盛り上がり: とくに前半は楽しく取り組めました！！'),
  ('fa4d0a92-3713-5ed4-9731-7f1035e3aa4a', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-04', '17:30:00', null, '通常 / アイデア大賞初級続き', '前回の確認をした後、魚の動きをプログラムしていました。クローンの知識が浅く正しく使えていなかったので少しアドバイスをしました。新しいスプライトを追加するときにも見た目に気を付けて工夫してくれていました。音にもかなりこだわりがあるようです。 自分でどんどん進めていきますが、うまくいっていない部分も自分で考えたい様子です。自分で考えて進めいたいタイプのようです。どうしても詰まったときには声をかけてくれました。声掛けのタイミングが難しいです。', null, 'タイピング: 集中して取り組めていました。
盛り上がり: 音の調整にとくに力をいれていました！！楽しそうでした！'),
  ('5f34f8d6-ad6b-5f18-af87-ccff080539cf', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-04', '17:30:00', null, '通常 / アイデア大賞に挑戦（あと2回）', 'オリジナルの作品はもとのコードを確認しつつ、すぐに完成させることが出来ました。アレンジにも、とても積極的に取り組むことができました。箒を加えたり、背景を変えたりしました。スプライトが出てくる場所にもこだわって、座標をつかいこなすことができていました。来週続きをする予定です。', null, 'タイピング: 集中して取り組めました。
盛り上がり: 検定の 合格証をもらえて嬉しそうな様子でした。持って帰りそびれていたので来週また渡します。'),
  ('ff81e9bc-c1a6-5b26-ac49-df25ef1cac8a', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-04', '16:30:00', null, '通常 / アイデア大賞初級続き おわりの画面の作成を提案してみる', '終わりの画面を作成していました。丁寧にタイプして作り、表示させました。自分でコードを確認してゲーム終わりのタイミングを探すことができました。背景の変化とスプライトの表示に悩んでいたので、メッセージを使うことを提案しました。 ハートにある文字を変更してオリジナリティを出したり、コメントにアピールポイントを書いたりして工夫しました。最後に作品を公開できました。', null, 'タイピング: とても集中して取り組めていました。正解率100%！
盛り上がり: タイトルにオリジナリティがあります！半角にこだわっていました！！'),
  ('d2b4a0d1-9abf-5f93-929c-25e689c3aff0', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-03', '16:30:00', null, '通常 / アレンジ大賞 中上級', '今日はまだ中上級の中の全てのコードが写し終わっておらず、アイテムの部分を中心にコードを追加していました。 この部分がどうやら難しかった様子で、写すことにとても集中して行っていました。 今週来週とまだげんきくんの場合は時間があるので、一旦今週の金曜までに写し終わるを目標にして、来週の時に少し自分でアレンジを加えられたらいいのかなと思います。', null, 'タイピング: なし
盛り上がり: 自分で何回もコードの動作確認をし、ゲームを作成。一つのブロックが長いため終了時間になっても、しばらく続けていました（20時前には帰らせました） 今はコードを写すことで精一杯の様子ではありますが、一旦集中すると中途半端になってしまうのが嫌だったようで、1時間まるっとプログラミングをしていました。'),
  ('b1e64716-635f-5151-96ec-ce8bc41dfa57', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-03', '16:30:00', null, '振替 / アレンジ大賞 むらっち', 'むらっち以外の人をクリックしてしまうと一点減点というゲームに変更。 また最初のバグのような部分もいくつかヒントを出しながら、自力で導き出してくれたので、ゲームとしては完成となりました。 残り時間は、マリオゲームの方を写し、どいいうコードを書いているのか？をみながら作成。コードを写すこと自体は苦ではない様子でとても集中して最後まで行っていました。', null, 'タイピング: なんと、2ヶ月前のうでだめしよりも３レベルもアップ！小学校2年生ではとてもすばらしい！
盛り上がり: ゲーム性として他人にわかりやすくするという点をこだわっていました。むらっちとは違う人を色で変化させたりし、とっても面白くしてくれていたように思います！'),
  ('42e7544d-702a-5d37-a713-6a69727f96d9', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-03', '17:30:00', null, '通常 / アレンジ大賞の作成', '春休みもあって授業前も遊び、授業が始まる時にはすごき眠たそうでした。前回作ったところが一部保存されてなくて、作り直すことにすごく落ち込んでいたが、何とか進ませました。とちゅう、転寝しがちになり、別のコードを持ってきてしまう不注意なことがありました。その後、ブロックの塊ごとに終えたら見直しすることがさせてやったので、最後にバグが残らず、きれいに作り上げることができました。ただ、それで時間が来てしまったので、アレンジをする時間はありませんでした。', null, 'タイピング: 上位36%といいスコアが出ました
盛り上がり: 奇麗に一巡で作り上げてので、完成の喜びはとてもよかったです'),
  ('c485ccbf-def4-5f15-8c92-bddc8b186dc5', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-03', '16:30:00', null, '通常 / アレンジ大賞 初級 むらっち', 'むらっちを虫に変更、虫を倒すというものに変えていました。 ここまではコスチュームの変化なので、実際のコードを変化させているのではないため、スコアを作って、点数が一定の条件になったら、何かしらのアクションを追加してみてはと提案。 点数が色々な点数になった際に出てくるメッセージを追加して、アレンジしていました。 来週は、おそらく完成に進むと思います。', null, 'タイピング: かつてのスコアよりもかなり伸びていて、以前はブラインドタッチもままならなかったのがとても成長したように思います！
盛り上がり: 色々な条件分岐を増やしてくれ、自分でもその条件をどのタイミングで出したらいいか？と考える力を発揮してくれていたように思います'),
  ('6154f172-7ff6-5614-8713-2cf6e3961140', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-03', '16:30:00', null, '振替 / アレンジ大賞の作成', 'ルイージのモグラに対してのダメージ判定がなかったり、ジャンプが1回しかできないバグを直していきました。途中いろいろといじりすぎてバグがなかったマリオにもバグが発生したので、リストアして探し直しました。それでもなかなか自力では見つけづらかったので、助言しました。そして、原因として上の「もし」の条件にかぶっていたり、変数名違いの不注意によるものでした。 モグラがあまりにも多く発生するので、モグラを殴るのアクションで消すようなアレンジを作り始めました。コスチューム番号の範囲で条件を指定して作ろうとはしていましたが、条件以外のときも消えてしまうことがあってうまくいきませんでした。そこのところ、次回で完成を行けたらいいと思う。', null, 'タイピング: 日本語1文字ずつ打つ間隔が短くなってきました'),
  ('1179accc-1e1c-5cd3-8ccd-39de1d246010', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-03', '17:30:00', null, '振替 / アレンジ大賞 初級のアレンジ', 'コスチュームなど変化させた部分までは自力でできました。 今度は以下の条件を追加したいとのことで、一緒に考えていました。 ①条件１タイム30秒のうちに、スコアが30にならなければ、ゲームオーバー ②タイム30のうちにスコアが30になったらクリア 変数を作って、ゲームオーバーとクリアをつくったまでは良かったのですが、①と②の条件分岐が意外に難しく、最後の時間内では終わらなかった→今週10日の土曜日に一緒に考えてもらえると助かります。', '変数を作って、ゲームオーバーとクリアをつくったまでは良かったのですが、①と②の条件分岐が意外に難しく、最後の時間内では終わらなかった→今週10日の土曜日に一緒に考えてもらえると助かります。', 'タイピング: 簡単レベルを選んで、なんとノーミス！とっても嬉しそうにしていました！
盛り上がり: 自分で考える力→こうしたいという意欲はとても素晴らしい。ちょっと今日は久しぶりだったのもあってうる覚えなところもありましたが、そっか、こういうことか！という理解につながっていたようで、良かったです。'),
  ('ebffd43c-6d57-54d3-a6fa-debb1e3453c1', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, null, '2023-03-28', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('1e117efb-adea-55c6-ad0f-bb1127d9148c', 'cf94ca77-6621-5a19-b35e-6f2e124107d6', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-28', '17:30:00', null, '通常 / Scratchを楽しむ', 'カウンター席で、飴を傍らに、熱心にパソコンに向かっていました。 最初はScratchのゲームで適当に遊んでいましたが、途中からアルスパークを開いてオリジナルのコスチューム編集を熱心にやっていました。Scratchのネコの色を変えて帽子を描き加え、マリオのようにしてバッタと追いかけっこをしながらぐるぐる動く作品を作ったので褒めたところ、その後5体くらい、新しいオリジナルスプライトを描いて動かしていました。', null, '盛り上がり: コスチューム編集画面でのお絵描きを熱心にやっていました。 Scratchでは、マイクラアスレチック系のゲームを開いて遊んでいました。'),
  ('6077ee97-1d29-59e6-856a-89e4db0e6906', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-28', '17:30:00', null, '通常 / アレンジ大賞の作成', '家でScratchで作成していたゲームがあるそうで、その仕様を活かしたいと思い出しながらアレンジをしていました。かなりオリジナリティの強い作品になりそうです。 条件分岐よりもメッセージを多用する方が好みのようです。一つのメッセージをきっかけにいくつかのコードが動くようにしていたため、メッセージの発信と受信の関係をきちんと整理することを勧めました。 隔週コースのため、自宅での作業もできることを提案しましたが、ゆずとくんなりにシミュレーションして、あと1回の授業時間内で完成できるとのことで、IDのお知らせはしませんでした。', null, '盛り上がり: かなり早く来室したため、ほぼ2時間かけて熱心にアレンジをしていました。 ゲームの遊び方の仕様を変えてみたかったらしく、オリジナルのボタンを作成して満足そうにしていました。'),
  ('b9343c23-e2e3-5f44-8d99-69aa7e1be397', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-28', '16:30:00', null, '振替 / アレンジ大賞作品の作成', 'スタート画面をこだわりをもって丁寧に編集していました。 ゲーム終了の画面を、メッセージを使ってきちんと作成することができていました。 絵やデザインに好みがあり、じっくりと編集したがる傾向がありますが、コードの方も促せば丁寧に読み取ることができました。 一人でどんどん先に進むというよりは、一つ完成すると先生に見てほしそうにして待っていて、声をかけると嬉しそうに解説をしてくれる、という感じです。', null, '盛り上がり: デザインの変更が満足できるところまでできたようで、嬉しそうにしていました。'),
  ('70cf1ff9-12f3-5dde-a50a-8b1f7f26f539', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-28', '17:30:00', null, '通常 / アレンジ大賞に挑戦', 'まずは元作品を見ながらプログラムを作ってもらいました。作りながら音の追加などの工夫をしていました。アイデアが尽きてしまったようなので、終わりの画面の設定を提案しました。その後、新たに魚などを追加して新しいステージを作っていました。魚を動かしたい方法があるようですが、時間の都合で最後まで終わりませんでした、次回挑戦です。', '魚を動かします。', 'タイピング: 学校でもやっているそうです。途中で疲れてしまったのか、適当に打ってしまっていることがありました。
盛り上がり: アレンジのアイデアが徐々に出てきました。'),
  ('73ce41e7-104a-5d9c-8b7c-9d4c4acb99a4', '7d01236e-620e-5177-a6f4-af325a582aae', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-28', '17:30:00', null, '通常 / アレンジ大賞に挑戦', '一通り遊んでもらいました。初級に取り組むことになりました。元の作品を見ながらまずはゲームを作ってもらいました。丁寧に取り組めていたので良かったです。アレンジとして音にこだわっていました。BGMとして設定した音を最後に止めるのにかなり苦戦している様子でした。プログラム時に背景を変化させることが必須なので、まずは自分で選んでもらいました。次回は背景選び＆音止めに挑戦する予定です。', 'BGMの音を止める', 'タイピング: とても集中して取り組んでいました！
盛り上がり: 音にこだわりがある様子でした！'),
  ('2d6f3fa4-8212-5398-8d27-44972ad8ae1a', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-28', '16:30:00', null, '通常 / アレンジ大賞初級に挑戦', 'もとのプログラムを見ながら作品を作りました。春休み中だからか、普段よりも集中力が低いように感じました。元の作品と同じようにプログラムし、終わりの画面の作成、出現をしました。 本人曰く、アレンジはあまり好きではないようです。アイデアもたくさん思い浮かぶようではないそうなので、こちらがアイデアを提供する必要があるかもしれません。', null, 'タイピング: 集中して取り組めていました。得点もかなり高かったです。
盛り上がり: マイクラの文字を何も見ずにタイプできるようになったそうです！報告してくれました。'),
  ('8725e0a9-735d-5f62-a8dc-8d8bd848d9ed', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-28', '16:30:00', null, '通常 / アレンジ大賞の作成', 'コスチュームの編集によるむらっちの動きはすぐに理解して、楽しそうにスプライトを変更して編集していました。 完成品を見ながらのコードの読み取りに関する質問には答えられるのですが（このコードはどの動き？や、出てくるむらっちの数を変えるには？など）、実際に編集を始めると、どこを変更すればいいんだっけ？という質問が何度かありました。読むことは慣れてきているようですが、書く方にはまだ不安があるのか、こちらに確認してからやりたがる傾向がありました。', null, '盛り上がり: コスチュームの編集にはさすがに慣れていて、仕様の理解も早かったです。 スタート画面の文章にもこだわって、楽しそうに取りかかっていました。'),
  ('ff0f4aea-b036-538c-bd6d-3525e145d72c', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-24', '16:30:00', null, '通常 / アレンジ大賞の作成', 'ゲームのアレンジは色々と思いつくようで、積極的に考えたアレンジを作成して試していました。 ゲームをクリアしたら、上からコインが回りながらおりてくるコードを作成していて、回るのと上から動くのが同時にできないと悩んでいたので、順次処理の説明をしました。ブロックは必ず上から順に実行するため、同じタイミングで実行させる手段を考えさせ、コードを並列で作成することに行きつくことができました。 ボーナスタイムの作成などは、自分がこれまで習ったブロックをうまく使用してできていました。', null, 'タイピング: 正誤率が上がってきていて、本人もこの数値を励みにしているようでした。
盛り上がり: とても楽しそうにアレンジをしていました。自分が考えたアレンジが形になるのがとにかくうれしそうで、いつもより口数も多く、何をしたいかという要望や質問も、通常より積極的にしてくれました。 アレンジを通して、複数のコードを作成すること、「止める」ブロックの3つの種類の違い、複数のメッセージの使い分けなどの理解が深まったようでした。'),
  ('123d3091-745a-5dbd-882f-ed06ebc358b5', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-24', '16:30:00', null, '通常 / アレンジ大賞の作成', '初めに見本のコードを完全に写経してからアレンジに入る、と言って、前回から1時間少しかけて、写経をしていました。虎くん曰く、「きちんとコードを見ながら写した」そうで、その後の編集などもすぐに該当箇所を見つけることができていて、「ちゃんと中身を見てたからね！」と得意そうでした。 昨年のコンテストで作成したモグラやキツネなどのキャラクターを取り入れて、アレンジを加えていました。こちらも何度も使っているため、どのコードでどのような動きをさせているのかがよくわかっていて、一緒に作成していた大空翔くんに、得意そうに説明したり、アレンジの成果を二人で試したりと、とても盛り上がっていました。', '備考有り', 'タイピング: タイピングは面倒だからと飛ばすことも多いのですが、プログラミング検定の合格証を渡して、タイピングに続いていい結果が出たね、と声掛けをしたら、「1回だけ練習してみようかな」と言いつつ3回ほど真剣に取り組んでいました。
盛り上がり: タイピングもアレンジも、今回は途中で投げることなく授業が終わるまでとても集中して取り組めていました。 自分のアレンジを大空翔くんや、時にたっちゃんが熱心に聞いてくれるのが、とても嬉しそうで、よりウケるアレンジをしようと一生懸命な様子が見られました。
備考: 家では検定があまりできなかったと話していたらしく、合格の証書を親子でとても喜んでいました。次の級にも興味があるそうですが、中学受験のため1～3月は難しそうとのこと…。でも、せっかく頑張ってきたプログラミングが内申のアピールポイントになるなら、次の級もチャレンジしたいというのが、本人とお母さんのご意向のようです。'),
  ('16d6dc1a-e21e-56f9-9ae6-59acc6eced82', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '70028bf6-d858-5232-8ea5-b8b16ca0503f', '2023-03-23', '17:30:00', null, '通常 / 演算式を活用したスプライトの色々な動きを学ぶ', '"スプライトが画面端に近づくにつれて動きの速さを変える、スプライトの大きさの変化のスピードを少しずつ変える、ボールがバウンドするような動き、三角関数を利用した波状の動きやばねのような動きなどの説明を受け、自分でも作成していました。 澤本先生の問いかけにもよく反応してくれていました。', null, '盛り上がり: もともとジャンプの動きを作るのが好きなせいか、「これ、俺がいつもやってるやつ！」などと嬉しそうに反応していました。'),
  ('3262111e-2c88-5f1d-831a-4bff8f471f0a', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '70028bf6-d858-5232-8ea5-b8b16ca0503f', '2023-03-23', '17:30:00', null, '通常 / 演算式を活用したスプライトの色々な動きを学ぶ', '"""スプライトが画面端に近づくにつれて動きの速さを変える、スプライトの大きさの変化のスピードを少しずつ変える、ボールがバウンドするような動き、三角関数を利用した波状の動きやばねのような動きなどの説明を受け、自分でも作成していました。 少し難しそうではありましたが、承太郎君と話しながら、最後まで頑張っていました。', null, 'タイピング: 相変わらずスピードはかなり速いです。
盛り上がり: スプライトがバウンドする動きの作成のところで、最初はめり込んでしまったのを面白がり、澤本先生の指示通りにして修正できたときは承太郎君に声をかけ、楽しそうにしていました。'),
  ('bf2f29d7-605d-54f0-a7a7-8dae1013def1', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '70028bf6-d858-5232-8ea5-b8b16ca0503f', '2023-03-23', '17:30:00', null, '演算式を活用したスプライトの色々な動きを学ぶ', '"スプライトが画面端に近づくにつれて動きの速さを変える、スプライトの大きさの変化のスピードを少しずつ変える、ボールがバウンドするような動き、三角関数を利用した波状の動きやばねのような動きなどの説明を受け、自分でも作成していました。 作成していた画面から、それなりに理解はできたいた模様です。', null, '盛り上がり: 特に悩むこともなく、スラスラと作成ができていました。'),
  ('4a6d8323-090e-5745-b9e5-b9c1478794c7', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-24', '16:30:00', null, '通常 / 初級アレンジ続き', '前回の続きに取り組みました。説明文をスタートボタンを押したときに何秒間か表示されるように工夫していました。「よーいドン」の表示もスムーズにいくように「〇秒まつ」を効率的に使うことができました。やりたいことは自分の言葉で説明することができていて良かったです。次回は、終わりの画面の出現に取り組みたいそうです。', null, 'タイピング: 集中して取り組むことが出来ていました！正誤率も100%でした！！
盛り上がり: とらくんの作品も気になりながら取り組んでいました。'),
  ('7ded00ca-3b36-5b8c-8093-3bc5571c9418', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-24', '17:30:00', null, '通常 / アレンジ大賞初級に挑戦', '最初に元のプログラムを見ながら、作品を作りました。次にアレンジに挑戦してもらいました。「アレンジ」という言葉にあまりなじみがなかったようです。具体例を私の作品で遊んで確認してもらいました。スコアが25点のときに、おわりの画面を表示するようにしました。むらっちの出る回数、クリックする回数が25点に満たないとうまくプログラムを終えることができないので、次週は終わりの条件の見直し、むらっちの出現回数の調整をするといいかなと思います。', null, '盛り上がり: アレンジ大賞の景品にとても興味ある様子でした。今日も1時間一杯取り組むことができていたので素晴らしかったです！'),
  ('a84b812c-0f0f-5fd0-92b2-0ccdafcd64f4', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-24', '18:40:00', null, '通常 / オリジナル作品の作成続き', '先週作っているゲームの広告ゲームの部分を作りました。アイデアが思い浮かばなかったようなので、私が作った作品を参考にしつつ、自分で新しいものを作っていました。「広告」というところに注目して作品を作ることができていました。キャッチゲームのような作りのものでしたが、広告から本編に戻るときに面白さがあってとても良かったです。', null, 'タイピング: とても集中して取り組むことができていました！スコアもかなり高かったです。
盛り上がり: とても楽しく取り組めました！'),
  ('0b53c385-9ea9-5523-87ba-8a09665111d7', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, null, '2023-03-24', '18:40:00', null, '休み（未対象）', null, null, null),
  ('8f06e66a-3db5-5789-8af6-fca8704281e0', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, null, '2023-03-24', '17:30:00', null, '休み（未対象）', null, null, null),
  ('10bd1cc0-d111-5f36-b06b-e1491adb6a6f', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, null, '2023-03-24', '16:30:00', null, '休み（未対象）', null, null, null),
  ('13f03cfb-6469-5312-97d7-37a69a302349', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '70028bf6-d858-5232-8ea5-b8b16ca0503f', '2023-03-23', '17:30:00', null, '通常 / 演算式を活用したスプライトの色々な動きを学ぶ', 'スプライトが画面端に近づくにつれて動きの速さを変える、スプライトの大きさの変化のスピードを少しずつ変える、ボールがバウンドするような動き、三角関数を利用した波状の動きやばねのような動きなどの説明を受け、自分でも作成していました。 なんとなくではありますが、理解はできたとのこと。', null, '盛り上がり: 説明を受けながら、他のPVのコードと照らし合わせて確認したりして、知識を吸収しようとする姿勢を見せていました。 最後のバウンドなどは、面白そうに取り組んでいました。'),
  ('76e94863-aaab-5834-a457-8f83106e6ea4', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-03-23', '16:30:00', null, '通常 / アレンジ大賞の作成', 'アレンジ大賞の作品を作っていきました。教室に来て浅いながらもアイデアは止まらずに作り続けていました。むらっちの色を変えて、その色の雰囲気に合わせて、音楽や背景を変えて作れていました。ただ、イメージをあるので、途中コードで困っていたのを助けていきました。そして、ダミーもつくり、それを押したらゲームオーバーになる仕組みで面白くなっていました。', null, 'タイピング: すくすくと進めていました
盛り上がり: 手を止まらずに作って楽しそうにやっていました。'),
  ('deefd34e-29cc-5e90-92cb-33505552e794', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-23', '17:30:00', null, '通常 / アレンジ大賞', '最初はいつものように自由作品を作っていたのですが、先週のマリオの続きをやろうと促すとやってくれました。まずは前回作った左右移動、ジャンプと同じ要領でパンチの動きを作りました。攻撃中かどうかを示す変数を使い、パンチしたときにHPを減らすのもできました。そして、HPが0になった時に不等式で判定して"1P(2P) WIN"の文字を表示しました。最後の方に、製作には至りませんでしたがアレンジのアイデアを話してくれました。虹色に光って大きなダメージを与える「スペシャルパンチ」を考えているそうです。', null, '盛り上がり: 作ったゲームで先生と対戦するのがすごく楽しそうでした'),
  ('c8ec407d-88c5-5077-8727-16ac203c6c3c', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-18', null, null, '通常 / アレンジ大賞作品の作成', 'ゆうかちゃんと一緒にアレンジ大賞の説明とゲームの説明をしているときは、ゆうかちゃんの反応がはやいせいか、うなずく程度でしたが、個人作成になって席をわけると発言ができるようになりました。 ゲームを可愛らしい雰囲気にしたいようで、選んだスプライトの編集などを工夫して熱心に作成していました。', null, '時間帯: その他
タイピング: 丁寧にできています
盛り上がり: 一人で作成を始めたら、発言や質問も増えて楽しそうに作成していました。'),
  ('e08ead57-79ba-537e-aaa8-211597db2dda', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-03-23', '16:30:00', null, '通常 / アレンジ大賞の作成', '前回に続いて中上級のアレンジ大賞の作品を作っていきました。基本は自分で考えながら作っていきました、アレンジでは第3勢力のすらぼーを作って、ランダムな動きで戦闘をかく乱するようになっていてとても面白くなっていました。', null, 'タイピング: 安定感が出ている'),
  ('6acdfc28-c697-5382-a4f7-c1f391b02a09', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-23', '16:30:00', null, '通常 / アレンジ大賞', 'むらっちたたきで遊んだあと作り始めました。写経してもいいと伝えましたが、できるところまで自力で作ることを選びました。オープニング画面を消してゲームスタートするところはできました。また、アレンジとしてはむらっちの頭の色にグラデーションをつけたり、背景を変えたりしていました。肝心のゲーム本体がまだ作れていないので、最後の方は本体の制作に移ろうと促しました。', null, 'タイピング: 英単語を頑張っていました！普段使わないキーがあったからか難しかったそうです
盛り上がり: アレンジを楽しんでいました。'),
  ('a610f311-6aa3-5f6d-ab43-54a5c0f324ab', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, null, '2023-03-17', '16:30:00', null, '休み（振替対象） / ⇒4/25（火）17:30～に振替え', null, null, null),
  ('45806518-35d0-518d-9b9e-c5918cccc836', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-20', '18:40:00', null, '通常 / アレンジ大賞続き', '前回の確認から始めていました。見本と見比べやすいようにパソコンをもう一台作りましたが、タブを移動して見比べるほうが快適な様子でした。とても集中して取り組めていました。体の上部と下部が別で動いてしまう事故が起きました。本人も怪しそうな箇所をピックアップして、原因を探していました。今まで作ったプログラムをよく確認する良い機会になりました。ブロックを外しながら原因を探す方法についても少し共有しました。理由はタイマーが怪しそうだという結論になりました。とても集中して取り組めていました！', null, null),
  ('eb2857d5-8184-5fc9-b72f-23b16a3dcb8d', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-20', '16:30:00', null, '通常 / アレンジ大賞', 'クローンは使ったことがなかったそうですが、クローンは分身だという話などをすると理解して写経しました。アレンジに関してはほうきでクモを追い払うものにすると決めて取り掛かりました。途中、スコアが加算されなくなるバグが起きましたが、クローンと本体の動きを混同していることが原因だと分かりました。「クローンされたとき」ブロックの使い方を説明すると修正できました。', null, '盛り上がり: やりたいアレンジの方向性がすぐ決まっていてすごいと思いました。'),
  ('1821566a-4fa8-516f-951a-69c1658ffbbd', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-20', '18:40:00', null, '通常 / 自由作品（最後の授業のため）', 'アレンジも大会を1時間でやりきるか、自分で自由作品を作るかを選んでもらい、自分で作品を作ってみるということになりました。 サッカーゲームを作ろうとしていた様子で、スピードが早くなるメーターや変数を組もうとしていました。参考にしていたのが過去問の２級問題。実際にやっていた問題を覚えていたのはとても素晴らしい！ ただスプライト同士のリレーションが関係して全てを完成するまでとは行きませんでした。 ただ、自分でやりたいものを決めてちゃんと作成しようとしたのは、良かったと思います。', null, 'タイピング: なし'),
  ('2efbe288-d186-5efc-bd0f-525a605c0d8f', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-20', '17:30:00', null, '通常 / アレンジ大賞に挑戦', '初級、中級の両方を遊んでもらいましたが、本人の希望で中級に取り組むことになりました。最初に「面倒くさい」と言っていましたが、いざ始めるとしっかり集中して取り組むことができました！「～回繰り返す」と「～まで待つ」を見間違えてうまくマリオが動いていませんでした。本人がプログラム的に怪しい箇所を探すことはできていました。見直しても間違いに気づくことができなかったので、注意力をもっと上げていきたいです。', null, 'タイピング: 集中して取り組めていました！！'),
  ('eaed0cab-cffa-5655-9670-e80cdecb672e', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-20', '16:30:00', null, '通常 / アレンジ大会 初級', '自分で変数を組み、むらっちが変数でさらに増えていくというコードを書きたかった様子、 ただクローンの動作自体が癖があるため、コードの組み立てとメッセージの送り合いに四苦八苦していました。 完成までとは行きませんでしたが、色々と自分で考えて組み立てようとしていたのは素晴らしい点だったなと思います。', null, 'タイピング: なし
盛り上がり: 最後の授業となったため今日は自分の発想を思う存分発揮してもらいました。 何かが完全にできなくても、ヒントがあれば「あぁそうか」と自分なりに理解できるということはとても素晴らしい能力の一つだと思います。'),
  ('7510bcd7-cdd6-5b9a-afb5-7d5653061b60', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-20', '16:30:00', null, '振替 / アレンジ大賞初級つづき', '前回の続きをしました。本格的にアレンジを進めていました！「スコアが40点以上になったら」の表現方法について共有しました。≧、≦をよく知らなかったようですが、説明後スムーズに使うことができていました。特定の点数になったらスプライトを消したいとのことだったので、「このスプライトの他のスクリプトを止める」というブロックの意味について紹介しました。スプライトに工夫を加え、とても面白い作品が作れています！', null, null),
  ('9f67df2f-2b65-5298-b6a7-e0e48101ca68', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-20', '16:30:00', null, '振替 / アレンジ大賞総選挙', '中級も気になるようですが、自分の出来る範囲でうまく作るということで初級に挑戦することにしました。今日はいつもと違う環境からかあまり集中もできず、気がかなり散っていました。ほぼブロックを書かずに「バグだ」と言っていたのが、残念でした。むらっちが出現する、クローンを使ったプログラムは完成させることが出来ました！次回はプログラムを完成させ、アレンジに入っていきたいです。', null, null),
  ('340aaf04-f8a9-53df-946e-ebb1976a12b7', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-20', '17:30:00', null, '通常 / アレンジ大賞', '自分でできるところはやって、できないところは完成版のコードを見ながら作るという形で進めました。ジャンプがよくわからないということだったので、座標の復習を軽くしたあとその部分を写経しました。移動やパンチ、キックは自力でできました。アレンジではルイージをオートで動くようにしたいと言っていたのですが、完成版と同じところを先に作り終わってからそっちに移ろうと促しました。', null, 'タイピング: きょうはココアタイピングとplaygramを両方準備していたのですが、珍しくplaygramをやってみていました。
盛り上がり: 賞は絶対取れないと言っていましたが、中上級のゲームでなくてもここから頑張れば可能性は出てくると元気づけました。'),
  ('08d93a7a-4ce0-50e9-800f-67de3d9e72ec', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-18', null, null, '通常 / アレンジ大賞作品の作成', 'アレンジ大賞の説明のときから、興味深そうに聴いてくれていました。クローンなど未履修のコードがあるため、なつめちゃんと一緒にゲームのコードの解説を聞いてもらいましたが、こちらの問いかけにも積極的に答えていて、コードを読み解くこともよくできていました。 むらっちのスプライトをガチャに変えたり、背景の色をグラデーションを使ってファンシーにしたりと、ゆうかちゃんらしい可愛いアレンジをしていました。 デザイン面では個性が出せたので、次回以降はコードの方でアレンジをしていこうと声掛けをしました。', 'コード面でのアレンジをしてもらいたいです。', '時間帯: その他
タイピング: 安定して高スコアを出せています。
盛り上がり: アレンジは好きそうで、終始楽しそうにやっていました。 色使いなど、ゆうかちゃん独自のアレンジセンスがよくできていて、声掛けをしたら嬉しそうに説明をしてくれました。'),
  ('5daa4183-5ad6-59f3-8d47-c74a7c2de699', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-18', null, null, '通常 / アレンジ大賞', '約束の時間までゲームをさせ、そのあとむらっちたたきのコードの写経をやってもらいました。今日はいつにも増して気が散ることが多かったのですが、ゲームの初期設定はできました。最後にみんなで今日の作品の見せ合いをしたのですが、そこではやりたいアレンジを話すことができていました。 パソコンやマウスを雑に扱って遊んでいたので、それは壊れちゃうからダメだよと伝えました。', null, '時間帯: その他'),
  ('0f9395f2-f85d-5565-b77c-48048cba8f7f', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-18', null, null, '通常 / アレンジ大賞', 'アレンジ大賞について説明すると、だいきくんはマリオのゲームを選びました。このゲームはすでにスクラッチで遊んだことがあるらしく、コードを見ると内容をほとんど理解したと言っていました。そのためコードをコピペすることで完全版の再現が終えました。そのあとは、HPが0になってもゲームが終了しないバグを直したり、音を追加したりという作業に入りました。デバッグができているので、コードの全体像や意味を把握することはできていると思います。', null, '時間帯: その他
盛り上がり: アレンジ大賞の賞品のことを説明しましたが興味がないようで、アレンジ自体をやりたい気持ちが強そうです。'),
  ('a92e5c6b-4dc2-5c68-9b17-f0cc0e40fcd6', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '25840600-1a86-5fb0-b223-dec47cec8c48', '2023-03-18', null, null, '通常 / アレンジ大賞総選挙', '最初から最後まで集中して、作品を作ることができました。', '初級課題が完成したので次回はアレンジ。 できれば 「どういうアレンジをするか決める→どれぐらいの時間で作るか決める→やってみる」 という手順でやったほうがいいと思います。', '時間帯: その他
タイピング: しませんでした
盛り上がり: 写経でしたが、途中でむらっちが出てくるところで画像を削っったり配置を調整したりするところではよく考えてできました。 課題の完成まで一生懸命取り組んでいました。
備考: 今日は以下のことを実行したため、最後まで集中して授業に取り組むことができました。 次回からの参考にしてください。 １、集中できない要素を取り除く 不要なタブ(ゲームなど)を消す、話を聞いているときにPCを操作させないことを徹底。 本人はわかっているので、ちゃんと注意すれば強く言わなくても大丈夫です。 ２、「もうちょっとまって」などの甘えに取り合わない 授業とは関係ないことや、今すべきでないことをしているときは、すぐにやめさせる。 本人もやるべきことはわかっているので大丈夫です。 ３、次のプロセスを守る 「何をやるか決める」→「どのくらいの時間でやるか決める」→「終わったら褒める」 ※時間設定は余裕を持った時間になるよう誘導。 ※集中が切れそうなときは残り時間を教えてあげる。 ※関係ないことをやっていたらすぐにやめさせる。関係ないことをやってるにもかかわらず「じゃあ〇〇が終わったらね」などとしてしまうと、集中できなくなってしまう。 ※「何をやるか決める」の部分は本人任せで、間延びしてしまうと集中が途切れる原因になりかねないので、対応には注意 授業後も家でアルスパークを使ってアレンジしたいと言っていたりと 集中して授業に取り組むことは、本人の充実感にもつながるので、次回もうまく集中して授業に取り組めるようにフォローをお願いいたします。'),
  ('8005abc7-e935-5c51-ab31-9e01276196af', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-17', '18:40:00', null, '通常 / アレンジ大賞作品の作成', 'アレンジ大賞の説明をしたとたんに、「アレンジしていいの？！」と食いついてきました。 むらっちのスプライトをすぐに戦闘機に変えて、熱心に元のコードを見ながら写していました。 コスチュームで図を回転させたり絵を足したりと、デザイン面、プログラム面の両方から頑張ってアレンジをしていました。', null, 'タイピング: 今日はすぐにプログラミングをやりたいとのことで、飛ばしました
盛り上がり: アイディアがどんどんわいてきて、お迎えがきてもしばらく止まらずに作成を続けていました。 戦闘機のパイロットを足したりセリフを足したりと、最後まで集中してアレンジをしていました。'),
  ('3ce42fb0-1658-5050-8798-5ae900108585', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-17', '18:40:00', null, '通常 / 自分の作品作成続き', 'リストのゲームはとりあえず完成した様子。ただ間違えたらゲームにするというのは、なかなかメッセージを送るのが難しかったようで、新たにゲームを作成していいか？と聞かれたため最後だしと思い、ひとまず自分なりに作品として作れるものを作成してもらいました。 まだ作品の途中なので来週どうなるか？は分かりませんができるところまでやってもらえたらそれでいいかなと思います。', null, '盛り上がり: １級が受かって嬉しそうでした。'),
  ('6bbe107c-9569-555b-b09b-200b7d1d3e65', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-17', '18:40:00', null, '通常 / アレンジ大賞に挑戦', '全てのプログラムを遊んでから選んでもらいました。1時間とても集中して取り組むことができていました。ひとつのスプライトではなく、いろいろなスプライトのプログラムを少しずつ進めていました。うまくプログラムが動かないことがあったようですが、メッセージと変数の名前が間違えやすいことを共有して、よく確認してもらいました。次回も続きをします！！', null, null),
  ('42585e04-e0d5-51c2-b213-0a7688f7a38f', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-17', '16:30:00', null, '通常 / アレンジ大賞作品の作成', '持参したPCのレスポンスが悪く、途中で教室のPCに替えました。 数回遊んだ後は、自力でアレンジしながら作ってみたいと言って、考えながら頑張っていました。 お迎えの時間まで頑張って、ゲーム部分はほぼ完成できていました。', null, '盛り上がり: PCを替えてからは調子が良さそうで、熱心に進めていました。 ニコニコしながらちょっとスプラッタなアレンジをしていました。'),
  ('4387ce96-e7d9-5cd2-9bce-1daa81e2a02f', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-17', '17:30:00', null, '通常 / アレンジ大会用のゲーム マリオゲームをアレンジする', '今日はクラス前に友達と遊んできたらしくちょっとお疲れモード。集中力も欠いていて、どのコードを今自分が書いているのかが分からなくなっている様子でした。 隣にいて、「どのコードを書いているか？」を聞きながら、やっていました。 まだ来週もしばらく全体のコードを写すというのに時間がかかってしまいそうなので、ちょっとせっついてやらせた方がいいかなと', null, 'タイピング: なし'),
  ('e0292f15-76be-5f30-b914-24e04d8f8038', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-17', '16:30:00', null, '通常 / アレンジ大会用の中級ーマリオゲーム', '最初に難しい中上級でもOKだよと話したら、アレンジがしにくそうと本人が言ったので、結果マリゲームの方でアレンジ作品を作成することになりました。ひとまずコード全体を写してゲームを完成させるところから。 やっている間にわからなくならないように、それぞれのブロックの塊にコメントを追加して自分で後で理解しやすいようにしていました。ひとまず今日は全部写すので精一杯だったぽいので、来週は自分でアレンジするところからだと思います。', null, 'タイピング: 集中して行っていました！
盛り上がり: 自分でアレンジしやすい方を理解している、写している最中にどういうコードを書いているのかを真剣に読んでいました！'),
  ('e193032e-3cc7-54e2-852b-1e5ab72d6405', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-17', '16:30:00', null, '通常 / アレンジ大賞に挑戦！', 'ゲームの内容は自分でなんとなく考えられている様子でした。むらっちが出現するときの見た目がうまくいっていないようだったので、コスチュームについての考えを共有し、プログラムの間違っていそうな箇所を自分で探して確認していました。見本と同じようにプログラムした後、オリジナル要素として追加したゴールドむらっちが出現する間隔を調整していました。クローンの考え方を共有してから工夫してもらうと、表現の幅が広がるかなと思いました。', null, 'タイピング: 集中して丁寧に取り組めていました！！'),
  ('7cccf476-b3bd-524f-8432-ecbcd6248fd9', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-17', '16:30:00', null, '通常 / アレンジ大賞作品の作成', '1時間、離席もせずに集中して取り組んでいました。 むらっちの他にひっかけキャラを作って、得点がマイナスされるアレンジを作成していました。コードもよく読んでいて、必要なコードのみをむらっちのスプライトを見て写していました。 一つ目のアレンジがちょうど時間内に終わりました。', null, '盛り上がり: やりたいアレンジがすぐ思いついたようで、楽しそうにアレンジしていました。 思うように表示ができなかったときも、自分でコードを見直して修正できて、得意そうにしていました。'),
  ('c8d2ea5a-1416-5258-b0b0-f16d7b480e54', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-17', '16:30:00', null, '通常 / アレンジ大賞に挑戦', 'スプライトを変更してプログラムを始めていました。コスチュームの順番に注意して、うさぎの滑らかな動きをプログラムすることができていました。最後に、クリア条件を設定していました。もしの使い方で混乱していましたが、最後にはうまくクリア画面を出すことができていました。次週はレベルアップさせて次のステージをプログラムしたいそうです。', null, null),
  ('b457964d-751e-5554-9fb3-b9d8663e67fb', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-16', '17:30:00', null, '通常 / サメから逃げろの完成、応用', 'サメから逃げろについては、サメに食べられたら隠すのだけできていなかったので、「もし～に触れたなら」を教えて完成させました。また、かずまくんの希望で隠れると同時に音を鳴らしました。さらに、タイマーで逃げた時間を記録したいとも言ってタイマーをつけました。 そのあと、レッスンから「アイスを食べに1」を始めました。数字を入力するところで全角になっていたため、全角と半角の違い・切り替え方を伝えました。一番最初の座標だけ決められました。', 'アイスを食べに1続き', 'タイピング: 徐々に慣れてきています
盛り上がり: 話が脱線することがなくなったわけではないですが、題材となったゲームに興味をもっているのである程度集中できています。'),
  ('0c3fb4ba-6c9e-54a6-94da-879ada94d117', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-16', '17:30:00', null, '通常 / アレンジ大賞作品の作成', 'マリオのコスチュームを丁寧に見ては考え込んでいました。攻撃の種類を増やすアレンジをしてみたいとのことで、コスチュームと攻撃の関係などを調べていたようでした。 スタート画面のボタンなどを熱心に作成していました。', null, 'タイピング: 相変わらず猛スピードで熱中していました
盛り上がり: ゆきちゃんは、元になる作品がある方がイメージがわきやすいようで、楽しそうにアレンジを考えていました。'),
  ('97aac9a3-c2c1-578e-9ffd-2c408a78b7f4', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-16', '17:30:00', null, '通常 / アレンジ大賞作品の作成', '中級と中上級をじっくりプレイした後、自分なりのアレンジがしやすそうだからとマリオを選んでいました。 承太郎君なりのゲームの開始イメージがあるようで、スタート画面から作成をしていました。', null, 'タイピング: ゆきちゃんと結果を見せ合いながら、かなりの勢いでやっていました。前回の毎パソの反省からか、ミスタイプを減らそうとする努力が見受けられました。
盛り上がり: スタート画面の作り込みなどが得意分野のせいか、楽しそうにサクサクと作っていました。
備考: 検定の結果を口頭で伝えたところ、「あー、よかった～」とほっとしたようでした。'),
  ('12496826-b3af-57d2-bbed-31b0744402ab', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-16', '17:30:00', null, '通常 / アレンジ大賞', '「完全に自分で作っていたら時間が足りなくなる」ということで、完成版のコードを見ながらやりました。ただ自分で理解しながらやっていたので、何を作っているのか聞くと毎回答えられていました。移動とジャンプまではほぼ完成して、攻撃やHPの設定は途中までできました。', null, '盛り上がり: ずっと集中してできていました。'),
  ('bd04c4ad-030f-5354-936f-b5911ea2ae57', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-16', '17:30:00', null, '通常 / アレンジ大賞', '今日はとても久しぶりにみんなと同じ題材に取り組んでいました。まずは左右移動とジャンプからやったのですが、座標のことを忘れていてx座標とy座標が紛らわしいようだったので復習して作りました。途中で背景のアレンジをしていたのですが、まずは基本の動きを作ってみようと促しました。「先生、わかんないからヒント出して！」と言われることが多く、あまり多すぎない範囲でヒントをあげました。', null, '盛り上がり: マリオのゲームに興味を持ってくれました。'),
  ('3804c426-bf01-5db4-b928-c329fb0c9395', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-16', '16:30:00', null, '通常 / 基本操作コース03_世界を創造しよう3～ 基本的なコードの習得', 'スプライトの左右の動きをカードを見て作成したら、そのまま何も見ずに上下の動きを作成できていました。x座標とy座標の違いについては、きちんと理解できているようでした。 左に動かすときに後ろ向きなのを改善したがったため、向きと回転方法の指定の説明をしました。回転方法は体験のときのことを覚えていて、解決したときはとても満足そうでした。 05あたりから、まとまったストーリーとして作成したがったため、単元のコードを取り入れながら話がつながるように作成していきました。その過程でメッセージの送受信を使いました。', '「06_物語を作ろう」を、おさらいを兼ねて見直した後、オリジナル作品', 'タイピング: 数字の早打ちをした後、ドラゴンタイピングに取り組んでいました。
盛り上がり: ストーリー性のある作品を完成させることができたからか、満足げにしていました。先週よりも「ここはこうやってみたら面白いんじゃないか」など自発的な発言が増えたため、答えられそうな場合はゼロの状態からの発問を少し増やしてみましたが、きちんと考えて答えてくれました。
備考: 好きなスプライトはグリフィンなどの架空生物だそうで、ネッシーやチュパカブラなどUMAに興味があるそうです。自由時間はスネークゲームで遊んでいました。'),
  ('e6bf313c-6d8f-5b2f-ae20-2f1faade0de6', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-16', '16:30:00', null, '通常 / 先週の復習、アレンジ', '前回のキャッチゲームをおさらいしつつ、アレンジ作品に取り掛かってもらいました。サッカーのキーパーとしてボールをキャッチするゲームを作ることに決めました。前回は画面上のランダムな場所にケーキを配置しましたが、今回は画面下にするなど応用していました。スコアをつけるのも前回同様できていました。キーパーがボールを取ったらボールが反射するようにしたいとのことでしたがここで詰まっていました。角度を変えてみるというヒントは伝えましたが、試行錯誤して時間内に答えが出なかったので次回に持ち越しです。', '続き', 'タイピング: 今日の敵は楽勝だったそうです
盛り上がり: 来たときは眠そうでしたが、やっているうちに楽しんで目が覚めていました。'),
  ('e549d188-08e5-5089-8466-7315629d6166', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-16', '17:30:00', null, '振替 / アレンジ大賞作品の作成', '同上', '同上', '盛り上がり: 同上'),
  ('e827295c-d8c0-5f43-a9ea-4850eaee5e75', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-16', '16:30:00', null, '通常 / アレンジ大賞作品の作成', 'アレンジ大賞の中級と中上級の両方をプレイして、参加作品を決めていました。 プレイヤーと手持ちのアイテムのアレンジを考えていると言って、素材のみの状態からスラスラとコードを組み立てていました。 難しい所は完成版を見ていると言いつつも、頻度はそれほど高くなく、自分で考えながら作成できていました。', '他の生徒さんの参加状況を見て、このままアレンジを続けるか、中級のマリオに変えてもらうか要検討', 'タイピング: プラチナ級を安定して出しています。
盛り上がり: 2時間連続で、途中身体が疲れた様子も見せていましたが、最後まで熱心にアレンジに取り組んでいました。'),
  ('bec9d2aa-e95e-51c6-ab7b-4a435fb7c375', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-09', '17:30:00', null, '通常 / できればサッカーゲームを作る', 'レッスン時間が始まる前から作成を始めていました。オリジナルのキャラクターを描いて、スプライトに使っていました。キーによる上下左右の移動ができていました。', null, null),
  ('06717865-e6f3-523d-8561-53db0e0129af', '7d01236e-620e-5177-a6f4-af325a582aae', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-03-14', '17:30:00', null, '通常 / チーズを探せアレンジ ドリル', '前回完成したチーズを探せを作成したので、そのアレンジをやりました。もとからいた邪魔者をあちこちに動かしたいとアイデアが出たが、なかなか進まなかったので、回転と乱数を使ってみては助言しました。そこからは邪魔者が迷路の枠内に動くように前回作ったものを振り返りながら自力で作ることができました。ただ、回転を2連続に左右回転を入れてしまって回転しないくなるバグをなっていたで、コードは一瞬で進むからできないことを伝えました。 次に、今まで習ったことを復習するためにドリルをやりました。直角に曲がりながら進む問題では、さっき回転のものを扱ったから楽々できました。斜めに進み続ける問題は、なぜか座標移動でやっていてなんか問題の意図を勘違いしていたそうでした。', null, 'タイピング: やっぱ早いです
盛り上がり: マリオみたいなゲームを作りたいそうです。'),
  ('649ef1b2-3e8b-5050-9da2-3105e916b154', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-14', '17:30:00', null, '通常 / 乱数、得点など、基礎も一通りおわったので自由製作。2回分あるし。作りたい内容を手で書く。細分化など。', '自由製作にしようと考えていましたが、アイデアが思いつかなかったようなので見送りました。座標についてやりました。「～と～」のブロックをうまく使うと座標の値と別の言葉を組み合わせられること、ぬるぬる動かすときとそうでないときの違いについて説明しました。どれもなんとなく理解できた様子でした。 最後に、iPadでドット絵のアプリを使って絵をかいてもらいました。操作にはかなり慣れたようです。ドット絵じゃないほうがいいかもしれません。', null, 'タイピング: ゆっくりでしたがしっかり取り組めました。'),
  ('ebd9287c-28b4-51f8-bb8e-f9e5a9c0b568', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-14', '17:30:00', null, '通常 / 自由作成（前回の続き）', '本で読んだことを再現していました。ぶつかったあとの動きのプログラムで苦戦していました。変数の中身を交換する順番に悩んでいたようです。最終的には自分で正しくプログラムを作ることができていました。現実世界で弾が衝突するときの様子についても共有できたので良かったです。', null, 'タイピング: いやいやながら集中して取り組んでいました。'),
  ('6fc6daa8-6a16-541b-b765-34823da8bed9', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-14', '16:30:00', null, '通常 / エネルギーをためてビームだす（よく考えてプログラムする）', '自分が表現したいことを、どの場所にプログラムするべきかについてよく考えながら取り組んでもらいました。 あるくんがクルクルするプログラムは自分でできました。ビームは長押しの方法に少し困っていたようです。「～までくりかえす」「～ではないまで待つ」の使い方について詳しく説明しました。ビームを動かす過程では端まで動かすにはどうすればよいのかについて考えることもできました。最後には、一度動かすだけでなく、繰り返しプログラムが動くようにすることができました。', null, 'タイピング: ポジションに注意して丁寧に取り組むことができました！！'),
  ('22f2ffc4-36b9-5263-b2fc-d3d8c4d5ebb2', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-03-14', '17:30:00', null, '通常 / 自由作品', '検定後だったので、自由製作をしました。鬼ごっこ的なものを作り、順調に作り進んでいたが、端にたどり着いたら背景転換する仕組みが一方通行しか変わらなくて悩んいました。そこで、背景にも個別に番号を振り分けられていることを教えると、その悩みは解消できていました。次くらいで完成はできると思います。', null, 'タイピング: 集中して取り組めていました。'),
  ('78be3e4f-22c2-56ab-83db-ff4ffc4cc391', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-03-14', '16:30:00', null, '通常 / ビームを打とう', '最初に検定が合格できたことなので、検定問題の振り返りをしました。作ったものを見たところ、魚が釣り針に捕まった時に魚のセリフがていませんでした。使用するブロックはすべて組めていたが、コードを停止させるコードが「すべてを止める」になってバグになっていたので、停止させるコードの種類を確認させました。 次に、為雄氏をしてビームを発射するものを作りました。ようくんには少しレベルが高いブロックがあるので、「ではない」や「まで繰り返す」などの知らないブロックについては使い方を紹介する呈で作っていきました。作っていく際でバグになったところは、半分くらいは自分で気づいていました。演算を使用するところは苦戦しました。', null, 'タイピング: 一瞬で終わらせました
盛り上がり: ビームが発射することよりも渦巻でぐにゃぐにゃになる方が楽しんでいました。'),
  ('500d1bf6-c9c1-5579-8714-f4636b391001', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, null, '2023-03-07', '16:30:00', null, '休み（未対象）', null, null, null),
  ('0c7fc94e-0df5-552e-881a-a06a3aa16238', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-13', '18:40:00', null, '通常 / 検定の見直し、ビームの発射プログラム', '一緒に検定の問題文とコードを照らし合わせて確認しましたが、間違っている箇所はなかったので、減点はアレンジをしていない分だけと思われます。そのあとビームの発射に移りました。問いかけで誘導しながら進めていき、以前使った「ではないまで待つ」や、今回マスターしたかった「まで繰り返す」を使ってビームを発射できました。ビームの大きさを変えるところまではいかなかったので次回続きをやります。', '続き', 'タイピング: 丁寧に打てていました。
盛り上がり: 目の前のコードに冷静に向き合っていました。'),
  ('f725395b-c94d-5d21-8abd-40807a1ccef4', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-13', '17:30:00', null, '通常 / 前回の図形の応用、クローンの活用', '先週の円を描くプログラムを復習し、「～歩動かす」と「～度回す」の両方を繰り返し行うことを振り返りました。今回もそれと同じように作れると伝え、作り始めてもらいました。 スプライト本体の動きとクローンの動きがごっちゃになっていたので、前者は「旗が押されたとき」、後者は「クローンされたとき」で作ればいいということを説明すると、両者を分けてバグをなくすことができました。一通り作り終わったあと、戦闘機が弾をよけ続けるゲームにアレンジしたいと言ったのでやってもらいました。生存した時間をタイマーで表示したり、弾の色を変えたりとしゅうくんの思う通りに改造できました。', null, 'タイピング: 少しスコアが下がってしまって残念そうでした。
盛り上がり: うずまきの模様に美しさを感じて面白そうでした。'),
  ('c4067d29-5f92-51ba-8035-90577de1f000', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-13', '16:30:00', null, '通常 / リストや箱としての変数をマスターする', '最初に、県名と県庁所在地名をそれぞれテキストファイルからリストにしました。文字列をtxtファイルとして保存する→空のリストにそのファイルを読み込むという流れをやってもらいました。 そのあと、箱としての変数iを使うことを伝えてコードを作り始めてもらいました。iは抽象的なので使い方を間違えているところもありましたが、iに具体的な値を入れて説明してみると理解して直すことができました。リストに関してはもともとよく分かっていたようで、「リストの〇番目」や「リストの長さ」などのブロックを使いこなしていました。', null, '盛り上がり: 県庁所在地を社会科でやったそうです'),
  ('94a5a5b3-e534-588a-b2be-dc587b28edd7', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-03-13', '17:30:00', null, '通常 / ゲームから見て１から作ろう', '検定問題から面白いものでゴーストシューティングを作りました。少し使うコードを指定して考えていくようにしていきました。どのように作れるか言葉して話してくれることはいいが、最初からがっつり完成したコードを作ろうとしたので、ただの写しにならないように止めました。乱数で座標の範囲を指定する際に、乱数の上限と下限がxy座標で混乱していました。乱数の範囲の決め方をしっかりとらえるために、ゆっくりスプライトを動かしながら確認しました。最後、ゴーストが十字架に当たる判定を作ったが、動くブロックを何秒で動かすブロックで作ったため、バグが残って終わりました。', null, '盛り上がり: ゲームから読み取る力は上手くなっている。'),
  ('e18b9abf-3b00-58da-9f15-ea71159f5a6e', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-13', '18:40:00', null, '通常 / 県庁所在地のリスト問題と、検定問題１級の復習', '検定１級合格！89点 で一応問題の復習をして、不等号の問題だけがミス（＜のみを使って数字と変数を入れ替えて表現してたので動き的にはあってる）なので、問題通りに解いていたら100点だったかと思います。 リストは、途中まで一緒にやってiというもの自体が箱という観点を確認したのと、リストの使い方を確認しました。リストは使い方が難しいものの、説明すると使い方自体は大丈夫そうだったので、来週は完成まで終わらせたいと思います。', null, 'タイピング: なし
盛り上がり: 検定が合格して嬉しそうでした！'),
  ('899ed36b-0251-5bf6-86f4-c782c042cbd0', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, null, '2023-03-13', '16:30:00', null, '休み（未対象）', null, null, null),
  ('41501482-42d1-572c-b624-9729c540f1a2', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, null, '2023-03-13', '16:30:00', null, '振替', null, null, null),
  ('378058b0-09c5-5a88-ba4b-9b10953b82a8', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-06', '17:30:00', null, '通常 / 先週の続き', '先週終わらなかった部分、分からなかった部分について動画を参照しながら作りました。変数でボールを加速・減速させるところが難しかったのでじっくりやっていました。時間終了時の処理なども含め、ゲームとして完成させることができました。', null, 'タイピング: 楽しくやっていました
盛り上がり: 少し大変そうではありましたが、投げ出さず完成までいけました。'),
  ('5c853044-ebc7-52a9-8dcd-f0d83975fffd', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-11', null, null, '通常 / 条件分岐の練習', '「もし～なら」の分岐が苦手なようなので最初から順にやってもらおうとしたのですが、1問目が解けたことを確認したところで「これ(1問目)のアレンジがしたい」と言ったのでそちらに移行しました。アルくんが移動した場所にクローンが残るというものでした。クローンを作ったあと「クローンされたとき」のブロックを使っていなかったので、それを使って続きを作ることを促しました。また、クローンは個数制限があることなどを伝え、クローンについての理解を深めました。', null, '時間帯: その他
タイピング: ふざけて違うキーを連続で押したりして遊んでいたので、タイピングを少しでも面白いと思ってもらいたいです。
盛り上がり: 自分で何か作るのが楽しそうです。'),
  ('392aec65-deb3-58c1-ad79-b782833728f7', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-11', null, null, '通常 / 【小技】アル君グルグル＿スタンプで、スプライトの変化を楽しむ', '今日は気分が完全にロボットに向いていて、最後までロボットをやりたいと訴えていました。 約束した時間までゲームをさせたところ、一度は席について前回の作品の説明をしてくれました。 今日の教材を提示して、前回ならった画像効果を変更してみたり、数値を変えてどこが変わるか見てもらうところまではできましたが、そのあとは、追いかけっこをするゲームにしたいと言いつつPCやマウスを隠そうとして遊んでいました。（備品を動かすことについては注意済み） 最後の方の時間では、iPadでお絵描きを楽しみました。', null, '時間帯: その他
盛り上がり: 画面上のことに少し飽きているのか、やたらと物を触りたがっていました。 こうくんにやたらとなついていました。'),
  ('622a2fbb-0d97-5ee0-a6e5-5aedcc6c8560', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-11', null, null, '通常 / 乱数の使い方、条件分岐の使い方 【DKゲーム】02迷路 チーズをさがせ！', '乱数を使ったサイコロはすぐに完成できて、サイコロの目が１から3までしか出ないようにして、のような発問にもすぐに答えられていました。 チーズを探せの細分化について、まだ動作のきっかけが曖昧なことがあったりもしますが、（チーズがランダムに移動するタイミングなど）、基本的なゲームの仕様に慣れることでできるようになりそうです。 壁にあたって跳ね返る動作について、-歩動かすタイミングに悩んでいたので、スプライトの一覧を注意してみるようヒントを出したところ、迷路のスプライトに触れたら、という条件を作ることができました。 変数はよく覚えていて、自分でスコア変数の作成、初期値設定、10ずつ変えるところまで作成できていました。', 'ねずみ以外のスプライトのコードを作成', '時間帯: その他
タイピング: まじめに取り組んでいました
盛り上がり: 細分化シートのスプライトの絵を丁寧に描いていて、嬉しそうに見せてくれました。 一つコードが完成するたびに、嬉しそうに見せてくれました。'),
  ('6ab2085b-4840-597f-928f-d23764829459', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-11', null, null, '通常 / PRGのゲーム制作', 'PRGの中で興味を持ったビルのゲームを素材のみverから作ることになりました。最初は等速ジャンプを作っていたのですが、途中で速度を変えたいとのことだったので、一度に変えるy座標の値を一定ではなく変数を使ってだんだん大きくしていくといいというヒントを出しました。試行錯誤ののちに滑らかなジャンプを作ることができました。ビルの動きは未完成だったため、来週続きをやるかもしれません。', '【Prg】34 ビルのすきまを抜けよう！続き(あと少しで完成)', '時間帯: その他
タイピング: もくもくと練習しています。
盛り上がり: どういう動きを作りたいのか、現時点では何ができていないのかなどを言葉にしてくれました。'),
  ('e31c7df5-9331-5f3a-a5b0-f2ad4f9ef5bb', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-11', null, null, '通常 / PRGのゲーム制作', 'PRGのゲームの中から好きなものを選んで、素材のみverから作ってもらいました。ゲームを遊んだあと、「だいたいのイメージは持てた」と言って作り始めました。鳥の変速ジャンプについては、スピードの変数を使って自力で作れました。鳥の角度を変えるところで詰まっていたので、「特定の角度になるまで回転させ続ける」というヒントを出しました。それでも自分ではわからなかったようで、お手本のコードから該当箇所を見つけて理解した様子を示し、そのコードをもとに作りました。ビルの動きについてはクローンを使うこともあってだいきくんには難しかったようで、ほぼコピペのようになってしまいました。最終的にはちょっとしたアレンジも加えてゲームとして完成しました。', null, '時間帯: その他
盛り上がり: ゲームを作る工程を楽しんでいます。'),
  ('81722266-83b0-5d15-b672-838faffed0da', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, null, '2023-03-11', null, null, '休み（振替対象）', null, null, '時間帯: その他'),
  ('b3142cc4-6b4c-52b8-9ea4-d2c4f48a505a', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-04', null, null, '通常 / ピンポンゲーム', '細分化を紙に書いてもらうと全体像がイメージしやすいと思って勧めたのですが、できるところから順番にやるのを希望したのでそうしました。マウスのx座標を使う場面は難しくて少し止まってしまいましたが、どういう動きを実現したいかを問いかけを通して整理していくと答えを出すことができました。スコアの変数のところは割と簡単に作れていました。', null, '時間帯: その他
タイピング: 安定して打てています。
盛り上がり: 分からない場所をしっかり考えることができました。'),
  ('a34f2116-edd2-5260-ac94-5436261d5bbf', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-10', '18:40:00', null, '通常 / アーチェリー', '矢印の動きは自分でしっかりと考えて取り組むことができました。矢印の向きを表現できるブロックを説明し、矢印が飛ぶようにしました。途中、なぜか特定の方向にしか飛ばないバクが発生し、原因を一緒に探しました。原因は、「端にふれまで～」のブロックがあったにも関わらず、矢が回転するときに端に触れてしまっていたからでした。 重力を表現するところまでいきませんでしたが、一時間集中して取り組むことができていました！', '次回は続きからです！！', null),
  ('d2e66fd2-f0e5-5e59-8598-46ae8d89fd2e', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-10', '17:30:00', null, '通常 / うずまき作品/ビーム', 'スペースキーを長押ししたあとに、ビームがでてくること、大きさを変えることをしっかり理解できていました。説明もできていたので良かったです。「スペースキーを離したとき」の考え方が難しかったようです。どこにプログラムを書くのかを質問してくれることが多かったのですが、徐々に自分で考えていってほしいです。 変数の使い方も復習しました。最終的には納得のいく形になったようです。', null, null),
  ('9eeac537-722b-58f4-851e-eacbc3b214a4', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-10', '16:30:00', null, '通常 / チーズを探せwith邪魔者 or 火山岩', '下で逃げる白鳥は自分でできていました。落ちてくる弾丸を上に設定することはできていましたが、乱数を使うことを提案しました。下に移動させるときに秒数、座標のどちらも乱数にして面白いゲームにしていました。座標を使う機会が多かったのですが、座標の上限と下限の意識が薄いようでした。出現させるタイミングを変更したり、体力として変数を設定することができていました！ゲーム自体は完成しました！', null, 'タイピング: 集中して取り組むことができました。'),
  ('36ee7e0e-998b-5208-9bc3-888480079e73', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-10', '16:30:00', null, '通常 / お花が咲いた【判定】', 'プログラムの内容を紙に書くことができました。ユーザーのアクションとリンクさせて書くことが少し苦手なようです。 雲に触れたときの判定を、太陽のコスチュームを変えて表現していることに気が付くことができました。変数の値を間違えてしまったため、正しくプログラムが動いていませんでした。プログラム全体を見る力がもう少しあるといいかな思います。判定については一緒にプログラムを見て確認することができました。', null, 'タイピング: 集中して取り組めていました！'),
  ('5ef4c521-76eb-5b93-8386-aae78d901875', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-10', '18:40:00', null, '通常 / 2週かけて（休会もあるので）少し長めの作品作成にトライ 都道府県のリストをまずやって（おさらいかねて）▶︎まちがったらゲーム▶︎正解するまで終わらないという作品作成につなげたい', '県庁所在地の部分は10個ぐらいを最初におこなってどのような変数があって、それがどうリストに繋げたらできるのか？を最初に理解してもらいました。 iの変数の部分が難しいので最初にiという箱の中に何個分のリストが入っている意味で変数を組んでいるんだよ〜と話したら、すぐにコードをかけていました。 そのあと２週をかけて何かのゲームに繋げてもらいたい話をし、リストで不正解になったらゲームをするという作品へ▶︎自分の好きなキャラクターのリストの問題に変更し、ゲームは来週ということになりました。', null, 'タイピング: お得に寿司を購入できていた様子です！
盛り上がり: ちゃんとリストの使いかた変数の使い方をマスターしており、すごく良かったと思います！'),
  ('18c2a0de-224c-59e9-86b1-0bf291f0ccfd', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-10', '17:30:00', null, '通常 / ビーム（まで待つ）', 'スプライトを変えてオリジナル要素を取り入れていました。ゲームの内容も自分でしっかりと把握することができ、自分の中で簡単に整理してプログラムすることができていました。「スペースキーを離したとき」のプログラムの仕方が難しかったようです。「おされた＋ではない」の組み合わせを説明しましたが、「日本語がおかしい、気持ち悪い」とのことでした。最終的にはゲームとして完成させることができました！！', null, 'タイピング: 集中して取り組むことができました！'),
  ('45532b17-6ff3-5f14-88be-c74d1cd3d113', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-10', '17:30:00', null, '通常 / ビームを作る https://app.arspark.jp/projects/29333/editor', '最初の動きの部分でかめはめ〜からのハーでビームを送りたかったのですが、その部分からつまづいていて、どうにか順番をかえて再現しようとしていました▶︎ここで必要なのはスタートの人がいないと、旗が押されたと、スペースキーが押されただけでは再現できないということを理解してもらい、そのあとは、なんとか自分で順番を組み、時には私と相談しながら最後までビームを作るまでできました。 （ただしビームの部分に関してはお手本を見ました）', null, 'タイピング: いつもと同じように調子良くタイピングしていました
盛り上がり: 一番良かったのは、プレイヤーの座標をちゃんと変数で作るということに気づいていた点と、ビームの位置が出る時に演算と変数をどう組み合わせたらいいのか、もしくは〜座標というコードを使うのかキチンと理解できていたということ、また〜までないまで待つは使えていたのですが、〜までないまで繰り返すではないとコードが作動しないということに気がつけた点でした。'),
  ('0660ebd1-2bdd-5b5c-bbc5-168a22847e0d', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-10', '16:30:00', null, '通常 / 基本操作コース05 音を作って遊ぶ▶︎自分で音楽を作って、ゲームに転用することを学ぶ', '音を作る時のコードの注意や、音階を番号でプログラミングは理解していることを、説明。最後にこぎつねこんこんを自分で描いてもらって、定義にするとコードを省略できるよという話までしました。', null, 'タイピング: 8割はタイプミスがなくなってきているので、先月よりも1割ほどアップしているなと思いました。
盛り上がり: すべての音階をかいて、こぎつねこんこんを作曲していました！集中力があってすばらしい！'),
  ('5667a564-7758-57f0-bd77-3c3636f1e71d', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-10', '16:30:00', null, '通常 / 自分の作品の続きから', 'バグがあり、そこを潰そうとして呼ぶ回数が多かった日でした。で肝心のコードですが、メッセージの送り合う部分が重複しているせいかうまく作動してない状態がありました。 私でも初見ではわからないので説明を聞きながら、作成したのですが、そもそものスプライトが押されたらコスチュームが変化するなどの初歩的な部分が忘れていたせいで余分なメッセージを送り合うことが続いていたためだと思います。 またメッセージの名前を「a」や「b」などの単語にしてしまい、それもあってかどのメッセージが本当に動かしたいコードに繋がっているのか本人も混乱している状態でした。 なので、メッセージは今後、ちゃんとした名前にすることを約束し、次の週も同じ作品を作ってみて、ちゃんとメッセージが送り合える状態まで完成させたいと思います。', null, 'タイピング: うでだめしで、上位20％のうでだめし上位２０％に入っていました！
盛り上がり: コードの中身を複雑にしようとしている部分はとても良い（複雑に慣ればなるほど、面白くなるというのはわかっているので）'),
  ('b4a4c3ff-28ef-5271-b678-b437df36eeff', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-09', '17:30:00', null, '通常 / キャッチゲーム', '始まる時間の3分後くらいに来て疲れた様子だったので水や飴を勧めたのですが、やる気はあったようで、断ってすぐにプログラミングを始めました。 画面の一番上や一番下を表現するのにy座標を使えばよいことを理解してくれました。左右の移動は最初「～キーが押されたとき」を使っていましたが、「もし～キーが押されたなら」にすると滑らかに移動できることを思い出して切り替えていました。途中、「もし～なら」の条件を何にするか迷うことがあったため、「調べる」か「演算」を探すといいと伝えると選ぶブロックを見つけられました。スコアの変数については、一度触れただけなのに何点も追加されるバグが出ました。そのため、1点加えたらすぐにケーキ(リンゴ)を上に戻さないと何回も反応することを説明すると修正できました。', null, '盛り上がり: お迎えのお父さんや弟さんにも嬉しそうに完成品を見せていました。'),
  ('95dd5050-dfee-523c-8111-b5b23ccb9952', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-03-09', '17:30:00', null, '通常 / 自由作成', '検定を終わって初めてだったので、自由に作品を作ってみました。過去に教室以外で作ったものを組み合わせて作ってくれました。作ったものは、ステージをスタンプを使って作っていました。この発想はステージ生成後に行動をしなくていいのでクローンから余分なものを省いた良い発想だと思いました。クローンを扱うには早いほかの子にも使えそうな気がします。また、重力落下を使ったじゃんっぷも困ることなく作れていました。 この自由製作で部長のまだ見ぬアイデア見れた気がします。', null, 'タイピング: ミスタイプを少なくしたく、やり直しが多かったです。
盛り上がり: 教室が近ければもっと期待といっていました'),
  ('0d06c298-12a4-5c08-b11a-949e025a569f', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-09', '16:30:00', null, '通常 / 教室に慣れる、基本操作コース02～', '授業カードをとても興味深そうに見ていたので、ファイルと合わせて丁寧に説明し、個々のスキルをマスターしていくと自分でゲームなどが作れるようになることを納得してくれたようでした。 カードをとても見たがるので、まずはカードの正解の通りにプログラミングをしてみてから、実行してどういう動きになったのか確認し、順番や数値を変えるとどうなるかを考えてから実際に編集して検証していく、という手順で進めました。今日の段階では、0から考えさせるよりもこの方法の方が自分の考えもよく話してくれ、楽しそうに取り組んでくれました。 使用したブロックを丁寧に端に並べておき、単元が進んだらそれらをまとめて実行して楽しんでいました。その過程で、繰り返しの位置や回数の意味が理解できたようでした。 色の効果の他、モザイクやピクセルなど、画像効果をとても面白がっていました。', null, 'タイピング: 学校でどちらも使っているので、両方やってみたいとのこと。 ココアタイピングは最初の検定をやっていました。すべて左手で打っているのと、大文字⇒小文字への読み替えが難しいようで、RやHで悩む様子が見られました。 マイタイピングで「あいうえお」のみを只管打つ、という課題をやっていたので、右手と左手をホームポジションに置いて打つことを教えました。あいうえおだけなら、こちらの方がはやい、と理解してくれたようでした。
盛り上がり: 一つ一つの単元を楽しんでくれていました。覚えたブロックをたくさんつなげて、秒数や繰り返しの回数を調整しては、動きの変化を楽しめていました。 ファイルの表にも一つ一つチェックをしてスランプを押したため、今日の学習成果が視覚化できて満足そうにしていました。
備考: ADHDで服薬有り、とのことだったので、「何かをさせられている感」をなるべく減らし、何のために何を学んでいるのかがわかりやすいように意識してみました。幸い、カード型の教材が気に入ったようで、最後まで集中が途切れることなく、楽しんでくれていました。 待ち時間にはマリオメーカーで遊んでいました。'),
  ('01a7150d-f438-5780-8f82-e61d727caf13', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-09', '17:30:00', null, '通常 / 座標の変化を理解し、サメから逃げろを作る', 'サメから逃げろでは座標の変化を使うので、基本操作コース03の中にある上下左右の移動を復習しました。x座標とy座標、「～ずつ変える」と「～にする」、「10ずつ変える」と「-10ずつ変える」、がそれぞれ紛らわしかったようでした。そのため、x座標とy座標の図を使って噛み砕いて説明したところ、「じゃあここはこうすればいいんだ！」と気づくことができました。思い出したというよりは今日初めてはっきりと理解した感じでした。 後半はサメから逃げろに入りました。プレイヤーの移動は前半でやった内容とほとんど同じだったため、自力で完成しました。サメの動きについては少し難しかったみたいですが、「最初に斜めを向く」「跳ね返るブロックを使う」などとヒントを出すと、今までの内容を思い出して作ることができました。', 'サメから逃げろ続き', 'タイピング: 楽しみながらやっていました
盛り上がり: うまく興味をプログラミングに向ければ、高い集中力を発揮してくれます。座標について理解した時はうれしさを表現していました。'),
  ('7bf79b6c-25c7-5341-9cd4-cdda1686fbf0', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-03-09', '17:30:00', null, '通常 / 自由作品', '文字pvを作りたいという知らせを聞いて、物理学が得意な広報の方がオンラインで教えてくださることができることを伝えたら、「ぜひやってみたい」と返事をしていました。したいことを先取りして学ぶことはいいことだと思います。 授業中は若干ネタ切れ気味になりなりながら、いろんなアクション効果を作っていました。特に、回転しながら進むことは何かに使えそうな気がして、別途軽いゲームも作っていました。', null, 'タイピング: タイピングにやけになって台パンをしてたことを注意しました。
盛り上がり: ゆきちゃんと話しながらもアイデアが出ていました。'),
  ('7c8298f8-0995-5083-bdef-3e17778dda46', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-03-09', '17:30:00', null, '通常 / DKアート07_うずまき作品 アートやペンツールを楽しむ', '検定後初の授業だったため、気楽にアート作品を楽しんでもらう目的で、コードはほぼ写経させました。 1か所コードの読み飛ばしがあり、アートの色が変わっていなかったため、自分で見直しをさせて修正することができました。 ペンツールなどの数値を変えて、作品がどのように変わるかを見てもらいました。', null, 'タイピング: 楽しそうにやっていました
盛り上がり: 検定が終わったせいか、リラックスして、じょうたろうくんと話しながら楽しそうに作成していました。
備考: 承太郎君と個人的に話していたのが聞こえたのですが… 以前は検定1級がとれたらやめるつもりだったようですが、最近はバスケが少し落ち着いたのと、タイピングで段をとるという目標ができて、そのついでに？プログラミングももうちょっとやってみたくなったので、まだ続ける、というようなことを話していました。'),
  ('a554e20d-cf06-50e3-b245-f50602b76751', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-03-09', '16:30:00', null, '通常 / 自由作品', '先週に引き続き電車の表示変更のものを作っていました。ただ、条件分岐が大量に作ってあったので、リストを使って圧縮できないかと提案して考えてもらいました。受けごたえ的にできそうな感じだったので、作ってもらいました。求めていた形とは少し違ったがリストから「答え」番目を指定してコスチュームを変えて自力で作ることができました。ひいろ君はコスチューム番号をリストに羅列して作っていたが、リストにコスチューム名を入れて指定する方法も教えました。また、リスト関連として、外部の文章からリストに取り込む方法を中央線の駅名を例に説明してあげました。これを知っておけば、別のところから情報を持ってきたいときに便利な手段を広げられたと思います。そして、ライト店頭も付け、立派な独自の行き先路線車両ができました。', null, 'タイピング: 淡々とやっています'),
  ('9f7de878-2951-5b61-a7ce-89b3c016af0a', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, null, '2023-03-09', '17:30:00', null, '休み（未対象） / 授業開始10分後にLINEし、既読はついたものの連絡なし', null, null, null),
  ('97ee308a-3626-58d3-a25d-f59f96d43210', '7d01236e-620e-5177-a6f4-af325a582aae', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-03-07', '17:30:00', null, '通常 / 乱数と「まで待つ」の利用に仕方を学ぼう', 'まず、作成が2週間空いたのでゲームを遊んでもらい前回作ったところまでを復習しました。ネズミの跳ね返りは跳ね返りとはどんな時にどうゆう動きをするかを質問形式に進めて紙に書いて作り上げていきました。回答に詰まるところもほとんどなく、1方向を丁寧に一緒に作ったらほかの方向も作れることができました。チーズの乱数移動は最初はどの範囲まで乱数を作ればいいか悩んでいたが、画面と座標の関係を説明したところ、チーズを自分で動かせて作ることができ、基本的なところは作り上げることができました。 結構黙々と作る感じだが、質問には答えてくれるタイプだと感じました。', null, 'タイピング: 5文字以上のアルファベットも詰まることなく打てていました。
盛り上がり: 自由時間にもタイピングやっていてハマっているのかな？'),
  ('df02a76a-c48d-5e3d-a13e-ed7316b841ce', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-03-07', '16:30:00', null, '通常 / 自由製作', '検定が終わったので今回は自由に製作しました。アルスパークのゲームをあさりながら、いろいろと考えていたが、なかなか選んでも気が変わって決まらず、結局自分で考えたものを作り始めました。動きが速く動かせるアルくんが小さいゾンビたちに当たらないようにするゲームでした。出来上がったものを見せてもらいましたが、ゾンビが当たり判定が1体のみでバグになっていました。同じ見た目のスプライトだったら1つの条件判定だけ足りる勘違いしていたので正せて良かったです。', null, 'タイピング: 新しいステージに進めていました。
盛り上がり: あちこちに興味がわいていきますね'),
  ('fa97c2c5-3aa6-573c-bf52-7cac5d143cf1', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-07', '16:30:00', null, '通常 / ペンツール（正方形→ドリルにあるやつ）', 'タイピングを頑張ったので、プログラミングの時間が少し短かったです。90度の考え方はよく知っていたのでスムーズに書くことができていました。ペンツールの色機能や太さの機能も使い、途中で色を変化させて楽しんでいました。三角形にも進みたかったのですが、角度についてよく知らないようだったので、角度の考え方について共有しました。', null, 'タイピング: 最終ステージまで根気よく取り組んでいました！'),
  ('bfb989a4-2c23-5fc2-b742-caf7614ff800', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-07', '17:30:00', null, '通常 / 乱数の使い方→迷路チーズ ブロックの使い方（ゲームっぽい感じで）', '乱数についてはよく知らなかったようなので、レッスンを終えたあともよく確認しました。迷路チーズのネズミの動きでは、「もし～ならば」を使って滑らかにプログラムする方法を共有しました。壁にぶつかる部分では、少しヒントを伝えただけで自分でプログラムすることができていました。チーズの動きは、座標と乱数を組み合せる方法を確認しました。スコアを設定したあと、ゲーム終了の条件もプログラムしました。本人はあまり積極的にアレンジしたい内容ではなかったようです。', null, 'タイピング: 評価はSでしたが、あまり得意ではないようです。'),
  ('7c9cc158-a3db-579a-a46e-7c8ae08b576a', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-07', '17:30:00', null, '通常 / 自由創作', '過去に遊んだ作品を再現するようです。ボールを投げる動作をプログラムしていました。ボールの速さをx、y座標と分けて考えているのが良かったです。途中納得しない動作があったようでしたが、繰り返し自分で試して検証することができていました。ボールの速さが投げている間一定なことが不自然だったようなので、動いている最中に速さが変わるようにすることを提案しました。', '来週はボールのコードを完成させたいそうです。発表もする予定です。', 'タイピング: 集中して取り組めていてよかったです。タイプミスが少なかったです！
盛り上がり: 時間いっぱい頑張れていました！'),
  ('5197a286-7169-5df9-931b-5f2774de4fd0', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '206ab993-7545-59d2-923a-89245c147dff', '2023-03-07', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('fb96c33e-02c9-591b-b38d-4326cfb99dc1', '7d01236e-620e-5177-a6f4-af325a582aae', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-28', '17:30:00', null, '通常 / さあ踊ろう', 'キーを押したときにポーズを変える、メッセージを使って順番にダンスする、スタンプで残像を残すなどをやりました。好きなコスチュームを選んで楽しいダンスを作り上げていました。ペンの使い方は教えましたが、それ以外は自力でできたところが多かったと思います。 時間が少しだけ残ったので、前回の迷路チーズを少し進めました。', '迷路チーズを探せ続き', 'タイピング: 集中していました'),
  ('06bb7442-1284-532d-9828-e94179935a0e', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-06', '18:40:00', null, '通常 / 自由作品', '主人公が鍵を取りに行くアクションゲームを作りました。主人公の横移動やジャンプは自力で作れていました。鍵を取ったときは色で判定していて、演出も凝っていました。', '【小技】背景スクロールの演習(素材のみverもあり)を紹介して、今回作ったゲームに取り入れてもらう', '盛り上がり: ゲームの構想をたくさん話してくれました。'),
  ('9ebf08ac-f0e1-5308-aa8b-802c12d5cdf8', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-06', '17:30:00', null, '通常 / ペンで図形を描く', '動画を見ながらやっていきました。紙に図形を書いて説明すると「～度回す」のイメージを持つことができ、正方形でやったことを正三角形や円、星型にも応用できました。最後に五輪のマークを描くのにチャレンジしてもらったのですが、1つの円を描いたあとに座標を変えるのが思いつかなかったようなので、質問で誘導しながら作りました。「図形を描いているとき以外はペンを上げておいたほうがいい」ということには自分で気づいていたので、ペンの扱い方はよく理解している思います。', null, 'タイピング: ぎりぎりで3級合格ラインに届かなかったようで残念そうでした。
盛り上がり: ときどき「分からない」と言いつつも、最後まで楽しく作り続けられました。'),
  ('652774d1-a1e4-594d-a5c0-8024b1f18a07', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-06', '18:40:00', null, '通常 / PRG 【Prg】23 走り幅とびゲームを作ろう', '今日は検定あとなので、自分が作りたい作品・・という日なのですがあらたくんの場合は、自分ではちょっと考えつかないというタイプなので一旦遊んでもらって、PRG２３の幅跳びになりました。１級の振り返りはやりたくないとのこと（笑） 動画を見ながらはお手のもので、割とさくさくやっている様子でした。', null, 'タイピング: なし'),
  ('13b8ac72-76e6-5df4-a151-77c7fe31d6c2', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-06', '16:30:00', null, '通常 / 自由作品 なほの作品を見ながら身近なもの〜自分が作成してみたいと思ったゲームを作成してみる https://app.arspark.jp/contents/30076', '推理ゲームを作成。なんで人間が倒れているのか？を答えを当てるゲームを作成していました。 問題を聞くという部分をやりたかった様子なので、来週も自分の作品をしていければなと思います。', null, 'タイピング: だいぶローマ字うちも早くなってきて、作品の中でも長文が打てるようになってきました。 あとは早さと正確さの問題だけかなと思うので、ちょっとずつ慣れていけばいいかなと思います。
盛り上がり: 推理小説のような物語ゲームを考えられるのはとてもすばらしい！言葉、文章が理解できているからだと思います。'),
  ('3355b491-5af3-5b70-ad25-d5b7fc3952cc', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-06', '16:30:00', null, '通常 / 自由作品 身近なもの〜自分が作りたいものまで見本として、なほの作品を見せてからhttps://app.arspark.jp/contents/30076', '３級検定の問題 十字架で敵をやっつけるのと、ペンギンがシュートを防御するというゲームを組み合わせて、敵が自分の方に向かってきたらやっつけるというゲームを作っていました。 前のゲームでこのコードをやったな、と覚えていて、上手に自分の作品に取り込もうとしていたのが今日の良かった点だなと思いました、来週も同じように自分の作品作りでOKかなと思います。', null, 'タイピング: なし
盛り上がり: ３Dに見せようと、奥の方からスプライトを出して手前に来るたびに大きく見せようとしていたのが、工夫しとても良かった点だと思います。'),
  ('4f411fae-02a3-5541-87fe-082e0d9c4bb1', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-06', '16:30:00', null, '通常 / PRG26 のウェイトリフティング で変数のインジケーターの使い方を学ぶ', 'お母さんが来るまで、完成に突き進み頑張っていました。途中学校でのイベントが疲れたのか、居眠りをしていましたが、中盤から盛り返しきちんとコードを動画を見ながら書いていました。 特に難しい部分で、クリックをして重さをあげる部分。動画をみて写して書いてもバグになっている様子なので、次週はそのあたりを再度見直しながらやるといいと思います。 動画は21分ごろまでのあたりです。', null, 'タイピング: なし
盛り上がり: 今日は多少勉強モードになってしまったので、当人にとっては大変だった様子でしたが途中で今日のやっている意味を明確にしたらやる気を取り戻せた感じでした。'),
  ('2716f53b-a5ce-5d33-9101-0b2713ba847b', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-27', '17:30:00', null, '通常 / スポーツゲームを作る', 'PRGの野球とサッカーから、サッカーを選んで作りました。ディフェンダーのy座標をランダムに変える、ゴール回数を変数で記録する、制限時間がたったらメッセージを送ってゲームを終了するなどしていました。わからないところはお手本のコードを見ることもありましたが、「そういうことか」と納得しながら進めていました。', null, 'タイピング: ステージを終わらせようと頑張っていました
盛り上がり: サッカーゲームに興味を持っていたので作るモチベーションがあったと思います。'),
  ('3be6e338-6fe9-5241-841c-aec3a0b274db', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-04', null, null, '通常 / 箱としてのスイッチ変数を使って、ネストを習得する', '今回は変数を箱として使うので、まず変数の入れ替えの問題を復習しました。忘れていたようなので、過去に自分が解いた問題のファイルを見ると思い出すことができました。 そのあと、スイッチの変数に応じて3通りに条件分岐するのをやってもらいました。「もし～でなければ～」を二つ重ねる書き方(ネスト)に誘導しましたが、難しかったようなので、最終的には「もし～」を3つ使う書き方を説明しました。ある程度は納得した様子でしたが、レベルの高い内容だったと思います。', null, '時間帯: その他
盛り上がり: ネストを理解したいという気持ちは強かったと思います。'),
  ('e86db3c3-ead5-59b3-80bf-a90329b1c798', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-04', null, null, '通常 / アルくん分身 https://app.arspark.jp/projects/4224/editor', '途中何回か休憩しながら、行いました。ペンツールを使うこと自体は慣れている様子で、幽霊効果、魚眼レンズ、など効果のコードを使って楽しくアルくんを分身させることをしてくれました。 特にキーで判断するというのは、すでに理解しているようなので、今後はリレーションの部分をどのタイミングで教えてあげるか？なのかなと思っています。', null, '時間帯: その他
タイピング: あいうえお のタイピングをしてみる▶︎ローマ字の一番簡単な部分から始めてみる ホームポジションだと難しかったため 概ねできているのでもしかすると「あいうえお」だけを訓練してもいいかも'),
  ('f7909c44-9316-5d23-8b81-f95283968d1d', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-04', null, null, '通常 / キャッチゲーム チュートリアルでりんごキャッチ１を今度は２の方でやってみるために、条件分岐でプレイヤーを動かす&したについたら、上にもどってまた落ちてくるということ', '誰が〜というのがまず、まだ分からない様子。ただ、そこは一度やってみて違うと思ったらもう一度違うスプライトに書いてみて、バグを見つけながらコードを書いてみるということをしていけたらと思います。 小学校のクラスで顔色を伺いながら「間違えるのははずかしい」という雰囲気になっているらしい。▶︎いつもクラスの最中もあってるかどうか？を迷う姿勢が見せるのはそのせい。 今後は色々なゲームをやるよりも、条件分岐、メッセージの部分をもう一度やり直すということを増やしていく方がいいかなと思っています。また上下左右の意識自体ももっと定着させたいので宇宙ゲーム１なども活用した方が良さそう', null, '時間帯: その他
タイピング: ローマ字タイピングも慣れてきた様子です。'),
  ('17435614-ec15-527d-aee6-311f553edd4c', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-03', '18:40:00', null, '通常 / 自由製作', '前半にすこしクローンの説明をしたので、クローンを使った自由製作を考えてくれました。スプライトの見た目もこだわって、箱に文字をいれたり、星の色を変えたり工夫してくれました！クローンの親機が表示されたまま、止まっているという問題が発生したので、隠す・表示するのブロックの位置について議論しました。集中して楽しく取り組めたので良かったです！', null, 'タイピング: 集中して取り組むことができました！スコアも高かったです！'),
  ('e7c16e39-b9d1-588c-b9e9-ddbed8ec6818', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-03', '17:30:00', null, '通常 / 自由製作', '作りたいプログラムをアルスパークから持ってきました。もともとは矢を的に当てるゲームでしたが、回る矢印を的に当てるゲームになりました。矢印を動かすときに、座標に注目してくれましたが、今回は「向き」がポイントになるので、「〇歩」が必要になることを説明しました。矢印は直線的に動くようになりましたが、的が動くようにオリジナルを加えてくれました！ 楽しく取り組めた様子でした！', null, 'タイピング: 集中して取り組むことができました。'),
  ('f35beb86-9ead-5989-8e4a-5c5ad840f1db', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-03', '18:40:00', null, '振替 / ３級 過去問19,20連続でチャンレジ', '１９の問題は特に問題なくできていました。２０の方では「りんごとばなな」の部分がやはり分からなかったようで、そこだけできなかった感じでした。 演算はかさなて使うことがあるんだよということを今日は学んだのと、変数が個別でも設定できることを学んでもらいました。', null, 'タイピング: なし
盛り上がり: 最後に19の問題で自分なりにボタンを設置し、速度を早くしたりしようとしていました。'),
  ('35674f0a-9267-58b7-8bb0-3e980e3836a2', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-03', '16:30:00', null, '通常 / だるまさんが転んだの続き 時間が空いていた（細分化からする）', '一度プレイしてもらい、プログラムに必要な部分を説明してもらいました。場合分けして丁寧に考えることができていたので、とても良かったです。以前考えたものと合わせてほぼ自力で取り組むことができていました。難しい部分はチュートリアルを照らし合わせていました。メッセージの種類が多く、使いこなすのが少し難しい様子でした。「あるくんが動いていたとき」の条件設定が抜けていたり、あるごんの向きが反対でうまくプログラムが動いていなかったりしましたが、最終的には完成させることができました。もっと細かい部分まで気を配れるようになりたいです。', null, null),
  ('7e469ee4-c06c-59fc-874a-9087f2c2b720', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-03', '16:30:00', null, '通常 / バナナとリンゴ（演算ブロックの使い方）', '「～と～」の使い方を詳しく説明しました！実際に手を動かすと、変数と日本語を同時に入力できるというところを、少し理解できた様子でした。算数的な要素はまだ苦手なようで、変数に乱数を代入し、変数を掛けるものとして使うということに、あまりピンときていなかったようです。最後にはクリア音を流したり、背景を変えたりしてアレンジすることができました！', null, 'タイピング: 集中して取り組めていたので良かったです！タイピング速度がはやいです！'),
  ('7becd453-f942-5ccd-8471-ae86f5766398', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-03', '16:30:00', null, '通常 / 自分の作品を作るデー', '自分の作品をつくるということで、コインが落ちてきてお金を貯める▶︎ボタンを設置し、お金が出てくる速さを変えながら、お金がだんだんと溜まったら、何かを買えるというゲーム作成に挑戦していました。 アイディア自体もとてもよいし、条件分岐を使う、変数と演算を組み合わせようとしていたことはとても良かったです。ただ、いくつかの条件を併用しようとなるとバグにつながるので、「動かない！」というのが多くなってきている様子。 一つづつ動作を確認してから条件を増やすことをした方がいいよと伝えると、すんなり受け入れてくれたので、ちょっとづつ複雑な動きにも対応できるのかなと思います。', null, 'タイピング: 上位30%に入っていました！'),
  ('ced4a516-2c21-58fc-b518-bd281fcf061e', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-03', '17:30:00', null, '通常 / 自由作品デーにしました', '今日は自分で作品を作る日にしました。 最初はネコのコスチュームを何パターンか作って、そこから何かのゲームにしようかと思っていたようでした。途中で猫の間違い探しゲームにしてみたら？と話したら「それもいいかも」と言っていたのですが、方針を変えて結局コスチュームをひたすらかくダケにしたようでした。 その後プチフォートナイトのようなものを作りたいと話していて、的に当たるゲームを作りたかったようです。 全体的に何かつくってみようと話すと1からは作れないのかなというのが若干の心配部分ではありますが、たくさんコードを見て覚えることを増やしていけば、そのうち自分でもコードを書けるようになるかなと思います。', null, 'タイピング: なし'),
  ('36b31861-b745-5cc2-9882-19e3f01f39ae', '80660755-d846-5cdd-91a4-0ab78fe29034', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-03', '18:40:00', null, '振替 / 基本操作コース07 ピンポンゲーム', '一個一個教えなくても条件分岐、回繰り返す、変数など、制御の部分ができていたので、年齢の割には、ちゃんとゲームとして面白さを理解していると感じました。 アレンジも上から剣が落ちてくるというスプライトを追加し明確に「この動作がやりたいんだけど・・」という相談になっていたので、この動きはどのコードで書くのか？という思考になっていると思います。', null, 'タイピング: だいぶタイピングにも慣れてローマ字打ちが理解できてきた様子です。
盛り上がり: アレンジがとてもすばらしい！'),
  ('fbe4eb09-6a55-5ca9-931e-ebf940478691', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, null, '2023-03-03', '18:40:00', null, '休み（未対象）', null, null, null),
  ('e93cb757-e7fc-5671-b6f9-b0289ff64146', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, null, '2023-03-03', '16:30:00', null, '休み（未対象）', null, null, null),
  ('65e2e8d4-f159-5c7e-8281-1bfb721c91f2', 'b2246586-4496-52f9-a825-be2488a00a31', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-02', '17:30:00', null, '通常 / prg04またはprg21の脱出ゲーム提示、使えるネタがあれば使ってもらう', 'レッスン前から作り始めていた、ネコのコスチュームがどんどん変わっていく作品に夢中でした。 動きや音は、まさきくんの作品にしては良い意味でおとなしく、コスチュームを変えていくことでアニメーションのように見える効果を楽しんでいたようでした。', null, null),
  ('273de549-3068-55c8-9f2e-40829852f02c', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-03-02', '17:30:00', null, '通常 / スプライトの動かし方を学ぼう', '最初に前回作った文字の動きを続けようとしました。何度かコードを動かして作ろうとしたが、注意散漫でなかなか進みませんでした。さらに、おしゃべり屋さんなので、唐突に違う話をし続けることはあります。そして、思考やおしゃべりが注意散漫だけでなく、画面やマウスをあちこち触って違うページに飛んだり、座っててもお尻を出したままな状態があります。 だから、最後に集中的に左右のスプライトの動かし方を学びました。完成したコードを見せて、どのブロックが必要なのか考えながら作り上げました。 かずまくんは、気が散ってしまうが、プログラミングにはとても楽しんでいるので、1つのことが停滞していたら、おモッキリ違うことに転換して教えていった方がいい。また、忘れやすい性格なので、前回やったことを再確認し、作るネタを変えていく方向で進めていく方がいい。', '前回の復習 左右の動きにボールも追加して動かしたい', 'タイピング: スコアが伸びていました
盛り上がり: 動きができた時の喜びはとても楽しそうでした。'),
  ('1cfdb480-1dd7-5400-995e-4534232d84d3', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, null, '2023-03-02', '17:30:00', null, '休み（振替対象）', null, null, '備考: 試験対策の為2/27に振替済み'),
  ('7161ff81-95de-59d5-8066-944dba865ef6', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-02', '16:30:00', null, '通常 / 検定直後なので自由作成', '最近凝っている文字PVを作りたいと言って、自分の好きな作品のコードを参考にしながらがんばっていました。 文字を表示させるときや図形の大きさを変えるときに、必ず演算のコードを使っていることが疑問だったようなので、しもさんに説明をしてもらいました。 時間経過とともに変化の速度を変えるためということで、ジャンプや車の速度などを例にした説明を聞き、なんとなくは納得したようでしたが、「早くこういうのができるようになって、他の人のようなＰＶを作りたい！！」と呻いていました。', null, 'タイピング: かなりのスピードでできていました。
盛り上がり: Scratchでやりたいことがまだまだたくさんある！という感じで、熱心にコードを読もうとしていました。目標が高く、そのための労力も惜しまない姿勢が頼もしいです。
備考: Scratch上での文字PV大会？の上位作品が好きで、よく見ているようです。 承太郎君の2ndアカウントで作品公開もしているようでしたが、まだまだ使えるスキルが少ないから自分としては物足りないとのことでした。'),
  ('112981a7-35c0-53c0-a67b-9696c1b5e5a1', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-02', '16:30:00', null, '通常 / ゾンビを倒せ１の続き 基本コードの確認をしながら', '前回作成したところまでの確認をしたところ、コードは合っているのにビームが表示されないと言って、自分で何度かチュートリアルを巻き戻して確認して悩んでいました。 「はしにふれたらかくす」の「はし」は左端にも有効だということを伝えたところ、スプライトの初期位置を変えて対応し、解決することができました。 座標はよくおぼえているようで、解説の途中で「これわかるから飛ばしてもいい？」と聞いてきました。 「矢印キーが押されたとき」と条件分岐を使ったときのスプライトの動きの違いは、説明の前に自分で気づいていました。 チュートリアルを聴きながら、「ここはy座標を変える」「ここは変数を1ずつ変える」などと先読みしてブロックを組むことができていました。 最後まで集中して、宇宙バトル2の最後まで終えることができました。', null, 'タイピング: 前回くらいからランキング順位3桁を取れるようになってきたので、盛り上がって取り組んでいます。
盛り上がり: チュートリアルの説明にその都度答えながら、一生懸命取り組めていました。 時間を少しオーバーしましたが、最後まで完成した作品をみずきくんにプレイさせて、嬉しそうにしていました。'),
  ('e68569cd-68c4-5090-bfad-8a9d14276ba0', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-03-02', '16:30:00', null, '通常 / 自由作成', '検定が続いたので、今日は自由作成にしました。時間を断って作品をのぞいてみると、やはり電車のものを作っていました。架空の路線を作って電車の型を合わせて行き先を作っていました。なりたいものを形を持っているの素晴らしいと思います。', null, 'タイピング: 手さばきがよくなってきました'),
  ('d2b5c271-621b-5384-985d-3040ba30b0d0', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-28', '16:30:00', null, '通常 / 検定練習', '周りの子と少し離れた席に座ってもらったのもあって、あまり気を散らさずに解いていくことができました。 合格ラインに乗るくらいにはできていたと思いますが、改善点もありました。「まで繰り返す」とするところを「もし～なら」で書いていたので質問したところ、そんなブロックあったっけという反応でした。しっかり覚えてもらいました。 また、アレンジの説明を単語で書いていたので、「～が～したときに～する」というような具体的な文で書きなおしてもらいました。', null, '盛り上がり: 完成した時など元気に報告してくれました。'),
  ('512d975b-6cf5-598d-b57d-31d964551f84', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-28', '17:30:00', null, '通常 / 基本操作コース08 さあ踊ろう', 'どの動きも一度プログラムしたことがあったようで、スムーズに進みました。「メッセージ」の機能とスタンプの機能、明るさ・モザイク・渦巻きの機能について勉強しました。ダンスのプログラムに工夫して、音を流したり背景を変えたりして一つの作品を作ってくれました。最後に時間が余ったので、迷路チーズを遊んで体験してもらいました。', null, 'タイピング: 丁寧に取り組めました！！
盛り上がり: 待ち時間に作っていた銃の連射のプログラムがとても面白かったです！工夫がすごい！'),
  ('04690c1a-41f8-543d-8124-c143bba629ec', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-28', '16:30:00', null, '振替 / 自由製作', '作りたいものがあるかをきいたところ、迷路脱出ゲームに興味を示してくれました。その後、オリジナルの作品を作ることになりました。作る前に作品の内容は教えてくれませんでした。 カエルとボールの追いかけっこのゲームを作ってくれました。変えるの動きやボールの見た目にこだわった、とても面白い作品になりました。たつきくんのアイデアで、ボールがワープします。完成したようです！', null, 'タイピング: 長文を丁寧にタイプできていました！
盛り上がり: 最後にとらくんの作品を楽しんでいました！'),
  ('026ad921-cf12-55d7-b3a5-a6c5b1329512', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-28', '16:30:00', null, '通常 / 既存ゲームをアレンジする', 'ゲームを複数遊んでみて、その中で興味を持ったインベーダーゲームをリミックス、アレンジしました。制限時間の設定がなかったので、秒数の変数を作り、1秒ずつカウントダウンしていきました。時間がマイナスになってもカウントダウンが続いていたので、どこかのタイミングで止めなきゃいけないよねと伝えると、演算を使って0秒で止めることができました。同様に、HPを設定して0になったら止めていました。最後はBGMとして音を追加しました。', null, 'タイピング: 初級から上級まで幅広くやっていました。
盛り上がり: 自発的にアレンジの内容を考えています'),
  ('7ca4f9f1-9052-5f2e-b667-86be59d76256', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-28', '16:30:00', null, '振替 / 3級検定問題(2回目にやるもの) 前回の復習か進めるか。', '最初に「前のやつより簡単すぎるけど本当に3級？」と聞いていました。 アレンジとして玉の動きを変則的に、魔法使いが縦横に動けるように工夫していました。うっかりミスとして、一度プログラムしたものを外してしまうことがありました。どうしても納得のいかない部分は自分で作ってしまう傾向がややあるようです。ほとんどの部分はよくプログラムできていました。', null, '盛り上がり: 最後にたつきくんの作ったゲームで遊んでいました！'),
  ('3f579e6a-54ab-5349-a970-64ceb2ab9ae6', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-28', '17:30:00', null, '通常 / 2級検定準備(2回目にやるやつ)', '問題を解きつつ、イライラしている様子でした。答え合わせをすると「もし～でなければ～」の範囲を間違えていたり、変数の数を間違えたりしていました。ミスしたところは大したことないのですが、複雑なプログラムのように見えてしまって、難しく感じている様子でした。「キーが押されたとき」のプログラムの仕方についても共有しました。', null, '盛り上がり: スプラトゥーンでよく遊んでいます。'),
  ('d12bdd4b-8b7a-5be9-ade5-9e737aa39481', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-27', '17:30:00', null, '通常 / ボールキャッチ', '動画を見ながらボールキャッチ1を、それが終わったあと2を作りました。 1は簡単だったようで、動画の内容を終えた後、ボールが落ちるタイミングを調整していました。 1では「～歩動かす」でボールを落としましたが、2ではその場所を座標を使って作りました。同じ動きでもコードはいくつかの書き方があることを理解できたと思います。また、座標に関して「～にする」と「～ずつ変える」の混同などもなくしっかりできています。', null, 'タイピング: ミスが前回より減っています。
盛り上がり: 今は何を作っているのかなどを積極的に言葉にしてくれました。'),
  ('ef03db10-f843-52f7-9a19-56bdc46b7bc7', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-27', '17:30:00', null, '通常 / 検定準備 4級応用課題17', '「（現在の設問より先の問題番号）の動作を止める」という言葉の意味がわからないと質問をしてきました。そこの問題文にマークをして先に該当する問題番号を解いてもらったところ、「ほかのスクリプトを止める」ということに気付くことができました。 問題文を読み飛ばすことがあるので、なるべく解いた問題に印をつけることを勧めました。しゅうくんなりに意識してチェックをしていましたが、1文まるまる飛ばしたところがありました。 大きさの数値や、座標のプラスマイナスが違っているところが3か所あったため、見直すときに数値のチェックをするよう伝えました。ただ、ムービーと何度も見比べて「何かおかしい」ということは自身で気づけていたので、おかしいところがあったら、数値チェックで乗り切ってくれるとよいのですが…。 「メッセージを送る」と「メッセージを受け取った時」の混同があり、最初は全部「送る」で作成していました。ムービーを見て、ここのコードが違う、というところまではわかっていたようなので、メッセージの復習をしてみました。 アレンジが苦手だというので、コードをあまりいじらずに、クリアの音楽を足すくらいでも構わないからやってみたらと勧めたら、時間内に完成させていました。', null, 'タイピング: タイピング検定の結果が、次の級までとても惜しいところだったのと、練習での最高記録に届かなかったことがとても悔しそうで、とても集中して取り組んでいました。そのせいか、これまでの最高記録が出せたそうです。
盛り上がり: 「ムービーと違う」ということを何度か申し出てきましたが、そこで投げ出さないで自分なりに最初のスプライトから見直す姿勢を見せてくれました。 持ってくるブロックは合っていることをほめてから、しゅうくんの注意する点を教えたところ、一生懸命聞いてやる気になってくれていました。 簡単なアレンジではありますが、無事に作品を壊さずできたことがとても嬉しそうでした。'),
  ('a3ac7e95-4d99-5f9e-bdc4-dd81379f70c1', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-27', '16:30:00', null, '通常 / 検定準備またはコンテスト作品', '検定の準備とコンテスト作品のいずれかを選んでもらいました。 今度のコンテストではるちゃんが一番伝えたいことと、どのようなゲームをイメージしているかを書き出してもらいました。 一番伝えたいことは「自分たちができる小さなことでウミガメを救うことができる」とのことだったので、「小さなこと」の具体的な内容を書き出してもらい、ゲームにできそうなものを選んでいきました。 自分が作りたいストーリーとゲームとの構成がなんとなく浮かんだところで、今日は作りたい所をやってみたいとのことで、オープニングの作成に入っていました。', null, 'タイピング: 毎パソの結果が思ったより良かったようで、意欲的にタイピングに取り組んでいました。
盛り上がり: タイピングの結果は嬉しそうにしていました。 コンテスト作品の概要を話すときも、自分が調べたことなどを一生懸命話してくれました。'),
  ('73fc98ec-61b1-5bbb-862c-4d299632f17f', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-27', '18:40:00', null, '通常 / 検定練習', '解き終わったところ何とも惜しいミスが連発していました。１つは条件の適応範囲がずれていることです。1級の問題は条件が3段構造になることもあるので1文だけの条件にミスっていました。ほかにはまで繰り返すで重複して「もし」を使っていました。若干の抜けがあったり、ケアレスミスが響いています。落ち着いて文章読解しよう。', null, null),
  ('13c9f530-68d5-5d5f-ac05-d7c5de986cb6', 'e17fbd99-e7bb-5a30-b401-9db822e69cec', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-27', '18:40:00', null, '通常 / 検定練習', '一通り作るのは早く終わったのですが、バグが出て困っていたようなので問題文を読み合わせしました。「ずっと」ブロックを忘れていたり、メッセージの「送る」と「送って待つ」を混同していたりと基本的なブロックのミスが少し見られました。 また、問題文には書いていないものを自己判断で入れてしまったり、「以下を繰り返す」の「以下」が指す内容を勘違いしていたりという間違いもありました。 全体的に自分でやりたい気持ちが大きくて問題文をしっかり読めていない感じがあったので、書いてあることを文字通り解釈するのが近道だということをアドバイスしました。', '検定練習（アレンジのやり方を伝える）', '盛り上がり: 懸命にバグつぶしに取りくんでいました。'),
  ('978964d1-79ee-52ce-b61c-4333fdbf7e13', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-27', '17:30:00', null, '振替 / 検定練習', '今回の問題を解いたところ、また、読み飛ばしと不等号の向き違いが発生しました。線を引いて読むことをしているので、本番はしっかり落ち着いてください、不等号の向きは今一度くらべられるものがOOより大きいなら開いている方と認識させました。ほかに、他スプライトの既存パラメータの場所がわからなかったそうです。これは知らなきゃできないので場所を確認しました。', '読み飛ばしに注意してく大歳', null),
  ('5a4e9c61-d65d-57fb-b0b5-5fa29322619b', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-27', '17:30:00', null, '振替 / 検定練習', '最初に前回の振り返りをしまｈした。能力的には問題はないが、文章の煩わしさから主語と目的語がずれていたり、条件の範囲の文章読解に2，3ミスやらていました。 今回解いた問題はミスがありませんでした。すごいよ！！定義が本質的にわかってなかった感じがして、文章通りそのまま作っていた感じがして、検定を終わったら定義の利用の仕方を深く学んでいけたらいいと思う。', null, null),
  ('e38e47d9-fd59-58cf-9f35-bbc02f4112c0', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-27', '16:30:00', null, '通常 / 検定練習', '時間内で余裕で解き終わっていたし、アレンジも十字架を打つたびに向きがランダムに帰ってくるもので評価されるものができていたので問題ないです。', null, null),
  ('25a160e3-47de-5d67-8166-bf6fa584d544', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-27', '16:30:00', null, '通常 / 検定練習', '終わってみた感じにどこかしらにバグを残していて悩んでいました。答えを最初から確認していったところ、ずっとを描かれていない所に差しこまれていました。ややわからない所が余計なものを足す癖を見えました。そして、「まで待つ」の表現が解いてるときはわからなかったが、答え合わせのときにすぐに気づけました。だが、わからない所があったとしても最後まで進めているのは良かったです。なので、バグると視野が狭くなる傾向があるので、落ち着いてコード欄から似た表現を探しすようにアドバイスしました。', null, null),
  ('8c3b5dee-4a17-59aa-b47b-763531769899', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-25', null, null, '通常 / ゲーム作成', '前半はタイピングと休憩で終わってしまいましたが、後半はすごい集中力を発揮して宇宙バトル1の内容をすべて終わらせました。敵の動きと弾丸の発射までできました。「先生、これで合ってる？」と確かめながら進めていきました。', null, '時間帯: その他
タイピング: 基本的な文字の練習をしていました
盛り上がり: 作ったゲームを、お迎えの時にきた弟さんに遊んでもらって嬉しそうでした'),
  ('89043e2b-a3f5-5608-90e8-abd6d418feca', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-25', null, null, '通常 / 基本操作コースで基礎を固める', 'リンゴを落下させて、地面に落ちたらコスチュームを変えるというのは問題なく作れていました。 スコアのつけ方が分からなかったようですが、どういうときに1点加えるのか聞くと、プレイヤーがリンゴに触れたときだと理解しました。 後半はアレンジに入りました。プレイヤーの周りに長方形を描いて当たり判定を広くしていました。 x座標をランダムに変えるのをやっていなかったので途中で勧めましたが、気が進まなかったみたいです。', null, '時間帯: その他
盛り上がり: アレンジを楽しんでいました'),
  ('5ad53d81-b41a-5e32-8583-1bfc4dc2cf97', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-25', null, null, '通常 / 自由作品', 'とても集中して取り組めました。Scratchで遊んだゲームをアルスパークに再現してくれました。途中、「2回クリックされたら」という動作を入れようと困っていたので、変数を使うことを提案しました。本人にとって新しい考え方だったようです。最後まで完成しませんでしたが、作りたいものが伝わってきました。コスチュームの変更のタイミングなど、細かいところまで気を配れていて素晴らしかったです。', '余裕があれば続きをやりたいです。', '時間帯: その他
タイピング: 来週はやりたいです！！！！
盛り上がり: 最後に作品を紹介し合って、楽しむことができました！'),
  ('4ec02a5c-454f-575f-a228-c8738992a273', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-25', null, null, '通常 / 追跡ゲームの応用 迷路チーズ', '一度遊ぶと、なんとなくゲームの構成が分かったようでした。ネズミの動きのプログラムはとてもスムーズにいきました。座標もしっかり理解できていて素晴らしかったです。「歩数」に切り替えるのもバッチリでした。壁に当たったときのプログラムに時間がかかりましたが、「止まっているように見えるだけ」とアドバイスしたところ、自分で考えてプログラムすることができていました。チーズも、座標の下限と上限の考え方を共有して、乱数をうまく使ってできていました。 最後にゆうれいのプログラムにとりかかりましたが、時間がなくて最後までできませんでした。次回に持ち越しです。', '幽霊のプログラムつづき', '時間帯: その他
タイピング: 丁寧にタイピングできていました！！
盛り上がり: 楽しく取り組むことができました！'),
  ('688dcf34-901a-51f0-a3c7-188ba71f4768', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-25', null, null, '振替 / ジャンプの動きをマスターする', '垂直ジャンプの動きを作る時にx座標とy座標を取り違えていましたが、横に動いてしまったのを見てすぐに気づいていました。また、ジャンプするためには繰り返しブロックを使えばよいことは分かっていましたが、繰り返しの仕方が間違っていました。そこで、「上に動き続ける→下に動き続ける」という流れを説明すると、それをコードに起こすことができました。 変数には慣れているようで、スコアの変数は初期化してから更新することができていました。 テキストの内容が全て終わったので最後はアレンジを加えていました。スコアが一定以上になると卵の速度が上がるというものでした。このとき判定に「もしスコア=〇なら」を使っていてうまくいかなかったので、等号を不等号にすると一瞬ではなくずっと作動することを伝えました。', null, '時間帯: その他
タイピング: 集中していました
盛り上がり: こちらが何か助言すると納得した様子を見せていました。ゲームをアレンジしているときは特に楽しそうでした。'),
  ('0df904f8-4a90-5367-a795-6bf3e0af896a', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-24', '18:40:00', null, '通常 / 前回の回答合わせ&２級の過去問で問題の慣れ', '問題の文章の書き方が、ややこしいのが１級の問題なので、文章がつながっている部分をどのように理解するか？がポイントなのかな？と思いました。 読み飛ばしに関してはないものの、うっかり〜まで待つ〜の部分を間違えたりするために小さなバグになってしまいそれを見つけられないという感じ。時間がかかる問題なので、１つのミスが全体に影響してしまうことを、痛感している様子でした。 その後に２級の問題を慣れのためにやってもらいましたが、２級は比較的簡単にできた様子でした。', null, 'タイピング: なし'),
  ('0fa1d16c-c746-5ba2-b9cd-7c9e68dd74ee', 'e17fbd99-e7bb-5a30-b401-9db822e69cec', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-24', '17:30:00', null, '通常 / 検定３級 1回目', '問題のやり方が慣れてないためか、ブロックを全部繋げてしまったり、文章の１行目を読みとばし、ブロックの使い慣れなどができなかった様子でした。 ただし、一度説明したら、なるほどと理解していたので、来週月曜日もう一度やってみると違うかなと思っています。 基本的な条件分岐などに関しては問題なくできていたので、問題ないなと思います。', null, 'タイピング: なし'),
  ('a1b03030-125b-5841-b921-407fa2634944', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-24', '17:30:00', null, '通常 / メッセージを送る▶︎うごきが先にあった後にメッセージが送られて、違うスプライトが受け取った時にまた動作する 見本の動作 ガチャガチャhttps://app.arspark.jp/contents/8680', 'いつもチュートリアルをみて動作をするだけでは、学びにならないかなと思ったので、ガチャガチャのコスチュームがボタンを押されたら代わり、その後にメッセージを送る。送られた相手がまた動きを行うの部分だけを、一緒にやってみました その後に自分でキャラクターを作ってもらい、自由作品としてみました。 爆弾のコスチュームを変えた後に、棒人間が表示されるというプログラムを書き（ほぼ見本と同じだが・・）、自分なりには満足していた様子でした。', null, 'タイピング: だいぶタイピングにも慣れてきているので、短い単語のタイピング練習であれば今後は少しずつ増やしてあげてもいいのかもと思います。
盛り上がり: 表示、隠す、ずっとなど基本的な部分に関しては理解ができてきている様子。 メッセージなどの部分に関してはどういう関係性になっているのか？をすべてはまだ理解できていない様子なので。すこしずつリレーションのプログラミングを増やしていければいいかなと思います'),
  ('0fa16543-f73e-5007-abd9-fa65176ea690', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-24', '17:30:00', null, '通常 / キャッチゲーム応用編', 'アイテムを落とすプログラムに少し困りました。初期位置の設定も、うまくブロックを組み合わせてプログラムできていました。高さを制御するプログラムもy座標を思い出せていたのでバッチリでした。落下の後、上に戻るプログラムに少し難儀しました。座標で制御するというアイデアがなかなか出てこないようです。 スコアのプログラムは全部自分でプログラムできていて素晴らしかったです。得点も、自分なりに考えて工夫できていました。アレンジとして、落ちたコップが割れる動き、コインのコスチュームの変化をつけてくれました。完成品にも満足そうでした。', null, 'タイピング: 集中して取り組めていました。
盛り上がり: 前向きに取り組んでくれました。'),
  ('8da58bd7-12b3-5929-bb39-507db2e3ce0e', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-24', '16:30:00', null, '通常 / 図形を描く 〇を描く→オリンピックを描く （△を描く） 最後に作品を作ってみる', '〇は難しいと言っていましたが、360度の考え方を説明すると、最終的にはなんとなく理解できたようです。角度の考え方を自分の中で少し整理し、描くことができていました。ペンの使い方は、前回やったことを覚えていたのでバッチリでした。 オリンピックのマークも位置をきちんと調整して取り組めました。最後に自由作品として、円を使った花を描いてくれました！', null, 'タイピング: 授業前から集中して取り組んでいました。得点も高く、満足そうでした。
盛り上がり: となりのたつきくんを気にしつつ取り組んでいました。楽しそうで良かったです。'),
  ('d3f41a18-8e3d-5395-a650-c530d0facded', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-24', '16:30:00', null, '通常 / ３級 応用問題 B019_mission', 'まで繰り返す〜というブロックを何回も使っているのにも関わらず、まで待つ〜のブロックを使っていたため、ボールの動作が動かない＆表示されないというバグに繋がっていた。 ブロックを繋げることに関しては以前よりもできるようになったものの、ちょっとしたミスが見受けられる。 当日もその部分が顕著にならなければいいのだけど、１回わからないという頭の思考になってしまうと考えることをやめてしまうので、完璧さを求めることで、ある意味問題嫌いにならなければいいなと思う', null, 'タイピング: なし'),
  ('ad29ae7f-e0d7-57cd-a335-2d38b95128a3', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-24', '16:30:00', null, '通常 / 図形を描く □ 〇 △ ペンツールの使い方（正方形を描く-ペンツール）', 'たのしく取り組めました！', null, 'タイピング: 正方形を描く（レッスン）・〇とオリンピックマークと自由作品/アルスパーク'),
  ('b7ab6d32-6ae8-549c-8967-d307edb2537a', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-24', '17:30:00', null, '通常 / ４級 応用問題 E019_mission', '問題の読み飛ばしがあり、バグにも気がついてない様子。今日は集中力がとても切れていた感じがしていて、そういう意味で文章の読むことを途中で諦めてしまった感じがある、 当日ちゃんとどの部分をやったのかキチンとチェックしながらやることを伝えて、本日は終わりました。', null, 'タイピング: なし'),
  ('1982bede-a1d0-5567-8c29-fe8d82a76511', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-17', '18:40:00', null, '通常 / ４級問題過去問 2回目', '特にヒントを求めることもなく、時間内に解き終わっていました。 アレンジでは、とても楽しそうにスプライトに手書きのイラストを付け足して喜んでいました。 「検定」というものに対しての理解はあやふやなところもありますが、問題文の通りに作成すると一つのゲームが出来上がり、それに対しるアレンジも推奨される、ということ自体を楽しんでいるように見えました。', null, '盛り上がり: 30分で一つのゲームができること、それのアレンジで少し遊んでも、注意されずに褒められることが、とても嬉しそうでした。'),
  ('58611892-3d31-57b4-a96e-c28ab73f7a2f', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, null, '2023-02-24', '18:40:00', null, '休み（未対象） / 振替をお休み', null, null, null),
  ('0d3b047b-4884-5491-84fd-492ce643c79e', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-20', '17:30:00', null, '通常 / スプライトごとの変数を使う', '今回作るのが以前作ったシューティングゲームに似ていることに気づき、そのコードを見返してキャラクターの移動とビームの発射を作りました。そのあと、プレイヤーごとにHPを作ってみようと促しましたが、一撃当たると試合終了になるのがいいと言って説得できなかったため、そこで中止にしました。しゅうくんも同じものを作っていたので、最後に2人で対戦してもらいました。', null, 'タイピング: 時間切れになったときは残念そうでした
盛り上がり: 少し詰まると嫌になってしまう様子が見られました。最後にしゅうくんと対戦しているときは楽しそうでした'),
  ('9cab0c40-6054-5d08-b4c3-b137f13dba1f', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-16', '16:30:00', null, '通常 / 宇宙バトルを応用してゾンビゲームを作る', '前回で宇宙バトル2の内容がだいたい作れていたようなので、きちんと理解できているか確認しました。矢印キーによる操作、「～へ行く」を使ったビームの発射、「スクリプトを止める」の使い方について、コードを参照しながら質問しました。ここはこういう意味だよねとすらすら答えられていて、内容をマスターできていることがわかりました。 そのあと、宇宙バトルを応用して新しいゲームを作ってみようと誘導し、ゾンビをたおせに入りました。宇宙バトルと同じようなスクリプトも多かったので途中まで問題なく進んでいたのですが、1つバグが起こりました。「端に触れたら隠す」というコードで一番最初から端に触れていたので、次回はそのことに気付いて修正してもらいたいです。', 'ゾンビをたおせ1の続き', 'タイピング: 楽しく取り組んでいました
盛り上がり: 最初に遊んだ段階から、ゾンビをたおせに興味を持っていました'),
  ('9f0694c2-91d3-5df5-b5c6-4bdf5441f967', '7d01236e-620e-5177-a6f4-af325a582aae', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-21', '17:30:00', null, '通常 / 新しくコードを知ろう', '先週の続いてゾンビゲームを作りました。作り終えた時に何か新しく知れたことあると聞いたところ、「ではない」とか「クローン」が答えてくれました。条件分岐の利用は慣れてきたそうです。 次に、乱数を理解するためにさいころを作りました。ランダム性を表現することに使えることを共有できたと思います。 さいごに、乱数と「では待つ」使うためにチーズを探せ」を作りました。ミミの動きに関して、上下左右に動く動きをまず右方向に座標や向きがどう変化するか確認してのち、ほか3方向も自走して作れていました。今選択してるスプライトがどの位置でどの向きをしているか曖昧な感じでしたので、確認方法も一緒に共有しました。', 'チーズを探せ続き', 'タイピング: 何回も取り組んでいました
備考: 体調に変化が起こったら言おう'),
  ('147efc44-f737-5005-84ea-6b889e95ee6d', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-21', '16:30:00', null, '通常 / 検定問題4級応用問題2', '比較的集中して取り組めていたようです。周りの様子に流されやすいようでした。タイピングを熱心にやりすぎた影響で、振り返りの時間を十分にとることができませんでした。やっている再中も「分からない」と聞いてくれましたが、本番は文にある日本語の意味が理解できなくても質問はできないので、心配です。 間違えたポイントは何か所かありました。どれも自分が良く知っている考え方・ブロックですが、文にある日本語から意味を抽出して知っているものに置き換えるのが大変苦手なようです。合格はできそうな出来でした。', null, 'タイピング: 分からないキーがあると、キーボードをぐしゃぐしゃにしていました。もったいないです。こだまの森を最後までクリアしました。'),
  ('8373c0ce-369a-56cf-bff4-44bb26f291df', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-21', '17:30:00', null, '通常 / 追跡ゲーム続きから（変数設定）', '変数とスコアの設定を説明しました。なんとなく分かったようです。「数字を入れる箱」として変数を紹介しました。変数が特定の値になったときに、スプライトを表示したり背景を変えたりするスクリプトも紹介しました。よく理解できている印象でした。ずっと加点されてしまう現象がおきたので、音を鳴らすブロックをうまく使うことを説明しました。 アレンジとして、ゲームクリアの表示・音を鳴らすことをしていました。最後に「すべてを止める」を使って、しっかり終えることができてので良かったです。', null, 'タイピング: 丁寧に取り組めていました！
盛り上がり: 最後、お父さんに見てもらって嬉しそうでした！'),
  ('1bbcae0c-316a-5dd8-b33e-11ca175583b5', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-21', '16:30:00', null, '通常 / こわざ（ピクセル・幽霊の効果など）を使う', 'とても楽しく取り組めていました。「ピクセル化」「幽霊化」のブロックも「～ずつ変える」「～にする」の違いも把握して使いこなせていました。数を変化させて試せていたのでとても良かったです。 40、41どちらもよくできていました。「歩かす」「色を変える」などタイミングも考慮してプログラムできていました。使い方は十分に理解できたようです。文字を打つのもだんだん安定してきました。アルファベットのドリルを見せてくれました。', null, 'タイピング: 集中して取り組めていました。タイプミスも少なかったです。'),
  ('be8488af-de7a-558f-99bd-ce4fb18fa9d8', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-21', '17:30:00', null, '通常 / 検定準備（検定問題2級応用問題5）', 'とても集中して取り組むことができていました。時間もちょうどよかったです。アレンジとして音を追加してくれました。 取り組んでいる最中に分からないことがあったようですが、演算の種類や変数名に間違いがないかなど、細かい確認するポイントを説明したところ、自分で間違いを発見することができたようです。 自信もかなりある様子でした。', null, 'タイピング: 本人がどうしてもやりたくないそうなのでスキップしました。来週は必ずやります。'),
  ('66022e38-1def-5d7d-accd-cdecf6ad5ae0', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-21', '17:30:00', null, '通常 / 検定練習', '前回に続いて検定の問題を解きました。4級の問題はアレンジも含めてものの15分で終わってしまったので完璧にできていました。「次に上の級も試してみる？」ときいたらやると答えたので、3級の問題も解きました。こちらはアレンジも含め5分時間が余りました。凡ミス1か所で能力的には問題はありませんでした。アレンジに関しては、4級をやった時はbgmをつけるだけで簡素すぎて加点が少なくなるよと伝えたところ、3級では体力をつけてゲームオーバー演出も作れて十分よくできていました。3級も安心して合格できると思います。', null, null),
  ('285ef1e9-7acb-5fa1-ab63-4c042b610e7b', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-21', '16:30:00', null, '通常 / 自由にアレンジしよう', '先週作ったパンを飛ばしてアルスタッフを倒すゲームの続きを作りました。元の作品に寄せず、サラちゃんのアイデアを中心に作っていきました。途中飛ばしたパンが手元に戻ってこないとき、やりたいこととコードを対応させながら自分自身でコードの位置を直せるように誘導させました。スタッフの判定を1回きりにさせたくて悩んでいたので、「コードを止める」ブロックを種類を含めて説明してあげました。これまでこのブロックをなんとなくつかっていた気がしたのでここで確認できたと思います。動きだけでは物足りない気がしたので、変数をつけて簡単な演算も作るように誘導しました。ノーヒントでは手が進んでいなかったので、統合のブロック持ってきて、これを使って考えてみてと誘導したら、自走して作れました。いい感じに完成したので楽しくできたとおも増す。', null, 'タイピング: 良いスコアを狙うために何回もやり直しが目立ちました
盛り上がり: こちらからはサラちゃんの考えを聞いてから少しだけ注文したのでストレスをためずに気持ちよくできていました。'),
  ('4cf90d19-2161-588f-b395-b0447599b26c', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-20', '17:30:00', null, '通常 / 特定のスプライトのみの変数を使う', '二人対戦のシューティングゲームを作りました。 弾丸のクローンを作るのですが、「クローンされたとき」のブロックを忘れていて動きませんでした。そこで、そのブロックがなかったらクローンで作られた分身が何をするのかわからないよねと伝えました。そして、以前作った一人プレイのシューティングゲームのコードを見て思い出してもらいました。また、クローンが適切なタイミングで削除されていなかったので、どういうときに消せばいいか聞くと、試行錯誤したあと削除のコードを作ることができました。 そのあと、それぞれのプレイヤーにHPを作るというのをやりました。変数を作成するときに「このスプライトのみ」にする方法を教え、2つのスプライトが別々に変数(HP)を持っている様子をイラストで伝えました。', null, 'タイピング: 記録が少し上がっていました
盛り上がり: お手本のゲームを見せたとき、面白そうと言ってくれました。'),
  ('54b7091e-3de8-5c79-acfc-d96ca9ed17ad', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-20', '16:30:00', null, '通常 / 検定練習', '2級の検定の練習問題を解きました。問題は難なく全て迷うことなく解けていていました。だが、ほかのスプライトのコスチューム番号「調べるにある水色ブロック」をコードの表し方が知らなかったそうです。このブロックはほかのコスチュームの既存のパラメータを変数として使えるので使える幅が広がること共有しました。ただ、このようなわからない所があったにもかかわらず、飛ばして解くことができたの検定の問題慣れができていると思います。', 'じゃんけんのやつの答え直し', null),
  ('be2ed75c-0120-5f5c-ab86-0ff7b0efb24c', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, null, '2023-02-20', '17:30:00', null, '休み（未対象）', null, null, null),
  ('ff77c728-2d30-5d7b-95ab-627a0aab6fae', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-20', '16:30:00', null, '通常 / 検定３級 応用18', '３級になるととても楽勝な状態で問題を解けていました。 アレンジの部分で音や数字を変えるだけではなくて他のスプライトを用意してアレンジして欲しいとリクエスト（多分それじゃないと加点されない話を伝えて）したところ、応援団を用意してそのスプライト自身に動きを作っていました。 ただ、他のスプライトを増やすとリレーションがややこしくなるから、問題と組み合わせてやるのはやだと話していたところが少し引っかかる（要は複雑になると嫌だということ）', null, 'タイピング: なし
盛り上がり: 問題自体の理解と面白くしようとする部分に関してはとてもよくできていました！'),
  ('0e10208b-1793-5c1e-9c7d-dc90f3882f0c', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-20', '16:30:00', null, '通常 / 検定４級1回目をやってみて、本番に合わせてみるか？', '最初は流れを説明し、こういう流れで進めるんだよ〜と伝えて行いました。 ほぼ一人でも解答ができている状態でかつアレンジもスプライトを追加し、跳ね返るようにしてくれていたので、基本的な動作を理解しているのだなと思います', '検定2回目を行う', 'タイピング: なし
盛り上がり: 検定をやってみてたのしかったとのこと。基本的には文章を読み解く力があるからこそ、なのかな？と思いました。'),
  ('ab2b0fd5-e7c2-592a-9fa0-6cd69418824f', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '25840600-1a86-5fb0-b223-dec47cec8c48', '2023-02-18', null, null, '通常 / 続き', '前回からの続きで、基本操作コース04の追跡ゲームを作成、その後振り返りをしながらアレンジをしました。自分のアイディアを形にできて満足そうでした。乱数をマスターしようも問題なくできていました。 「ずっと」と「もし〇〇なら」の組み合わせを忘れていたのでおさらいしました。', '「乱数をマスターしよう」の振り返りと「追跡ゲームの応用」 ※追跡ゲームの応用は楽しみにしている様子でした。', '時間帯: その他
タイピング: 積極的に取り組んでいる様子。教室に来た時からタイピングを始めていた。
盛り上がり: アレンジでは敵を作るアイディアが完成した時はすごくうれしそうでした。 新しいことでも積極的に学べています。'),
  ('ecfb6ff6-62a0-5aa7-a6f5-ef760ed34b9f', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-18', null, null, '通常 / 検定２級 応用問題１１', '「りんごとばなな」の演算の使い方忘れ、バグの削除と修正がうまくいかなかったものの 、それ以外はちゃんと問題文通りに行えていました。 アレンジをすることは一回飛ばして考えて、すべての答えを正確に答えることに重きを置いた様子。答え合わせをした感じだと当日はうまくいきそうな様子なので、来週は自由作品で（本人の希望）行いたいと思います', null, '時間帯: その他
タイピング: なし'),
  ('5e52c058-b64e-5b59-9141-e7fbe6e7cfa5', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-18', null, null, '通常 / そうすけくんが好きなものを行う、ゾンビが良かったが、結局今日は音を使うものになりました', '自分で楽器を描いて、音を選び、音程の高さなどを調節しながら音を出すというコードを行いました。〜秒待つというコードを加えた上でいくつかの楽器を押すと鳴るという仕組みをつくり楽しんでいました。', null, '時間帯: その他
タイピング: F,J,K,Lのアルファベットをタイピングする練習を行いました。割と単体のタイピングであればできそうなので少しずつ行う回数を増やしていければいいかなと思います。
盛り上がり: 今日は45分なんとか、集中力がきれずに頑張ることができました、最初にタイピングを行うことで、だいぶ机に向かう時間が増えるなという印象です'),
  ('bc382d56-d5d8-5557-ade5-3cfad8f4934d', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-18', null, null, '通常 / ゲームの細分化', '最初に先週解いた検定の問題を軽く答えあわせしました。どんなゲームに作ったの問尋ねながら、問題文と見比べながら確認していきました。わかりにくかったところを聞くと、コードを止めるところがはてなを思い浮かべていました。 次に宇宙バトル2を作りました。ゲームを遊んでみて、どのスプライトがどんな動きをしているかは口で答えられていました。ただ、それをコードに作り始めると、上手く対応ができていませんでした。一部使うブロックを提示したら、ほかのブロックも持ってこられていてコードをくみ上げられていました。作りたいことのトリガーとなるコードを提示すれば作り進められる能力はできている思います。ゲームは完成はできました。', '検定', '時間帯: その他
タイピング: 着実に打てる文字が増えてきました'),
  ('4524047e-80c8-52f8-bf3f-88d29fe3673c', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-18', null, null, '通常 / 基本操作コース04 追跡ゲーム＞ポイント、背景チェンジ、レベルアップの文字表示、アレンジ', '色々と質問しながら、変数の使い方、メッセージの送り方、ずっと〜がないとコードが作動しないなど、ポイントを押さえながら学習。その後に自分でアレンジ〜になった時にもうひとつコインを追加して、減点する〜やスコアを０に戻すなど自分で手を加えることを行いました。', null, '時間帯: その他
タイピング: あまりタイピングは得意ではない様子で、時間をかけてゆっくり行っていました。
盛り上がり: アレンジになった時に発想がとてもすばらしく、もう一つコインを出して、０にしてなんとかクリアにならないようにするという状態を作っていました。 変数の〜にするや〜づつ変わる、の違いもちゃんと理解でき、使い分けができていたと思います'),
  ('4c6033ca-e2fa-5124-b1aa-eac053eb9b91', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-17', '18:40:00', null, '通常 / １級過去問３問目', '50分と時間が長いため受験のみ（前回の答え合わせはしないで、問題数を多く解く方に比重を置くことにしました。）１箇所だけどうしてもバグになってしまう箇所がある様子で、そこがうまくいけば〜と話していたので、おおかたはできている様子。 来週２問分の答え合わせをして、試験に挑みたいと思います', null, 'タイピング: タイピングは板についてきているので、次回のマイパソの結果が楽しみです。'),
  ('b60b6530-0ea1-5e59-95d9-2041a420eb3e', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-17', '17:30:00', null, '通常 / ４級問題 エントリー第15回応用課題1', '途中で少ししゃべったり姿勢が崩れたりもしましたが、時間内に最後までできていました。 「ステージの場所」という指示を見落として、背景の指定ブロックをスプライトの方へ入れてしまっていましたが、他はできていました。問題文の読み落としに注意するよう伝えました。', null, 'タイピング: 練習モードをいくつかやっていました。
盛り上がり: 答え合わせをしながら、正解を確認しては嬉しそうにしていました。 問題を見た瞬間、「さらちゃんの天狗の動きだ！」とおもしろがっていました。'),
  ('0b6e5a69-c6f6-58c3-bc9c-4db3793ad457', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-17', '18:40:00', null, '通常 / 検定過去問 3回目', '遅刻してきたため、3回目の応用問題受験のみ、 見た感じでは、手応えありな様子でした。 次回の月曜日に答え合わせ', null, null),
  ('66d2b964-63fe-55c1-8986-df1553bbff19', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-17', '16:30:00', null, '通常 / ペンツールで図形を描く→【小技】アル君グルグル＿スタンプ（https://app.arspark.jp/contents/21971）', '四角を描くところから、スタンプのペンツールをつかって、花火の作品を作成するまで頑張ってみました。 彼女の良いところはきちんと説明された部分に関してはとても理解をしようという意欲があるので、今回のようにゲーム性というよりかはアート的な作品を作ることで、角度の問題などを理解してくれる感じがします。', null, 'タイピング: どちらも１級を目指して何回も練習していました、高得点をマークしていたので次回は必ず受験させてあげる方がいいかなと思います
